function getNavigationLockStateForHash(hash = "#home") {
  const normalizedHash = normalizeNavigationHash(hash || "#home");
  const isAdminContext = isAdminUser();
  const growNetworkUnlocked = isGrowNetworkUnlocked(getSessions());
  const communityGrowUnlocked = isCommunityGrowUnlocked(getSessions());

  if (!isAdminContext && (normalizedHash === "#gallery" || normalizedHash.startsWith("#gallery/"))) {
    if (!growNetworkUnlocked) {
      return {
        locked: true,
        mode: "grow-network",
        message: "Start your first soaking session to begin unlocking the Grow Network.",
        ctaLabel: "Start First Session",
        ctaHref: "#new",
      };
    }

    if (!communityGrowUnlocked) {
      return {
        locked: true,
        mode: "community-grow",
        message: "Community Grow becomes available after your first grow snapshot is created.",
        ctaLabel: "Go To My Sessions",
        ctaHref: "#sessions",
      };
    }
  }

  if (!isAdminContext && !growNetworkUnlocked && (
    normalizedHash === "#sources"
    || normalizedHash.startsWith("#sources/")
    || normalizedHash === "#network"
    || normalizedHash.startsWith("#network/")
  )) {
    return {
      locked: true,
      mode: "grow-network",
      message: "Start your first soaking session to begin unlocking the Grow Network.",
      ctaLabel: "Start First Session",
      ctaHref: "#new",
    };
  }

  return {
    locked: false,
    mode: "",
    message: "",
    ctaLabel: "",
    ctaHref: "",
  };
}

function ensureNavigationLockToast() {
  let toast = document.querySelector("#navigation-lock-toast");
  if (toast) {
    return toast;
  }

  toast = document.createElement("section");
  toast.id = "navigation-lock-toast";
  toast.className = "navigation-lock-toast";
  toast.hidden = true;
  toast.innerHTML = `
    <div class="navigation-lock-toast__shell">
      <div class="navigation-lock-toast__copy">
        <strong class="navigation-lock-toast__title">Grow Network</strong>
        <p class="navigation-lock-toast__message"></p>
      </div>
      <div class="navigation-lock-toast__actions">
        <a class="button button-primary navigation-lock-toast__cta" href="#new" hidden></a>
        <button type="button" class="navigation-lock-toast__close" aria-label="Dismiss message">×</button>
      </div>
    </div>
  `;

  toast.querySelector(".navigation-lock-toast__close")?.addEventListener("click", () => {
    toast.hidden = true;
    toast.classList.remove("is-visible");
  });

  document.body.appendChild(toast);
  return toast;
}

function showNavigationLockToast(config = {}) {
  const toast = ensureNavigationLockToast();
  const title = String(config.title || "Grow Network").trim() || "Grow Network";
  const message = String(config.message || "Start your first soaking session to begin unlocking the Grow Network.").trim();
  const ctaLabel = String(config.ctaLabel || "").trim();
  const ctaHref = String(config.ctaHref || "").trim();
  const titleNode = toast.querySelector(".navigation-lock-toast__title");
  const messageNode = toast.querySelector(".navigation-lock-toast__message");
  const ctaNode = toast.querySelector(".navigation-lock-toast__cta");

  if (titleNode) {
    titleNode.textContent = title;
  }
  if (messageNode) {
    messageNode.textContent = message;
  }
  if (ctaNode instanceof HTMLAnchorElement) {
    if (ctaLabel && ctaHref) {
      ctaNode.hidden = false;
      ctaNode.textContent = ctaLabel;
      ctaNode.setAttribute("href", ctaHref);
    } else {
      ctaNode.hidden = true;
      ctaNode.textContent = "";
      ctaNode.setAttribute("href", "#home");
    }
  }

  toast.hidden = false;
  toast.classList.add("is-visible");

  if (typeof toast.__hideTimeoutId === "number" && toast.__hideTimeoutId) {
    window.clearTimeout(toast.__hideTimeoutId);
  }

  toast.__hideTimeoutId = window.setTimeout(() => {
    toast.classList.remove("is-visible");
    toast.hidden = true;
    toast.__hideTimeoutId = 0;
  }, 5200);
}

function ensureGrowRemindersPromptModal() {
  let modal = document.querySelector("#grow-reminders-prompt-modal");
  if (modal instanceof HTMLDialogElement) {
    return modal;
  }

  modal = document.createElement("dialog");
  modal.id = "grow-reminders-prompt-modal";
  modal.className = "snapshot-modal grow-reminders-modal";
  modal.innerHTML = `
    <div class="snapshot-modal-card grow-reminders-modal-card" role="document" aria-labelledby="grow-reminders-prompt-title">
      <div class="snapshot-modal-copy grow-reminders-modal-copy">
        <p class="eyebrow">Grow Reminders</p>
        <h3 id="grow-reminders-prompt-title">Enable Grow Reminders</h3>
        <p>Cannakan® Grow can notify you when it’s time to check soaking, move seeds to germination, update results, capture snapshots, or restock supplies.</p>
        <p class="muted grow-reminders-modal-note">You can change this anytime in your profile settings.</p>
      </div>
      <div class="snapshot-modal-actions grow-reminders-modal-actions">
        <button type="button" class="button button-primary" data-grow-reminders-enable="true">Enable Notifications</button>
        <button type="button" class="button button-secondary" data-grow-reminders-dismiss="true">Not Now</button>
      </div>
    </div>
  `;

  modal.addEventListener("click", (event) => {
    if (event.target === modal && modal.open) {
      modal.close("dismissed");
    }
  });

  document.body.appendChild(modal);
  return modal;
}

async function requestGrowRemindersBrowserPermission() {
  if (!("Notification" in window) || typeof Notification.requestPermission !== "function") {
    return "unsupported";
  }

  try {
    return await Notification.requestPermission();
  } catch (error) {
    console.warn("[Grow Reminders] Notification permission request failed.", error);
    return "error";
  }
}

function getGrowRemindersBrowserPermissionState() {
  if (!("Notification" in window)) {
    return "unsupported";
  }

  return String(Notification.permission || "default").trim().toLowerCase() || "default";
}

function getNotificationPermissionStateMeta(permissionState = getGrowRemindersBrowserPermissionState()) {
  const normalizedState = String(permissionState || "default").trim().toLowerCase();
  switch (normalizedState) {
    case "granted":
      return {
        key: "granted",
        label: "Granted",
        tone: "success",
        description: "This browser can receive Cannakan® Grow reminder notifications when push delivery is enabled.",
        guidance: "",
      };
    case "denied":
      return {
        key: "denied",
        label: "Denied",
        tone: "critical",
        description: "This browser is currently blocking notification permission requests.",
        guidance: "To re-enable later, open your browser site settings for this app and allow notifications, then turn Push Notifications Enabled back on here.",
      };
    case "unsupported":
      return {
        key: "unsupported",
        label: "Unsupported",
        tone: "warning",
        description: "This browser or device does not currently support notification permission prompts.",
        guidance: "In-app notifications still work here, but browser/device push reminders are not available on this device.",
      };
    case "default":
    default:
      return {
        key: "default",
        label: "Not enabled",
        tone: "info",
        description: "Notification permission has not been granted yet for this browser.",
        guidance: "Turn on Push Notifications Enabled to request permission when you’re ready.",
      };
  }
}

function renderNotificationPermissionStateMarkup(options = {}) {
  const {
    permissionState = getGrowRemindersBrowserPermissionState(),
    title = "Browser / Device Permission",
    compact = false,
  } = options || {};
  const meta = getNotificationPermissionStateMeta(permissionState);
  return `
    <div class="profile-notification-permission${compact ? " profile-notification-permission--compact" : ""} is-${escapeHtml(meta.tone)}">
      <div class="profile-notification-permission-head">
        <div class="profile-notification-permission-copy">
          <strong>${escapeHtml(title)}</strong>
          <span>${escapeHtml(meta.description)}</span>
        </div>
        <span class="profile-permission-badge is-${escapeHtml(meta.tone)}">${escapeHtml(meta.label)}</span>
      </div>
      ${meta.guidance ? `<p class="profile-notification-guidance">${escapeHtml(meta.guidance)}</p>` : ""}
    </div>
  `;
}

function getConfiguredPushPublicKey() {
  return String(
    window.CANNAKAN_SUPABASE_CONFIG?.pushPublicKey
    || window.CANNAKAN_SUPABASE_CONFIG?.push_public_key
    || window.CANNAKAN_PUSH_PUBLIC_KEY
    || "",
  ).trim();
}

function supportsPushSubscriptionApi() {
  return Boolean(
    window.isSecureContext
    && "serviceWorker" in navigator
    && "PushManager" in window,
  );
}

function getCurrentPushDeviceKey() {
  return getOrCreateSiteVisitorId();
}

function getPushDeviceLabel() {
  const environment = getInstallEnvironment();
  const browserLabel = environment.browser === "edge"
    ? "Edge"
    : (environment.browser === "safari"
      ? "Safari"
      : (environment.browser === "chrome" ? "Chrome" : "Browser"));
  const deviceLabel = environment.device === "mobile" ? "Mobile" : "Desktop";
  return `${browserLabel} on ${deviceLabel}`;
}

function urlBase64ToUint8Array(value = "") {
  const padding = "=".repeat((4 - (value.length % 4)) % 4);
  const base64 = `${value}${padding}`.replace(/-/g, "+").replace(/_/g, "/");
  const rawData = window.atob(base64);
  return Uint8Array.from([...rawData].map((character) => character.charCodeAt(0)));
}

const SERVICE_WORKER_READY_TIMEOUT_MS = 12000;
const SERVICE_WORKER_DIAGNOSTIC_READY_TIMEOUT_MS = 3500;
const PUSH_SERVICE_INITIALIZING_TITLE = "Push notifications are still initializing on this device.";
const PUSH_SERVICE_INITIALIZING_GUIDANCE = "Give the app a moment to finish connecting, then try again.";
const PUSH_SERVICE_INITIALIZING_MESSAGE = `${PUSH_SERVICE_INITIALIZING_TITLE} ${PUSH_SERVICE_INITIALIZING_GUIDANCE}`;

function isPushServiceInitializingMessage(value = "") {
  const message = String(value || "").trim().toLowerCase();
  return Boolean(
    message
    && (
      message.includes("service worker registration is not ready")
      || message.includes("service worker notification delivery is not ready")
      || message.includes("no active service worker")
      || (message.includes("pushmanager") && message.includes("subscription failed"))
    ),
  );
}

function getUserFacingPushMessage(value = "", fallback = "") {
  const message = String(value || "").trim();
  if (isPushServiceInitializingMessage(message)) {
    return PUSH_SERVICE_INITIALIZING_MESSAGE;
  }
  return message || fallback;
}

function getServiceWorkerLifecycleStatus(registration = null) {
  if (!("serviceWorker" in navigator) || !window.isSecureContext) {
    return "unsupported";
  }

  if (!registration) {
    return "inactive";
  }

  if (registration.active) {
    return "active";
  }

  const installingState = String(registration.installing?.state || "").trim().toLowerCase();
  const waitingState = String(registration.waiting?.state || "").trim().toLowerCase();

  if (installingState === "activating" || waitingState === "activating") {
    return "activating";
  }
  if (registration.installing) {
    return "installing";
  }
  if (registration.waiting) {
    return "waiting";
  }

  return "inactive";
}

function syncPushDiagnosticsServiceWorkerStatus(registration = null) {
  if (!appState.pushDiagnostics) {
    return;
  }

  appState.pushDiagnostics = {
    ...appState.pushDiagnostics,
    serviceWorkerStatus: getServiceWorkerLifecycleStatus(registration),
  };
}

async function waitForServiceWorkerActivation(registration = null, timeoutMs = SERVICE_WORKER_READY_TIMEOUT_MS) {
  if (!registration) {
    return null;
  }

  if (registration.active) {
    return registration;
  }

  return new Promise((resolve) => {
    let finished = false;
    const trackedWorkers = new Set();
    const safeTimeoutMs = Math.max(1000, Number(timeoutMs) || SERVICE_WORKER_READY_TIMEOUT_MS);

    const cleanup = () => {
      registration.removeEventListener?.("updatefound", handleUpdateFound);
      navigator.serviceWorker.removeEventListener?.("controllerchange", handleControllerChange);
      trackedWorkers.forEach((worker) => {
        worker.removeEventListener?.("statechange", handleWorkerStateChange);
      });
      trackedWorkers.clear();
      window.clearTimeout(timeoutId);
    };

    const finish = (nextRegistration = registration) => {
      if (finished) {
        return;
      }

      const activeRegistration = nextRegistration?.active
        ? nextRegistration
        : (registration.active ? registration : null);
      if (!activeRegistration) {
        return;
      }

      finished = true;
      appState.serviceWorkerRegistration = activeRegistration;
      syncPushDiagnosticsServiceWorkerStatus(activeRegistration);
      cleanup();
      resolve(activeRegistration);
    };

    const refreshRegistration = async () => {
      try {
        const latestRegistration = await navigator.serviceWorker.getRegistration(registration.scope);
        if (latestRegistration) {
          appState.serviceWorkerRegistration = latestRegistration;
          trackWorker(latestRegistration.installing);
          trackWorker(latestRegistration.waiting);
          finish(latestRegistration);
        } else {
          finish(registration);
        }
      } catch (error) {
        finish(registration);
      }
    };

    function handleWorkerStateChange() {
      void refreshRegistration();
    }

    function handleUpdateFound() {
      trackWorker(registration.installing);
      trackWorker(registration.waiting);
      void refreshRegistration();
    }

    function handleControllerChange() {
      void refreshRegistration();
    }

    function trackWorker(worker) {
      if (!worker || trackedWorkers.has(worker)) {
        return;
      }

      trackedWorkers.add(worker);
      worker.addEventListener?.("statechange", handleWorkerStateChange);
      if (worker.state === "activated") {
        void refreshRegistration();
      }
    }

    const timeoutId = window.setTimeout(() => {
      if (finished) {
        return;
      }

      finished = true;
      cleanup();
      resolve(registration.active ? registration : null);
    }, safeTimeoutMs);

    registration.addEventListener?.("updatefound", handleUpdateFound);
    navigator.serviceWorker.addEventListener?.("controllerchange", handleControllerChange);
    trackWorker(registration.installing);
    trackWorker(registration.waiting);
    void refreshRegistration();
  });
}

async function waitForNavigatorServiceWorkerReady(timeoutMs = SERVICE_WORKER_READY_TIMEOUT_MS) {
  const safeTimeoutMs = Math.max(1000, Number(timeoutMs) || SERVICE_WORKER_READY_TIMEOUT_MS);
  return Promise.race([
    navigator.serviceWorker.ready.then((registration) => registration || null).catch(() => null),
    new Promise((resolve) => {
      window.setTimeout(() => resolve(null), safeTimeoutMs);
    }),
  ]);
}

async function getServiceWorkerRegistration(options = {}) {
  const {
    requireActive = true,
    timeoutMs = SERVICE_WORKER_READY_TIMEOUT_MS,
    update = false,
  } = options || {};

  if (!("serviceWorker" in navigator) || !window.isSecureContext) {
    syncPushDiagnosticsServiceWorkerStatus(null);
    return null;
  }

  try {
    let registration = appState.serviceWorkerRegistration || await navigator.serviceWorker.getRegistration();
    if (!registration) {
      registration = await navigator.serviceWorker.register("/service-worker.js");
    }

    appState.serviceWorkerRegistration = registration || null;
    syncPushDiagnosticsServiceWorkerStatus(registration);

    if (registration && update) {
      void registration.update().catch((error) => {
        console.warn("[Push Delivery] Service worker update check failed.", error);
      });
    }

    if (!registration || !requireActive) {
      return registration || null;
    }

    const readyRegistration = await Promise.race([
      waitForNavigatorServiceWorkerReady(timeoutMs),
      waitForServiceWorkerActivation(registration, timeoutMs).then((nextRegistration) => {
        return nextRegistration?.active
          ? waitForNavigatorServiceWorkerReady(Math.min(Math.max(1000, Number(timeoutMs) || SERVICE_WORKER_READY_TIMEOUT_MS), 3000))
          : null;
      }),
    ]);
    const activeRegistration = readyRegistration?.active
      ? readyRegistration
      : null;

    appState.serviceWorkerRegistration = activeRegistration || registration || null;
    syncPushDiagnosticsServiceWorkerStatus(appState.serviceWorkerRegistration);
    return activeRegistration || null;
  } catch (error) {
    console.warn("[Push Delivery] Service worker not ready.", error);
    syncPushDiagnosticsServiceWorkerStatus(appState.serviceWorkerRegistration || null);
    return null;
  }
}

function getUserPushSubscriptionsStorageKey(userId = "") {
  const normalizedUserId = String(userId || "").trim();
  return normalizedUserId
    ? `${USER_PUSH_SUBSCRIPTIONS_STORAGE_KEY}:${normalizedUserId}`
    : USER_PUSH_SUBSCRIPTIONS_STORAGE_KEY;
}

function getPushDeliveredNotificationEventsStorageKey(userId = "") {
  const normalizedUserId = String(userId || "").trim();
  return normalizedUserId
    ? `${PUSH_DELIVERED_NOTIFICATION_EVENTS_STORAGE_KEY}:${normalizedUserId}`
    : PUSH_DELIVERED_NOTIFICATION_EVENTS_STORAGE_KEY;
}

function getPushSendFailuresStorageKey(userId = "") {
  const normalizedUserId = String(userId || "").trim();
  return normalizedUserId
    ? `${PUSH_SEND_FAILURES_STORAGE_KEY}:${normalizedUserId}`
    : PUSH_SEND_FAILURES_STORAGE_KEY;
}

function normalizePushSubscriptionRecord(record = {}) {
  const sourceRecord = record && typeof record === "object" ? record : {};
  const endpoint = String(sourceRecord.endpoint || "").trim();
  const deviceKey = String(sourceRecord.deviceKey || sourceRecord.device_key || "").trim();
  const userId = String(sourceRecord.userId || sourceRecord.user_id || "").trim();
  const subscriptionPayload = sourceRecord.subscription && typeof sourceRecord.subscription === "object"
    ? sourceRecord.subscription
    : {};

  if (!deviceKey && !endpoint) {
    return null;
  }

  return {
    id: String(sourceRecord.id || "").trim(),
    userId,
    deviceKey: deviceKey || endpoint,
    endpoint,
    subscription: subscriptionPayload,
    p256dhKey: String(sourceRecord.p256dhKey || sourceRecord.p256dh_key || "").trim(),
    authKey: String(sourceRecord.authKey || sourceRecord.auth_key || "").trim(),
    permissionState: String(sourceRecord.permissionState || sourceRecord.permission_state || "default").trim().toLowerCase() || "default",
    pushEnabled: Boolean(sourceRecord.pushEnabled ?? sourceRecord.push_enabled),
    userAgent: String(sourceRecord.userAgent || sourceRecord.user_agent || "").trim(),
    deviceLabel: String(sourceRecord.deviceLabel || sourceRecord.device_label || "").trim(),
    lastSeenAt: String(sourceRecord.lastSeenAt || sourceRecord.last_seen_at || "").trim(),
    lastTestedAt: String(sourceRecord.lastTestedAt || sourceRecord.last_tested_at || "").trim(),
    lastDeliveryAt: String(sourceRecord.lastDeliveryAt || sourceRecord.last_delivery_at || "").trim(),
    disabledAt: String(sourceRecord.disabledAt || sourceRecord.disabled_at || "").trim(),
    removedAt: String(sourceRecord.removedAt || sourceRecord.removed_at || "").trim(),
    createdAt: String(sourceRecord.createdAt || sourceRecord.created_at || "").trim(),
    updatedAt: String(sourceRecord.updatedAt || sourceRecord.updated_at || "").trim(),
  };
}

function getCurrentPushEndpointCandidate() {
  return String(appState.currentPushEndpoint || appState.currentPushSubscriptionRecord?.endpoint || "").trim();
}

function isCurrentPushSubscriptionRecord(record = {}) {
  const endpoint = String(record?.endpoint || "").trim();
  const currentEndpoint = getCurrentPushEndpointCandidate();
  if (endpoint && currentEndpoint) {
    return endpoint === currentEndpoint;
  }
  return String(record?.deviceKey || "").trim() === getCurrentPushDeviceKey();
}

function getPushDeviceVisualStatus(record = {}) {
  if (record?.removedAt || record?.removed_at) {
    return "removed";
  }
  const result = getPushDeviceTestResult(record);
  if (result?.ok === false) {
    return isStalePushFailureText(result.message || "")
      ? "stale"
      : "failed";
  }
  const deliveryStatus = getPushDeviceDeliveryStatus(record);
  if (deliveryStatus) {
    if (isStalePushFailureText(deliveryStatus.failureCode || "") || isStalePushFailureText(deliveryStatus.failureReason || "")) {
      return "stale";
    }
    if (isFailedPushDeliveryStatus(deliveryStatus.status)) {
      return String(deliveryStatus.status || "").trim().toLowerCase() === "invalid" ? "stale" : "failed";
    }
  }
  if (record?.disabledAt || record?.disabled_at || record?.pushEnabled === false || record?.permissionState !== "granted") {
    return "paused";
  }
  return "active";
}

function getPushDeviceStatusMeta(record = {}) {
  switch (getPushDeviceVisualStatus(record)) {
    case "stale":
      return { label: "Stale", tone: "warning", cardClass: "is-stale" };
    case "failed":
      return { label: "Failed", tone: "warning", cardClass: "is-warning" };
    case "removed":
      return { label: "Removed", tone: "critical", cardClass: "is-removed" };
    case "paused":
      return { label: "Paused", tone: "info", cardClass: "is-paused" };
    case "active":
    default:
      return { label: "Active", tone: "success", cardClass: "" };
  }
}

function isPushDeviceCleanupCandidate(record = {}) {
  const status = getPushDeviceVisualStatus(record);
  return status === "failed" || status === "stale";
}

function sortPushSubscriptionsCurrentDeviceFirst(records = []) {
  return [...records].sort((left, right) => {
    const leftCurrent = isCurrentPushSubscriptionRecord(left) ? 1 : 0;
    const rightCurrent = isCurrentPushSubscriptionRecord(right) ? 1 : 0;
    if (leftCurrent !== rightCurrent) {
      return rightCurrent - leftCurrent;
    }
    return (Date.parse(right?.updatedAt || right?.lastSeenAt || "") || 0) - (Date.parse(left?.updatedAt || left?.lastSeenAt || "") || 0);
  });
}

function loadStoredUserPushSubscriptions(userId = "") {
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedUserId) {
    return [];
  }

  try {
    const storedValue = JSON.parse(localStorage.getItem(getUserPushSubscriptionsStorageKey(normalizedUserId)) || "[]");
    if (!Array.isArray(storedValue)) {
      return [];
    }
    return sortPushSubscriptionsCurrentDeviceFirst(
      storedValue
        .map((record) => normalizePushSubscriptionRecord(record))
        .filter(Boolean),
    );
  } catch (error) {
    console.warn("[Push Delivery] Failed to read stored push subscriptions.", error);
    return [];
  }
}

function syncUserPushSubscriptionsCache(userId = "", records = [], options = {}) {
  const normalizedUserId = String(userId || "").trim();
  const { persistLocal = true } = options || {};
  const normalizedRecords = sortPushSubscriptionsCurrentDeviceFirst(
    (Array.isArray(records) ? records : [])
      .map((record) => normalizePushSubscriptionRecord(record))
      .filter(Boolean),
  );

  appState.pushSubscriptions = normalizedRecords;
  appState.currentPushSubscriptionRecord = normalizedRecords.find((record) => isCurrentPushSubscriptionRecord(record)) || null;

  if (persistLocal && normalizedUserId) {
    try {
      localStorage.setItem(
        getUserPushSubscriptionsStorageKey(normalizedUserId),
        JSON.stringify(normalizedRecords),
      );
    } catch (error) {
      console.warn("[Push Delivery] Failed to persist local push subscriptions.", error);
    }
  }

  return normalizedRecords;
}

function getCurrentUserPushSubscriptions(userId = appState.user?.id || "") {
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedUserId) {
    appState.pushSubscriptions = [];
    appState.currentPushSubscriptionRecord = null;
    return [];
  }

  if (!Array.isArray(appState.pushSubscriptions) || !appState.pushSubscriptions.length) {
    return syncUserPushSubscriptionsCache(normalizedUserId, loadStoredUserPushSubscriptions(normalizedUserId), {
      persistLocal: false,
    });
  }

  appState.currentPushSubscriptionRecord = appState.pushSubscriptions.find((record) => isCurrentPushSubscriptionRecord(record)) || null;
  return appState.pushSubscriptions;
}

function isUserPushSubscriptionsTableMissingError(error) {
  return isSupabaseTableMissingError(error, USER_PUSH_SUBSCRIPTIONS_TABLE);
}

function markUserPushSubscriptionsTableUnavailable() {
  appState.pushSubscriptionsTableUnavailable = true;
  appState.pushSubscriptionsError = "";
  logRuntimeIssueOnce(
    "warn",
    "push-subscriptions-backend-fallback",
    "Push subscriptions backend unavailable. Using local device fallback.",
  );
}

function getPushSubscriptionSupportState() {
  const permissionState = getGrowRemindersBrowserPermissionState();
  const pushPreferenceEnabled = appState.notificationPreferences?.pushNotificationsEnabled === true;
  const currentSubscription = appState.currentPushSubscriptionRecord;
  const hasActiveSubscription = Boolean(currentSubscription?.endpoint && !currentSubscription?.disabledAt);
  const serviceWorkerReady = Boolean(appState.serviceWorkerRegistration?.active);

  if (!window.isSecureContext || !("serviceWorker" in navigator)) {
    return "unsupported";
  }
  if (permissionState === "denied") {
    return "denied";
  }
  if (permissionState !== "granted") {
    return "default";
  }
  if (currentSubscription?.disabledAt) {
    return "disabled";
  }
  if (!supportsPushSubscriptionApi()) {
    return "local-only";
  }
  if (!pushPreferenceEnabled) {
    return "preference-paused";
  }
  if (hasActiveSubscription) {
    return serviceWorkerReady ? "subscribed" : "service-worker-pending";
  }
  if (!serviceWorkerReady) {
    return "service-worker-pending";
  }
  if (!getConfiguredPushPublicKey()) {
    return "not-configured";
  }
  return "ready";
}

function getPushSubscriptionSupportMeta(state = getPushSubscriptionSupportState()) {
  switch (String(state || "").trim()) {
    case "subscribed":
      return {
        tone: "success",
        label: "Subscribed",
        title: "This device is ready for push delivery.",
        description: "Important grow reminders can be delivered through the browser/PWA notification channel on this device.",
      };
    case "ready":
      return {
        tone: "info",
        label: "Ready",
        title: "Push delivery can be activated on this device.",
        description: "Browser permission is granted. Saving push preferences will connect this device subscription when a public key is available.",
      };
    case "not-configured":
      return {
        tone: "warning",
        label: "Key Needed",
        title: "Browser delivery is available, but no push key is configured yet.",
        description: "Local notification tests can still run now. A VAPID/public push key must be added before backend push delivery can subscribe this device.",
      };
    case "service-worker-pending":
      return {
        tone: "warning",
        label: "Preparing",
        title: PUSH_SERVICE_INITIALIZING_TITLE,
        description: PUSH_SERVICE_INITIALIZING_GUIDANCE,
      };
    case "local-only":
      return {
        tone: "warning",
        label: "Local Only",
        title: "System notifications can run locally, but push subscription APIs are unavailable here.",
        description: "This device can still use service-worker notification delivery while the app is open, but it cannot create a reusable push subscription record.",
      };
    case "disabled":
      return {
        tone: "info",
        label: "Disabled",
        title: "Push delivery is disabled on this device.",
        description: "Register this device again when you want it to receive browser/device reminders.",
      };
    case "preference-paused":
      return {
        tone: "warning",
        label: "Paused",
        title: "Push notifications are paused by your account preference.",
        description: "Turn on Enable Push Notifications to let registered devices receive test pushes and grow reminders.",
      };
    case "denied":
      return {
        tone: "critical",
        label: "Blocked",
        title: "Browser/device notification delivery is blocked.",
        description: "Re-enable notifications in your browser site settings, then turn push notifications back on here.",
      };
    case "default":
    default:
      return {
        tone: "info",
        label: "Not Enabled",
        title: "This device has not granted browser notification permission yet.",
        description: "Enable push notifications to request permission and prepare this device for future reminder delivery.",
      };
  }
}

function renderPushDeliveryStateMarkup() {
  const meta = getPushSubscriptionSupportMeta();
  const subscriptions = getCurrentUserPushSubscriptions();
  const activeDeviceCount = subscriptions.filter((record) => record.pushEnabled && !record.disabledAt).length;
  const currentDeviceRecord = appState.currentPushSubscriptionRecord;
  const canSendTest = canUseBrowserNotificationDelivery();
  const canDisableCurrentDevice = Boolean(currentDeviceRecord && !currentDeviceRecord.disabledAt);
  return `
    <div class="profile-notification-permission profile-push-delivery-state is-${escapeHtml(meta.tone)}">
      <div class="profile-notification-permission-head">
        <div class="profile-notification-permission-copy">
          <strong>Push Delivery Status</strong>
          <span>${escapeHtml(meta.title)}</span>
        </div>
        <span class="profile-permission-badge is-${escapeHtml(meta.tone)}">${escapeHtml(meta.label)}</span>
      </div>
      <p class="profile-notification-guidance">${escapeHtml(meta.description)}</p>
      <div class="profile-push-delivery-meta">
        <span>${escapeHtml(activeDeviceCount === 1 ? "1 active device" : `${activeDeviceCount} active devices`)}</span>
        <span>${escapeHtml(currentDeviceRecord?.endpoint ? "Current device subscription saved" : "Current device subscription not saved yet")}</span>
      </div>
      <div class="profile-push-delivery-actions">
        <button type="button" class="button button-secondary" data-profile-push-test="true"${canSendTest ? "" : " disabled"}>Send Test Notification</button>
        <button type="button" class="button button-secondary" data-profile-push-disable="true"${canDisableCurrentDevice ? "" : " disabled"}>Disable On This Device</button>
      </div>
    </div>
  `;
}

function canViewPushDiagnosticsPanel() {
  return Boolean(appState.user && (isAdminUser() || isLocalDevQaBypassActive()));
}

function formatPushDiagnosticsTimestamp(value = "") {
  const timestamp = Date.parse(String(value || "").trim());
  if (!Number.isFinite(timestamp)) {
    return "Not recorded yet";
  }
  return new Date(timestamp).toLocaleString([], {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  });
}

function getPushDiagnosticsStatusMeta(isPositive, positiveLabel = "Ready", negativeLabel = "Unavailable") {
  return isPositive
    ? { tone: "success", label: positiveLabel }
    : { tone: "warning", label: negativeLabel };
}

function renderPushDiagnosticsRowMarkup(label = "", value = "", tone = "info", helper = "") {
  return `
    <div class="profile-push-diagnostics-row">
      <div class="profile-push-diagnostics-copy">
        <strong>${escapeHtml(label)}</strong>
        ${helper ? `<span>${escapeHtml(helper)}</span>` : ""}
      </div>
      <span class="profile-permission-badge is-${escapeHtml(tone)}">${escapeHtml(value)}</span>
    </div>
  `;
}

function getActiveRegisteredPushDevices(records = getCurrentUserPushSubscriptions()) {
  return sortPushSubscriptionsCurrentDeviceFirst(
    (Array.isArray(records) ? records : [])
      .map((record) => normalizePushSubscriptionRecord(record))
      .filter((record) => (
        record
        && Boolean(record.endpoint)
        && Boolean(record.deviceKey)
        && getPushDeviceVisualStatus(record) !== "removed"
      )),
  );
}

function getPushDeviceDisplayLabel(record = {}) {
  const label = String(record?.deviceLabel || "").trim();
  if (label) {
    return isCurrentPushSubscriptionRecord(record) ? `${label} · Current device` : label;
  }

  const userAgent = String(record?.userAgent || "").toLowerCase();
  const browser = userAgent.includes("edg/")
    ? "Edge"
    : (userAgent.includes("firefox")
      ? "Firefox"
      : (userAgent.includes("safari") && !userAgent.includes("chrome") ? "Safari" : "Browser"));
  const platform = userAgent.includes("windows")
    ? "Windows"
    : (userAgent.includes("android")
      ? "Android"
      : (userAgent.includes("iphone") || userAgent.includes("ipad") ? "iOS" : "Device"));
  const fallback = `${browser} on ${platform}`;
  return isCurrentPushSubscriptionRecord(record) ? `${fallback} · Current device` : fallback;
}

function getPushDeviceTestResult(record = {}) {
  const key = String(record?.deviceKey || "").trim();
  return key ? (appState.pushDiagnostics?.deviceTestResults?.[key] || null) : null;
}

function getPushDeviceDeliveryStatus(record = {}) {
  const key = String(record?.deviceKey || "").trim();
  return key ? (appState.pushDeliveryStatuses?.[key] || null) : null;
}

function isFailedPushDeliveryStatus(status = "") {
  return ["failed", "invalid", "rejected", "expired", "stale"].includes(String(status || "").trim().toLowerCase());
}

function isStalePushFailureText(value = "") {
  const text = String(value || "").trim().toLowerCase();
  return Boolean(
    text
    && (
      text.includes("404")
      || text.includes("410")
      || text.includes("gone")
      || text.includes("expired")
      || text.includes("invalid")
      || text.includes("not registered")
      || text.includes("unregistered")
      || text.includes("rejected")
    ),
  );
}

function setPushDeviceTestResults(deviceKeys = [], result = {}) {
  const normalizedKeys = (Array.isArray(deviceKeys) ? deviceKeys : [deviceKeys])
    .map((entry) => String(entry || "").trim())
    .filter(Boolean);
  if (!normalizedKeys.length) {
    return;
  }

  const timestamp = new Date().toISOString();
  const nextResults = {
    ...(appState.pushDiagnostics?.deviceTestResults || {}),
  };
  normalizedKeys.forEach((deviceKey) => {
    nextResults[deviceKey] = {
      ok: result.ok === true,
      message: String(result.message || "").trim(),
      at: timestamp,
    };
  });
  appState.pushDiagnostics = {
    ...(appState.pushDiagnostics || {}),
    deviceTestResults: nextResults,
    lastTestResult: result.ok === true ? "Test push sent" : "Test push failed",
    lastTestAt: timestamp,
    lastErrorMessage: result.ok === true ? "" : String(result.message || "").trim(),
  };
}

function renderPushRegisteredDeviceMarkup(record = {}, options = {}) {
  const { canSend = false, sendingKey = "" } = options || {};
  const deviceKey = String(record?.deviceKey || "").trim();
  const endpoint = String(record?.endpoint || "").trim();
  const isSending = sendingKey === deviceKey;
  const result = getPushDeviceTestResult(record);
  const resultTone = result?.ok === true ? "success" : "warning";
  const statusMeta = getPushDeviceStatusMeta(record);
  const isCurrent = isCurrentPushSubscriptionRecord(record);
  const canSendDevice = canSend && getPushDeviceVisualStatus(record) === "active" && record.pushEnabled === true && !record.disabledAt && record.permissionState === "granted";
  const lastSeen = record?.lastSeenAt ? formatPushDiagnosticsTimestamp(record.lastSeenAt) : "";
  const created = record?.createdAt ? formatPushDiagnosticsTimestamp(record.createdAt) : "";
  const lastTested = record?.lastTestedAt ? formatPushDiagnosticsTimestamp(record.lastTestedAt) : "";
  const lastDelivery = record?.lastDeliveryAt ? formatPushDiagnosticsTimestamp(record.lastDeliveryAt) : "";
  const details = [
    lastSeen ? `Last seen ${lastSeen}` : "",
    created ? `Created ${created}` : "",
    lastTested ? `Last tested ${lastTested}` : "",
    lastDelivery ? `Last delivery ${lastDelivery}` : "",
  ].filter(Boolean);

  return `
    <article class="profile-push-device-card ${escapeHtml(statusMeta.cardClass)}${isCurrent ? " is-current" : ""}">
      <div class="profile-push-device-main">
        <div class="profile-push-diagnostics-copy">
          <strong>${escapeHtml(getPushDeviceDisplayLabel(record))}</strong>
          <span>${escapeHtml(details.length ? details.join(" · ") : "No device timestamps recorded yet")}</span>
        </div>
        <span class="profile-permission-badge is-${escapeHtml(statusMeta.tone)}">${escapeHtml(statusMeta.label)}</span>
      </div>
      <div class="profile-push-device-actions">
        <button
          type="button"
          class="button button-secondary"
          data-profile-push-diagnostics-test-device="${escapeHtml(deviceKey)}"
          ${canSendDevice && deviceKey && !isSending ? "" : "disabled"}
        >${isSending ? "Sending..." : "Send Test To This Device"}</button>
        <button
          type="button"
          class="button button-secondary profile-push-device-remove"
          data-profile-push-device-remove="${escapeHtml(deviceKey)}"
          data-profile-push-device-endpoint="${escapeHtml(endpoint)}"
          ${deviceKey || endpoint ? "" : "disabled"}
        >Remove This Device</button>
      </div>
      ${result ? `<p class="profile-push-device-feedback is-${escapeHtml(resultTone)}">${escapeHtml(result.message || (result.ok ? "Test push sent." : "Test push failed."))}</p>` : ""}
    </article>
  `;
}

function renderPushRegisteredDevicesMarkup(options = {}) {
  const diagnostics = appState.pushDiagnostics || {};
  const devices = getActiveRegisteredPushDevices();
  const sendableDevices = devices.filter((record) => getPushDeviceVisualStatus(record) === "active" && record.pushEnabled === true && !record.disabledAt && record.permissionState === "granted");
  const pushPreferenceEnabled = appState.notificationPreferences?.pushNotificationsEnabled === true;
  const canUseBackendActions = !diagnostics.loading && diagnostics.backendReachable && Boolean(getCurrentAuthAccessToken());
  const canSend = pushPreferenceEnabled && canUseBackendActions && diagnostics.backendConfigured && sendableDevices.length > 0;
  const canRemoveFailed = canUseBackendActions && devices.length > 0;
  const canKeepCurrent = canUseBackendActions && Boolean(getCurrentPushEndpointCandidate() || appState.currentPushSubscriptionRecord?.deviceKey) && devices.some((record) => !isCurrentPushSubscriptionRecord(record));
  const sendingKey = String(diagnostics.sendingDeviceKey || "").trim();
  const isSendingAll = sendingKey === "__all__";
  const isCleaning = sendingKey.startsWith("__cleanup__");
  const helperText = pushPreferenceEnabled
    ? "Send test pushes to specific endpoints, or clean up stale saved devices without changing notification preferences."
    : "Registered devices are saved, but delivery is paused until Enable Push Notifications is turned on.";

  return `
    <section class="profile-push-devices-panel" aria-label="Registered push devices">
      <div class="profile-push-devices-head">
        <div class="profile-push-diagnostics-copy">
          <strong>Registered Push Devices</strong>
          <span>${escapeHtml(helperText)}</span>
        </div>
        <div class="profile-push-device-actions">
          <button
            type="button"
            class="button button-secondary"
            data-profile-push-diagnostics-test-all="true"
            ${canSend && !isSendingAll && !isCleaning ? "" : "disabled"}
          >${isSendingAll ? "Sending..." : "Send Test To All Devices"}</button>
          <button
            type="button"
            class="button button-secondary"
            data-profile-push-cleanup-failed="true"
            ${canRemoveFailed && !isCleaning ? "" : "disabled"}
          >Remove Failed Devices</button>
          <button
            type="button"
            class="button button-secondary"
            data-profile-push-keep-current="true"
            ${canKeepCurrent && !isCleaning ? "" : "disabled"}
          >Keep Only Current Device</button>
        </div>
      </div>
      <div class="profile-push-device-list">
        ${devices.length
          ? devices.map((record) => renderPushRegisteredDeviceMarkup(record, { canSend, sendingKey })).join("")
          : '<p class="profile-notification-guidance">No active registered push devices found yet.</p>'}
      </div>
      ${options.feedback ? `<p class="profile-push-device-feedback is-${escapeHtml(options.feedbackTone || "info")}">${escapeHtml(options.feedback)}</p>` : ""}
    </section>
  `;
}

function renderPushDiagnosticsPanelMarkup() {
  if (!canViewPushDiagnosticsPanel()) {
    return "";
  }

  const diagnostics = appState.pushDiagnostics || {};
  const serviceWorkerStatus = String(diagnostics.serviceWorkerStatus || "unknown").trim().toLowerCase();
  const serviceWorkerBadge = (() => {
    switch (serviceWorkerStatus) {
      case "active":
        return getPushDiagnosticsStatusMeta(true, "Active", "Missing");
      case "installing":
        return { tone: "info", label: "Installing" };
      case "waiting":
        return { tone: "info", label: "Waiting" };
      case "activating":
        return { tone: "info", label: "Activating" };
      case "unsupported":
        return { tone: "warning", label: "Unsupported" };
      case "loading":
        return { tone: "info", label: "Checking" };
      default:
        return { tone: "warning", label: "Inactive" };
    }
  })();
  const permissionMeta = getNotificationPermissionStateMeta(diagnostics.permissionState || getGrowRemindersBrowserPermissionState());
  const subscriptionMeta = getPushSubscriptionSupportMeta(diagnostics.pushSupportState || getPushSubscriptionSupportState());
  const pushPreferenceEnabled = appState.notificationPreferences?.pushNotificationsEnabled === true;
  console.info("[Push Diagnostics] computed state", {
    pushNotificationsEnabled: pushPreferenceEnabled,
    canonicalPreferenceValue: appState.notificationPreferences?.push_notifications_enabled,
    activeRegisteredDeviceCount: getActiveRegisteredPushDevices().length,
    currentDeviceRegistered: diagnostics.currentDeviceRegistered === true,
    backendReachable: diagnostics.backendReachable === true,
    backendConfigured: diagnostics.backendConfigured === true,
  });
  const preferenceMeta = pushPreferenceEnabled
    ? { tone: "success", label: "Enabled" }
    : { tone: "warning", label: "Paused" };
  const vapidMeta = getPushDiagnosticsStatusMeta(Boolean(diagnostics.vapidKeyAvailable), "Available", "Missing");
  const backendMeta = diagnostics.backendReachable
    ? {
      tone: diagnostics.backendConfigured ? "success" : "warning",
      label: String(diagnostics.backendStatusLabel || (diagnostics.backendConfigured ? "Configured" : "Reachable")).trim() || (diagnostics.backendConfigured ? "Configured" : "Reachable"),
    }
    : { tone: diagnostics.loading ? "info" : "warning", label: diagnostics.loading ? "Checking" : "Unavailable" };
  const serviceWorkerReady = serviceWorkerStatus === "active";
  const deviceMeta = serviceWorkerReady && diagnostics.currentDeviceRegistered
    ? (pushPreferenceEnabled
      ? getPushDiagnosticsStatusMeta(true, diagnostics.currentDeviceSaved ? "Registered" : "Subscribed")
      : { tone: "warning", label: diagnostics.currentDeviceSaved ? "Registered / Paused" : "Subscribed / Paused" })
    : { tone: serviceWorkerReady ? "info" : "warning", label: serviceWorkerReady ? "Unregistered" : "SW Pending" };
  const canRegister = !diagnostics.loading && diagnostics.permissionState !== "unsupported" && serviceWorkerStatus !== "unsupported";
  const canSendTest = pushPreferenceEnabled && !diagnostics.loading && serviceWorkerReady && diagnostics.currentDeviceRegistered && diagnostics.backendReachable && diagnostics.backendConfigured;
  const lastTestLabel = diagnostics.lastTestResult
    ? `${diagnostics.lastTestResult} · ${formatPushDiagnosticsTimestamp(diagnostics.lastTestAt)}`
    : "No test sent yet";
  const canUnregister = !diagnostics.loading && serviceWorkerReady && diagnostics.currentDeviceRegistered;

  return `
    <div class="profile-notification-permission profile-push-diagnostics-panel is-info">
      <div class="profile-notification-permission-head">
        <div class="profile-notification-permission-copy">
          <strong>Push Diagnostics</strong>
          <span>Admin/dev-only health checks for browser push setup and backend delivery.</span>
        </div>
        <span class="profile-permission-badge is-info">Dev</span>
      </div>
      <div class="profile-push-diagnostics-grid">
        ${renderPushDiagnosticsRowMarkup("Service worker", serviceWorkerBadge.label, serviceWorkerBadge.tone, "Install + runtime notification shell status")}
        ${renderPushDiagnosticsRowMarkup("Browser permission", permissionMeta.label, permissionMeta.tone, "Current browser/device notification permission")}
        ${renderPushDiagnosticsRowMarkup("User preference", preferenceMeta.label, preferenceMeta.tone, pushPreferenceEnabled ? "Registered devices are active delivery targets" : "Notifications are paused by user preference; subscriptions remain saved")}
        ${renderPushDiagnosticsRowMarkup("Push subscription", subscriptionMeta.label, subscriptionMeta.tone, "Current Push API readiness for this device")}
        ${renderPushDiagnosticsRowMarkup("VAPID public key", vapidMeta.label, vapidMeta.tone, "Public push key availability in runtime config")}
        ${renderPushDiagnosticsRowMarkup("Backend /api/push-send", backendMeta.label, backendMeta.tone, diagnostics.backendReachable ? (String(diagnostics.backendMessage || "").trim() || "Serverless route responded to diagnostics check") : "Push sender route has not responded yet")}
        ${renderPushDiagnosticsRowMarkup("Current device", deviceMeta.label, deviceMeta.tone, serviceWorkerReady ? (diagnostics.currentDeviceSaved ? "Device record is stored for this signed-in user" : "No saved device record yet") : "Waiting for an active service worker before reporting this device ready")}
      </div>
      <div class="profile-push-delivery-meta profile-push-diagnostics-meta">
        <span>Last refresh: ${escapeHtml(formatPushDiagnosticsTimestamp(diagnostics.lastRefreshedAt))}</span>
        <span>Last test: ${escapeHtml(lastTestLabel)}</span>
      </div>
      ${!pushPreferenceEnabled ? '<p class="profile-notification-guidance">Push notifications are paused by user preference. Turn on Enable Push Notifications and save to allow tests and grow reminders to deliver.</p>' : ""}
      ${diagnostics.lastErrorMessage ? `<p class="profile-notification-guidance">Last error: ${escapeHtml(diagnostics.lastErrorMessage)}</p>` : ""}
      <div class="profile-push-delivery-actions profile-push-diagnostics-actions">
        <button type="button" class="button button-secondary" data-profile-push-diagnostics-register="true"${canRegister ? "" : " disabled"}>Register This Device</button>
        <button type="button" class="button button-secondary" data-profile-push-diagnostics-test="true"${canSendTest ? "" : " disabled"}>Send Test Push</button>
        <button type="button" class="button button-secondary" data-profile-push-diagnostics-refresh="true"${diagnostics.loading ? " disabled" : ""}>Refresh Status</button>
        <button type="button" class="button button-secondary" data-profile-push-diagnostics-unregister="true"${canUnregister ? "" : " disabled"}>Unregister This Device</button>
      </div>
      ${renderPushRegisteredDevicesMarkup()}
    </div>
  `;
}

async function refreshPushDiagnosticsState(options = {}) {
  const {
    scope = document,
    preserveLastStatus = true,
  } = options || {};

  if (!canViewPushDiagnosticsPanel()) {
    return null;
  }

  const nextState = {
    ...(appState.pushDiagnostics || {}),
    loading: true,
    serviceWorkerStatus: "loading",
    lastErrorMessage: preserveLastStatus ? String(appState.pushDiagnostics?.lastErrorMessage || "").trim() : "",
  };
  appState.pushDiagnostics = nextState;
  syncPushDiagnosticsStateUi(scope);

  let backendReachable = false;
  let backendConfigured = false;
  let backendStatusLabel = "Unavailable";
  let backendMessage = "";
  let lastErrorMessage = preserveLastStatus ? String(appState.pushDiagnostics?.lastErrorMessage || "").trim() : "";

  try {
    let registration = await getServiceWorkerRegistration({ requireActive: false });
    if (registration && !registration.active) {
      const readyRegistration = await getServiceWorkerRegistration({
        requireActive: true,
        timeoutMs: SERVICE_WORKER_DIAGNOSTIC_READY_TIMEOUT_MS,
      });
      registration = readyRegistration || registration;
    }
    const serviceWorkerStatus = getServiceWorkerLifecycleStatus(registration);
    const serviceWorkerReady = serviceWorkerStatus === "active";
    if (appState.user?.id) {
      await loadUserPushSubscriptions(appState.user);
      await loadUserPushDeliveryStatuses(appState.user);
    }
    const browserSubscription = serviceWorkerReady
      ? await getCurrentBrowserPushSubscription({ registration })
      : null;
    if (browserSubscription?.endpoint) {
      appState.currentPushEndpoint = String(browserSubscription.endpoint || "").trim();
      syncUserPushSubscriptionsCache(String(appState.user?.id || "").trim(), getCurrentUserPushSubscriptions(), {
        persistLocal: false,
      });
    }
    const currentDeviceRecord = appState.currentPushSubscriptionRecord;

    try {
      const response = await fetch("/api/push-send", {
        method: "GET",
        cache: "no-store",
      });
      backendReachable = response.ok;
      const payload = await response.json().catch(() => ({}));
      backendConfigured = payload?.configured === true;
      backendStatusLabel = response.ok
        ? (String(payload?.statusLabel || "").trim() || (backendConfigured ? "Configured" : "Reachable"))
        : `HTTP ${response.status}`;
      backendMessage = response.ok
        ? String(payload?.message || "").trim()
        : "";
    } catch (error) {
      backendReachable = false;
      backendConfigured = false;
      backendStatusLabel = "Unavailable";
      backendMessage = "";
      lastErrorMessage = error?.message || "Could not reach /api/push-send.";
    }

    appState.pushDiagnostics = {
      ...(appState.pushDiagnostics || {}),
      loading: false,
      serviceWorkerStatus,
      permissionState: getGrowRemindersBrowserPermissionState(),
      pushSupportState: getPushSubscriptionSupportState(),
      vapidKeyAvailable: Boolean(getConfiguredPushPublicKey()),
      backendReachable,
      backendConfigured,
      backendStatusLabel,
      backendMessage,
      currentDeviceRegistered: Boolean(serviceWorkerReady && (browserSubscription || (currentDeviceRecord && !currentDeviceRecord.disabledAt && (currentDeviceRecord.endpoint || currentDeviceRecord.pushEnabled)))),
      currentDeviceSaved: Boolean(serviceWorkerReady && currentDeviceRecord && !currentDeviceRecord.disabledAt && currentDeviceRecord.deviceKey),
      lastErrorMessage,
      lastRefreshedAt: new Date().toISOString(),
    };
  } catch (error) {
    appState.pushDiagnostics = {
      ...(appState.pushDiagnostics || {}),
      loading: false,
      serviceWorkerStatus: getServiceWorkerLifecycleStatus(appState.serviceWorkerRegistration || null),
      permissionState: getGrowRemindersBrowserPermissionState(),
      pushSupportState: getPushSubscriptionSupportState(),
      vapidKeyAvailable: Boolean(getConfiguredPushPublicKey()),
      backendReachable,
      backendConfigured,
      backendStatusLabel,
      backendMessage: "",
      currentDeviceRegistered: false,
      currentDeviceSaved: false,
      lastErrorMessage: error?.message || "Push diagnostics could not be refreshed.",
      lastRefreshedAt: new Date().toISOString(),
    };
  }

  syncPushDiagnosticsStateUi(scope);
  return appState.pushDiagnostics;
}

function loadDeliveredPushNotificationEvents(userId = "") {
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedUserId) {
    return new Set();
  }

  try {
    const storedValue = JSON.parse(localStorage.getItem(getPushDeliveredNotificationEventsStorageKey(normalizedUserId)) || "[]");
    if (!Array.isArray(storedValue)) {
      return new Set();
    }
    return new Set(storedValue.map((entry) => String(entry || "").trim()).filter(Boolean));
  } catch (error) {
    console.warn("[Push Delivery] Failed to read delivered push events.", error);
    return new Set();
  }
}

function saveDeliveredPushNotificationEvents(eventKeys = new Set(), userId = "") {
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedUserId) {
    return;
  }

  try {
    localStorage.setItem(
      getPushDeliveredNotificationEventsStorageKey(normalizedUserId),
      JSON.stringify([...new Set(
        [...(eventKeys instanceof Set ? eventKeys : new Set(eventKeys || []))]
          .map((entry) => String(entry || "").trim())
          .filter(Boolean),
      )]),
    );
  } catch (error) {
    console.warn("[Push Delivery] Failed to persist delivered push events.", error);
  }
}

function hasDeliveredPushNotificationEvent(eventKey = "", userId = appState.user?.id || "") {
  const normalizedEventKey = String(eventKey || "").trim();
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedEventKey || !normalizedUserId) {
    return false;
  }
  return loadDeliveredPushNotificationEvents(normalizedUserId).has(normalizedEventKey);
}

function markPushNotificationEventDelivered(eventKey = "", userId = appState.user?.id || "") {
  const normalizedEventKey = String(eventKey || "").trim();
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedEventKey || !normalizedUserId) {
    return;
  }
  const deliveredEvents = loadDeliveredPushNotificationEvents(normalizedUserId);
  deliveredEvents.add(normalizedEventKey);
  saveDeliveredPushNotificationEvents(deliveredEvents, normalizedUserId);
}

function loadPushSendFailureState(userId = "") {
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedUserId) {
    return {};
  }

  try {
    const storedValue = JSON.parse(localStorage.getItem(getPushSendFailuresStorageKey(normalizedUserId)) || "{}");
    return storedValue && typeof storedValue === "object" && !Array.isArray(storedValue)
      ? storedValue
      : {};
  } catch (error) {
    logRuntimeIssueOnce(
      "warn",
      "push-send-failure-state-read",
      "Push delivery retry state could not be read; continuing with in-memory guard only.",
      error,
    );
    return {};
  }
}

function savePushSendFailureState(records = {}, userId = "") {
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedUserId) {
    return;
  }

  const now = Date.now();
  const normalizedRecords = Object.entries(records && typeof records === "object" ? records : {})
    .reduce((accumulator, [key, value]) => {
      const normalizedKey = String(key || "").trim();
      const nextRetryAt = Number(value?.nextRetryAt || 0) || 0;
      if (!normalizedKey || (nextRetryAt > 0 && nextRetryAt < now - PUSH_SEND_MAX_RETRY_DELAY_MS)) {
        return accumulator;
      }
      accumulator[normalizedKey] = {
        attempts: Math.max(0, Number(value?.attempts || 0) || 0),
        nextRetryAt,
        status: Number(value?.status || 0) || 0,
        code: String(value?.code || "").trim(),
        message: String(value?.message || "").trim(),
        updatedAt: String(value?.updatedAt || new Date(now).toISOString()).trim(),
      };
      return accumulator;
    }, {});

  try {
    localStorage.setItem(getPushSendFailuresStorageKey(normalizedUserId), JSON.stringify(normalizedRecords));
  } catch (error) {
    logRuntimeIssueOnce(
      "warn",
      "push-send-failure-state-write",
      "Push delivery retry state could not be saved.",
      error,
    );
  }
}

function getPushSendFailureRecord(eventKey = "", userId = appState.user?.id || "") {
  const normalizedEventKey = String(eventKey || "").trim();
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedEventKey || !normalizedUserId) {
    return null;
  }
  return loadPushSendFailureState(normalizedUserId)[normalizedEventKey] || null;
}

function shouldSkipBackendPushSendForEvent(eventKey = "", userId = appState.user?.id || "") {
  const record = getPushSendFailureRecord(eventKey, userId);
  if (!record) {
    return false;
  }

  const nextRetryAt = Number(record.nextRetryAt || 0) || 0;
  if (nextRetryAt > Date.now()) {
    return true;
  }
  return false;
}

function recordBackendPushSendFailure(eventKey = "", details = {}, userId = appState.user?.id || "") {
  const normalizedEventKey = String(eventKey || "").trim();
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedEventKey || !normalizedUserId) {
    return null;
  }

  const records = loadPushSendFailureState(normalizedUserId);
  const previous = records[normalizedEventKey] || {};
  const attempts = Math.min(PUSH_SEND_MAX_ATTEMPTS, Math.max(0, Number(previous.attempts || 0) || 0) + 1);
  const retryDelay = Math.min(
    PUSH_SEND_MAX_RETRY_DELAY_MS,
    PUSH_SEND_BASE_RETRY_DELAY_MS * (2 ** Math.max(0, attempts - 1)),
  );
  const nextRetryAt = Date.now() + (attempts >= PUSH_SEND_MAX_ATTEMPTS ? PUSH_SEND_MAX_RETRY_DELAY_MS : retryDelay);
  const nextRecord = {
    attempts,
    nextRetryAt,
    status: Number(details?.status || 0) || 0,
    code: String(details?.code || "").trim(),
    message: String(details?.message || "").trim(),
    updatedAt: new Date().toISOString(),
  };
  records[normalizedEventKey] = nextRecord;
  savePushSendFailureState(records, normalizedUserId);
  return nextRecord;
}

function recordBackendPushSendSkip(eventKey = "", details = {}, userId = appState.user?.id || "") {
  const normalizedEventKey = String(eventKey || "").trim();
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedEventKey || !normalizedUserId) {
    return null;
  }

  const records = loadPushSendFailureState(normalizedUserId);
  const previous = records[normalizedEventKey] || {};
  const nextRecord = {
    attempts: Math.max(1, Number(previous.attempts || 0) || 0),
    nextRetryAt: Date.now() + PUSH_SEND_SKIP_RETRY_DELAY_MS,
    status: Number(details?.status || 0) || 0,
    code: String(details?.code || "").trim(),
    message: String(details?.message || "").trim(),
    updatedAt: new Date().toISOString(),
  };
  records[normalizedEventKey] = nextRecord;
  savePushSendFailureState(records, normalizedUserId);
  return nextRecord;
}

function clearBackendPushSendFailure(eventKey = "", userId = appState.user?.id || "") {
  const normalizedEventKey = String(eventKey || "").trim();
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedEventKey || !normalizedUserId) {
    return;
  }

  const records = loadPushSendFailureState(normalizedUserId);
  if (!Object.prototype.hasOwnProperty.call(records, normalizedEventKey)) {
    return;
  }
  delete records[normalizedEventKey];
  savePushSendFailureState(records, normalizedUserId);
}

function clearPushNotificationEventDelivered(eventKey = "", userId = appState.user?.id || "") {
  const normalizedEventKey = String(eventKey || "").trim();
  const normalizedUserId = String(userId || "").trim();
  if (!normalizedEventKey || !normalizedUserId) {
    return;
  }
  const deliveredEvents = loadDeliveredPushNotificationEvents(normalizedUserId);
  if (!deliveredEvents.delete(normalizedEventKey)) {
    return;
  }
  saveDeliveredPushNotificationEvents(deliveredEvents, normalizedUserId);
}

function shouldShowGrowRemindersPrompt(routeHash = appState.currentRouteHash || window.location.hash || "#home") {
  if (!appState.user || !hasCompletedProfile() || isAdminAreaRawRoute()) {
    return false;
  }

  const normalizedRoute = normalizeNavigationHash(routeHash);
  if (!["#home", "#sessions"].includes(normalizedRoute)) {
    return false;
  }

  if (document.querySelector("#auth-modal")?.open) {
    return false;
  }

  const promptState = loadGrowRemindersPromptState(appState.user.id);
  return promptState.status === "pending";
}

function maybeOpenGrowRemindersPrompt(routeHash = appState.currentRouteHash || window.location.hash || "#home") {
  if (!shouldShowGrowRemindersPrompt(routeHash)) {
    return;
  }

  const modal = ensureGrowRemindersPromptModal();
  if (!(modal instanceof HTMLDialogElement) || modal.open) {
    return;
  }

  const enableButton = modal.querySelector('[data-grow-reminders-enable="true"]');
  const dismissButton = modal.querySelector('[data-grow-reminders-dismiss="true"]');
  if (!(enableButton instanceof HTMLButtonElement) || !(dismissButton instanceof HTMLButtonElement)) {
    return;
  }

  const cleanup = () => {
    enableButton.disabled = false;
    dismissButton.disabled = false;
    enableButton.onclick = null;
    dismissButton.onclick = null;
    modal.onclose = null;
  };

  const closeWithStatus = (status = "dismissed") => {
    saveGrowRemindersPromptState(status, appState.user?.id || "");
    cleanup();
    if (modal.open) {
      modal.close(status);
    }
  };

  modal.onclose = () => {
    const finalStatus = ["enabled", "dismissed", "denied"].includes(String(modal.returnValue || "").trim().toLowerCase())
      ? String(modal.returnValue).trim().toLowerCase()
      : "dismissed";
    saveGrowRemindersPromptState(finalStatus, appState.user?.id || "");
    cleanup();
  };

  dismissButton.onclick = () => {
    closeWithStatus("dismissed");
  };

  enableButton.onclick = async () => {
    enableButton.disabled = true;
    dismissButton.disabled = true;
    try {
      const existingPreferences = appState.notificationPreferences
        || loadStoredUserNotificationPreferences(appState.user?.id || "");
      const permissionResult = await requestGrowRemindersBrowserPermission();
      const notificationsEnabled = permissionResult === "granted" || permissionResult === "unsupported";
      await saveUserNotificationPreferences({
        ...existingPreferences,
        growRemindersEnabled: notificationsEnabled,
        pushNotificationsEnabled: permissionResult === "granted",
      }, {
        requirePersistence: false,
        debugContext: "grow-reminders-prompt",
      });
      if (permissionResult === "granted") {
        try {
          await subscribeCurrentDeviceToPushNotifications();
        } catch (error) {
          console.warn("[Grow Reminders] Push subscription sync failed after prompt.", error);
        }
      }
      if (permissionResult === "denied") {
        closeWithStatus("denied");
        showNavigationLockToast({
          title: "Grow Reminders",
          message: "Notifications are currently blocked in your browser. You can change this later in your browser and profile settings.",
        });
      } else {
        closeWithStatus("enabled");
        showNavigationLockToast({
          title: "Grow Reminders",
          message: "Notifications are enabled. You can update them anytime in your profile settings.",
        });
      }
      safeRender();
    } catch (error) {
      console.warn("[Grow Reminders] Could not enable notifications.", error);
      closeWithStatus("denied");
      showNavigationLockToast({
        title: "Grow Reminders",
        message: "We couldn't enable notifications right now. You can try again anytime in your profile settings.",
      });
    }
  };

  modal.showModal();
}

function syncNavigationAvailabilityState() {
  const navigationLinks = document.querySelectorAll(".topbar-nav a, .mobile-nav-link[data-mobile-nav-link='true']");
  navigationLinks.forEach((link) => {
    if (!(link instanceof HTMLAnchorElement)) {
      return;
    }

    const lockState = getNavigationLockStateForHash(link.getAttribute("href") || "#home");
    link.classList.toggle("is-locked", lockState.locked);
    link.dataset.navLocked = lockState.locked ? "true" : "false";
    link.dataset.navLockMode = lockState.mode || "";
    if (lockState.locked) {
      link.setAttribute("aria-disabled", "true");
      link.setAttribute("data-lock-message", lockState.message || "");
      link.setAttribute("data-lock-cta-label", lockState.ctaLabel || "");
      link.setAttribute("data-lock-cta-href", lockState.ctaHref || "");
      link.setAttribute("title", lockState.message || "Locked");
    } else {
      link.removeAttribute("aria-disabled");
      link.removeAttribute("data-lock-message");
      link.removeAttribute("data-lock-cta-label");
      link.removeAttribute("data-lock-cta-href");
      link.removeAttribute("title");
    }
  });
}

function normalizeSessionVisibilityStatus(status = "") {
  const normalizedStatus = String(status || "").trim().toLowerCase();
  if (["deleted", "archived", "archived_test", "hidden"].includes(normalizedStatus)) {
    return normalizedStatus;
  }
  return normalizedStatus === "active" ? "active" : "";
}

function isSessionSoftDeleted(session = null) {
  if (!session) {
    return false;
  }

  return Boolean(
    session.userDeleted
    || session.user_deleted
    || String(session.userDeletedAt || session.user_deleted_at || "").trim()
    || session.isDeleted
    || session.is_deleted
    || String(session.deletedAt || session.deleted_at || "").trim()
    || ["deleted", "archived", "archived_test", "hidden"].includes(
      normalizeSessionVisibilityStatus(session.visibilityStatus || session.visibility_status || ""),
    )
    || ["deleted", "archived", "archived_test"].includes(
      normalizeSessionStatus(session.sessionStatus || session.session_status || ""),
    )
  );
}

function isMockGrowSession(session = null) {
  return Boolean(session?.isMock || session?.is_mock || session?.is_mock_data);
}

function isTestGrowSession(session = null) {
  return Boolean(session?.isTest || session?.is_test);
}

function isGrowSessionAnalyticsExcluded(session = null) {
  return Boolean(session?.excludedFromAnalytics || session?.excluded_from_analytics);
}

function getDateHourDelta(startAt, endAt = new Date()) {
  if (!(startAt instanceof Date) || Number.isNaN(startAt.getTime())) {
    return null;
  }
  if (!(endAt instanceof Date) || Number.isNaN(endAt.getTime())) {
    return null;
  }
  return Math.max(0, (endAt.getTime() - startAt.getTime()) / (60 * 60 * 1000));
}

function getLatestSessionLifecycleActivityAt(session = null) {
  if (!session) {
    return null;
  }

  const candidates = [
    session.updatedAt || session.updated_at || "",
    session.completedAt || session.completed_at || "",
    session.firstPlantedAt || session.first_planted_at || "",
    session.germinationStartedAt || session.germination_started_at || "",
    session.soakStartedAt || session.soak_started_at || "",
    session.sessionStartedAt || session.session_started_at || "",
    session.timerStartAt || session.timer_start_at || "",
    session.createdAt || session.created_at || "",
  ]
    .map((value) => parseCompletedAtValue(value))
    .filter((date) => date instanceof Date && !Number.isNaN(date.getTime()));

  return candidates.reduce((latestDate, date) => {
    if (!latestDate || date.getTime() > latestDate.getTime()) {
      return date;
    }
    return latestDate;
  }, null);
}

function getSessionLifecycleTimestampHealth(session = null, now = new Date()) {
  const normalizedStatus = normalizeSessionStatus(session?.sessionStatus || session?.session_status || "");
  const sessionStartedAtIso = getSessionStartedAtIso(session)
    || parseCompletedAtValue(session?.createdAt || session?.created_at || "")?.toISOString()
    || "";
  const soakStartedAtIso = getSessionSoakStartedAtIso(session)
    || sessionStartedAtIso;
  const hasStartedIntent = Boolean(
    ["soaking", "germinating", "completed"].includes(normalizedStatus)
    || String(session?.sessionStartedAt || session?.session_started_at || "").trim()
    || String(session?.soakStartedAt || session?.soak_started_at || "").trim()
    || String(session?.timerStartAt || session?.timer_start_at || "").trim()
    || String(session?.date || "").trim()
  );
  const timelineValidation = validateGrowSessionTimelineOrder({
    sessionStartedAt: sessionStartedAtIso,
    soakStartedAt: soakStartedAtIso,
    germinationStartedAt: session?.germinationStartedAt || session?.germination_started_at || "",
    completedAt: session?.completedAt || session?.completed_at || "",
  }, {
    requireSessionStarted: hasStartedIntent,
    requireSoakStarted: hasStartedIntent,
    requireCompleted: normalizedStatus === "completed",
  });
  if (!timelineValidation.isValid) {
    return { isValid: false, reason: "invalid_timestamp_order", message: timelineValidation.message || "Session timestamps need review." };
  }

  const futureGraceMs = SESSION_LIFECYCLE_STALE_THRESHOLDS.futureTimestampGraceMinutes * 60 * 1000;
  const futureTimestamp = [
    session?.updatedAt || session?.updated_at || "",
    session?.completedAt || session?.completed_at || "",
    session?.firstPlantedAt || session?.first_planted_at || "",
    session?.germinationStartedAt || session?.germination_started_at || "",
    session?.soakStartedAt || session?.soak_started_at || "",
    session?.sessionStartedAt || session?.session_started_at || "",
    session?.timerStartAt || session?.timer_start_at || "",
    session?.createdAt || session?.created_at || "",
  ]
    .map((value) => parseCompletedAtValue(value))
    .find((date) => date instanceof Date && !Number.isNaN(date.getTime()) && date.getTime() > now.getTime() + futureGraceMs);

  if (futureTimestamp) {
    return { isValid: false, reason: "future_timestamp", message: "Session timestamps are ahead of the current time." };
  }

  return { isValid: true, reason: "", message: "" };
}

function formatLifecycleHoursShort(hours = 0) {
  const normalizedHours = Math.max(0, Number(hours) || 0);
  if (normalizedHours >= 24) {
    const days = Math.floor(normalizedHours / 24);
    return `${days}d`;
  }
  return `${Math.floor(normalizedHours)}h`;
}

function getGrowSessionLifecycleHealth(session = null, options = {}) {
  const normalizedSession = normalizeStoredSession(session) || session;
  const now = options.now instanceof Date && !Number.isNaN(options.now.getTime())
    ? options.now
    : new Date();
  if (!normalizedSession) {
    return {
      classification: "healthy",
      lifecycleState: "draft",
      reason: "",
      label: "Healthy",
      detail: "No session data yet",
      suppressReminders: false,
      activeMetricEligible: false,
    };
  }

  const visibilityStatus = normalizeSessionVisibilityStatus(normalizedSession.visibilityStatus || normalizedSession.visibility_status || "");
  const normalizedStatus = normalizeSessionStatus(normalizedSession.sessionStatus || normalizedSession.session_status || "");
  const hardDeleted = Boolean(
    normalizedSession.isDeleted
    || normalizedSession.is_deleted
    || String(normalizedSession.deletedAt || normalizedSession.deleted_at || "").trim()
    || ["deleted", "archived", "archived_test"].includes(normalizedStatus)
  );
  const archived = Boolean(
    hardDeleted
    || normalizedSession.userDeleted
    || normalizedSession.user_deleted
    || String(normalizedSession.userDeletedAt || normalizedSession.user_deleted_at || "").trim()
    || ["deleted", "archived", "archived_test", "hidden"].includes(visibilityStatus)
  );

  if (archived) {
    return {
      classification: "archived",
      lifecycleState: hardDeleted ? "deleted" : "archived",
      reason: hardDeleted ? "deleted_or_archived" : "hidden_by_owner",
      label: hardDeleted ? "Archived" : "Hidden",
      detail: "Not included in active session workflows",
      suppressReminders: true,
      activeMetricEligible: false,
    };
  }

  const timestampHealth = getSessionLifecycleTimestampHealth(normalizedSession, now);
  const completedAt = getSessionCompletedAtDate(normalizedSession);
  if (!timestampHealth.isValid) {
    return {
      classification: "stale",
      lifecycleState: "stale",
      reason: timestampHealth.reason,
      label: "Needs attention",
      detail: timestampHealth.message,
      suppressReminders: true,
      activeMetricEligible: false,
    };
  }

  if (normalizedStatus === "completed" || completedAt) {
    return {
      classification: "completed",
      lifecycleState: "completed",
      reason: "",
      label: "Completed",
      detail: "Session completed",
      suppressReminders: true,
      activeMetricEligible: false,
    };
  }

  if (["abandoned", "failed", "canceled", "cancelled"].includes(normalizedStatus)) {
    return {
      classification: "abandoned",
      lifecycleState: "abandoned",
      reason: "terminal_incomplete_status",
      label: "Session inactive",
      detail: "Session ended without completion",
      suppressReminders: true,
      activeMetricEligible: false,
    };
  }

  const progressKey = getSessionProgressKeyFromSession(normalizedSession);
  const sessionStartedAt = getSessionDurationStartAt(normalizedSession);
  const stageStartedAt = getSessionStageDurationStartAt(normalizedSession);
  const lastActivityAt = getLatestSessionLifecycleActivityAt(normalizedSession) || stageStartedAt || sessionStartedAt;
  const sessionHours = getDateHourDelta(sessionStartedAt, now);
  const stageHours = getDateHourDelta(stageStartedAt, now);
  const inactiveHours = getDateHourDelta(lastActivityAt, now);
  const missingGerminationStartedAt = normalizedStatus === "germinating"
    && !parseCompletedAtValue(normalizedSession.germinationStartedAt || normalizedSession.germination_started_at || "");

  const staleDetail = inactiveHours !== null
    ? `Inactive ${formatLifecycleHoursShort(inactiveHours)}`
    : "Session timing needs review";

  if (
    inactiveHours !== null
    && inactiveHours >= SESSION_LIFECYCLE_STALE_THRESHOLDS.inactiveAbandonedHours
  ) {
    return {
      classification: "abandoned",
      lifecycleState: "abandoned",
      reason: "inactive_abandoned_threshold",
      label: "Session inactive",
      detail: staleDetail,
      suppressReminders: true,
      activeMetricEligible: false,
    };
  }

  if (
    inactiveHours !== null
    && inactiveHours >= SESSION_LIFECYCLE_STALE_THRESHOLDS.inactiveStaleHours
  ) {
    return {
      classification: "stale",
      lifecycleState: "stale",
      reason: "inactive_stale_threshold",
      label: "Session inactive",
      detail: staleDetail,
      suppressReminders: true,
      activeMetricEligible: false,
    };
  }

  if (missingGerminationStartedAt) {
    return {
      classification: "needs_attention",
      lifecycleState: "active",
      reason: "missing_germination_started_at",
      label: "Needs attention",
      detail: "Germination start time missing",
      suppressReminders: true,
      activeMetricEligible: true,
    };
  }

  if (normalizedStatus === "soaking" || progressKey === "soaking") {
    if (sessionHours !== null && sessionHours >= SESSION_LIFECYCLE_STALE_THRESHOLDS.soakingAbandonedHours) {
      return {
        classification: "abandoned",
        lifecycleState: "abandoned",
        reason: "soaking_abandoned_threshold",
        label: "Session inactive",
        detail: `Soaking ${formatLifecycleHoursShort(sessionHours)}`,
        suppressReminders: true,
        activeMetricEligible: false,
      };
    }
    if (sessionHours !== null && sessionHours >= SESSION_LIFECYCLE_STALE_THRESHOLDS.soakingStaleHours) {
      return {
        classification: "stale",
        lifecycleState: "stale",
        reason: "soaking_stale_threshold",
        label: "Session inactive",
        detail: `Soaking ${formatLifecycleHoursShort(sessionHours)}`,
        suppressReminders: true,
        activeMetricEligible: false,
      };
    }
    if (sessionHours !== null && sessionHours >= SESSION_LIFECYCLE_STALE_THRESHOLDS.soakingAttentionHours) {
      return {
        classification: "needs_attention",
        lifecycleState: "active",
        reason: "soaking_attention_threshold",
        label: "Needs attention",
        detail: `Soaking ${formatLifecycleHoursShort(sessionHours)}`,
        suppressReminders: false,
        activeMetricEligible: true,
      };
    }
  }

  if (["germination", "first-germinated"].includes(progressKey) || normalizedStatus === "germinating") {
    if (stageHours !== null && stageHours >= SESSION_LIFECYCLE_STALE_THRESHOLDS.germinationAbandonedHours) {
      return {
        classification: "abandoned",
        lifecycleState: "abandoned",
        reason: "germination_abandoned_threshold",
        label: "Session inactive",
        detail: `Germinating ${formatLifecycleHoursShort(stageHours)}`,
        suppressReminders: true,
        activeMetricEligible: false,
      };
    }
    if (stageHours !== null && stageHours >= SESSION_LIFECYCLE_STALE_THRESHOLDS.germinationStaleHours) {
      return {
        classification: "stale",
        lifecycleState: "stale",
        reason: "germination_stale_threshold",
        label: "Session inactive",
        detail: `Germinating ${formatLifecycleHoursShort(stageHours)}`,
        suppressReminders: true,
        activeMetricEligible: false,
      };
    }
    if (stageHours !== null && stageHours >= SESSION_LIFECYCLE_STALE_THRESHOLDS.germinationAttentionHours) {
      return {
        classification: "needs_attention",
        lifecycleState: "active",
        reason: "germination_attention_threshold",
        label: "Needs attention",
        detail: `Germinating ${formatLifecycleHoursShort(stageHours)}`,
        suppressReminders: false,
        activeMetricEligible: true,
      };
    }
  }

  return {
    classification: "healthy",
    lifecycleState: ["soaking", "germinating", "active", "first-germinated"].includes(normalizedStatus) || progressKey
      ? "active"
      : "draft",
    reason: "",
    label: "Healthy",
    detail: "Session is active",
    suppressReminders: false,
    activeMetricEligible: ["soaking", "germinating", "active", "first-germinated"].includes(normalizedStatus) || Boolean(progressKey),
  };
}

function isGrowSessionLifecycleRemindable(session = null) {
  const lifecycleHealth = getGrowSessionLifecycleHealth(session);
  const normalizedStatus = normalizeSessionStatus(session?.sessionStatus || session?.session_status || "");
  return Boolean(
    ["healthy", "needs_attention"].includes(lifecycleHealth.classification)
    && ["soaking", "germinating"].includes(normalizedStatus)
    && !lifecycleHealth.suppressReminders
  );
}

function normalizeGrowSessionLifecycleState(sessionOrStatus = null) {
  const session = sessionOrStatus && typeof sessionOrStatus === "object" ? sessionOrStatus : null;
  if (session && isSessionSoftDeleted(session)) {
    return "deleted";
  }

  const normalizedStatus = normalizeSessionStatus(
    session ? (session.sessionStatus || session.session_status || "") : sessionOrStatus,
  );
  if (["deleted", "archived", "archived_test"].includes(normalizedStatus)) {
    return "deleted";
  }
  if (["abandoned", "failed", "canceled", "cancelled"].includes(normalizedStatus)) {
    return "abandoned";
  }
  if (session) {
    const lifecycleHealth = getGrowSessionLifecycleHealth(session);
    if (["completed", "stale", "abandoned"].includes(lifecycleHealth.classification)) {
      return lifecycleHealth.lifecycleState;
    }
  }
  if (normalizedStatus === "completed") {
    return "completed";
  }
  if (["soaking", "germinating", "active", "first-germinated"].includes(normalizedStatus)) {
    return "active";
  }
  return "draft";
}

function isGrowSessionAnalyticsEligible(session = null, options = {}) {
  const normalizedSession = normalizeStoredSession(session) || session;
  if (!normalizedSession) {
    return false;
  }
  if (isTestGrowSession(normalizedSession) || isGrowSessionAnalyticsExcluded(normalizedSession)) {
    return false;
  }
  if (!options.includeMock && isMockGrowSession(normalizedSession)) {
    return false;
  }
  const visibilityStatus = normalizeSessionVisibilityStatus(
    normalizedSession.visibilityStatus || normalizedSession.visibility_status || "",
  );
  const normalizedStatus = normalizeSessionStatus(
    normalizedSession.sessionStatus || normalizedSession.session_status || "",
  );
  if (
    normalizedSession.isDeleted
    || normalizedSession.is_deleted
    || String(normalizedSession.deletedAt || normalizedSession.deleted_at || "").trim()
    || ["deleted", "archived", "archived_test"].includes(visibilityStatus)
    || ["deleted", "archived", "archived_test"].includes(normalizedStatus)
  ) {
    return false;
  }
  if (normalizedStatus !== "completed") {
    return false;
  }

  return validateGrowSessionTimelineOrder({
    sessionStartedAt: getSessionStartedAtIso(normalizedSession),
    soakStartedAt: getSessionSoakStartedAtIso(normalizedSession),
    germinationStartedAt: normalizedSession?.germinationStartedAt || "",
    completedAt: normalizedSession?.completedAt || "",
  }, {
    requireCompleted: true,
  }).isValid;
}

function getVisibleUserSessions(sessions = []) {
  return (sessions || []).filter((session) => !isSessionSoftDeleted(session));
}

function getAggregateStatsSessions(sessions = []) {
  return (sessions || []).filter((session) => isCompletedValidSessionForAnalytics(session));
}

function getSessionUiHiddenReason(session = null) {
  if (!session) {
    return "";
  }
  if (session.userDeleted || session.user_deleted || String(session.userDeletedAt || session.user_deleted_at || "").trim()) {
    return "user_deleted";
  }
  if (session.isDeleted || session.is_deleted || String(session.deletedAt || session.deleted_at || "").trim()) {
    return "deleted";
  }
  const visibilityStatus = normalizeSessionVisibilityStatus(session.visibilityStatus || session.visibility_status || "");
  if (["deleted", "archived", "archived_test", "hidden"].includes(visibilityStatus)) {
    return visibilityStatus;
  }
  const sessionStatus = normalizeSessionStatus(session.sessionStatus || session.session_status || "");
  if (["deleted", "archived", "archived_test"].includes(sessionStatus)) {
    return sessionStatus;
  }
  return "";
}

function logSessionDeleteVisibilityChange(sessionId = "", previousSession = null, nextSession = null, reason = "session-delete") {
  if (!isDevelopmentErrorDetailsEnabled()) {
    return;
  }

  const normalizedSessionId = String(sessionId || nextSession?.id || previousSession?.id || "").trim();
  const oldStatus = normalizeSessionStatus(previousSession?.sessionStatus || previousSession?.session_status || "");
  const newStatus = normalizeSessionStatus(nextSession?.sessionStatus || nextSession?.session_status || "");
  const hiddenReason = getSessionUiHiddenReason(nextSession);
  console.info("[Grow Session Delete]", {
    reason,
    sessionId: normalizedSessionId,
    oldStatus,
    newStatus,
    hiddenFromUi: isSessionSoftDeleted(nextSession),
    hiddenReason,
    analyticsEligible: isGrowSessionAnalyticsEligible(nextSession),
  });
}

