let appIconRenderSequence = 0;

function decorateAppIconSymbolMarkup(symbolMarkup = "", shapeClass = "cg-icon-main-shape") {
  return String(symbolMarkup || "").replace(
    /<(path|circle|rect|polygon|polyline|line|ellipse)\b/g,
    `<$1 class="${shapeClass}"`,
  );
}

function getPremiumIconClassNames(iconName = "", variant = "plain") {
  return {
    wrapper: [],
    svg: [],
  };
}

function renderAppIconSvgMarkup(iconName = "info", options = {}) {
  const {
    className = "",
    extraSvgClasses = [],
    label = "",
    decorative = true,
  } = options;
  const symbolMarkup = APP_ICON_LIBRARY[iconName] || APP_ICON_LIBRARY.info;
  const iconToken = `cg-icon-${String(iconName || "info").replace(/[^a-z0-9_-]/gi, "").toLowerCase()}-${appIconRenderSequence += 1}`;
  const plateGradientId = `${iconToken}-plate-gradient`;
  const detailGradientId = `${iconToken}-detail-gradient`;
  const glowGradientId = `${iconToken}-glow-gradient`;
  const svgClasses = ["cg-icon-svg", ...extraSvgClasses, className].filter(Boolean).join(" ");
  const ariaAttributes = decorative
    ? 'aria-hidden="true" focusable="false"'
    : `role="img" aria-label="${escapeHtml(label || iconName)}" focusable="false"`;
  return `
    <svg
      class="${escapeHtml(svgClasses)}"
      viewBox="0 0 24 24"
      ${ariaAttributes}
      style="--cg-icon-primary-fill:url(#${escapeHtml(plateGradientId)}); --cg-icon-secondary-fill:url(#${escapeHtml(detailGradientId)}); --cg-icon-glow-fill:url(#${escapeHtml(glowGradientId)});"
    >
      <defs>
        <linearGradient id="${escapeHtml(plateGradientId)}" x1="4" y1="3.5" x2="20" y2="20.5" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stop-color="#d9ff9f"></stop>
          <stop offset="46%" stop-color="#94d159"></stop>
          <stop offset="100%" stop-color="#4f8f1d"></stop>
        </linearGradient>
        <linearGradient id="${escapeHtml(detailGradientId)}" x1="7" y1="5" x2="18" y2="18" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stop-color="#f4ffd8"></stop>
          <stop offset="100%" stop-color="#7cc33a"></stop>
        </linearGradient>
        <radialGradient id="${escapeHtml(glowGradientId)}" cx="50%" cy="30%" r="70%">
          <stop offset="0%" stop-color="#ecffc6" stop-opacity="0.96"></stop>
          <stop offset="45%" stop-color="#94d159" stop-opacity="0.92"></stop>
          <stop offset="100%" stop-color="#4e8120" stop-opacity="0.88"></stop>
        </radialGradient>
      </defs>
      <g class="cg-icon-shadow-layer" aria-hidden="true">
        ${decorateAppIconSymbolMarkup(symbolMarkup, "cg-icon-shadow-shape")}
      </g>
      <g class="cg-icon-main-layer">
        ${decorateAppIconSymbolMarkup(symbolMarkup, "cg-icon-main-shape")}
      </g>
    </svg>
  `;
}

function renderAppIconMarkup(iconName = "info", options = {}) {
  const {
    variant = "plain",
    className = "",
    label = "",
    decorative = true,
    interactive = false,
  } = options;
  const premiumClassNames = getPremiumIconClassNames(iconName, variant);
  const wrapperClasses = [
    "cg-icon",
    interactive ? "icon-interactive" : "icon-static",
    variant === "plate" ? "cg-icon--plate" : "cg-icon--plain",
    ...premiumClassNames.wrapper,
    className,
  ].filter(Boolean).join(" ");
  const wrapperAttributes = decorative
    ? 'aria-hidden="true"'
    : `role="img" aria-label="${escapeHtml(label || iconName)}"`;
  return `
    <span class="${escapeHtml(wrapperClasses)}" ${wrapperAttributes}>
      ${renderAppIconSvgMarkup(iconName, {
        decorative: true,
        extraSvgClasses: premiumClassNames.svg,
      })}
    </span>
  `;
}

function formatAppNotificationDateTime(createdAt = "") {
  const parsedDate = parseCompletedAtValue(createdAt);
  if (!parsedDate) {
    return "Just now";
  }
  return formatTimingDateTime(parsedDate);
}

function closeAppNotificationCenter() {
  appState.notificationCenterOpen = false;
  appState.notificationSnoozeMenuOpenId = "";
  if (appNotificationTrigger) {
    appNotificationTrigger.setAttribute("aria-expanded", "false");
  }
  if (appNotificationPanel) {
    appNotificationPanel.hidden = true;
  }
}

function getNotificationActionButtonClassName(action = {}) {
  const variant = String(action?.variant || "secondary").trim();
  if (variant === "primary") {
    return "button button-primary app-notification-action-button app-notification-action-button--primary";
  }
  if (variant === "ghost") {
    return "button button-secondary app-notification-action-button app-notification-action-button--ghost";
  }
  return "button button-secondary app-notification-action-button";
}

function queueSessionDetailNotificationFocus(sessionId = "", target = "") {
  appState.sessionDetailPendingFocusSessionId = String(sessionId || "").trim();
  appState.sessionDetailPendingFocusTarget = String(target || "").trim();
}

function clearSessionDetailNotificationFocus() {
  appState.sessionDetailPendingFocusSessionId = "";
  appState.sessionDetailPendingFocusTarget = "";
}

function queueSessionDetailNotificationAction(sessionId = "", actionKind = "", options = {}) {
  const normalizedSessionId = String(sessionId || "").trim();
  const normalizedActionKind = String(actionKind || "").trim();
  if (!normalizedSessionId || !normalizedActionKind) {
    appState.sessionDetailPendingNotificationAction = null;
    return;
  }
  appState.sessionDetailPendingNotificationAction = {
    sessionId: normalizedSessionId,
    actionKind: normalizedActionKind,
    eventKey: String(options.eventKey || "").trim(),
    optionKey: String(options.optionKey || "").trim(),
  };
}

function clearSessionDetailNotificationAction() {
  appState.sessionDetailPendingNotificationAction = null;
}

function navigateToNotificationSessionTarget(sessionId = "", options = {}) {
  const normalizedSessionId = String(sessionId || "").trim();
  if (!normalizedSessionId) {
    return;
  }
  const session = getNotificationSessionReference(normalizedSessionId);
  if (!session || isSessionSoftDeleted(session)) {
    showNavigationLockToast({
      title: "Session unavailable",
      message: "This reminder points to a session that is no longer available.",
    });
    return;
  }
  const {
    focusTarget = "",
  } = options || {};
  if (focusTarget) {
    queueSessionDetailNotificationFocus(normalizedSessionId, focusTarget);
  } else {
    clearSessionDetailNotificationFocus();
  }
  const targetRoute = `#sessions/${normalizedSessionId}`;
  if (hasPendingUnsavedChanges()) {
    promptForUnsavedChangesNavigation(targetRoute);
    return;
  }
  navigateToHashRoute(targetRoute);
}

function canApplySessionNotificationMutation(sessionId = "") {
  const normalizedSessionId = String(sessionId || "").trim();
  const currentRoute = getCurrentAppPathRoute();
  const isCurrentSessionDetail = String(currentRoute?.name || "").trim() === "session-detail"
    && String(currentRoute?.params?.id || "").trim() === normalizedSessionId;
  if (!normalizedSessionId || !isCurrentSessionDetail || !hasPendingUnsavedChanges()) {
    return true;
  }

  showNavigationLockToast({
    title: "Save changes first",
    message: "Please save or discard your current session edits before using a one-tap notification action for this session.",
  });
  return false;
}

function applyPendingSessionDetailNotificationFocus(session = null, detail = null) {
  const sessionId = String(session?.id || "").trim();
  if (
    !sessionId
    || !detail
    || appState.sessionDetailPendingFocusSessionId !== sessionId
    || !appState.sessionDetailPendingFocusTarget
  ) {
    return;
  }

  const focusTarget = appState.sessionDetailPendingFocusTarget;
  let targetElement = null;
  if (focusTarget === "results") {
    targetElement = detail.chartShell || detail.progressSection || detail.runProgressSection;
  } else if (focusTarget === "snapshot") {
    targetElement = detail.snapshotSection || detail.generateSnapshotButton;
  }

  if (targetElement) {
    scrollElementIntoViewAfterLayout(targetElement, {
      delayMs: 180,
      behavior: "smooth",
      block: "start",
    });
  }

  if (focusTarget === "snapshot" && detail.generateSnapshotButton instanceof HTMLElement) {
    window.setTimeout(() => {
      detail.generateSnapshotButton?.focus?.({ preventScroll: true });
    }, 240);
  }

  clearSessionDetailNotificationFocus();
}

async function logGrowReminderNotificationAction(actionRecord = {}) {
  const accessToken = getCurrentAuthAccessToken();
  if (!accessToken || !actionRecord?.eventKey) {
    return false;
  }

  try {
    const response = await fetch("/api/grow-reminder-action", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${accessToken}`,
      },
      body: JSON.stringify(actionRecord),
    });
    return response.ok;
  } catch (error) {
    console.warn("[Notifications] Could not log grow reminder action.", error);
    return false;
  }
}

function findAppNotificationByEventKey(eventKey = "") {
  const normalizedEventKey = String(eventKey || "").trim();
  if (!normalizedEventKey) {
    return null;
  }
  return getAppNotifications().find((entry) => String(entry?.eventKey || "").trim() === normalizedEventKey) || null;
}

async function applyPendingSessionDetailNotificationAction(session = null, detail = null) {
  const pendingAction = appState.sessionDetailPendingNotificationAction;
  const sessionId = String(session?.id || "").trim();
  if (!pendingAction || !sessionId || pendingAction.sessionId !== sessionId) {
    return;
  }

  clearSessionDetailNotificationAction();
  const eventKey = String(pendingAction.eventKey || "").trim();
  const optionKey = String(pendingAction.optionKey || "").trim();
  const notification = findAppNotificationByEventKey(eventKey) || {
    id: `push-action-${Date.now()}`,
    eventKey,
    category: normalizeSessionStatus(session?.sessionStatus || "") === "soaking" ? "soaking-reminder" : "germination-reminder",
    notificationType: "grow-reminder",
    route: `#sessions/${sessionId}`,
    sessionId,
  };

  switch (pendingAction.actionKind) {
    case "update-stage":
      void logGrowReminderNotificationAction({ eventKey, sessionId, action: "update-stage-opened" });
      window.setTimeout(() => detail?.statusTrigger?.click?.(), 180);
      return;
    case "snooze": {
      const resolvedOptionKey = optionKey || "30m";
      if (canSnoozeNotification(notification)) {
        snoozeAppNotification(notification, resolvedOptionKey);
      }
      void logGrowReminderNotificationAction({ eventKey, sessionId, action: "snooze-reminder", snoozeOption: resolvedOptionKey });
      return;
    }
    case "mark-germinating":
      await handleAppNotificationAction(notification, {
        kind: "session-stage-germinating",
        label: "Mark Germinating",
        sessionId,
        eventKey,
      });
      void logGrowReminderNotificationAction({ eventKey, sessionId, action: "mark-germinating" });
      return;
    case "mark-first-germinated":
      await handleAppNotificationAction(notification, {
        kind: "session-stage-first-germinated",
        label: "Mark Germination Started",
        sessionId,
        eventKey,
      });
      void logGrowReminderNotificationAction({ eventKey, sessionId, action: "mark-first-germinated" });
      return;
    case "mark-completed":
      await handleAppNotificationAction(notification, {
        kind: "session-stage-completed",
        label: "Mark Completed",
        sessionId,
        eventKey,
      });
      void logGrowReminderNotificationAction({ eventKey, sessionId, action: "mark-completed" });
      return;
    default:
      return;
  }
}

async function updateSessionFromNotification(sessionId = "", updater = null, options = {}) {
  const normalizedSessionId = String(sessionId || "").trim();
  if (!normalizedSessionId || typeof updater !== "function") {
    return null;
  }

  const session = getSessions().find((entry) => String(entry?.id || "").trim() === normalizedSessionId);
  if (!session || isSessionSoftDeleted(session)) {
    showNavigationLockToast({
      title: "Session unavailable",
      message: "This session is no longer available from notifications.",
    });
    return null;
  }

  updater(session);
  const savedSession = await saveSessionUpdate(session);
  if (savedSession) {
    Object.assign(session, savedSession);
  }
  if (savedSession) {
    markUnsavedChangesSaved();
  }
  return savedSession;
}

function toggleAppNotificationCenter(forceOpen) {
  const shouldOpen = typeof forceOpen === "boolean"
    ? forceOpen
    : !appState.notificationCenterOpen;
  appState.notificationCenterOpen = shouldOpen;
  if (appNotificationTrigger) {
    appNotificationTrigger.setAttribute("aria-expanded", shouldOpen ? "true" : "false");
  }
  if (appNotificationPanel) {
    appNotificationPanel.hidden = !shouldOpen;
  }
}

async function handleAppNotificationAction(notification = null, action = null) {
  if (!notification || !action) {
    return;
  }

  const normalizedKind = String(action.kind || "").trim();
  const targetRoute = String(action.route || notification.route || "").trim();
  const targetSessionId = String(action.sessionId || notification.sessionId || "").trim();
  const targetEventKey = String(action.eventKey || notification.eventKey || "").trim();

  if (normalizedKind === "dismiss-event") {
    if (targetEventKey) {
      dismissAppNotificationEvent(targetEventKey);
      removeAppNotificationsByEventKeys([targetEventKey]);
    } else {
      markAppNotificationRead(notification.id);
    }
    closeAppNotificationCenter();
    showNavigationLockToast({
      title: "Session kept active",
      message: "The completion reminder was dismissed for now. You can continue updating the session whenever you’re ready.",
    });
    return;
  }

  markAppNotificationRead(notification.id);
  closeAppNotificationCenter();

  if (normalizedKind === "filter-paper-modal") {
    openFilterPaperInventoryModal();
    return;
  }

  if (normalizedKind === "filter-paper-store") {
    openFilterPaperStore();
    return;
  }

  if (normalizedKind === "session-update-stage") {
    navigateToHashRoute(targetRoute || `#sessions/${targetSessionId}/notify/update-stage/${encodeURIComponent(targetEventKey)}`);
    return;
  }

  if (normalizedKind === "session-stage-germinating") {
    if (!canApplySessionNotificationMutation(targetSessionId)) {
      return;
    }
    const savedSession = await updateSessionFromNotification(targetSessionId, (session) => {
      session.sessionStatus = "germinating";
      session.germinationStartedAt = session.germinationStartedAt || new Date().toISOString();
      session.completedAt = "";
    });
    if (savedSession) {
      safeRender();
      showNavigationLockToast({
        title: "Germination started",
        message: "The session stage was updated to Germinating so timing data stays accurate.",
      });
    }
    return;
  }

  if (normalizedKind === "session-stage-first-germinated") {
    if (!canApplySessionNotificationMutation(targetSessionId)) {
      return;
    }
    const savedSession = await updateSessionFromNotification(targetSessionId, (session) => {
      const timestamp = new Date().toISOString();
      session.sessionStatus = "germinating";
      session.germinationStartedAt = session.germinationStartedAt || getSessionStatusStartedAtValue(session) || timestamp;
      captureFirstPlantedEventForSession(session);
      session.firstPlantedAt = session.firstPlantedAt || timestamp;
      session.completedAt = "";
    });
    if (savedSession) {
      safeRender();
      showNavigationLockToast({
        title: "Germination started",
        message: "First sprout timing was recorded for this session.",
      });
    }
    return;
  }

  if (normalizedKind === "session-complete" || normalizedKind === "session-stage-completed") {
    if (!canApplySessionNotificationMutation(targetSessionId)) {
      return;
    }
    const savedSession = await updateSessionFromNotification(targetSessionId, (session) => {
      captureFirstPlantedEventForSession(session);
      session.sessionStatus = "completed";
      session.germinationStartedAt = session.germinationStartedAt || getSessionStatusStartedAtValue(session) || new Date().toISOString();
      session.completedAt = session.completedAt || new Date().toISOString();
    });
    if (savedSession) {
      safeRender();
      showNavigationLockToast({
        title: "Session completed",
        message: "The session was marked complete and timing analytics were finalized.",
      });
    }
    return;
  }

  if (normalizedKind === "session-focus-results") {
    navigateToNotificationSessionTarget(targetSessionId, { focusTarget: "results" });
    return;
  }

  if (normalizedKind === "session-focus-snapshot") {
    navigateToNotificationSessionTarget(targetSessionId, { focusTarget: "snapshot" });
    return;
  }

  if ((normalizedKind === "route" || normalizedKind === "open-session") && targetRoute) {
    if (targetSessionId) {
      const session = getNotificationSessionReference(targetSessionId);
      if (!session || isSessionSoftDeleted(session)) {
        showNavigationLockToast({
          title: "Session unavailable",
          message: "This notification points to a session that is no longer available.",
        });
        return;
      }
    }
    if (hasPendingUnsavedChanges()) {
      promptForUnsavedChangesNavigation(targetRoute);
      return;
    }
    navigateToHashRoute(targetRoute);
  }
}

function renderAppNotificationCardMarkup(notification = {}) {
  const categoryMeta = getAppNotificationCategoryMeta(notification.category);
  const relativeTime = formatGrowNetworkNotificationRelativeTime(notification.createdAt);
  const dateTimeLabel = formatAppNotificationDateTime(notification.createdAt);
  const sessionLabel = String(notification.sessionLabel || "").trim();
  const actions = Array.isArray(notification.actions) ? notification.actions.filter(Boolean) : [];
  const canSnooze = canSnoozeNotification(notification);
  const isSnoozeMenuOpen = canSnooze && appState.notificationSnoozeMenuOpenId === notification.id;

  return `
    <article class="app-notification-card${notification.isRead ? "" : " is-unread"}" data-app-notification-id="${escapeHtml(notification.id)}">
      <span class="app-notification-card-icon is-${escapeHtml(categoryMeta.tone)}" aria-hidden="true">
        ${renderAppIconMarkup(categoryMeta.icon, { variant: "plate", className: "app-notification-card-icon-art" })}
      </span>
      <div class="app-notification-card-main">
        <div class="app-notification-card-topline">
          <span class="app-notification-category is-${escapeHtml(categoryMeta.tone)}">${escapeHtml(categoryMeta.label)}</span>
          <span class="app-notification-time" title="${escapeHtml(dateTimeLabel)}">${escapeHtml(relativeTime)} • ${escapeHtml(dateTimeLabel)}</span>
        </div>
        <h4>${escapeHtml(notification.title)}</h4>
        <p>${escapeHtml(notification.message || "")}</p>
        <div class="app-notification-card-footer">
          ${sessionLabel ? `<span class="app-notification-session-link">${escapeHtml(sessionLabel)}</span>` : '<span class="app-notification-session-link app-notification-session-link--empty">In-app alert</span>'}
          <div class="app-notification-card-actions">
            ${actions.map((action, index) => `
              <button
                type="button"
                class="${escapeHtml(getNotificationActionButtonClassName(action))}"
                data-app-notification-open="${escapeHtml(notification.id)}"
                data-app-notification-action-index="${escapeHtml(String(index))}"
              >${escapeHtml(action.label)}</button>
            `).join("")}
            ${canSnooze ? `
              <button
                type="button"
                class="button button-secondary app-notification-action-button app-notification-action-button--snooze${isSnoozeMenuOpen ? " is-open" : ""}"
                data-app-notification-snooze-toggle="${escapeHtml(notification.id)}"
                aria-expanded="${isSnoozeMenuOpen ? "true" : "false"}"
              >Remind Me Later</button>
            ` : ""}
            ${notification.isRead
              ? '<span class="app-notification-read-state">Read</span>'
              : `<button type="button" class="button button-secondary app-notification-read-button" data-app-notification-read="${escapeHtml(notification.id)}">Mark read</button>`}
          </div>
          ${isSnoozeMenuOpen ? `
            <div class="app-notification-snooze-menu" role="group" aria-label="Snooze reminder options">
              ${APP_NOTIFICATION_SNOOZE_OPTIONS.map((option) => `
                <button
                  type="button"
                  class="button button-secondary app-notification-snooze-option"
                  data-app-notification-snooze-option="${escapeHtml(option.key)}"
                  data-app-notification-snooze-notification="${escapeHtml(notification.id)}"
                >${escapeHtml(option.label)}</button>
              `).join("")}
            </div>
          ` : ""}
        </div>
      </div>
    </article>
  `;
}

function renderAppNotificationCenter() {
  syncDueSnoozedAppNotifications();
  if (appNotificationTriggerIcon && !appNotificationTriggerIcon.innerHTML.trim()) {
    appNotificationTriggerIcon.innerHTML = renderAppIconMarkup("notificationBell", {
      variant: "plate",
      className: "app-notification-trigger-icon-art",
    });
  }

  const shouldShowCenter = canRenderAuthenticatedAppShell();
  if (appNotificationCenter) {
    appNotificationCenter.hidden = !shouldShowCenter;
  }
  if (!shouldShowCenter) {
    closeAppNotificationCenter();
    if (appNotificationBadge) {
      appNotificationBadge.hidden = true;
      appNotificationBadge.textContent = "";
    }
    return;
  }

  const notifications = getAppNotifications(appState.user?.id || "");
  const unreadCount = getUnreadAppNotificationCount(notifications);
  const totalCount = notifications.length;

  if (appNotificationBadge) {
    const badgeLabel = formatAppNotificationBadgeCount(unreadCount);
    appNotificationBadge.hidden = !badgeLabel;
    appNotificationBadge.textContent = badgeLabel;
  }

  if (appNotificationTrigger) {
    appNotificationTrigger.classList.toggle("has-unread", unreadCount > 0);
    appNotificationTrigger.setAttribute(
      "aria-label",
      unreadCount > 0
        ? `Open notifications (${unreadCount} unread)`
        : "Open notifications",
    );
  }

  if (appNotificationPanelSubtitle) {
    appNotificationPanelSubtitle.textContent = totalCount
      ? `${unreadCount} unread of ${totalCount} total notification${totalCount === 1 ? "" : "s"}.`
      : "Stay on top of session progress, supplies, snapshots, and community updates.";
  }

  if (appNotificationMarkAllReadButton) {
    appNotificationMarkAllReadButton.hidden = unreadCount === 0;
  }

  if (appNotificationList) {
    appNotificationList.innerHTML = totalCount
      ? notifications.map((notification) => renderAppNotificationCardMarkup(notification)).join("")
      : `
        <div class="app-notification-empty-state">
          <span class="app-notification-empty-state-icon" aria-hidden="true">
            ${renderAppIconMarkup("notificationBell", { variant: "plate", className: "app-notification-empty-state-icon-art" })}
          </span>
          <div class="app-notification-empty-state-copy">
            <strong>No notifications yet.</strong>
            <p>Your future grow reminders, unlocks, supplies alerts, and community activity will show up here.</p>
          </div>
        </div>
      `;
  }

  toggleAppNotificationCenter(appState.notificationCenterOpen);
}

function hydrateAppIconSlots(root = document) {
  if (!root || typeof root.querySelectorAll !== "function") {
    return;
  }

  root.querySelectorAll("[data-app-icon]").forEach((slot) => {
    const iconName = String(slot.dataset.appIcon || "").trim() || "info";
    const variant = String(slot.dataset.iconVariant || "plain").trim() === "plate" ? "plate" : "plain";
    const label = String(slot.dataset.iconLabel || "").trim();
    const decorative = slot.dataset.iconDecorative !== "false";
    const interactive = slot.dataset.iconInteractive === "true";
    const premiumClassNames = getPremiumIconClassNames(iconName, variant);
    slot.classList.add(
      "cg-icon",
      interactive ? "icon-interactive" : "icon-static",
      variant === "plate" ? "cg-icon--plate" : "cg-icon--plain",
      ...premiumClassNames.wrapper,
    );
    slot.innerHTML = renderAppIconSvgMarkup(iconName, {
      decorative: true,
      extraSvgClasses: premiumClassNames.svg,
    });
    if (decorative) {
      slot.setAttribute("aria-hidden", "true");
      slot.removeAttribute("role");
      slot.removeAttribute("aria-label");
    } else {
      slot.removeAttribute("aria-hidden");
      slot.setAttribute("role", "img");
      slot.setAttribute("aria-label", label || iconName);
    }
  });
}

function inferAppIconNameForLegacySectionIcon(iconElement) {
  const contextText = String(
    iconElement?.closest(".section-title-with-icon, .app-section-header-main, .section-heading, .app-section-header")?.textContent
    || iconElement?.closest("section, article, div")?.textContent
    || "",
  ).toLowerCase();

  if (!contextText) {
    return "";
  }
  if (contextText.includes("community grow moderation")) {
    return "certificationShield";
  }
  if (contextText.includes("source profile") || contextText.includes("source directory") || contextText.includes("source")) {
    return "sourceDirectoryBars";
  }
  if (contextText.includes("active session")) {
    return "activeSessionWaveform";
  }
  if (contextText.includes("timeline") || contextText.includes("lifecycle")) {
    return "activeSessionWaveform";
  }
  if (contextText.includes("recent completed")) {
    return "check";
  }
  if (contextText.includes("history")) {
    return "clock";
  }
  if (contextText.includes("session duration") || contextText.includes("timing")) {
    return "clock";
  }
  if (contextText.includes("germination progress") || contextText.includes("progress by partition")) {
    return "chart";
  }
  if (contextText.includes("germination rate") || contextText.includes("overall session germination")) {
    return "chart";
  }
  if (contextText.includes("session notes") || contextText.includes("notes")) {
    return "reportDocument";
  }
  if (contextText.includes("session images") || contextText.includes("images")) {
    return "uploadImage";
  }
  if (contextText.includes("share your grow snapshot") || contextText.includes("share")) {
    return "uploadImage";
  }
  if (contextText.includes("session detail")) {
    return "reportDocument";
  }
  if (contextText.includes("new session") || contextText.includes("my sessions") || contextText.includes("grow tracking")) {
    return "mySessionsSprout";
  }
  if (contextText.includes("published snapshots") || contextText.includes("submitted snapshots") || contextText.includes("snapshots")) {
    return "uploadImage";
  }
  if (contextText.includes("community grow")) {
    return "communityGroup";
  }
  if (contextText.includes("analytics") || contextText.includes("trend")) {
    return "chart";
  }
  if (contextText.includes("members") || contextText.includes("profile")) {
    return "profileUser";
  }
  if (contextText.includes("admin")) {
    return "adminShield";
  }
  return "";
}

function upgradeLegacySectionTitleIcons(root = document) {
  if (!root || typeof root.querySelectorAll !== "function") {
    return;
  }

  root.querySelectorAll("svg.section-title-icon").forEach((legacyIcon) => {
    const iconName = inferAppIconNameForLegacySectionIcon(legacyIcon);
    if (!iconName) {
      return;
    }
    const wrapper = document.createElement("span");
    wrapper.innerHTML = renderAppIconMarkup(iconName, {
      variant: "plate",
      className: "section-title-icon",
    }).trim();
    const replacement = wrapper.firstElementChild;
    if (replacement) {
      legacyIcon.replaceWith(replacement);
    }
  });
}

function normalizeSectionHeaderLayouts(root = document) {
  if (!root || typeof root.querySelectorAll !== "function") {
    return;
  }

  const applySectionTypographyClasses = (container) => {
    if (!(container instanceof HTMLElement)) {
      return;
    }

    container.classList.add("section-heading-block");
    Array.from(container.children).forEach((child) => {
      if (!(child instanceof HTMLElement)) {
        return;
      }
      if (child.matches(".eyebrow")) {
        child.classList.add("section-eyebrow");
        return;
      }
      if (child.matches("h1, h2, h3, h4, h5, .admin-collapsible-title, .app-section-header-title")) {
        child.classList.add("section-title");
        return;
      }
      if (child.matches("p:not(.eyebrow), .muted, .admin-collapsible-description, .app-section-header-subtitle, .dashboard-subtitle, .app-hero-subtitle")) {
        child.classList.add("section-subtitle");
      }
    });
  };

  root.querySelectorAll(".section-title-with-icon.app-section-header-main").forEach((header) => {
    if (!(header instanceof HTMLElement) || header.dataset.sectionHeaderNormalized === "true") {
      return;
    }

    const icon = Array.from(header.children).find((child) => (
      child instanceof HTMLElement
      && (child.classList.contains("section-title-icon") || child.classList.contains("cg-icon"))
    )) || null;
    const content = Array.from(header.children).find((child) => child instanceof HTMLElement && child !== icon) || null;
    if (!(icon instanceof HTMLElement) || !(content instanceof HTMLElement)) {
      return;
    }

    const directChildren = Array.from(content.children).filter((child) => child instanceof HTMLElement);
    if (!directChildren.length) {
      return;
    }

    const titleStack = document.createElement("div");
    titleStack.className = "section-header-title-stack";
    const descriptionStack = document.createElement("div");
    descriptionStack.className = "section-header-description-stack";

    directChildren.forEach((child) => {
      if (child.matches(".eyebrow, h1, h2, h3, h4, h5, .admin-collapsible-title, .app-section-header-title")) {
        titleStack.appendChild(child);
        return;
      }
      descriptionStack.appendChild(child);
    });

    if (!titleStack.children.length) {
      return;
    }

    applySectionTypographyClasses(titleStack);
    applySectionTypographyClasses(descriptionStack);
    content.replaceWith(titleStack);
    if (descriptionStack.children.length) {
      header.appendChild(descriptionStack);
    }
    header.dataset.sectionHeaderNormalized = "true";
  });

  root.querySelectorAll([
    ".app-section-header-main > div",
    ".grow-network-hero-copy",
    ".grow-network-panel-header > div",
    ".profile-page-copy",
    ".profile-section-heading",
    ".auth-card > div:first-child",
    ".snapshot-modal-copy",
  ].join(", ")).forEach((container) => {
    applySectionTypographyClasses(container);
  });
}

