function renderSetupScreen() {
  const setupCard = cloneTemplate(templates.setup);
  if (setupCard instanceof DocumentFragment && isLocalDevelopmentHost() && !isSupabaseConfigured()) {
    const setupSection = setupCard.firstElementChild;
    if (setupSection instanceof HTMLElement) {
      const helper = document.createElement("section");
      helper.className = "local-dev-qa-setup-helper";
      helper.innerHTML = `
        <div class="local-dev-qa-setup-helper-copy">
          <p class="eyebrow">Local QA</p>
          <h3>Run the app shell without Supabase</h3>
          <p class="muted">Enable a localhost-only mock user so you can test sessions, reminders, and notifications while the real setup screen stays intact for production.</p>
          <p class="muted">CSTP admin workflows require real local Supabase auth, <code>admin_users</code> membership, and an API-capable local runtime. The mock user does not validate protected CSTP admin APIs.</p>
          <p class="local-dev-qa-setup-helper-note">Storage key: <code>${escapeHtml(DEV_QA_BYPASS_STORAGE_KEY)}</code></p>
        </div>
        <div class="local-dev-qa-setup-helper-actions">
          <button type="button" class="button button-secondary" data-enable-dev-qa-bypass="true">Enable Dev QA Bypass</button>
        </div>
      `;
      helper.querySelector("[data-enable-dev-qa-bypass='true']")?.addEventListener("click", () => {
        setLocalDevQaBypassEnabled(true);
        window.location.reload();
      });
      setupSection.append(helper);
    }
  }
  app.replaceChildren(setupCard);
}

function closeNewSessionSystemModal({ navigateBack = false } = {}) {
  const overlay = document.querySelector("#new-session-system-modal-overlay");
  if (!overlay || overlay.dataset.closing === "true") {
    return;
  }

  overlay.dataset.closing = "true";
  overlay.classList.add("closing");
  overlay.querySelector(".new-session-system-modal")?.classList.add("closing");
  appState.newSessionSystemModalOpen = false;
  document.body.classList.remove("modal-open");

  window.setTimeout(() => {
    overlay.remove();
    if (navigateBack && window.location.hash === "#new") {
      window.location.hash = appState.newSessionReturnHash || "#sessions";
    }
    if (navigateBack) {
      clearNewSessionSeedVaultStarterIntent();
    }
  }, 180);
}

function selectNewSessionSystemType(systemType) {
  const normalizedSystemType = systemType === "TRA" ? "TRA" : "KAN";
  appState.newSessionSystemType = normalizedSystemType;
  closeNewSessionSystemModal();
  window.location.hash = `#new/${normalizedSystemType}`;
}

function ensureNewSessionSystemModal() {
  let overlay = document.querySelector("#new-session-system-modal-overlay");
  if (overlay) {
    return overlay;
  }

  overlay = document.createElement("div");
  overlay.id = "new-session-system-modal-overlay";
  overlay.className = "new-session-system-modal-overlay";
  overlay.hidden = false;
  overlay.dataset.closing = "false";
  overlay.innerHTML = `
    <div class="new-session-system-modal" role="dialog" aria-modal="true" aria-labelledby="new-session-system-modal-title">
      <button type="button" class="modal-close" aria-label="Close">×</button>
      <div class="new-session-system-modal-copy">
        <h2 id="new-session-system-modal-title">Choose System Type</h2>
      </div>
      <div class="new-session-system-options">
        <button type="button" class="new-session-system-option" data-system-type="KAN">
          <strong>KAN</strong>
          <span>8-part radial system</span>
        </button>
        <button type="button" class="new-session-system-option" data-system-type="TRA">
          <strong>TRa</strong>
          <span>16-part tray system</span>
        </button>
      </div>
    </div>
  `;

  overlay.addEventListener("click", (event) => {
    if (event.target === overlay) {
      event.preventDefault();
      event.stopPropagation();
      closeNewSessionSystemModal({ navigateBack: true });
    }
  });

  overlay.querySelector(".modal-close")?.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    closeNewSessionSystemModal({ navigateBack: true });
  });

  overlay.querySelectorAll("[data-system-type]").forEach((button) => {
    button.addEventListener("click", () => {
      selectNewSessionSystemType(button.dataset.systemType || "KAN");
    });
  });

  if (!ensureNewSessionSystemModal.escapeBound) {
    document.addEventListener("keydown", (event) => {
      if (event.key === "Escape" && appState.newSessionSystemModalOpen) {
        closeNewSessionSystemModal({ navigateBack: window.location.hash === "#new" });
      }
    });
    ensureNewSessionSystemModal.escapeBound = true;
  }

  document.body.appendChild(overlay);
  return overlay;
}

function openNewSessionSystemModal() {
  const overlay = ensureNewSessionSystemModal();
  overlay.hidden = false;
  overlay.dataset.closing = "false";
  overlay.classList.remove("closing");
  overlay.querySelector(".new-session-system-modal")?.classList.remove("closing");
  appState.newSessionSystemModalOpen = true;
  document.body.classList.add("modal-open");
  overlay.querySelector(".modal-close")?.focus();
}

function getNewSessionNameField(form) {
  const sessionNameField = form?.elements?.sessionName;
  return sessionNameField instanceof HTMLInputElement ? sessionNameField : null;
}

function getCurrentNewSessionForm() {
  const form = document.querySelector("#session-form");
  return form instanceof HTMLFormElement ? form : null;
}

function syncNewSessionNameState(form) {
  const sessionNameField = getNewSessionNameField(form);
  if (!form || !sessionNameField) {
    return false;
  }

  const isEmpty = !String(sessionNameField.value || "").trim();
  const nameShell = sessionNameField.closest("[data-session-name-field]");

  form.classList.toggle("session-name-empty", isEmpty);
  form.classList.remove("session-name-warning");
  nameShell?.classList.toggle("is-empty", isEmpty);
  nameShell?.classList.remove("is-warning");
  sessionNameField.setAttribute("aria-invalid", "false");
  sessionNameField.setCustomValidity("");
  if (!isEmpty) {
    sessionNameField.dataset.namePromptDismissed = "false";
  }

  return !isEmpty;
}

function applyNewSessionNamePromptValue(form, value = "") {
  const sessionNameField = getNewSessionNameField(form);
  if (!form || !sessionNameField) {
    return false;
  }

  const nextName = String(value || "").trim();
  sessionNameField.value = nextName;
  sessionNameField.defaultValue = nextName;
  sessionNameField.dataset.namePromptDismissed = String(!nextName);
  sessionNameField.setCustomValidity("");
  syncNewSessionNameState(form);
  updateNewSessionNameDefaultSuggestion(form);
  sessionNameField.dispatchEvent(new Event("input", { bubbles: true }));
  sessionNameField.dispatchEvent(new Event("change", { bubbles: true }));
  return Boolean(nextName);
}

function shouldApplyNewSessionPromptName(form, initialFieldValue = "") {
  const sessionNameField = getNewSessionNameField(form);
  if (!sessionNameField) {
    return false;
  }

  const currentName = String(sessionNameField.value || "").trim();
  const initialName = String(initialFieldValue || "").trim();
  return !currentName || currentName === initialName;
}

function dismissNewSessionNamePrompt(form) {
  const sessionNameField = getNewSessionNameField(form);
  if (sessionNameField) {
    sessionNameField.dataset.namePromptDismissed = "true";
  }
  syncNewSessionNameState(form);
  updateNewSessionNameDefaultSuggestion(form);
}

function getNewSessionSaveButtons(form) {
  return [...(form?.querySelectorAll?.('[data-new-session-save-button="true"]') || [])]
    .filter((button) => button instanceof HTMLButtonElement);
}

function setSessionSaveButtonLabel(button, label) {
  if (!(button instanceof HTMLButtonElement)) {
    return;
  }

  const labelNode = button.querySelector("[data-session-save-button-label], [data-save-button-label]");
  if (labelNode) {
    labelNode.textContent = label;
    return;
  }

  button.textContent = label;
}

function getSaveButtonIconMarkup() {
  return `
    <span class="save-button-icon" data-save-button-icon aria-hidden="true">
      <svg viewBox="0 0 24 24" focusable="false" aria-hidden="true">
        <path d="M5 4.75h11.2L19.25 7.8v11.45H5V4.75Z"></path>
        <path d="M8 4.75v5h7.5v-5"></path>
        <path d="M8 19.25v-5.5h8v5.5"></path>
        <path d="M13.6 6.25v2"></path>
      </svg>
    </span>
  `;
}

function isSaveButtonIconCandidate(button) {
  if (!(button instanceof HTMLButtonElement)) {
    return false;
  }
  if (button.matches("[data-save-icon-exempt='true'], .button-danger, .gallery-admin-reject")) {
    return false;
  }
  const label = button.textContent.replace(/\s+/g, " ").trim().toLowerCase();
  const explicitSaveAction = button.matches([
    "[data-save-icon-button='true']",
    "[data-new-session-save-button='true']",
    "[data-session-save-button='true']",
    "[data-filter-paper-modal-save='true']",
    "[data-filter-paper-setup-save='true']",
    "[data-unsaved-action='save']",
  ].join(", "));
  if (explicitSaveAction) {
    return true;
  }
  if (button.closest("[data-seed-vault-entry-form]") && label === "add seeds") {
    return true;
  }
  if (/(^|\s)save(\s|$|[&:])/.test(label)) {
    return true;
  }
  return label === "update password";
}

function enhanceSaveButtonIcon(button) {
  if (!isSaveButtonIconCandidate(button)) {
    return;
  }

  button.dataset.saveIconButton = "true";
  button.classList.add("save-button");
  const hasIcon = Boolean(button.querySelector("[data-save-button-icon], .detail-save-shortcut-icon"));
  const labelNode = button.querySelector("[data-save-button-label], [data-session-save-button-label]");
  if (hasIcon && labelNode) {
    return;
  }

  const label = button.textContent.replace(/\s+/g, " ").trim() || NEW_SESSION_SAVE_BUTTON_DEFAULT_LABEL;
  button.innerHTML = `${getSaveButtonIconMarkup()}<span data-save-button-label>${escapeHtml(label)}</span>`;
}

function enhanceGlobalSaveButtonIcons(scope = document) {
  const root = scope instanceof Element || scope instanceof Document ? scope : document;
  if (root instanceof HTMLButtonElement) {
    enhanceSaveButtonIcon(root);
    return;
  }
  root.querySelectorAll?.("button").forEach((button) => {
    enhanceSaveButtonIcon(button);
  });
}

function initializeGlobalSaveButtonIcons() {
  if (!document.body || document.body.dataset.saveButtonIconsBound === "true") {
    return;
  }

  document.body.dataset.saveButtonIconsBound = "true";
  enhanceGlobalSaveButtonIcons(document);
  const observer = new MutationObserver((mutations) => {
    const shouldRefresh = mutations.some((mutation) => (
      mutation.type === "childList"
      || mutation.type === "characterData"
      || (mutation.type === "attributes" && mutation.target instanceof HTMLButtonElement)
    ));
    if (!shouldRefresh) {
      return;
    }
    window.requestAnimationFrame(() => enhanceGlobalSaveButtonIcons(document));
  });
  observer.observe(document.body, {
    attributes: true,
    attributeFilter: ["class", "data-save-icon-button", "data-save-state"],
    childList: true,
    characterData: true,
    subtree: true,
  });
}

function clearNewSessionSaveButtonTimer(form) {
  if (form?.__newSessionSaveButtonTimer) {
    window.clearTimeout(form.__newSessionSaveButtonTimer);
    form.__newSessionSaveButtonTimer = null;
  }
}

function setNewSessionSaveButtonState(form, state = "default") {
  const buttons = getNewSessionSaveButtons(form);
  if (buttons.length === 0) {
    return;
  }

  clearNewSessionSaveButtonTimer(form);
  const isSaved = state === "saved";
  buttons.forEach((button) => {
    button.classList.toggle("is-saved", isSaved);
    button.setAttribute("data-save-state", isSaved ? "saved" : "default");
    button.disabled = isSaved;
    setSessionSaveButtonLabel(button, isSaved ? SESSION_SAVE_BUTTON_SAVED_LABEL : NEW_SESSION_SAVE_BUTTON_DEFAULT_LABEL);
  });

  if (isSaved) {
    form.__newSessionSaveButtonTimer = window.setTimeout(() => {
      setNewSessionSaveButtonState(form, "default");
    }, SESSION_SAVE_BUTTON_SAVED_RESET_MS);
  }
}

function resetNewSessionSaveButtonState(form) {
  setNewSessionSaveButtonState(form, "default");
}

function waitForNewSessionSavedStateVisibility() {
  return new Promise((resolve) => {
    window.setTimeout(resolve, NEW_SESSION_SAVE_BUTTON_SAVED_MIN_MS);
  });
}

function closeNewSessionNamePrompt({ focusField = false } = {}) {
  const overlay = document.querySelector("#new-session-name-modal-overlay");
  if (!overlay || overlay.dataset.closing === "true") {
    return;
  }

  const sessionNameField = document.querySelector('#session-form input[name="sessionName"]');
  overlay.dataset.closing = "true";
  overlay.classList.add("closing");
  overlay.querySelector(".new-session-name-modal")?.classList.add("closing");
  document.body.classList.remove("modal-open");

  window.setTimeout(() => {
    overlay.remove();
    if (focusField && sessionNameField instanceof HTMLInputElement) {
      sessionNameField.focus({ preventScroll: true });
    }
  }, 180);
}

function ensureNewSessionNamePrompt(form) {
  let overlay = document.querySelector("#new-session-name-modal-overlay");
  if (overlay) {
    return overlay;
  }

  overlay = document.createElement("div");
  overlay.id = "new-session-name-modal-overlay";
  overlay.className = "new-session-name-modal-overlay";
  overlay.dataset.closing = "false";
  overlay.innerHTML = `
    <div class="new-session-name-modal" role="dialog" aria-modal="true" aria-labelledby="new-session-name-modal-title" aria-describedby="new-session-name-modal-subtitle">
      <button type="button" class="modal-close" data-new-session-name-close aria-label="Close">×</button>
      <div class="new-session-name-modal-copy">
        <p class="eyebrow">First action</p>
        <h2 id="new-session-name-modal-title">Name Your Grow Session</h2>
        <p id="new-session-name-modal-subtitle">Give this session a clear name before continuing.</p>
      </div>
      <form class="new-session-name-modal-form" data-new-session-name-modal-form>
        <label class="new-session-name-modal-field">
          <span>Session Name</span>
          <input id="new-session-name-modal-input" type="text" maxlength="80" placeholder="Blue Dream Test" autocomplete="off">
        </label>
        <div class="new-session-name-examples" aria-label="Session name examples">
          <span>Examples:</span>
          <ul>
            <li>Blue Dream Test</li>
            <li>This Season Outdoor Grow</li>
            <li>KAN A - 2026 Pheno Hunt</li>
          </ul>
        </div>
        <div class="new-session-name-modal-actions">
          <button type="submit" class="button button-primary">Continue</button>
          <button type="button" class="button button-secondary" data-new-session-name-skip>Skip for now</button>
        </div>
      </form>
    </div>
  `;

  const modalForm = overlay.querySelector("[data-new-session-name-modal-form]");
  const modalInput = overlay.querySelector("#new-session-name-modal-input");

  const applyPrompt = () => {
    const targetForm = getCurrentNewSessionForm() || form;
    if (modalInput instanceof HTMLInputElement) {
      if (shouldApplyNewSessionPromptName(targetForm, overlay.dataset.initialSessionName || "")) {
        applyNewSessionNamePromptValue(targetForm, modalInput.value);
      } else {
        syncNewSessionNameState(targetForm);
        updateNewSessionNameDefaultSuggestion(targetForm);
      }
    }
    closeNewSessionNamePrompt({ focusField: false });
  };

  const skipPrompt = () => {
    dismissNewSessionNamePrompt(getCurrentNewSessionForm() || form);
    closeNewSessionNamePrompt({ focusField: false });
  };

  modalForm?.addEventListener("submit", (event) => {
    event.preventDefault();
    applyPrompt();
  });

  overlay.querySelector("[data-new-session-name-skip]")?.addEventListener("click", (event) => {
    event.preventDefault();
    skipPrompt();
  });

  overlay.querySelector("[data-new-session-name-close]")?.addEventListener("click", (event) => {
    event.preventDefault();
    skipPrompt();
  });

  overlay.addEventListener("click", (event) => {
    if (event.target === overlay) {
      event.preventDefault();
      skipPrompt();
    }
  });

  if (!ensureNewSessionNamePrompt.escapeBound) {
    document.addEventListener("keydown", (event) => {
      const activeOverlay = document.querySelector("#new-session-name-modal-overlay");
      if (event.key === "Escape" && activeOverlay && activeOverlay.dataset.closing !== "true") {
        event.preventDefault();
        const activeForm = document.querySelector("#session-form");
        dismissNewSessionNamePrompt(activeForm);
        closeNewSessionNamePrompt({ focusField: false });
      }
    });
    ensureNewSessionNamePrompt.escapeBound = true;
  }

  document.body.appendChild(overlay);
  return overlay;
}

function openNewSessionNamePrompt(form) {
  const sessionNameField = getNewSessionNameField(form);
  if (!form || !sessionNameField) {
    return false;
  }

  const overlay = ensureNewSessionNamePrompt(form);
  const modalInput = overlay.querySelector("#new-session-name-modal-input");
  if (modalInput instanceof HTMLInputElement) {
    modalInput.value = sessionNameField.value || "";
  }
  overlay.dataset.initialSessionName = String(sessionNameField.value || "").trim();
  overlay.dataset.closing = "false";
  overlay.classList.remove("closing");
  overlay.querySelector(".new-session-name-modal")?.classList.remove("closing");
  document.body.classList.add("modal-open");
  refreshLearnContinueWatchingSection();
  window.setTimeout(() => {
    if (modalInput instanceof HTMLInputElement) {
      modalInput.focus();
      modalInput.select();
    }
  }, 0);
  return true;
}

