function getLearnTutorialCategories() {
  const draftMap = loadAdminTutorialDraftsFromStorage();
  const categoryDefinitions = [...LEARN_TUTORIAL_CATEGORIES, ...LEARN_TUTORIAL_FUTURE_CATEGORIES];
  const categoryShells = categoryDefinitions.map((category) => ({
    ...category,
    categoryOrder: Number.isFinite(Number(category.categoryOrder)) ? Number(category.categoryOrder) : 999,
    tutorials: [],
  }));
  const categoryMap = new Map(categoryShells.map((category) => [category.id, category]));

  LEARN_TUTORIAL_CATEGORIES.forEach((category) => {
    category.tutorials.forEach((tutorial, index) => {
      const draft = draftMap[tutorial.id] || {};
      const videoDraft = draft.video || {};
      const categoryId = categoryMap.has(draft.categoryId) ? draft.categoryId : category.id;
      const categoryOrder = Number.isFinite(Number(draft.categoryOrder))
        ? Number(draft.categoryOrder)
        : (Number.isFinite(Number(categoryMap.get(categoryId)?.categoryOrder)) ? Number(categoryMap.get(categoryId)?.categoryOrder) : 999);
      const videoProvider = normalizeTutorialVideoProvider(draft.videoProvider || videoDraft.videoProvider || videoDraft.provider || tutorial.videoProvider || tutorial.video?.videoProvider || tutorial.video?.provider || "none");
      const cloudflareStreamId = String(draft.cloudflareStreamId || videoDraft.cloudflareStreamId || tutorial.cloudflareStreamId || tutorial.video?.cloudflareStreamId || "").trim();
      const mp4Url = String(draft.mp4Url || videoDraft.mp4Url || tutorial.mp4Url || tutorial.video?.mp4Url || "").trim();
      const embedUrl = String(draft.embedUrl || videoDraft.embedUrl || tutorial.embedUrl || tutorial.video?.embedUrl || "").trim();
      const posterUrl = String(draft.posterUrl || videoDraft.posterUrl || videoDraft.poster || draft.thumbnailUrl || tutorial.posterUrl || tutorial.video?.posterUrl || tutorial.video?.poster || tutorial.thumbnailUrl || "").trim();
      const captionsUrl = String(draft.captionsUrl || videoDraft.captionsUrl || tutorial.captionsUrl || tutorial.video?.captionsUrl || "").trim();
      const transcriptUrl = String(draft.transcriptUrl || videoDraft.transcriptUrl || tutorial.transcriptUrl || tutorial.video?.transcriptUrl || "").trim();
      const transcriptText = String(draft.transcriptText || videoDraft.transcriptText || tutorial.transcriptText || tutorial.video?.transcriptText || "").trim();
      const draftFeaturedOrder = Number(draft.featuredOrder);
      const tutorialFeaturedOrder = Number(tutorial.featuredOrder);
      const featuredOrder = Number.isFinite(draftFeaturedOrder) && draftFeaturedOrder > 0
        ? draftFeaturedOrder
        : (Number.isFinite(tutorialFeaturedOrder) && tutorialFeaturedOrder > 0 ? tutorialFeaturedOrder : index + 1);
      const featuredLabel = String(draft.featuredLabel ?? tutorial.featuredLabel ?? "").trim();
      const audience = normalizeLearnAudience(draft.audience ?? tutorial.audience ?? "public");
      const isPublic = draft.isPublic ?? tutorial.isPublic ?? audience === "public";
      const mergedTutorial = {
        ...tutorial,
        ...draft,
        id: tutorial.id,
        baseCategoryId: category.id,
        categoryId,
        categoryOrder,
        audience,
        isPublic: normalizeLearnPublicFlag(isPublic, audience === "public"),
        visibilityNote: String(draft.visibilityNote ?? tutorial.visibilityNote ?? "").trim(),
        duration: String(draft.duration || tutorial.duration || "").trim() || tutorial.duration,
        difficulty: String(draft.difficulty || tutorial.difficulty || getLearnTutorialDifficultyLabel(tutorial)).trim(),
        status: getTutorialVisibilityStatus({
          status: draft.status || draft.visibilityStatus || tutorial.status || tutorial.visibilityStatus || "coming-soon",
          scheduled: draft.scheduled ?? tutorial.scheduled,
        }),
        visibilityStatus: getTutorialVisibilityStatus({
          status: draft.visibilityStatus || draft.status || tutorial.visibilityStatus || tutorial.status || "coming-soon",
          scheduled: draft.scheduled ?? tutorial.scheduled,
        }),
        scheduled: Boolean(draft.scheduled ?? tutorial.scheduled),
        releaseDate: String(draft.releaseDate ?? tutorial.releaseDate ?? "").trim(),
        comingSoonLabel: String(draft.comingSoonLabel ?? tutorial.comingSoonLabel ?? "").trim(),
        thumbnailUrl: String(draft.thumbnailUrl || tutorial.thumbnailUrl || "").trim(),
        order: Number.isFinite(Number(draft.order)) ? Number(draft.order) : (Number.isFinite(Number(tutorial.order)) ? Number(tutorial.order) : index + 1),
        featured: Boolean(draft.featured ?? tutorial.featured),
        featuredOrder,
        featuredLabel,
        qrLabel: String(draft.qrLabel ?? tutorial.qrLabel ?? "").trim(),
        qrDescription: String(draft.qrDescription ?? tutorial.qrDescription ?? "").trim(),
        qrCampaignTag: String(draft.qrCampaignTag ?? tutorial.qrCampaignTag ?? "").trim(),
        qrDestinationUrl: String(draft.qrDestinationUrl ?? tutorial.qrDestinationUrl ?? "").trim(),
        recommendedFor: normalizeLearnTutorialTextList(draft.recommendedFor || tutorial.recommendedFor),
        priority: Number.isFinite(Number(draft.priority)) ? Number(draft.priority) : (Number.isFinite(Number(tutorial.priority)) ? Number(tutorial.priority) : 999),
        relatedFeature: String(draft.relatedFeature ?? tutorial.relatedFeature ?? "").trim(),
        userStage: String(draft.userStage ?? tutorial.userStage ?? "").trim(),
        onboardingPriority: Boolean(draft.onboardingPriority ?? tutorial.onboardingPriority),
        videoProvider,
        cloudflareStreamId,
        mp4Url,
        embedUrl,
        posterUrl,
        captionsUrl,
        transcriptUrl,
        transcriptText,
        quickSteps: normalizeLearnTutorialTextList(draft.quickSteps || tutorial.quickSteps),
        tips: normalizeLearnTutorialTextList(draft.tips || tutorial.tips),
        relatedTutorialIds: normalizeLearnTutorialTextList(draft.relatedTutorialIds || tutorial.relatedTutorialIds),
        video: {
          videoProvider,
          provider: videoProvider,
          cloudflareStreamId,
          mp4Url,
          embedUrl,
          posterUrl,
          poster: posterUrl,
          captionsUrl,
          transcriptUrl,
          transcriptText,
        },
        _sortOrder: Number.isFinite(Number(draft.order)) ? Number(draft.order) : (Number.isFinite(Number(tutorial.order)) ? Number(tutorial.order) : index + 1),
      };
      categoryMap.get(categoryId)?.tutorials.push(mergedTutorial);
    });
  });

  return categoryShells
    .sort((left, right) => {
      const orderDelta = (Number(left.categoryOrder) || 999) - (Number(right.categoryOrder) || 999);
      if (orderDelta !== 0) {
        return orderDelta;
      }
      return String(left.title || "").localeCompare(String(right.title || ""));
    })
    .map((category) => ({
      ...category,
      tutorials: category.tutorials.sort((left, right) => (
        ((Number(left.categoryOrder) || 999) - (Number(right.categoryOrder) || 999))
        || ((Number(left._sortOrder) || 999) - (Number(right._sortOrder) || 999))
        || String(left.title || "").localeCompare(String(right.title || ""))
      )).map(({ _sortOrder, ...tutorial }) => tutorial),
    }));
}

function getLearnCategory(categoryId = "") {
  return getLearnTutorialCategories().find((category) => category.id === categoryId) || null;
}

function getLearnTutorialById(tutorialId = "") {
  for (const category of getLearnTutorialCategories()) {
    const tutorial = category.tutorials.find((item) => item.id === tutorialId);
    if (tutorial) {
      return { category, tutorial };
    }
  }
  return null;
}

