function openLearnTutorialFromHelper(tutorialId = "", source = "Empty state") {
  const normalizedTutorialId = String(tutorialId || "").trim();
  const tutorialEntry = getLearnTutorialById(normalizedTutorialId);
  if (tutorialEntry && canCurrentUserViewLearnItem(tutorialEntry.tutorial)) {
    openLearnTutorialModal(normalizedTutorialId, { source });
    return;
  }

  window.location.hash = normalizedTutorialId ? "#learn/grow-app" : "#learn";
}

function getContextualOnboardingPrompt(promptId = "") {
  return CONTEXTUAL_ONBOARDING_PROMPTS[String(promptId || "").trim()] || null;
}

function getContextualOnboardingStorageKey(promptId = "") {
  return `${CONTEXTUAL_ONBOARDING_STORAGE_PREFIX}${String(promptId || "").trim()}`;
}

function getContextualOnboardingPromptState(promptId = "") {
  const key = getContextualOnboardingStorageKey(promptId);
  if (!key) {
    return null;
  }

  try {
    const storedValue = JSON.parse(localStorage.getItem(key) || "null");
    const status = String(storedValue?.status || "").trim().toLowerCase();
    if (!["dismissed", "completed"].includes(status)) {
      return null;
    }
    return {
      status,
      tutorialId: String(storedValue?.tutorialId || "").trim(),
      updatedAt: String(storedValue?.updatedAt || "").trim(),
      persistence: "local",
      userId: String(storedValue?.userId || "").trim(),
    };
  } catch (error) {
    console.warn("[Onboarding] Failed to read prompt state.", { promptId, error });
    return null;
  }
}

function saveContextualOnboardingPromptState(promptId = "", status = "dismissed", tutorialId = "") {
  const normalizedPromptId = String(promptId || "").trim();
  const normalizedStatus = String(status || "").trim().toLowerCase() === "completed" ? "completed" : "dismissed";
  if (!normalizedPromptId) {
    return;
  }

  try {
    localStorage.setItem(getContextualOnboardingStorageKey(normalizedPromptId), JSON.stringify({
      status: normalizedStatus,
      tutorialId: String(tutorialId || "").trim(),
      updatedAt: new Date().toISOString(),
      persistence: "local",
      userId: appState.user?.id || "",
    }));
  } catch (error) {
    console.warn("[Onboarding] Failed to save prompt state.", { promptId: normalizedPromptId, error });
  }
}

function shouldShowContextualOnboardingPrompt(promptId = "") {
  const prompt = getContextualOnboardingPrompt(promptId);
  if (!prompt || getContextualOnboardingPromptState(promptId)) {
    return false;
  }
  const visibleActions = (prompt.actions || []).filter((action) => {
    const tutorialEntry = getLearnTutorialById(action.tutorialId);
    return tutorialEntry && canCurrentUserViewLearnItem(tutorialEntry.tutorial);
  });
  return visibleActions.length > 0 && !visibleActions.some((action) => isTutorialCompleted(action.tutorialId));
}

function isTutorialRecommendedForContexts(tutorialId = "", contexts = []) {
  const normalizedTutorialId = String(tutorialId || "").trim();
  const normalizedContexts = normalizeLearnTutorialTextList(contexts);
  if (!normalizedTutorialId || !normalizedContexts.length) {
    return false;
  }

  const tutorialEntry = getLearnTutorialById(normalizedTutorialId);
  const recommendedFor = normalizeLearnTutorialTextList(tutorialEntry?.tutorial?.recommendedFor);
  return recommendedFor.some((context) => normalizedContexts.includes(context));
}

function getLearnTutorialDurationLabel(tutorial = {}) {
  const [duration] = String(tutorial.duration || "2 min • Beginner").split("•").map((part) => part.trim());
  return duration || "2 min";
}

function getLearnTutorialDifficultyLabel(tutorial = {}) {
  if (tutorial.difficulty) {
    return String(tutorial.difficulty || "").trim() || "Beginner";
  }
  const [, difficulty] = String(tutorial.duration || "2 min • Beginner").split("•").map((part) => part.trim());
  return difficulty || "Beginner";
}

function getLearnTutorialLearningPoints(tutorial = {}, category = {}) {
  if (Array.isArray(tutorial.whatYoullLearn) && tutorial.whatYoullLearn.length) {
    return tutorial.whatYoullLearn;
  }

  return [
    `How ${tutorial.title || "this tutorial"} fits into the ${category.eyebrow || "Cannakan® Grow"} workflow.`,
    "The key setup decisions to make before continuing.",
    "What to look for when you apply this step in a real grow session.",
  ];
}

function getLearnTutorialQuickSteps(tutorial = {}) {
  return normalizeLearnTutorialTextList(tutorial.quickSteps);
}

function getLearnTutorialTips(tutorial = {}) {
  return normalizeLearnTutorialTextList(tutorial.tips);
}

function getRelatedLearnTutorials(category = {}, tutorial = {}) {
  const relatedTutorialIds = normalizeLearnTutorialTextList(tutorial.relatedTutorialIds);
  if (relatedTutorialIds.length) {
    const tutorialEntries = getLearnTutorialCategories().flatMap((learnCategory) => (
      learnCategory.tutorials.map((learnTutorial) => ({ category: learnCategory, tutorial: learnTutorial }))
    ));
    return relatedTutorialIds
      .map((relatedTutorialId) => tutorialEntries.find((entry) => entry.tutorial.id === relatedTutorialId)?.tutorial)
      .filter((relatedTutorial) => relatedTutorial && relatedTutorial.id !== tutorial.id)
      .filter((relatedTutorial) => shouldShowTutorialOnPublicLearn(relatedTutorial) || getTutorialVisibilityStatus(tutorial) === "draft")
      .slice(0, 3);
  }

  return Array.isArray(category.tutorials)
    ? category.tutorials
      .filter((item) => item.id !== tutorial.id && (shouldShowTutorialOnPublicLearn(item) || getTutorialVisibilityStatus(tutorial) === "draft"))
      .slice(0, 3)
    : [];
}

function getLearnTutorialVisualTheme(tutorial = {}, category = {}) {
  const categoryId = String(category.id || tutorial.categoryId || tutorial.baseCategoryId || "").trim();
  if (categoryId === "kan-system") {
    return {
      theme: "kan",
      label: "KAN® System",
      icon: "kan-device",
    };
  }
  return {
    theme: "app",
    label: "Grow App",
    icon: "app-dashboard",
  };
}

function getLearnTutorialThumbnailUrl(tutorial = {}) {
  const video = getTutorialVideoConfig(tutorial);
  return resolveLearnTutorialThumbnailAssetPath(tutorial.thumbnailUrl || tutorial.posterUrl || video.posterUrl || "");
}

function isLearnTutorialGettingStarted(tutorial = {}) {
  return LEARN_GETTING_STARTED_CHECKLIST.some((item) => (
    item.type === "tutorial" && item.tutorialId === tutorial.id
  ));
}

