function closeLearnTutorialModal() {
  const overlay = document.querySelector("#learn-tutorial-modal-overlay");
  if (!overlay || overlay.dataset.closing === "true") {
    return;
  }

  trackTutorialAnalyticsEvent("tutorial_dismissed", {
    tutorialId: overlay.dataset.activeTutorialId || "",
    category: overlay.dataset.activeTutorialCategory || "",
    source: overlay.dataset.activeTutorialSource || "Tutorial modal",
  });
  overlay.dataset.closing = "true";
  overlay.classList.add("closing");
  overlay.querySelector(".learn-tutorial-modal")?.classList.add("closing");
  document.body.classList.remove("modal-open");

  window.setTimeout(() => {
    overlay.remove();
  }, 180);
}

function ensureLearnTutorialModal() {
  let overlay = document.querySelector("#learn-tutorial-modal-overlay");
  if (overlay) {
    return overlay;
  }

  overlay = document.createElement("div");
  overlay.id = "learn-tutorial-modal-overlay";
  overlay.className = "learn-tutorial-modal-overlay";
  overlay.dataset.closing = "false";
  overlay.innerHTML = `
    <div class="learn-tutorial-modal" role="dialog" aria-modal="true" aria-labelledby="learn-tutorial-modal-title" aria-describedby="learn-tutorial-modal-description">
      <button type="button" class="modal-close" data-learn-tutorial-close aria-label="Close">×</button>
      <div class="learn-tutorial-modal-scroll" data-learn-tutorial-modal-content></div>
    </div>
  `;

  overlay.addEventListener("click", (event) => {
    if (event.target === overlay) {
      event.preventDefault();
      closeLearnTutorialModal();
    }
  });

  overlay.querySelectorAll("[data-learn-tutorial-close]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      closeLearnTutorialModal();
    });
  });

  if (!ensureLearnTutorialModal.escapeBound) {
    document.addEventListener("keydown", (event) => {
      const activeOverlay = document.querySelector("#learn-tutorial-modal-overlay");
      if (event.key === "Escape" && activeOverlay && activeOverlay.dataset.closing !== "true") {
        event.preventDefault();
        closeLearnTutorialModal();
      }
    });
    ensureLearnTutorialModal.escapeBound = true;
  }

  document.body.appendChild(overlay);
  return overlay;
}

function removeCompletedTutorialPrompts(tutorialId = "") {
  const normalizedTutorialId = String(tutorialId || "").trim();
  if (!normalizedTutorialId) {
    return;
  }

  document.querySelectorAll("[data-contextual-onboarding-prompt]").forEach((promptElement) => {
    if (!(promptElement instanceof HTMLElement)) {
      return;
    }
    const promptId = promptElement.dataset.contextualOnboardingPrompt || "";
    const prompt = getContextualOnboardingPrompt(promptId);
    const isRelatedPrompt = (prompt?.actions || []).some((action) => action.tutorialId === normalizedTutorialId);
    if (!isRelatedPrompt) {
      return;
    }
    saveContextualOnboardingPromptState(promptId, "completed", normalizedTutorialId);
    promptElement.classList.add("is-dismissing");
    window.setTimeout(() => promptElement.remove(), 170);
  });
}

