function refreshLearnGettingStartedChecklistUi(scope = document) {
  const root = scope instanceof Document ? scope : document;
  const checklistState = getLearnGettingStartedChecklistState();
  const checklistMap = new Map(checklistState.map((item) => [item.id, item]));
  const completedCount = checklistState.filter((item) => item.completed).length;

  root.querySelectorAll("[data-learn-checklist-count]").forEach((countElement) => {
    if (countElement instanceof HTMLElement) {
      countElement.textContent = `${completedCount}/${checklistState.length} complete`;
    }
  });

  root.querySelectorAll("[data-learn-checklist-item]").forEach((itemElement) => {
    if (!(itemElement instanceof HTMLElement)) {
      return;
    }
    const checklistItem = checklistMap.get(itemElement.dataset.learnChecklistItem || "");
    if (!checklistItem) {
      return;
    }
    itemElement.classList.toggle("is-completed", checklistItem.completed);
    itemElement.classList.toggle("is-auto-completed", checklistItem.autoCompleted);
    const toggle = itemElement.querySelector("[data-learn-checklist-toggle]");
    if (toggle instanceof HTMLInputElement) {
      toggle.checked = checklistItem.completed;
      toggle.disabled = checklistItem.autoCompleted;
    }
  });
}

function bindLearnGettingStartedChecklist(scope = document) {
  scope.querySelectorAll("[data-learn-checklist-toggle]").forEach((toggle) => {
    if (!(toggle instanceof HTMLInputElement) || toggle.dataset.learnChecklistBound === "true") {
      return;
    }
    toggle.dataset.learnChecklistBound = "true";
    toggle.addEventListener("change", () => {
      setLearnGettingStartedChecklistItemState(toggle.dataset.learnChecklistToggle || "", toggle.checked, "manual");
      refreshLearnGettingStartedChecklistUi(document);
    });
  });
  refreshLearnGettingStartedChecklistUi(document);
}

function getActiveLearnTutorialFilter(scope = document) {
  const filterGroup = scope.querySelector?.("[data-learn-filter-group]") || document.querySelector("[data-learn-filter-group]");
  return String(filterGroup?.dataset.activeFilter || "all").trim() || "all";
}

function doesLearnTutorialMatchFilter(card, activeFilter = "all") {
  if (!(card instanceof HTMLElement)) {
    return false;
  }

  if (activeFilter === "all") {
    return true;
  }
  if (activeFilter === "kan-system" || activeFilter === "grow-app") {
    return card.dataset.learnTutorialCategoryId === activeFilter;
  }
  if (activeFilter === "getting-started") {
    return card.dataset.learnGettingStarted === "true";
  }
  if (activeFilter === "coming-soon") {
    return ["coming-soon", "scheduled"].includes(card.dataset.learnTutorialStatus || "");
  }
  if (activeFilter === "completed") {
    return card.dataset.learnProgressStatus === "completed";
  }
  if (activeFilter === "not-started") {
    return card.dataset.learnProgressStatus === "not-started";
  }
  return true;
}

function applyLearnTutorialFilters(scope = document) {
  const root = scope instanceof Document ? scope : document;
  const searchInput = root.querySelector("[data-learn-search]") || document.querySelector("[data-learn-search]");
  const filterGroup = root.querySelector("[data-learn-filter-group]") || document.querySelector("[data-learn-filter-group]");
  if (!(searchInput instanceof HTMLInputElement) || !(filterGroup instanceof HTMLElement)) {
    return;
  }

  const query = searchInput.value.trim().toLowerCase();
  const activeFilter = getActiveLearnTutorialFilter(root);
  let visibleCount = 0;

  document.querySelectorAll("[data-learn-tutorial-open]").forEach((card) => {
    if (!(card instanceof HTMLElement)) {
      return;
    }
    const searchableText = String(card.dataset.learnSearchText || "").toLowerCase();
    const matchesSearch = !query || searchableText.includes(query);
    const matchesFilter = doesLearnTutorialMatchFilter(card, activeFilter);
    const isVisible = matchesSearch && matchesFilter;
    card.hidden = !isVisible;
    if (isVisible) {
      visibleCount += 1;
    }
  });

  document.querySelectorAll("[data-learn-category]").forEach((categorySection) => {
    if (!(categorySection instanceof HTMLElement)) {
      return;
    }
    const hasVisibleTutorials = Array.from(categorySection.querySelectorAll("[data-learn-tutorial-open]"))
      .some((card) => card instanceof HTMLElement && !card.hidden);
    categorySection.hidden = !hasVisibleTutorials;
  });

  document.querySelectorAll("[data-learn-featured-section]").forEach((featuredSection) => {
    if (!(featuredSection instanceof HTMLElement)) {
      return;
    }
    const hasVisibleFeaturedTutorials = Array.from(featuredSection.querySelectorAll("[data-learn-featured-card='true']"))
      .some((card) => card instanceof HTMLElement && !card.hidden);
    featuredSection.hidden = !hasVisibleFeaturedTutorials;
  });

  document.querySelectorAll("[data-learn-empty-state]").forEach((emptyState) => {
    if (emptyState instanceof HTMLElement) {
      emptyState.hidden = visibleCount > 0;
    }
  });
}

function clearLearnTutorialFilters(scope = document) {
  const root = scope instanceof Document ? scope : document;
  const searchInput = root.querySelector("[data-learn-search]") || document.querySelector("[data-learn-search]");
  const filterGroup = root.querySelector("[data-learn-filter-group]") || document.querySelector("[data-learn-filter-group]");
  if (searchInput instanceof HTMLInputElement) {
    searchInput.value = "";
  }
  if (filterGroup instanceof HTMLElement) {
    filterGroup.dataset.activeFilter = "all";
    filterGroup.querySelectorAll("[data-learn-filter]").forEach((chip) => {
      const isActive = chip instanceof HTMLElement && chip.dataset.learnFilter === "all";
      chip.classList.toggle("is-active", isActive);
      chip.setAttribute("aria-pressed", isActive ? "true" : "false");
    });
  }
  trackTutorialAnalyticsEvent("tutorial_filter_used", {
    source: "Learn page",
    metadata: { filter: "clear" },
  });
  applyLearnTutorialFilters(root);
}

function bindLearnTutorialFilters(scope = document) {
  const searchInput = scope.querySelector("[data-learn-search]");
  if (searchInput instanceof HTMLInputElement && searchInput.dataset.learnSearchBound !== "true") {
    searchInput.dataset.learnSearchBound = "true";
    searchInput.addEventListener("input", () => {
      applyLearnTutorialFilters(document);
      const query = searchInput.value.trim();
      if (query && searchInput.dataset.lastTrackedTutorialSearch !== query) {
        searchInput.dataset.lastTrackedTutorialSearch = query;
        trackTutorialAnalyticsEvent("tutorial_search_used", {
          source: "Learn page",
          metadata: { query },
        });
      }
    });
  }

  scope.querySelectorAll("[data-learn-filter]").forEach((chip) => {
    if (!(chip instanceof HTMLButtonElement) || chip.dataset.learnFilterBound === "true") {
      return;
    }
    chip.dataset.learnFilterBound = "true";
    chip.addEventListener("click", () => {
      const filterGroup = chip.closest("[data-learn-filter-group]");
      if (filterGroup instanceof HTMLElement) {
        filterGroup.dataset.activeFilter = chip.dataset.learnFilter || "all";
        filterGroup.querySelectorAll("[data-learn-filter]").forEach((button) => {
          const isActive = button === chip;
          button.classList.toggle("is-active", isActive);
          button.setAttribute("aria-pressed", isActive ? "true" : "false");
        });
      }
      trackTutorialAnalyticsEvent("tutorial_filter_used", {
        source: "Learn page",
        metadata: { filter: chip.dataset.learnFilter || "all" },
      });
      applyLearnTutorialFilters(document);
    });
  });

  scope.querySelectorAll("[data-learn-clear-filters]").forEach((button) => {
    if (!(button instanceof HTMLButtonElement) || button.dataset.learnClearBound === "true") {
      return;
    }
    button.dataset.learnClearBound = "true";
    button.addEventListener("click", () => clearLearnTutorialFilters(document));
  });

  applyLearnTutorialFilters(document);
}

function openLearnTutorialModal(tutorialId = "", options = {}) {
  const tutorialEntry = getLearnTutorialById(tutorialId);
  if (!tutorialEntry) {
    return;
  }

  const { category, tutorial } = tutorialEntry;
  if (!canCurrentUserViewLearnItem(tutorial)) {
    window.location.hash = "#learn";
    return;
  }

  markTutorialViewed(tutorial.id);
  const overlay = ensureLearnTutorialModal();
  overlay.dataset.activeTutorialId = tutorial.id;
  overlay.dataset.activeTutorialCategory = category.title || category.id || "";
  overlay.dataset.activeTutorialSource = getTutorialAnalyticsSourceLabel(options.source);
  trackTutorialAnalyticsEvent("tutorial_modal_opened", {
    tutorialId: tutorial.id,
    category: category.title || category.id || "",
    categoryId: category.id || "",
    source: options.source,
  });
  const modal = overlay.querySelector(".learn-tutorial-modal");
  const content = overlay.querySelector("[data-learn-tutorial-modal-content]");
  if (content) {
    if (getTutorialVisibilityStatus(tutorial) !== "published") {
      content.innerHTML = renderLearnAvailabilityPreviewMarkup(tutorial, { eyebrow: category.title || "Tutorial" });
    } else {
      content.innerHTML = renderLearnTutorialModalContentMarkup(tutorial, category);
      content.querySelectorAll("[data-learn-related-tutorial]").forEach((button) => {
        button.addEventListener("click", () => {
          openLearnTutorialModal(button.dataset.learnRelatedTutorial || "", { source: "Tutorial modal related" });
        });
      });
      bindLearnTutorialProgressActions(content, tutorial.id);
      bindLearnTutorialFeedbackActions(content, tutorial.id);
      refreshTutorialProgressUi(tutorial.id);
      refreshLearnTutorialFeedbackUi(tutorial.id);
    }
    content.scrollTop = 0;
  }
  overlay.dataset.closing = "false";
  overlay.classList.remove("closing");
  modal?.classList.remove("closing");
  document.body.classList.add("modal-open");
  window.setTimeout(() => {
    overlay.querySelector("[data-learn-tutorial-close]")?.focus();
  }, 0);
}

function openLearnCollectionModal(collectionId = "") {
  const collection = getLearnTutorialCollectionById(collectionId);
  if (!collection) {
    return;
  }
  if (!canCurrentUserViewLearnItem(collection)) {
    window.location.hash = "#learn";
    return;
  }

  saveLearnCollectionProgress(collection.id, { lastOpenedAt: new Date().toISOString() });
  const overlay = ensureLearnTutorialModal();
  overlay.dataset.activeTutorialId = "";
  overlay.dataset.activeTutorialCategory = "Learning Path";
  overlay.dataset.activeTutorialSource = "Learning Path";
  const modal = overlay.querySelector(".learn-tutorial-modal");
  const content = overlay.querySelector("[data-learn-tutorial-modal-content]");
  if (content) {
    if (getTutorialVisibilityStatus(collection) !== "published") {
      content.innerHTML = renderLearnAvailabilityPreviewMarkup(collection, { eyebrow: "Learning Path" });
    } else {
      content.innerHTML = renderLearnCollectionModalContentMarkup(collection);
      content.querySelectorAll("[data-learn-collection-tutorial]").forEach((button) => {
        button.addEventListener("click", () => {
          saveLearnCollectionProgress(collection.id, { started: true, lastOpenedAt: new Date().toISOString() });
          openLearnTutorialModal(button.dataset.learnCollectionTutorial || "", { source: `Learning Path: ${collection.title}` });
        });
      });
      content.querySelector("[data-learn-collection-start]")?.addEventListener("click", (event) => {
        const button = event.currentTarget;
        if (!(button instanceof HTMLElement)) {
          return;
        }
        saveLearnCollectionProgress(collection.id, { started: true, lastOpenedAt: new Date().toISOString() });
        openLearnTutorialModal(button.dataset.learnCollectionFirstTutorial || "", { source: `Learning Path: ${collection.title}` });
      });
    }
    content.scrollTop = 0;
  }
  overlay.dataset.closing = "false";
  overlay.classList.remove("closing");
  modal?.classList.remove("closing");
  document.body.classList.add("modal-open");
  window.setTimeout(() => {
    overlay.querySelector("[data-learn-tutorial-close]")?.focus();
  }, 0);
}

