function bindProfilePageForm(form) {
  if (!form || !appState.user) {
    return;
  }

  const messageElement = form.querySelector("#profile-settings-message");
  const submitButton = form.querySelector("#profile-settings-submit");
  const notificationPreferences = appState.notificationPreferences || DEFAULT_NOTIFICATION_PREFERENCES;
  const profilePageSettings = getCurrentProfilePageSettings();
  const state = {
    saving: false,
    resaveRequested: false,
    savePromise: null,
  };
  const notificationFieldNames = [...PROFILE_NOTIFICATION_PREFERENCE_FIELD_NAMES];
  const privacyFieldNames = [
    "notifyCommunityActivity",
    "showProfileInCommunityGrow",
    "allowFollowers",
    "showGrowStatsPublicly",
  ];

  const getFormState = () => ({
    growRemindersEnabled: Boolean(form.elements.growRemindersEnabled?.checked),
    notifySoakingReminders: Boolean(form.elements.notifySoakingReminders?.checked),
    notifyGerminationReminders: Boolean(form.elements.notifyGerminationReminders?.checked),
    notifySnapshotReminders: Boolean(form.elements.notifySnapshotReminders?.checked),
    notifySupplyReminders: Boolean(form.elements.notifySupplyReminders?.checked),
    notifyCommunityActivity: Boolean(form.elements.notifyCommunityActivity?.checked),
    pushNotificationsEnabled: Boolean(form.elements.pushNotificationsEnabled?.checked),
    showProfileInCommunityGrow: Boolean(form.elements.showProfileInCommunityGrow?.checked),
    allowFollowers: Boolean(form.elements.allowFollowers?.checked),
    showGrowStatsPublicly: Boolean(form.elements.showGrowStatsPublicly?.checked),
  });

  const setMessage = (message, isError = false) => {
    if (!messageElement) {
      return;
    }
    const displayMessage = getUserFacingPushMessage(message);
    const isInitializing = isPushServiceInitializingMessage(message) || displayMessage === PUSH_SERVICE_INITIALIZING_MESSAGE;
    messageElement.textContent = displayMessage;
    messageElement.classList.toggle("is-error", Boolean(displayMessage && isError && !isInitializing));
    messageElement.classList.toggle("is-warning", Boolean(displayMessage && isInitializing));
  };

  const setSavingState = (isSaving) => {
    state.saving = isSaving;
    if (submitButton instanceof HTMLButtonElement) {
      submitButton.disabled = isSaving;
      submitButton.textContent = isSaving ? "Saving..." : "Save Changes";
    }
  };

  const updateUnsavedState = () => {
    refreshUnsavedChangesState();
    if (
      !state.saving
      && !appState.unsavedChanges.hasUnsavedChanges
      && messageElement?.textContent === "Changes are waiting to be saved."
    ) {
      setMessage("");
    }
  };

  const applyFormState = (nextValues = {}) => {
    applyNotificationPreferenceStateToForm(form, nextValues);
    const fieldNames = [
      "notifyCommunityActivity",
      "showProfileInCommunityGrow",
      "allowFollowers",
      "showGrowStatsPublicly",
    ];
    fieldNames.forEach((fieldName) => {
      const field = form.elements[fieldName];
      if (field instanceof HTMLInputElement && field.type === "checkbox" && nextValues[fieldName] !== undefined) {
        field.checked = Boolean(nextValues[fieldName]);
      }
    });
    syncGrowReminderToggleAvailability(form);
    syncNotificationPermissionStateUi(form);
    syncPushDeliveryStateUi(form);
    syncPushDiagnosticsStateUi(form);
    bindPushDeliveryActions();
    bindPushDiagnosticsActions();
  };

  const syncLocalProfileState = (nextValues = getFormState()) => {
    const normalizedUserId = String(appState.user?.id || "").trim();
    const notificationPreferenceState = getNormalizedNotificationPreferenceState(nextValues);
    appState.notificationPreferences = syncUserNotificationPreferencesCache(normalizedUserId, {
      ...(appState.notificationPreferences || loadStoredUserNotificationPreferences(normalizedUserId)),
      ...notificationPreferenceState,
    });
    appState.profilePageSettings = syncProfilePageSettingsCache(normalizedUserId, {
      ...getCurrentProfilePageSettings(),
      notifyCommunityActivity: nextValues.notifyCommunityActivity,
      showProfileInCommunityGrow: nextValues.showProfileInCommunityGrow,
      allowFollowers: nextValues.allowFollowers,
      showGrowStatsPublicly: nextValues.showGrowStatsPublicly,
    });
    appState.profilePageSettingsUserId = normalizedUserId;
  };

  const refreshPushPreferenceDependentUi = () => {
    syncPushDeliveryStateUi(form);
    syncPushDiagnosticsStateUi(form);
    bindPushDeliveryActions();
    bindPushDiagnosticsActions();
  };

  const bindPushDeliveryActions = () => {
    form.querySelector("[data-profile-push-test='true']")?.addEventListener("click", async () => {
      try {
        setMessage("Sending test notification...");
        await sendProfilePushTestNotification();
        syncPushDeliveryStateUi(form);
        bindPushDeliveryActions();
        setMessage("Test notification sent.");
      } catch (error) {
        setMessage(error.message || "Could not send a test notification right now.", true);
      }
    });

    form.querySelector("[data-profile-push-disable='true']")?.addEventListener("click", async () => {
      try {
        setMessage("Disabling push delivery on this device...");
        await disableCurrentDevicePushNotifications();
        syncPushDeliveryStateUi(form);
        bindPushDeliveryActions();
        setMessage("Push delivery was disabled on this device.");
      } catch (error) {
        setMessage(error.message || "Could not disable push delivery on this device.", true);
      }
    });
  };

  const enablePushPreferenceForDiagnostics = async () => {
    const nextPreferences = {
      ...(appState.notificationPreferences || getDefaultNotificationPreferences()),
      pushNotificationsEnabled: true,
      push_notifications_enabled: true,
    };
    appState.notificationPreferences = syncUserNotificationPreferencesCache(
      String(appState.user?.id || "").trim(),
      nextPreferences,
    );
    if (form.elements.pushNotificationsEnabled instanceof HTMLInputElement) {
      form.elements.pushNotificationsEnabled.checked = true;
    }
    updateUnsavedState();
    try {
      appState.notificationPreferences = await saveUserNotificationPreferences(nextPreferences, {
        requirePersistence: true,
        debugContext: "push-diagnostics-register",
        verifyAfterSave: true,
      });
    } catch (error) {
      console.warn("[Push Diagnostics] Push preference save fell back to local storage.", error);
    }
  };

  const bindPushDiagnosticsActions = () => {
    const testAllButton = form.querySelector("[data-profile-push-diagnostics-test-all='true']");
    if (testAllButton instanceof HTMLButtonElement && testAllButton.dataset.bound !== "true") {
      testAllButton.dataset.bound = "true";
      testAllButton.addEventListener("click", async () => {
        const devices = getActiveRegisteredPushDevices();
        const deviceKeys = devices.map((record) => record.deviceKey).filter(Boolean);
        try {
          if (!deviceKeys.length) {
            throw new Error("No active registered push devices are available for a test.");
          }
          setMessage("Sending test push to all registered devices...");
          appState.pushDiagnostics = {
            ...(appState.pushDiagnostics || {}),
            sendingDeviceKey: "__all__",
          };
          syncPushDiagnosticsStateUi(form);
          bindPushDiagnosticsActions();
          const result = await sendBackendPushTestToRegisteredDevices({ allDevices: true });
          const sentCount = Number(result?.sentCount || 0);
          const failedCount = Number(result?.failedCount || 0) + Number(result?.invalidatedCount || 0);
          const sentDeviceKeys = Array.isArray(result?.sentDeviceKeys) ? result.sentDeviceKeys : [];
          const failedDeviceKeys = [
            ...(Array.isArray(result?.failedDeviceKeys) ? result.failedDeviceKeys : []),
            ...(Array.isArray(result?.invalidatedDeviceKeys) ? result.invalidatedDeviceKeys : []),
          ];
          const message = sentCount > 0
            ? `Test push sent to ${sentCount} registered device${sentCount === 1 ? "" : "s"}.`
            : (result?.reason || "No registered devices accepted the test push.");
          if (sentDeviceKeys.length) {
            setPushDeviceTestResults(sentDeviceKeys, {
              ok: true,
              message: "Test push sent to all registered devices.",
            });
          }
          if (failedDeviceKeys.length) {
            setPushDeviceTestResults(failedDeviceKeys, {
              ok: false,
              message: "Test push failed for this device.",
            });
          }
          if (!sentDeviceKeys.length && !failedDeviceKeys.length) {
            setPushDeviceTestResults(deviceKeys, {
              ok: false,
              message,
            });
          }
          appState.pushDiagnostics = {
            ...(appState.pushDiagnostics || {}),
            sendingDeviceKey: "",
            lastTestResult: sentCount > 0 && failedCount === 0 ? "Test push sent" : "Test push failed",
            lastTestAt: new Date().toISOString(),
            lastErrorMessage: failedCount > 0 || sentCount <= 0 ? message : "",
          };
          await refreshPushDiagnosticsState({ scope: form, preserveLastStatus: true });
          bindPushDiagnosticsActions();
          setMessage(message, sentCount <= 0 || failedCount > 0);
        } catch (error) {
          setPushDeviceTestResults(deviceKeys, {
            ok: false,
            message: error.message || "Could not send test push to registered devices.",
          });
          appState.pushDiagnostics = {
            ...(appState.pushDiagnostics || {}),
            sendingDeviceKey: "",
            lastErrorMessage: error.message || "Could not send test push to registered devices.",
          };
          syncPushDiagnosticsStateUi(form);
          bindPushDiagnosticsActions();
          setMessage(error.message || "Could not send test push to registered devices.", true);
        }
      });
    }

    form.querySelectorAll("[data-profile-push-diagnostics-test-device]").forEach((button) => {
      if (!(button instanceof HTMLButtonElement) || button.dataset.bound === "true") {
        return;
      }
      button.dataset.bound = "true";
      button.addEventListener("click", async () => {
        const deviceKey = String(button.dataset.profilePushDiagnosticsTestDevice || "").trim();
        const device = getActiveRegisteredPushDevices().find((record) => record.deviceKey === deviceKey) || null;
        try {
          if (!deviceKey || !device) {
            throw new Error("That registered push device is no longer available.");
          }
          setMessage(`Sending test push to ${getPushDeviceDisplayLabel(device)}...`);
          appState.pushDiagnostics = {
            ...(appState.pushDiagnostics || {}),
            sendingDeviceKey: deviceKey,
          };
          syncPushDiagnosticsStateUi(form);
          bindPushDiagnosticsActions();
          const result = await sendBackendPushTestToRegisteredDevices({ targetDeviceKeys: [deviceKey] });
          const sentCount = Number(result?.sentCount || 0);
          const failedCount = Number(result?.failedCount || 0) + Number(result?.invalidatedCount || 0);
          const message = sentCount > 0
            ? "Test push sent to this device."
            : (result?.reason || "This device did not accept the test push.");
          setPushDeviceTestResults([deviceKey], {
            ok: sentCount > 0 && failedCount === 0,
            message,
          });
          appState.pushDiagnostics = {
            ...(appState.pushDiagnostics || {}),
            sendingDeviceKey: "",
          };
          await refreshPushDiagnosticsState({ scope: form, preserveLastStatus: true });
          bindPushDiagnosticsActions();
          setMessage(message, sentCount <= 0 || failedCount > 0);
        } catch (error) {
          setPushDeviceTestResults([deviceKey], {
            ok: false,
            message: error.message || "Could not send a test push to this device.",
          });
          appState.pushDiagnostics = {
            ...(appState.pushDiagnostics || {}),
            sendingDeviceKey: "",
            lastErrorMessage: error.message || "Could not send a test push to this device.",
          };
          syncPushDiagnosticsStateUi(form);
          bindPushDiagnosticsActions();
          setMessage(error.message || "Could not send a test push to this device.", true);
        }
      });
    });

    form.querySelectorAll("[data-profile-push-device-remove]").forEach((button) => {
      if (!(button instanceof HTMLButtonElement) || button.dataset.bound === "true") {
        return;
      }
      button.dataset.bound = "true";
      button.addEventListener("click", async () => {
        const deviceKey = String(button.dataset.profilePushDeviceRemove || "").trim();
        const endpoint = String(button.dataset.profilePushDeviceEndpoint || "").trim();
        const device = getActiveRegisteredPushDevices().find((record) => (
          (deviceKey && record.deviceKey === deviceKey)
          || (endpoint && record.endpoint === endpoint)
        )) || null;
        try {
          if (!device) {
            throw new Error("That registered push device is no longer available.");
          }
          if (!window.confirm(`Remove ${getPushDeviceDisplayLabel(device)} from registered push devices?`)) {
            return;
          }
          setMessage(`Removing ${getPushDeviceDisplayLabel(device)}...`);
          appState.pushDiagnostics = {
            ...(appState.pushDiagnostics || {}),
            sendingDeviceKey: `__cleanup__${deviceKey || endpoint}`,
          };
          syncPushDiagnosticsStateUi(form);
          bindPushDiagnosticsActions();
          const result = await cleanupPushSubscriptions({
            mode: "remove-device",
            deviceKey,
            endpoint,
          });
          appState.pushDiagnostics = {
            ...(appState.pushDiagnostics || {}),
            sendingDeviceKey: "",
          };
          await refreshPushDiagnosticsState({ scope: form, preserveLastStatus: true });
          bindPushDiagnosticsActions();
          setMessage(result?.removedCount ? "Push device removed." : "No matching push device was removed.");
        } catch (error) {
          appState.pushDiagnostics = {
            ...(appState.pushDiagnostics || {}),
            sendingDeviceKey: "",
            lastErrorMessage: error.message || "Could not remove that push device.",
          };
          syncPushDiagnosticsStateUi(form);
          bindPushDiagnosticsActions();
          setMessage(error.message || "Could not remove that push device.", true);
        }
      });
    });

    form.querySelector("[data-profile-push-cleanup-failed='true']")?.addEventListener("click", async () => {
      const devices = getActiveRegisteredPushDevices();
      try {
        if (!devices.length) {
          throw new Error("No registered push devices are available to clean up.");
        }
        if (!window.confirm("Remove failed or stale push devices?")) {
          return;
        }
        setMessage("Removing failed push devices...");
        appState.pushDiagnostics = {
          ...(appState.pushDiagnostics || {}),
          sendingDeviceKey: "__cleanup__failed",
        };
        syncPushDiagnosticsStateUi(form);
        bindPushDiagnosticsActions();
        const result = await cleanupPushSubscriptions({ mode: "remove-failed" });
        appState.pushDiagnostics = {
          ...(appState.pushDiagnostics || {}),
          sendingDeviceKey: "",
        };
        await refreshPushDiagnosticsState({ scope: form, preserveLastStatus: true });
        bindPushDiagnosticsActions();
        const removedCount = Number(result?.removedCount || 0);
        setMessage(removedCount ? `Removed ${removedCount} failed push device${removedCount === 1 ? "" : "s"}.` : "No failed push devices were removed.");
      } catch (error) {
        appState.pushDiagnostics = {
          ...(appState.pushDiagnostics || {}),
          sendingDeviceKey: "",
          lastErrorMessage: error.message || "Could not remove failed push devices.",
        };
        syncPushDiagnosticsStateUi(form);
        bindPushDiagnosticsActions();
        setMessage(error.message || "Could not remove failed push devices.", true);
      }
    });

    form.querySelector("[data-profile-push-keep-current='true']")?.addEventListener("click", async () => {
      try {
        const currentRecord = await ensureCurrentUserPushSubscriptionState({ persistRecord: false });
        const currentEndpoint = getCurrentPushEndpointCandidate();
        if (!currentEndpoint && !currentRecord?.deviceKey) {
          throw new Error("Register this browser first so the current device can be identified safely.");
        }
        const otherDevices = getActiveRegisteredPushDevices().filter((record) => !isCurrentPushSubscriptionRecord(record));
        if (!otherDevices.length) {
          throw new Error("Only the current device is registered right now.");
        }
        if (!window.confirm(`Keep only this browser/device and remove ${otherDevices.length} other push device${otherDevices.length === 1 ? "" : "s"}?`)) {
          return;
        }
        setMessage("Keeping only the current push device...");
        appState.pushDiagnostics = {
          ...(appState.pushDiagnostics || {}),
          sendingDeviceKey: "__cleanup__current",
        };
        syncPushDiagnosticsStateUi(form);
        bindPushDiagnosticsActions();
        const result = await cleanupPushSubscriptions({
          mode: "keep-current",
          currentEndpoint,
          currentDeviceKey: currentRecord?.deviceKey || getCurrentPushDeviceKey(),
        });
        appState.pushDiagnostics = {
          ...(appState.pushDiagnostics || {}),
          sendingDeviceKey: "",
        };
        await refreshPushDiagnosticsState({ scope: form, preserveLastStatus: true });
        bindPushDiagnosticsActions();
        const removedCount = Number(result?.removedCount || 0);
        setMessage(removedCount ? `Kept this device and removed ${removedCount} other push device${removedCount === 1 ? "" : "s"}.` : "No other push devices were removed.");
      } catch (error) {
        appState.pushDiagnostics = {
          ...(appState.pushDiagnostics || {}),
          sendingDeviceKey: "",
          lastErrorMessage: error.message || "Could not keep only the current device.",
        };
        syncPushDiagnosticsStateUi(form);
        bindPushDiagnosticsActions();
        setMessage(error.message || "Could not keep only the current device.", true);
      }
    });

    form.querySelector("[data-profile-push-diagnostics-refresh='true']")?.addEventListener("click", async () => {
      try {
        setMessage("Refreshing push diagnostics...");
        await refreshPushDiagnosticsState({ scope: form, preserveLastStatus: true });
        bindPushDiagnosticsActions();
        setMessage("Push diagnostics refreshed.");
      } catch (error) {
        setMessage(error.message || "Could not refresh push diagnostics right now.", true);
      }
    });

    form.querySelector("[data-profile-push-diagnostics-register='true']")?.addEventListener("click", async () => {
      try {
        setMessage("Registering this device for push delivery...");
        let permissionState = getGrowRemindersBrowserPermissionState();
        if (permissionState === "unsupported") {
          throw new Error("This browser/device does not support push notification registration.");
        }
        if (permissionState !== "granted") {
          permissionState = await requestGrowRemindersBrowserPermission();
          if (permissionState !== "granted") {
            throw new Error("Browser notification permission must be granted before this device can be registered.");
          }
        }
        await enablePushPreferenceForDiagnostics();
        await subscribeCurrentDeviceToPushNotifications();
        await refreshPushDiagnosticsState({ scope: form, preserveLastStatus: true });
        bindPushDiagnosticsActions();
        setMessage("This device is registered for push delivery.");
      } catch (error) {
        appState.pushDiagnostics = {
          ...(appState.pushDiagnostics || {}),
          lastErrorMessage: error.message || "Could not register this device for push delivery.",
        };
        syncPushDiagnosticsStateUi(form);
        bindPushDiagnosticsActions();
        setMessage(error.message || "Could not register this device for push delivery.", true);
      }
    });

    form.querySelector("[data-profile-push-diagnostics-test='true']")?.addEventListener("click", async () => {
      try {
        setMessage("Sending test push...");
        await sendProfilePushTestNotification();
        appState.pushDiagnostics = {
          ...(appState.pushDiagnostics || {}),
          lastTestResult: "Test push sent",
          lastTestAt: new Date().toISOString(),
          lastErrorMessage: "",
        };
        await refreshPushDiagnosticsState({ scope: form, preserveLastStatus: true });
        bindPushDiagnosticsActions();
        setMessage("Test push sent.");
      } catch (error) {
        appState.pushDiagnostics = {
          ...(appState.pushDiagnostics || {}),
          lastTestResult: "Test push failed",
          lastTestAt: new Date().toISOString(),
          lastErrorMessage: error.message || "Could not send a test push right now.",
        };
        syncPushDiagnosticsStateUi(form);
        bindPushDiagnosticsActions();
        setMessage(error.message || "Could not send a test push right now.", true);
      }
    });

    form.querySelector("[data-profile-push-diagnostics-unregister='true']")?.addEventListener("click", async () => {
      try {
        setMessage("Unregistering this device...");
        await disableCurrentDevicePushNotifications();
        await refreshPushDiagnosticsState({ scope: form, preserveLastStatus: true });
        bindPushDiagnosticsActions();
        setMessage("This device is no longer registered for push delivery.");
      } catch (error) {
        appState.pushDiagnostics = {
          ...(appState.pushDiagnostics || {}),
          lastErrorMessage: error.message || "Could not unregister this device right now.",
        };
        syncPushDiagnosticsStateUi(form);
        bindPushDiagnosticsActions();
        setMessage(error.message || "Could not unregister this device right now.", true);
      }
    });
  };

  const patchSavedFieldsIntoBaseline = (fieldNames, savedValues) => {
    if (!Array.isArray(fieldNames) || !fieldNames.length) {
      return;
    }

    patchUnsavedChangesBaseline((baseline) => {
      const nextBaseline = { ...baseline };
      fieldNames.forEach((fieldName) => {
        if (Object.prototype.hasOwnProperty.call(savedValues, fieldName)) {
          nextBaseline[fieldName] = Boolean(savedValues[fieldName]);
        }
      });
      return nextBaseline;
    });
  };

  const waitForProfileSaveIdle = async () => {
    let lastResult = !appState.unsavedChanges.hasUnsavedChanges;

    while (state.savePromise || state.saving || state.resaveRequested) {
      if (state.savePromise) {
        lastResult = await state.savePromise;
        continue;
      }
      await Promise.resolve();
    }

    return Boolean(lastResult) && !appState.unsavedChanges.hasUnsavedChanges;
  };

  const persistProfileSettings = async ({ source = "manual" } = {}) => {
    if (state.saving) {
      state.resaveRequested = true;
      return source === "manual"
        ? waitForProfileSaveIdle()
        : (state.savePromise || Promise.resolve(false));
    }

    const pendingValues = getFormState();
    let permissionState = getGrowRemindersBrowserPermissionState();
    let pushNotificationsEnabled = Boolean(pendingValues.pushNotificationsEnabled);
    if (pushNotificationsEnabled && permissionState === "unsupported") {
      pushNotificationsEnabled = false;
      if (!pushNotificationsEnabled && form.elements.pushNotificationsEnabled instanceof HTMLInputElement) {
        form.elements.pushNotificationsEnabled.checked = false;
      }
    } else if (pushNotificationsEnabled && permissionState !== "granted") {
      const requestedPermission = await requestGrowRemindersBrowserPermission();
      permissionState = requestedPermission;
      pushNotificationsEnabled = requestedPermission === "granted";
      if (!pushNotificationsEnabled && form.elements.pushNotificationsEnabled instanceof HTMLInputElement) {
        form.elements.pushNotificationsEnabled.checked = false;
      }
    }
    const normalizedPendingValues = {
      ...pendingValues,
      pushNotificationsEnabled,
    };
    const notificationPreferencesPayload = {
      ...getNormalizedNotificationPreferenceState(normalizedPendingValues),
      notifyCommunityActivity: normalizedPendingValues.notifyCommunityActivity,
    };
    const profilePageSettingsPayload = {
      notifyCommunityActivity: normalizedPendingValues.notifyCommunityActivity,
      showProfileInCommunityGrow: normalizedPendingValues.showProfileInCommunityGrow,
      allowFollowers: normalizedPendingValues.allowFollowers,
      showGrowStatsPublicly: normalizedPendingValues.showGrowStatsPublicly,
    };

    syncLocalProfileState(normalizedPendingValues);
    updateUnsavedState();
    setSavingState(true);
    setMessage("Saving...");

    state.saving = true;
    state.savePromise = (async () => {
      let cloudSyncUnavailable = false;
      try {
        appState.notificationPreferences = await saveUserNotificationPreferences(
          notificationPreferencesPayload,
          {
            requirePersistence: true,
            debugContext: "profile-settings",
            verifyAfterSave: true,
          },
        );
      } catch (error) {
        console.warn("[Profile Settings] Notification preferences save failed.", error);
        cloudSyncUnavailable = true;
      }

      try {
        if (notificationPreferencesPayload.pushNotificationsEnabled) {
          await subscribeCurrentDeviceToPushNotifications();
        }
      } catch (error) {
        console.warn("[Profile Settings] Push subscription sync failed.", error);
        cloudSyncUnavailable = true;
      }

      try {
        appState.profilePageSettings = await savePublicMemberProfileSettings(
          profilePageSettingsPayload,
          {
            requirePersistence: true,
            debugContext: "profile-settings",
            verifyAfterSave: true,
          },
        );
        appState.profilePageSettingsUserId = String(appState.user?.id || "").trim();
      } catch (error) {
        console.warn("[Profile Settings] Privacy settings save failed.", error);
        cloudSyncUnavailable = true;
      }

      patchSavedFieldsIntoBaseline(notificationFieldNames, appState.notificationPreferences || pendingValues);
      patchSavedFieldsIntoBaseline(privacyFieldNames, appState.profilePageSettings || pendingValues);

      applyFormState({
        growRemindersEnabled: appState.notificationPreferences?.growRemindersEnabled,
        notifySoakingReminders: appState.notificationPreferences?.notifySoakingReminders,
        notifyGerminationReminders: appState.notificationPreferences?.notifyGerminationReminders,
        notifySnapshotReminders: appState.notificationPreferences?.notifySnapshotReminders,
        notifySupplyReminders: appState.notificationPreferences?.notifySupplyReminders,
        notifyCommunityActivity: appState.profilePageSettings?.notifyCommunityActivity,
        pushNotificationsEnabled: appState.notificationPreferences?.pushNotificationsEnabled,
        showProfileInCommunityGrow: appState.profilePageSettings?.showProfileInCommunityGrow,
        allowFollowers: appState.profilePageSettings?.allowFollowers,
        showGrowStatsPublicly: appState.profilePageSettings?.showGrowStatsPublicly,
      });
      syncLocalProfileState();
      updateUnsavedState();

      if (permissionState === "unsupported") {
        setMessage("Preferences saved. This browser/device does not support push notifications, so in-app reminders will stay available without browser delivery.");
        return true;
      }
      if (permissionState === "denied") {
        setMessage("Preferences saved. Browser/device push notifications remain blocked until you re-enable notifications in your browser settings.");
        return true;
      }
      if (cloudSyncUnavailable) {
        setMessage("Preferences saved locally. Cloud sync unavailable.");
        return true;
      }

      setMessage(source === "auto" ? "Saved" : "Profile settings saved.");
      return true;
    })().finally(() => {
      setSavingState(false);
      state.saving = false;
      state.savePromise = null;

      if (state.resaveRequested) {
        state.resaveRequested = false;
        void persistProfileSettings({ source: "auto" });
      }
    });

    return source === "manual" ? waitForProfileSaveIdle() : state.savePromise;
  };

  registerUnsavedChangesContext({
    pageHash: "#profile",
    contextType: "profile",
    getSignature: () => JSON.stringify(getFormState()),
    saveFn: () => persistProfileSettings({ source: "manual" }),
  });

  form.addEventListener("input", () => {
    syncLocalProfileState();
    syncGrowReminderToggleAvailability(form);
    refreshPushPreferenceDependentUi();
    updateUnsavedState();
    if (!state.saving && appState.unsavedChanges.hasUnsavedChanges && !messageElement?.classList.contains("is-error")) {
      setMessage("Changes are waiting to be saved.");
    }
  });

  form.addEventListener("change", (event) => {
    if (!(event.target instanceof HTMLInputElement) || event.target.type !== "checkbox") {
      return;
    }
    syncLocalProfileState();
    syncGrowReminderToggleAvailability(form);
    refreshPushPreferenceDependentUi();
    updateUnsavedState();
    void persistProfileSettings({ source: "auto" });
  });

  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    await persistProfileSettings({ source: "manual" });
  });

  applyFormState({
    ...notificationPreferences,
    notifyCommunityActivity: profilePageSettings.notifyCommunityActivity,
    showProfileInCommunityGrow: profilePageSettings.showProfileInCommunityGrow,
    allowFollowers: profilePageSettings.allowFollowers,
    showGrowStatsPublicly: profilePageSettings.showGrowStatsPublicly,
  });

  if (canViewPushDiagnosticsPanel()) {
    void refreshPushDiagnosticsState({ scope: form, preserveLastStatus: true }).then(() => {
      bindPushDiagnosticsActions();
    });
  }
}

function renderProfilePage() {
  if (!appState.user) {
    renderProfileSignInPrompt();
    return;
  }

  const displayName = String(appState.profile?.username || "").trim();
  const email = String(appState.user?.email || appState.profile?.email || "").trim() || "No email on file";
  const notificationPreferences = appState.notificationPreferences || DEFAULT_NOTIFICATION_PREFERENCES;
  const profilePageSettings = getCurrentProfilePageSettings();
  const currentPublicProfile = getPublicMemberProfile(String(appState.user?.id || "").trim()) || buildCurrentUserPublicMemberProfileFallback(appState.user, appState.profile, profilePageSettings);
  const profileSetupComplete = hasCompletedProfile();
  const memberSinceValue = appState.profile?.createdAt || appState.user?.created_at || "";
  const memberSinceLabel = memberSinceValue ? formatPublicMemberJoinedDateLabel(memberSinceValue) : "Not available yet";
  const accountInfoRows = [
    { label: "Email", value: email },
    { label: "Display Name", value: displayName || "Choose a display name in Edit Profile" },
    { label: "Public Handle", value: currentPublicProfile?.publicHandle ? `@${currentPublicProfile.publicHandle}` : "Not set" },
    { label: "Region", value: currentPublicProfile?.locationRegion || "Not set" },
    { label: "Member Since", value: memberSinceLabel },
    { label: "Profile Visibility", value: profilePageSettings.showProfileInCommunityGrow !== false ? "Public in Community Grow" : "Private" },
  ];
  const ownerPublicStats = calculatePublicProfileStats({
    memberId: String(appState.user?.id || "").trim(),
    snapshots: getApprovedPublicSnapshotsForMember(String(appState.user?.id || "").trim()),
    includeOwnerPrivate: true,
  });
  const usesNotificationFallback = Boolean(appState.notificationPreferencesTableUnavailable);

  app.innerHTML = `
    <section class="card profile-page" aria-label="Profile and settings">
      <div class="profile-page-glow" aria-hidden="true"></div>
      <header class="profile-page-header">
        <div class="profile-page-hero">
          ${renderProfileAvatarMarkup({
            avatarUrl: appState.profile?.avatarUrl || "",
            displayName: getProfileDisplayName(),
            className: "profile-page-avatar",
            fallbackClassName: "profile-page-avatar is-fallback",
          })}
          <div class="profile-page-copy">
            <p class="eyebrow">Control Center</p>
            <h2>${escapeHtml(getProfileDisplayName())}</h2>
            <p class="profile-page-email">${escapeHtml(email)}</p>
          </div>
        </div>
        <div class="profile-page-header-actions">
          <span class="profile-status-badge is-member">Member</span>
          <a class="button button-secondary profile-page-edit-button" href="${escapeHtml(getPublicMemberProfileRoute(currentPublicProfile || appState.user?.id || ""))}">View Public Profile</a>
          <button type="button" class="button button-secondary profile-page-edit-button" data-profile-open-editor="true">Edit Profile</button>
        </div>
      </header>
      <form id="profile-settings-form" class="profile-settings-form">
        <div class="profile-page-layout">
          <article class="profile-section-card" id="profile-account-info-card">
            <div class="profile-section-heading">
              <div>
                <p class="eyebrow">Account Info</p>
                <h3>Account Info</h3>
                <p class="profile-section-subtitle">Your ${BRAND_APP_NAME} identity details.</p>
              </div>
              <span class="profile-status-badge ${profileSetupComplete ? "is-complete" : "is-pending"}">${escapeHtml(profileSetupComplete ? "Profile ready" : "Setup incomplete")}</span>
            </div>
            <div class="profile-account-grid">
              ${accountInfoRows.map((row) => `
                <div class="profile-detail-card">
                  <span class="profile-detail-label">${escapeHtml(row.label)}</span>
                  <strong class="profile-detail-value">${escapeHtml(row.value)}</strong>
                </div>
              `).join("")}
            </div>
            <p class="profile-section-note">${profileSetupComplete
              ? "Update your display name and avatar any time with Edit Profile."
              : "Complete your display name and avatar so your public and community profile can stay consistent."}</p>
            ${currentPublicProfile?.bio ? `<p class="profile-section-note"><strong>Bio:</strong> ${escapeHtml(currentPublicProfile.bio)}</p>` : ""}
          </article>
          <article class="profile-section-card">
            <div class="profile-section-heading">
              <div>
                <p class="eyebrow">Public Backbone</p>
                <h3>Profile Stats</h3>
                <p class="profile-section-subtitle">Public-safe stats are ready for Community Grow, trust, and future reputation features.</p>
              </div>
            </div>
            <div class="profile-account-grid">
              ${[
                { label: "Public Snapshots", value: ownerPublicStats.totalPublicSnapshots.toLocaleString() },
                { label: "Completed Sessions", value: ownerPublicStats.completedSessions.toLocaleString() },
                { label: "Avg Germination", value: getProfileAnalyticsRateLabel(ownerPublicStats.averageGerminationRate) },
                { label: "Best Result", value: getProfileAnalyticsRateLabel(ownerPublicStats.bestGerminationRate) },
                { label: "Seeds Tested", value: getProfileAnalyticsCountLabel(ownerPublicStats.totalSeedsTested) },
                { label: "Completion Rate", value: getProfileAnalyticsRateLabel(ownerPublicStats.completionRate) },
                { label: "Favorite Source", value: ownerPublicStats.favoriteSource || "Not enough data" },
                { label: "Favorite Variety", value: ownerPublicStats.favoriteVariety || "Not enough data" },
              ].map((row) => `
                <div class="profile-detail-card">
                  <span class="profile-detail-label">${escapeHtml(row.label)}</span>
                  <strong class="profile-detail-value">${escapeHtml(row.value)}</strong>
                </div>
              `).join("")}
            </div>
          </article>
          <article class="profile-section-card" id="profile-notification-preferences-card" tabindex="-1">
            <div class="profile-section-heading">
              <div>
                <p class="eyebrow">Notifications</p>
                <h3>Notification Preferences</h3>
                <p class="profile-section-subtitle">Control grow-stage reminders, community activity, and browser/device notification readiness.</p>
              </div>
            </div>
            <div data-notification-permission-state="true"></div>
            <div data-push-delivery-state="true">${renderPushDeliveryStateMarkup()}</div>
            ${canViewPushDiagnosticsPanel() ? `<div data-push-diagnostics-state="true">${renderPushDiagnosticsPanelMarkup()}</div>` : ""}
            <div class="profile-toggle-list">
              ${renderProfileSettingsToggleMarkup({
                name: "growRemindersEnabled",
                title: "Grow reminders",
                description: "Master control for in-app reminders that help keep stage timing, updates, and analytics accurate.",
                checked: notificationPreferences.growRemindersEnabled !== false,
              })}
              ${renderProfileSettingsToggleMarkup({
                name: "notifySoakingReminders",
                title: "Soaking reminders",
                description: "Remind me when it is time to check soaking progress and move sessions into Germination.",
                checked: notificationPreferences.notifySoakingReminders !== false,
              })}
              ${renderProfileSettingsToggleMarkup({
                name: "notifyGerminationReminders",
                title: "Germination reminders",
                description: "Remind me to update germination results and mark sessions complete when timing matters.",
                checked: notificationPreferences.notifyGerminationReminders !== false,
              })}
              ${renderProfileSettingsToggleMarkup({
                name: "notifySnapshotReminders",
                title: "Snapshot reminders",
                description: "Prompt me to capture grow snapshots so Community Grow and snapshot workflows stay active.",
                checked: notificationPreferences.notifySnapshotReminders !== false,
              })}
              ${renderProfileSettingsToggleMarkup({
                name: "notifySupplyReminders",
                title: "Supply reminders",
                description: "Alert me when global filter paper supply is running low or critical.",
                checked: notificationPreferences.notifySupplyReminders !== false,
              })}
              ${renderProfileSettingsToggleMarkup({
                name: "notifyCommunityActivity",
                title: "Community activity",
                description: "Receive Community Grow activity, unlock, and discovery notifications in the app.",
                checked: notificationPreferences.notifyCommunityActivity !== false,
              })}
              ${renderProfileSettingsToggleMarkup({
                name: "pushNotificationsEnabled",
                title: "Enable Push Notifications",
                description: "Master control for browser/device delivery to registered push devices.",
                checked: notificationPreferences.pushNotificationsEnabled === true,
              })}
            </div>
            <p class="profile-section-note">${usesNotificationFallback
              ? "Notification preferences are currently using your latest saved browser fallback while the backend is unavailable."
              : `Notification settings are connected to your saved ${BRAND_APP_NAME} preferences and will reload whenever you sign back in.`}</p>
          </article>
          <article class="profile-section-card" id="profile-privacy-community-card">
            <div class="profile-section-heading">
              <div>
                <p class="eyebrow">Privacy</p>
                <h3>Privacy & Community</h3>
                <p class="profile-section-subtitle">Choose how visible your profile is in Community Grow and Grow Network.</p>
              </div>
            </div>
            <div class="profile-toggle-list">
              ${renderProfileSettingsToggleMarkup({
                name: "showProfileInCommunityGrow",
                title: "Show profile in Community Grow",
                description: "Display your identity when you share public grow activity.",
                checked: profilePageSettings.showProfileInCommunityGrow !== false,
              })}
              ${renderProfileSettingsToggleMarkup({
                name: "allowFollowers",
                title: "Allow followers",
                description: "Let other growers follow your public profile.",
                checked: profilePageSettings.allowFollowers !== false,
              })}
              ${renderProfileSettingsToggleMarkup({
                name: "showGrowStatsPublicly",
                title: "Show grow stats publicly",
                description: "Include high-level grow performance in public-facing profile surfaces.",
                checked: profilePageSettings.showGrowStatsPublicly !== false,
              })}
            </div>
            <p class="profile-section-note">These community preferences save to your Grow Network profile when available, with a safe local fallback if needed.</p>
          </article>
          <article class="profile-section-card">
            <div class="profile-section-heading">
              <div>
                <p class="eyebrow">Future Settings</p>
                <h3>Future Settings</h3>
                <p class="profile-section-subtitle">Reserved slots for profile tools already planned into the settings structure.</p>
              </div>
            </div>
            <div class="profile-future-list" aria-label="Future settings placeholders">
              <div class="profile-future-item is-disabled">
                <strong>Avatar Upload</strong>
                <span>Coming soon</span>
              </div>
              <div class="profile-future-item is-disabled">
                <strong>Bio</strong>
                <span>Coming soon</span>
              </div>
              <div class="profile-future-item is-disabled">
                <strong>Linked Socials</strong>
                <span>Coming soon</span>
              </div>
            </div>
          </article>
        </div>
        <div class="profile-page-actions">
          <p id="profile-settings-message" class="profile-page-message" role="status" aria-live="polite"></p>
          <div class="inline-actions">
            <button id="profile-settings-submit" type="submit" class="button button-primary">Save Changes</button>
          </div>
        </div>
      </form>
    </section>
  `;

  app.querySelector("[data-profile-open-editor='true']")?.addEventListener("click", () => {
    openProfileEditor();
  });

  bindProfilePageForm(app.querySelector("#profile-settings-form"));

  if (appState.profilePagePendingFocusSection === "notification-preferences") {
    appState.profilePagePendingFocusSection = "";
    const notificationCard = app.querySelector("#profile-notification-preferences-card");
    if (notificationCard instanceof HTMLElement) {
      queueMicrotask(() => {
        notificationCard.scrollIntoView({ behavior: "smooth", block: "start" });
        notificationCard.focus({ preventScroll: true });
      });
    }
  }
}

function renderProfileSetupScreen() {
  app.replaceChildren(cloneTemplate(templates.profile));
  const title = document.querySelector("#profile-title");
  const copy = document.querySelector("#profile-copy");
  const eyebrow = document.querySelector("#profile-eyebrow");
  const submit = document.querySelector("#profile-submit");

  if (title) {
    title.textContent = "Set up your profile";
  }
  if (copy) {
    copy.textContent = `Choose the username you want ${BRAND_APP_NAME} to show in the app. You can also add an optional profile picture and set notification preferences.`;
  }
  if (eyebrow) {
    eyebrow.textContent = "Profile Setup";
  }
  if (submit) {
    submit.textContent = "Save Profile";
  }

  const message = document.querySelector("#profile-message");
  if (message && appState.profileError) {
    message.textContent = appState.profileError;
  }

  bindProfileForm(document.querySelector("#profile-form"), {
    mode: "setup",
    initialProfile: appState.profile,
    initialNotificationPreferences: appState.notificationPreferences,
    onSaved: () => {
      window.location.hash = "#home";
      safeRender();
    },
  });
}

function openProfileEditor() {
  if (!appState.user) {
    return;
  }

  let modal = document.querySelector("#profile-modal");
  if (!modal) {
    modal = document.createElement("dialog");
    modal.id = "profile-modal";
    modal.className = "snapshot-modal profile-modal";
    modal.innerHTML = `
      <form method="dialog" class="snapshot-modal-card profile-modal-card">
        <div class="snapshot-modal-copy">
          <p class="eyebrow">Account</p>
          <h3>Edit Profile</h3>
          <p class="muted">Update the public-safe name, handle, bio, region, and avatar shown in ${BRAND_APP_NAME}.</p>
        </div>
        <div id="profile-modal-body"></div>
        <div class="snapshot-modal-actions">
          <button type="button" class="button button-secondary" data-profile-close>Close</button>
        </div>
      </form>
    `;
    document.body.appendChild(modal);
  }

  const body = modal.querySelector("#profile-modal-body");
  if (!body) {
    return;
  }

  body.replaceChildren(cloneTemplate(templates.profile));
  body.querySelector(".profile-card")?.classList.add("profile-card-inline");
  const title = body.querySelector("#profile-title");
  const copy = body.querySelector("#profile-copy");
  const eyebrow = body.querySelector("#profile-eyebrow");
  const submit = body.querySelector("#profile-submit");
  if (title) {
    title.textContent = "Edit your profile";
  }
  if (copy) {
    copy.textContent = `Update the public-safe name, handle, bio, region, avatar, and notification preferences used in ${BRAND_APP_NAME}.`;
  }
  if (eyebrow) {
    eyebrow.textContent = "Profile";
  }
  if (submit) {
    submit.textContent = "Update Profile";
  }

  bindProfileForm(body.querySelector("#profile-form"), {
    mode: "edit",
    initialProfile: appState.profile,
    initialNotificationPreferences: appState.notificationPreferences,
    onSaved: () => {
      updateAuthStatus();
      safeRender();
      if (modal.open) {
        modal.close();
      }
    },
  });

  modal.querySelector("[data-profile-close]")?.addEventListener("click", () => {
    if (modal.open) {
      modal.close();
    }
  }, { once: true });

  modal.showModal();
}

function bindProfileForm(form, options = {}) {
  if (!form) {
    return;
  }

  const profile = options.initialProfile || appState.profile || null;
  const notificationPreferences = options.initialNotificationPreferences || appState.notificationPreferences || DEFAULT_NOTIFICATION_PREFERENCES;
  const existingPublicProfile = appState.publicMemberProfiles[String(appState.user?.id || "").trim()] || null;
  const usernameInput = form.elements.username;
  const publicHandleInput = form.elements.publicHandle;
  const locationRegionInput = form.elements.locationRegion;
  const bioInput = form.elements.bio;
  const avatarInput = form.elements.avatar;
  const message = form.querySelector("#profile-message");
  const preview = form.querySelector("#profile-avatar-preview");
  const removeButton = form.querySelector("#profile-remove-avatar");
  const deleteButton = form.querySelector("#profile-delete-account");
  const submitButton = form.querySelector("#profile-submit");
  const notificationDefaultsNote = form.querySelector("#profile-preferences-default-note");
  const defaultSubmitLabel = submitButton?.textContent || "Save Profile";
  const state = {
    profile,
    removeAvatar: false,
    pendingFile: null,
    previewUrl: "",
  };

  const setProfileFormMessage = (text = "", tone = "") => {
    if (!message) {
      return;
    }
    message.textContent = text;
    message.classList.remove("is-error", "is-success", "is-warning");
    if (tone) {
      message.classList.add(`is-${tone}`);
    }
  };

  const syncNotificationPreferenceAvailability = () => {
    if (notificationDefaultsNote) {
      notificationDefaultsNote.hidden = !appState.notificationPreferencesTableUnavailable;
    }
    syncNotificationPermissionStateUi(form);
    syncGrowReminderToggleAvailability(form);
  };

  usernameInput.value = profile?.username || "";
  if (publicHandleInput instanceof HTMLInputElement) {
    publicHandleInput.value = existingPublicProfile?.publicHandle || "";
  }
  if (locationRegionInput instanceof HTMLInputElement) {
    locationRegionInput.value = existingPublicProfile?.locationRegion || "";
  }
  if (bioInput instanceof HTMLTextAreaElement) {
    bioInput.value = existingPublicProfile?.bio || "";
  }
  applyNotificationPreferenceStateToForm(form, notificationPreferences);
  syncNotificationPreferenceAvailability();
  bindFileUploadControl(avatarInput);
  updateFileUploadName(avatarInput);
  renderProfileAvatarPreview(preview, removeButton, state, profile);

  form.addEventListener("change", (event) => {
    if (!(event.target instanceof HTMLInputElement) || event.target.type !== "checkbox") {
      return;
    }
    syncNotificationPreferenceAvailability();
    if (!message?.classList.contains("is-error")) {
      setProfileFormMessage("");
    }
  });

  avatarInput.addEventListener("change", () => {
    const file = avatarInput.files?.[0];
    updateFileUploadName(avatarInput);
    if (!file) {
      return;
    }

    if (!file.type.startsWith("image/")) {
      setProfileFormMessage("Images only. Please choose a valid profile picture.", "error");
      return;
    }

    if (file.size > MAX_IMAGE_SIZE_BYTES) {
      setProfileFormMessage("Image is too large. Please choose an image under 12 MB.", "error");
      return;
    }

    if (state.previewUrl) {
      URL.revokeObjectURL(state.previewUrl);
    }

    state.pendingFile = file;
    state.removeAvatar = false;
    state.previewUrl = URL.createObjectURL(file);
    setProfileFormMessage("");
    renderProfileAvatarPreview(preview, removeButton, state, profile);
  });

  removeButton?.addEventListener("click", () => {
    if (state.previewUrl) {
      URL.revokeObjectURL(state.previewUrl);
      state.previewUrl = "";
    }
    state.pendingFile = null;
    state.removeAvatar = true;
    avatarInput.value = "";
    updateFileUploadName(avatarInput, []);
    renderProfileAvatarPreview(preview, removeButton, state, profile);
  });

  deleteButton?.addEventListener("click", async () => {
    const confirmed = await confirmAccountDeletion();
    if (!confirmed) {
      return;
    }

    deleteButton.disabled = true;
    if (submitButton) {
      submitButton.disabled = true;
    }
    setProfileFormMessage("");

    try {
      const scheduledProfile = await scheduleUserDeletion();
      const scheduledForLabel = formatSessionNameDate(scheduledProfile.deletionScheduledFor.slice(0, 10));
      appState.authNotice = `Account deletion is scheduled for ${scheduledForLabel}. Your app data has not been permanently removed yet. Contact support to fully remove login credentials.`;
      await appState.supabase?.auth.signOut();
    } catch (error) {
      console.error("[Cannakan Profile] Delete profile failed", error);
      setProfileFormMessage(error.message || "Could not delete your account data.", "error");
    } finally {
      deleteButton.disabled = false;
      if (submitButton) {
        submitButton.disabled = false;
      }
    }
  });

  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    console.log("[Cannakan Profile] Save Profile clicked", {
      mode: options.mode || "setup",
      username: String(usernameInput.value || "").trim(),
      hasPendingAvatar: Boolean(state.pendingFile),
      removeAvatar: state.removeAvatar,
    });
    const username = String(usernameInput.value || "").trim();
    const rawPublicHandle = String(publicHandleInput?.value || "").trim();
    const publicHandle = normalizePublicProfileHandle(rawPublicHandle);
    const locationRegion = normalizePublicProfileTextField(locationRegionInput?.value || "", 80);
    const bio = normalizePublicProfileTextField(bioInput?.value || "", 280);

    if (!username) {
      setProfileFormMessage("Please enter a username before saving.", "error");
      usernameInput.reportValidity();
      return;
    }
    if (rawPublicHandle && !publicHandle) {
      setProfileFormMessage("Public handle must be 3-32 letters, numbers, underscores, or hyphens.", "error");
      publicHandleInput?.reportValidity?.();
      return;
    }

    if (submitButton) {
      submitButton.disabled = true;
      submitButton.textContent = "Saving...";
    }
    if (deleteButton) {
      deleteButton.disabled = true;
    }
    setProfileFormMessage("");

    try {
      const warnings = [];
      let avatarUrl = state.profile?.avatarUrl || "";
      let avatarPath = state.profile?.avatarPath || "";
      let growRemindersPromptStatusToPersist = "";
      const notificationPreferenceValues = getNormalizedNotificationPreferenceState({
        growRemindersEnabled: Boolean(form.elements.growRemindersEnabled?.checked),
        notifySoakingReminders: Boolean(form.elements.notifySoakingReminders?.checked),
        notifyGerminationReminders: Boolean(form.elements.notifyGerminationReminders?.checked),
        notifySnapshotReminders: Boolean(form.elements.notifySnapshotReminders?.checked),
        notifySupplyReminders: Boolean(form.elements.notifySupplyReminders?.checked),
        notifyCommunityActivity: Boolean(form.elements.notifyCommunityActivity?.checked),
        pushNotificationsEnabled: Boolean(form.elements.pushNotificationsEnabled?.checked),
      }, notificationPreferences);
      let pushNotificationsEnabled = notificationPreferenceValues.pushNotificationsEnabled;
      if (pushNotificationsEnabled) {
        const permissionState = getGrowRemindersBrowserPermissionState();
        let nextPermissionState = permissionState;
        if (nextPermissionState === "unsupported") {
          pushNotificationsEnabled = false;
          growRemindersPromptStatusToPersist = "enabled";
          if (form.elements.pushNotificationsEnabled instanceof HTMLInputElement) {
            form.elements.pushNotificationsEnabled.checked = false;
          }
          warnings.push("Push notifications are not available on this browser/device. In-app grow reminders will still stay available.");
        } else if (nextPermissionState !== "granted") {
          nextPermissionState = await requestGrowRemindersBrowserPermission();
        }

        if (nextPermissionState === "denied") {
          pushNotificationsEnabled = false;
          growRemindersPromptStatusToPersist = "denied";
          if (form.elements.pushNotificationsEnabled instanceof HTMLInputElement) {
            form.elements.pushNotificationsEnabled.checked = false;
          }
          warnings.push("Push notifications stay off because browser notifications are blocked. You can enable them later in your browser and profile settings.");
        } else if (nextPermissionState === "granted") {
          growRemindersPromptStatusToPersist = "enabled";
        } else if (nextPermissionState !== "unsupported") {
          pushNotificationsEnabled = false;
          growRemindersPromptStatusToPersist = "dismissed";
          if (form.elements.pushNotificationsEnabled instanceof HTMLInputElement) {
            form.elements.pushNotificationsEnabled.checked = false;
          }
          warnings.push("Push notifications were not enabled because notification permission was not granted.");
        }
      } else {
        growRemindersPromptStatusToPersist = "dismissed";
      }
      const notificationPreferencePayload = {
        ...notificationPreferenceValues,
        pushNotificationsEnabled,
      };

      // Save the profile name first so avatar storage problems do not block the main profile save.
      appState.profile = await saveUserProfile({
        username,
        avatarUrl,
        avatarPath,
      });
      state.profile = appState.profile;

      if (state.removeAvatar) {
        const removedAvatarPath = avatarPath;
        avatarUrl = "";
        avatarPath = "";
        appState.profile = await saveUserProfile({
          username,
          avatarUrl,
          avatarPath,
        });
        state.profile = appState.profile;

        if (removedAvatarPath) {
          try {
            await removeProfileAvatarFromStorage(removedAvatarPath);
          } catch (error) {
            console.error("[Cannakan Profile] Avatar removal cleanup failed", error);
            warnings.push("Profile saved, but we could not remove the previous profile image from storage.");
          }
        }
      }

      if (state.pendingFile) {
        try {
          const previousAvatarPath = avatarPath;
          const uploadedAvatar = await uploadProfileAvatar(state.pendingFile);
          avatarUrl = uploadedAvatar.url;
          avatarPath = uploadedAvatar.path;
          appState.profile = await saveUserProfile({
            username,
            avatarUrl,
            avatarPath,
          });
          state.profile = appState.profile;

          if (previousAvatarPath) {
            try {
              await removeProfileAvatarFromStorage(previousAvatarPath);
            } catch (error) {
              console.error("[Cannakan Profile] Previous avatar cleanup failed", error);
              warnings.push("Profile saved and new image applied, but we could not clean up the previous image.");
            }
          }
        } catch (error) {
          console.error("[Cannakan Profile] Avatar upload/save warning", error);
          warnings.push(`Profile saved, but the profile image could not be saved: ${error.message || "Unknown image error."}`);
        }
      }

      try {
        appState.notificationPreferences = await saveUserNotificationPreferences(notificationPreferencePayload);
        appState.profilePageSettings = await savePublicMemberProfileSettings({
          notifyCommunityActivity: notificationPreferencePayload.notifyCommunityActivity,
          bio,
          publicHandle,
          locationRegion,
        }, {
          requirePersistence: true,
          debugContext: "profile-editor-notification-settings",
          verifyAfterSave: false,
        });
        appState.profilePageSettingsUserId = String(appState.user?.id || "").trim();
        if (growRemindersPromptStatusToPersist) {
          saveGrowRemindersPromptState(growRemindersPromptStatusToPersist, appState.user?.id || "");
        }
        applyNotificationPreferenceStateToForm(form, appState.notificationPreferences);
        syncNotificationPreferenceAvailability();
        if (appState.notificationPreferencesTableUnavailable) {
          warnings.push("Profile saved. Notification preferences are using safe defaults until the backend is available.");
        }
      } catch (error) {
        console.warn("[Cannakan Profile] Public profile/settings save warning", error);
        const publicMessage = getPublicMemberProfileSaveErrorMessage(error, error.message || "Unknown settings error.");
        warnings.push(isPublicProfileHandleCollisionError(error) || publicMessage.includes("profile handle is already taken")
          ? publicMessage
          : `Profile saved, but public profile or notification preferences could not be saved: ${publicMessage}`);
        syncNotificationPreferenceAvailability();
      }

      try {
        if (notificationPreferencePayload.pushNotificationsEnabled) {
          await subscribeCurrentDeviceToPushNotifications();
        }
      } catch (error) {
        console.warn("[Cannakan Profile] Push subscription sync warning", error);
        warnings.push(`Profile saved, but push delivery could not be updated on this device: ${error.message || "Unknown push sync error."}`);
      }

      if (state.previewUrl) {
        URL.revokeObjectURL(state.previewUrl);
        state.previewUrl = "";
      }
      state.pendingFile = null;
      state.removeAvatar = false;
      avatarInput.value = "";
      updateFileUploadName(avatarInput, []);
      renderProfileAvatarPreview(preview, removeButton, state, state.profile);

      if (warnings.length) {
        setProfileFormMessage(warnings.join(" "), "warning");
      } else {
        setProfileFormMessage("Profile saved.", "success");
      }

      window.setTimeout(() => {
        options.onSaved?.(appState.profile, {
          warnings,
        });
      }, 650);
    } catch (error) {
      console.error("[Cannakan Profile] Save profile failed", error);
      setProfileFormMessage(error.message || "Could not save your profile.", "error");
    } finally {
      if (submitButton) {
        submitButton.disabled = false;
        submitButton.textContent = defaultSubmitLabel;
      }
      if (deleteButton) {
        deleteButton.disabled = false;
      }
    }
  });
}

function ensureDeleteAccountModal() {
  let modal = document.querySelector("#delete-account-modal");
  if (modal) {
    return modal;
  }

  modal = document.createElement("dialog");
  modal.id = "delete-account-modal";
  modal.className = "snapshot-modal delete-account-modal";
  modal.innerHTML = `
    <form method="dialog" class="snapshot-modal-card profile-modal-card delete-account-modal-card">
      <div id="delete-account-step-warning" class="delete-account-step">
        <div class="snapshot-modal-copy">
          <p class="eyebrow">Danger Zone</p>
          <h3>Warning: schedule account deletion</h3>
          <p class="muted">Warning: this will schedule deletion of your profile, saved sessions, and uploaded images. This cannot be undone once permanent cleanup happens.</p>
        </div>
        <div class="snapshot-modal-actions">
          <button type="button" class="button button-secondary" data-delete-account-cancel>Cancel</button>
          <button type="button" class="button button-danger" data-delete-account-continue>Continue to Permanent Delete</button>
        </div>
      </div>
      <div id="delete-account-step-confirm" class="delete-account-step" hidden>
        <div class="snapshot-modal-copy">
          <p class="eyebrow">Final Confirmation</p>
          <h3>Schedule account deletion</h3>
          <p class="muted">Type DELETE to schedule deletion of your ${BRAND_APP_NAME} app data in 7 days. Your login credentials are not removed from Supabase Auth by this frontend action.</p>
        </div>
        <label class="auth-form">
          <span>Type DELETE to confirm</span>
          <input id="delete-account-confirm-input" type="text" autocomplete="off" placeholder="DELETE">
        </label>
        <p id="delete-account-confirm-message" class="form-message" role="alert" aria-live="polite"></p>
        <div class="snapshot-modal-actions">
          <button type="button" class="button button-secondary" data-delete-account-back>Back</button>
          <button type="button" class="button button-danger" data-delete-account-confirm disabled>Schedule Account Deletion</button>
        </div>
      </div>
    </form>
  `;
  document.body.appendChild(modal);
  return modal;
}

function confirmAccountDeletion() {
  const modal = ensureDeleteAccountModal();
  const warningStep = modal.querySelector("#delete-account-step-warning");
  const confirmStep = modal.querySelector("#delete-account-step-confirm");
  const input = modal.querySelector("#delete-account-confirm-input");
  const message = modal.querySelector("#delete-account-confirm-message");
  const cancelButton = modal.querySelector("[data-delete-account-cancel]");
  const continueButton = modal.querySelector("[data-delete-account-continue]");
  const backButton = modal.querySelector("[data-delete-account-back]");
  const confirmButton = modal.querySelector("[data-delete-account-confirm]");

  if (!warningStep || !confirmStep || !input || !message || !cancelButton || !continueButton || !backButton || !confirmButton) {
    return Promise.resolve(false);
  }

  warningStep.hidden = false;
  confirmStep.hidden = true;
  input.value = "";
  message.textContent = "";
  confirmButton.disabled = true;

  return new Promise((resolve) => {
    const cleanup = (result) => {
      cancelButton.onclick = null;
      continueButton.onclick = null;
      backButton.onclick = null;
      confirmButton.onclick = null;
      input.oninput = null;
      modal.removeEventListener("cancel", onCancel);
      if (modal.open) {
        modal.close();
      }
      resolve(result);
    };

    const onCancel = (event) => {
      event.preventDefault();
      cleanup(false);
    };

    cancelButton.onclick = () => cleanup(false);
    continueButton.onclick = () => {
      warningStep.hidden = true;
      confirmStep.hidden = false;
      input.focus();
    };
    backButton.onclick = () => {
      confirmStep.hidden = true;
      warningStep.hidden = false;
      input.value = "";
      message.textContent = "";
      confirmButton.disabled = true;
    };
    input.oninput = () => {
      const matches = String(input.value || "").trim() === "DELETE";
      confirmButton.disabled = !matches;
      if (matches) {
        message.textContent = "";
      }
    };
    confirmButton.onclick = () => {
      cleanup(true);
    };

    modal.addEventListener("cancel", onCancel, { once: true });
    modal.showModal();
    continueButton.focus();
  });
}

