function formatTestedSourceMockNumber(value) {
  return Number.isFinite(value) ? value.toLocaleString() : "0";
}

function formatTestedSourceMockPercent(value) {
  return Number.isFinite(value) ? `${value}%` : "0%";
}

function formatTestedSourceMockRank(value) {
  return Number.isFinite(value) && value > 0 ? `#${value}` : "—";
}

function formatTestedSourceMockSampleSize(value) {
  return Number.isFinite(value) && value > 0 ? `${value} seeds` : "";
}

function normalizeTestedSourceMockRecord(source = {}) {
  const community = source?.community || {};
  const cstp = source?.cstp || {};
  const trackRecord = source?.trackRecord || {};
  const directoryStats = source?.directoryStats || {};
  return {
    ...source,
    isMock: true,
    is_mock: true,
    sourceTypeLabel: String(source?.sourceTypeLabel || source?.type || "Source").trim() || "Source",
    logoUrl: String(source?.logoUrl || source?.logo || "").trim(),
    community: {
      ...community,
      avgRate: formatTestedSourceMockPercent(Number(community?.avgRate)),
      sessions: formatTestedSourceMockNumber(Number(community?.sessions)),
      rank: formatTestedSourceMockRank(Number(community?.rank)),
      seedsTracked: formatTestedSourceMockNumber(Number(community?.seedsTracked)),
    },
    cstp: {
      ...cstp,
      sampleSize: formatTestedSourceMockSampleSize(Number(cstp?.sampleSize)),
      resultPercent: Number(cstp?.resultPercent) > 0 ? formatTestedSourceMockPercent(Number(cstp?.resultPercent)) : "",
    },
    trackRecord: {
      ...trackRecord,
      totalCerts: formatTestedSourceMockNumber(Number(trackRecord?.totalCerts)),
      gold: formatTestedSourceMockNumber(Number(trackRecord?.gold)),
      silver: formatTestedSourceMockNumber(Number(trackRecord?.silver)),
      qualificationRate: formatTestedSourceMockPercent(Number(trackRecord?.qualificationRate)),
    },
    directoryStats: {
      ...directoryStats,
      sessionsLogged: formatTestedSourceMockNumber(Number(directoryStats?.sessionsLogged)),
      varietiesLogged: formatTestedSourceMockNumber(Number(directoryStats?.varietiesLogged)),
      lastLoggedAt: String(directoryStats?.lastLoggedAt || "").trim(),
    },
  };
}

function getSourceDirectorySessionLoggedAt(session = {}) {
  const dateTimeValue = session?.date && session?.time
    ? parseSessionStartDateTime(session.date, session.time)
    : null;
  const fallbackDate = parseCompletedAtValue(
    session?.updatedAt
    || session?.createdAt
    || session?.completedAt
    || "",
  );
  return dateTimeValue || fallbackDate || null;
}

function formatSourceDirectoryLastLoggedDate(value = "") {
  const parsedDate = parseCompletedAtValue(String(value || "").trim());
  if (!parsedDate) {
    return "Not logged yet";
  }
  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  }).format(parsedDate);
}

function buildSourceDirectorySessionAggregate() {
  const sourceMap = new Map();
  const breederKeys = new Set();
  const varietyKeys = new Set();
  const sessions = (Array.isArray(getSessions()) ? getSessions() : [])
    .filter((session) => isGrowSessionAnalyticsEligible(session));

  sessions.forEach((session) => {
    const resultSummary = getSessionResultSummary(session);
    const sessionLoggedAt = getSourceDirectorySessionLoggedAt(session);
    const sessionLoggedTime = sessionLoggedAt?.getTime() || 0;
    const sessionLoggedValue = sessionLoggedAt?.toISOString() || "";

    resultSummary.partitions.forEach((partitionResult) => {
      const partition = partitionResult.rawPartition;
      const sourceName = partitionResult.source;
      const breederName = String(partition?.breeder || sourceName || "").trim();
      const varietyName = partitionResult.seedVariety;

      if (breederName) {
        breederKeys.add(normalizeSourceNameForMatching(breederName));
      }
      if (varietyName) {
        varietyKeys.add(partitionResult.varietyKey || getPartitionSeedVarietyAnalyticsKey(partition));
      }
    });

    resultSummary.sourceGroups.forEach((sourceGroup) => {
      if (!sourceGroup.key || !sourceGroup.label) {
        return;
      }

      const existingEntry = sourceMap.get(sourceGroup.key) || {
        key: sourceGroup.key,
        name: sourceGroup.label,
        sessionsLogged: 0,
        totalSeeds: 0,
        totalGerminated: 0,
        varieties: new Map(),
        lastLoggedAt: "",
        lastLoggedTime: 0,
      };

      existingEntry.name = existingEntry.name || sourceGroup.label;
      existingEntry.totalSeeds += sourceGroup.totalSeeds;
      existingEntry.totalGerminated += sourceGroup.totalGerminated;
      sourceGroup.contributingPartitions.forEach((partitionResult) => {
        if (partitionResult.seedVariety) {
          existingEntry.varieties.set(partitionResult.varietyKey, partitionResult.seedVariety);
        }
      });
      existingEntry.sessionsLogged += 1;
      if (sessionLoggedTime > existingEntry.lastLoggedTime) {
        existingEntry.lastLoggedTime = sessionLoggedTime;
        existingEntry.lastLoggedAt = sessionLoggedValue;
      }

      sourceMap.set(sourceGroup.key, existingEntry);
    });
  });

  return {
    sourceMap,
    totalBreedersLogged: breederKeys.size,
    totalVarietiesLogged: varietyKeys.size,
  };
}

function getSourceDirectoryTrackRecordForSource(sourceName = "", fallbackTrackRecord = {}) {
  const normalizedSourceKey = normalizeComparableSourceKey(sourceName);
  const publishedCertifications = getAdminCstpTestSessions()
    .filter((session) => (
      session?.certificationPublished === true
      && isAdminCstpCertificationEligible(session?.qualificationResult)
      && normalizeComparableSourceKey(session?.sourceName || "") === normalizedSourceKey
    ));
  if (!publishedCertifications.length) {
    return {
      ...fallbackTrackRecord,
      totalCerts: Number(fallbackTrackRecord?.totalCerts) || 0,
      gold: Number(fallbackTrackRecord?.gold) || 0,
      silver: Number(fallbackTrackRecord?.silver) || 0,
      qualificationRate: Number(fallbackTrackRecord?.qualificationRate) || 0,
      lastTest: String(fallbackTrackRecord?.lastTest || "Not tested"),
    };
  }

  const goldCount = publishedCertifications.filter((session) => normalizeAdminCstpQualificationResult(session?.qualificationResult) === "gold").length;
  const silverCount = publishedCertifications.filter((session) => normalizeAdminCstpQualificationResult(session?.qualificationResult) === "silver").length;
  const latestPublished = publishedCertifications
    .map((session) => session?.publishedAt || session?.completedAt || "")
    .filter(Boolean)
    .sort((left, right) => (Date.parse(right) || 0) - (Date.parse(left) || 0))[0] || "";
  const totalCerts = goldCount + silverCount;
  return {
    totalCerts,
    gold: goldCount,
    silver: silverCount,
    qualificationRate: totalCerts > 0 ? 100 : 0,
    lastTest: latestPublished ? formatSourceDirectoryLastLoggedDate(latestPublished) : "Not tested",
  };
}

function getSourceProfileMockRecord(sourceId = "") {
  const normalizedId = String(sourceId || "").trim().toLowerCase();
  return normalizeTestedSourceMockRecord({
    ...SOURCE_PROFILE_DEMO_RECORD,
    id: normalizedId || SOURCE_PROFILE_DEMO_RECORD.id,
  });
}

function getSourceDirectoryPreviewMockRecord(sourceId = "") {
  const normalizedId = String(sourceId || "").trim().toLowerCase();
  if (!normalizedId) {
    return null;
  }

  if (normalizedId === String(SOURCE_PROFILE_DEFAULT_MOCK_ID || "").trim().toLowerCase()) {
    return getSourceProfileMockRecord(normalizedId);
  }

  const previewRecord = testedSourcesMock
    .map((source) => normalizeTestedSourceMockRecord(source))
    .find((source) => String(source?.id || "").trim().toLowerCase() === normalizedId);

  return previewRecord || null;
}

function getSampleSourceProfileRecord(sourceId = "") {
  const normalizedId = String(sourceId || "").trim().toLowerCase();
  if (!normalizedId) {
    return null;
  }

  const sampleSessions = buildSampleSessions().filter((session) => (
    isGrowSessionAnalyticsEligible(session, { includeMock: true })
  ));
  const matchingSessions = sampleSessions.filter((session) => {
    const partitions = Array.isArray(session?.partitions) ? session.partitions : [];
    return partitions.some((partition) => getPartitionSourceAnalyticsKey(partition) === normalizedId);
  });
  if (!matchingSessions.length) {
    return null;
  }

  const aggregate = {
    name: "",
    sessionsLogged: 0,
    totalSeeds: 0,
    totalGerminated: 0,
    varieties: new Map(),
    lastLoggedAt: "",
    lastLoggedTime: 0,
  };

  matchingSessions.forEach((session) => {
    const sourceGroup = getSessionResultSummary(session).sourceGroups.find((group) => group.key === normalizedId) || null;
    if (!sourceGroup) {
      return;
    }
    const sessionLoggedAt = getSourceDirectorySessionLoggedAt(session);
    const sessionLoggedTime = sessionLoggedAt?.getTime() || 0;
    const sessionLoggedValue = sessionLoggedAt?.toISOString() || "";

    aggregate.name = aggregate.name || sourceGroup.label;
    aggregate.totalSeeds += sourceGroup.totalSeeds;
    aggregate.totalGerminated += sourceGroup.totalGerminated;
    sourceGroup.contributingPartitions.forEach((partitionResult) => {
      if (partitionResult.seedVariety) {
        aggregate.varieties.set(partitionResult.varietyKey, partitionResult.seedVariety);
      }
    });
    aggregate.sessionsLogged += 1;
    if (sessionLoggedTime > aggregate.lastLoggedTime) {
      aggregate.lastLoggedTime = sessionLoggedTime;
      aggregate.lastLoggedAt = sessionLoggedValue;
    }
  });

  if (!aggregate.name) {
    return null;
  }

  const averageRate = aggregate.totalSeeds > 0
    ? Math.round((aggregate.totalGerminated / aggregate.totalSeeds) * 100)
    : 0;
  const trackRecord = getSourceDirectoryTrackRecordForSource(aggregate.name, {});

  return normalizeTestedSourceMockRecord({
    id: normalizedId,
    name: aggregate.name,
    type: "Source / Breeder",
    sourceTypeLabel: "Source / Breeder",
    logoUrl: "",
    websiteUrl: "",
    description: "",
    community: {
      avgRate: averageRate,
      sessions: aggregate.sessionsLogged,
      rank: 0,
      seedsTracked: aggregate.totalSeeds,
    },
    cstp: {},
    trackRecord,
    directoryStats: {
      sessionsLogged: aggregate.sessionsLogged,
      varietiesLogged: aggregate.varieties.size,
      lastLoggedAt: aggregate.lastLoggedAt,
    },
  });
}

function buildRealSourceProfileRecord(sourceId = "") {
  const normalizedId = String(sourceId || "").trim();
  if (!normalizedId) {
    return null;
  }

  const { sourceMap } = buildSourceDirectorySessionAggregate();
  const sourceRecord = findSourceById(normalizedId) || null;
  const sourceAggregateKey = sourceRecord
    ? String(sourceRecord.id || "").trim()
    : normalizedId;
  const sessionAggregate = sourceMap.get(sourceAggregateKey)
    || (sourceRecord ? sourceMap.get(normalizeSourceNameForMatching(sourceRecord.name || "")) : null)
    || null;
  if (!sourceRecord && !sessionAggregate) {
    return null;
  }
  const totalSeeds = Math.max(0, Number(sessionAggregate?.totalSeeds) || 0);
  const totalGerminated = Math.max(0, Number(sessionAggregate?.totalGerminated) || 0);
  const averageRate = totalSeeds > 0 ? Math.round((totalGerminated / totalSeeds) * 100) : 0;
  const sourceName = String(sourceRecord?.name || sessionAggregate?.name || normalizedId).trim();
  const rankedSources = Array.from(sourceMap.values())
    .sort((left, right) => {
      const sessionDelta = Math.max(0, Number(right?.sessionsLogged) || 0) - Math.max(0, Number(left?.sessionsLogged) || 0);
      if (sessionDelta !== 0) {
        return sessionDelta;
      }
      return String(left?.name || "").localeCompare(String(right?.name || ""));
    });
  const rankIndex = rankedSources.findIndex((entry) => (
    String(entry?.key || "").trim() === sourceAggregateKey
    || normalizeSourceNameForMatching(entry?.name || "") === normalizeSourceNameForMatching(sourceName)
  ));
  const trackRecord = getSourceDirectoryTrackRecordForSource(sourceName, {});

  return normalizeTestedSourceMockRecord({
    id: sourceRecord?.id || normalizedId,
    name: sourceName,
    type: sourceRecord ? "Breeder / Seed Source" : "Source / Breeder",
    sourceTypeLabel: sourceRecord ? "Breeder / Seed Source" : "Source / Breeder",
    logoUrl: sourceRecord?.logoUrl || "",
    websiteUrl: sourceRecord?.websiteUrl || "",
    description: sourceRecord?.description || "",
    community: {
      avgRate: averageRate,
      sessions: Math.max(0, Number(sessionAggregate?.sessionsLogged) || 0),
      rank: rankIndex >= 0 ? rankIndex + 1 : 0,
      seedsTracked: totalSeeds,
    },
    cstp: {},
    trackRecord,
    directoryStats: {
      sessionsLogged: Math.max(0, Number(sessionAggregate?.sessionsLogged) || 0),
      varietiesLogged: sessionAggregate?.varieties instanceof Map ? sessionAggregate.varieties.size : 0,
      lastLoggedAt: String(sessionAggregate?.lastLoggedAt || "").trim(),
    },
  });
}

function getSourceProfileRecord(sourceId = "") {
  const normalizedId = String(sourceId || "").trim().toLowerCase();
  const mockDataEnabled = isMockDataEnabled();
  if (mockDataEnabled) {
    return getSourceProfileMockRecord(normalizedId);
  }
  return buildRealSourceProfileRecord(normalizedId)
    || getSourceDirectoryPreviewMockRecord(normalizedId)
    || getSampleSourceProfileRecord(normalizedId);
}

function formatSourceProfileMonthYear(value = "", fallback = "Not available") {
  const parsedDate = parseCompletedAtValue(String(value || "").trim());
  if (!parsedDate) {
    return fallback;
  }
  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    year: "numeric",
  }).format(parsedDate);
}

function formatSourceProfileSampleSize(value = "") {
  const normalizedValue = String(value || "").trim();
  if (!normalizedValue) {
    return "Not available";
  }
  return /\bseed/i.test(normalizedValue) ? normalizedValue : `${normalizedValue} seeds`;
}

function getCstpTooltipCopy(label = "") {
  const normalizedLabel = String(label || "").trim().toLowerCase();
  if (!normalizedLabel) {
    return "";
  }
  if (normalizedLabel.includes("cstp")) {
    return CSTP_TOOLTIP_COPY.cstp;
  }
  if (normalizedLabel.includes("gold")) {
    return CSTP_TOOLTIP_COPY.gold;
  }
  if (normalizedLabel.includes("silver")) {
    return CSTP_TOOLTIP_COPY.silver;
  }
  if (normalizedLabel.includes("active certification")) {
    return CSTP_TOOLTIP_COPY["active certification"];
  }
  if (normalizedLabel.includes("expiring soon")) {
    return CSTP_TOOLTIP_COPY["expiring soon"];
  }
  return "";
}

function renderSourceProfileMetricCard({
  label,
  value,
  detail = "",
  progressValue = Number.NaN,
} = {}) {
  const numericProgressValue = Number(progressValue);
  const hasProgress = Number.isFinite(numericProgressValue);
  const clampedProgressValue = Math.max(0, Math.min(100, numericProgressValue));
  return `
    <article class="card stat-card card-accent card-accent-green source-profile-stat-card">
      <span class="stat-label">${escapeHtml(label)}</span>
      <strong class="stat-value">${escapeHtml(value)}</strong>
      ${hasProgress ? `
        <div class="source-profile-stat-progress" aria-hidden="true">
          <span style="width: ${escapeHtml(String(clampedProgressValue))}%;"></span>
        </div>
      ` : ""}
      <p class="summary-subtext">${escapeHtml(detail)}</p>
    </article>
  `;
}

function getSourceProfileCstpState(sourceProfile = {}) {
  const publishedCertification = getLatestPublishedAdminCstpCertificationForSource(sourceProfile, { activeOnly: false });
  const activePublishedCertification = getPublishedAdminCstpCertificationForSource(sourceProfile);
  const mockCstp = isMockDataEnabled() && sourceProfile?.cstp && typeof sourceProfile.cstp === "object"
    ? sourceProfile.cstp
    : null;

  if (publishedCertification) {
    const qualificationResult = normalizeAdminCstpQualificationResult(publishedCertification.qualificationResult);
    const qualificationLabel = getAdminCstpQualificationLabel(qualificationResult);
    const lifecycleState = getAdminCstpCertificationLifecycleState({
      qualificationResult,
      publishedAt: publishedCertification.publishedAt || "",
    });
    const stateLabel = lifecycleState.isExpired
      ? "Expired Certification"
      : (lifecycleState.isExpiringSoon ? "Expiring Soon" : "Report Available");
    const stateToneClass = lifecycleState.isExpired
      ? "is-expired"
      : (lifecycleState.isExpiringSoon ? "is-expiring" : "is-active");
    return {
      status: qualificationResult,
      publishedAt: publishedCertification.publishedAt || "",
      testedAt: publishedCertification.completedAt || publishedCertification.publishedAt || "",
      expiresAt: lifecycleState.expiresAt || "",
      heading: "2. CSTP Verification",
      helperText: CSTP_DEFINITION,
      statusLabel: `${qualificationLabel} Certified`,
      toneClass: qualificationResult === "gold" ? "is-gold" : "is-silver",
      usesBadge: true,
      isMuted: lifecycleState.isExpired,
      hasReport: Boolean(activePublishedCertification),
      pills: [
        { label: qualificationLabel, toneClass: qualificationResult === "gold" ? "is-gold" : "is-silver" },
        { label: stateLabel, toneClass: stateToneClass },
      ],
      rows: [
        { label: "Test Date", value: formatSourceProfileMonthYear(publishedCertification.completedAt || publishedCertification.publishedAt || "") },
        { label: "Valid Until", value: formatSourceProfileMonthYear(lifecycleState.expiresAt || "") },
        { label: "Total Seeds Tested", value: formatSourceProfileSampleSize(publishedCertification.sampleSize || "") },
        { label: "Observation Window", value: String(publishedCertification.totalGerminationTime || "").trim() || "Not available" },
      ],
    };
  }

  if (mockCstp) {
    const mockStatus = String(mockCstp.status || "").trim().toLowerCase();
    const qualificationResult = ["gold", "silver"].includes(mockStatus)
      ? mockStatus
      : "";
    const isExpired = mockStatus === "expired";
    const isExpiringSoon = mockCstp.expiringSoon === true;
    const mockObservationWindow = qualificationResult === "silver"
      ? "6 days, 8 hours"
      : (qualificationResult === "gold" ? "6 days, 4 hours" : "Not available");
    return {
      status: qualificationResult || (isExpired ? "expired" : (mockStatus || "not-tested")),
      publishedAt: "",
      testedAt: String(mockCstp.testedDate || "").trim(),
      expiresAt: String(mockCstp.validUntil || "").trim(),
      heading: "2. CSTP Verification",
      helperText: CSTP_DEFINITION,
      statusLabel: qualificationResult
        ? `${getAdminCstpQualificationLabel(qualificationResult)} Certified`
        : (isExpired ? "Expired Certification" : (mockStatus === "tested" ? "CSTP Tested" : "Report Unavailable")),
      toneClass: qualificationResult
        ? (qualificationResult === "gold" ? "is-gold" : "is-silver")
        : (isExpired ? "is-expired" : "is-neutral"),
      usesBadge: Boolean(qualificationResult),
      isMuted: !qualificationResult,
      hasReport: Boolean(qualificationResult),
      pills: qualificationResult
        ? [
          { label: getAdminCstpQualificationLabel(qualificationResult), toneClass: qualificationResult === "gold" ? "is-gold" : "is-silver" },
          { label: isExpired ? "Expired Certification" : (isExpiringSoon ? "Expiring Soon" : "Report Available"), toneClass: isExpired ? "is-expired" : (isExpiringSoon ? "is-expiring" : "is-active") },
        ]
        : [
          { label: isExpired ? "Previously Tested" : (mockStatus === "tested" ? "CSTP Tested" : "Report Unavailable"), toneClass: isExpired ? "is-expired" : "is-neutral" },
        ],
      rows: [
        { label: "Test Date", value: String(mockCstp.testedDate || "").trim() || "Not available" },
        { label: "Valid Until", value: String(mockCstp.validUntil || "").trim() || "Not available" },
        { label: "Total Seeds Tested", value: formatSourceProfileSampleSize(mockCstp.sampleSize || "") },
        { label: "Observation Window", value: mockObservationWindow },
      ],
    };
  }

  return {
    status: "not-tested",
    publishedAt: "",
    testedAt: "",
    expiresAt: "",
    heading: "2. CSTP Verification",
    helperText: CSTP_DEFINITION,
    statusLabel: "Report Unavailable",
    toneClass: "is-neutral",
    usesBadge: false,
    isMuted: true,
    hasReport: false,
    pills: [
      { label: "Report Unavailable", toneClass: "is-neutral" },
    ],
    rows: [
      { label: "Test Date", value: "Not available" },
      { label: "Valid Until", value: "Not available" },
      { label: "Total Seeds Tested", value: "Not available" },
      { label: "Observation Window", value: "Not available" },
    ],
  };
}

function renderSourceProfileCstpVisualMarkup(cstpState = {}) {
  const toneClass = escapeHtml(cstpState.toneClass || "");
  const badgeAsset = cstpState.badgeAsset
    || SOURCE_PROFILE_CSTP_BADGE_ASSETS[cstpState.status]
    || (cstpState.status === "expired" ? SOURCE_PROFILE_CSTP_BADGE_ASSETS.expired : "");
  if (badgeAsset) {
    const badgeAlt = cstpState.statusLabel || "CSTP certification badge";
    const badgeTitle = getCstpTooltipCopy(cstpState.statusLabel || cstpState.status || "CSTP");
    return `
      <div class="source-profile-cstp-visual source-profile-cstp-visual--image ${toneClass}">
        <img
          src="${escapeHtml(badgeAsset)}"
          alt="${escapeHtml(badgeAlt)}"
          title="${escapeHtml(badgeTitle || getCstpTooltipCopy("CSTP"))}"
          class="source-profile-cstp-badge-image"
          loading="lazy"
          decoding="async"
        >
      </div>
    `;
  }

  const textLabel = cstpState.visualTitle
    || (cstpState.status === "tested"
      ? "CSTP Tested"
      : (cstpState.status === "not-tested" ? "Report Unavailable" : "Previously Tested"));
  const textCaption = cstpState.visualNote
    || (cstpState.status === "tested"
      ? "Tested-only record with no public Gold or Silver report"
      : (cstpState.status === "not-tested" ? "No public CSTP report on record" : "No active public report available"));
  return `
    <div class="source-profile-cstp-visual source-profile-cstp-visual--text ${toneClass}">
      <span class="source-profile-cstp-visual-label" title="${escapeHtml(getCstpTooltipCopy(cstpState.visualLabel || "CSTP"))}">${escapeHtml(cstpState.visualLabel || "CSTP")}</span>
      <strong>${escapeHtml(textLabel)}</strong>
      <span class="source-profile-cstp-visual-note">${escapeHtml(textCaption)}</span>
    </div>
  `;
}

function getSourceDirectoryMockRecords() {
  const { sourceMap } = buildSourceDirectorySessionAggregate();
  const baseSourcesByKey = new Map(
    (isMockDataEnabled() ? testedSourcesMock : [])
      .map((source) => normalizeTestedSourceMockRecord(source))
      .filter(Boolean)
      .map((source) => [normalizeSourceNameForMatching(source.name || source.id || ""), source]),
  );

  const mergedRecords = [];
  sourceMap.forEach((entry, sourceKey) => {
    const baseSource = baseSourcesByKey.get(sourceKey) || null;
    const totalSeeds = entry.totalSeeds;
    const totalGerminated = entry.totalGerminated;
    const averageRate = totalSeeds > 0 ? Math.round((totalGerminated / totalSeeds) * 100) : 0;
    const trackRecord = getSourceDirectoryTrackRecordForSource(entry.name, baseSource?.trackRecord || {});
    mergedRecords.push(normalizeTestedSourceMockRecord({
      ...(baseSource || {}),
      id: String(baseSource?.id || sourceKey).trim(),
      name: entry.name,
      type: baseSource?.type || "Source / Breeder",
      sourceTypeLabel: baseSource?.sourceTypeLabel || baseSource?.type || "Source / Breeder",
      logoUrl: baseSource?.logoUrl || baseSource?.logo || "",
      website: baseSource?.website || "",
      establishedLabel: baseSource?.establishedLabel || "",
      community: {
        avgRate: averageRate,
        sessions: entry.sessionsLogged,
        rank: 0,
        seedsTracked: totalSeeds,
      },
      cstp: {
        ...(baseSource?.cstp || {}),
      },
      trackRecord,
      directoryStats: {
        sessionsLogged: entry.sessionsLogged,
        varietiesLogged: entry.varieties.size,
        lastLoggedAt: entry.lastLoggedAt,
      },
    }));
    baseSourcesByKey.delete(sourceKey);
  });

  baseSourcesByKey.forEach((baseSource, sourceKey) => {
    const communitySessions = parseSourceDirectoryMetricNumber(baseSource?.community?.sessions);
    const fallbackLastActivity = String(baseSource?.trackRecord?.lastTest || "").trim().toLowerCase() === "not tested"
      ? ""
      : String(baseSource?.trackRecord?.lastTest || baseSource?.cstp?.testedDate || "").trim();
    mergedRecords.push(normalizeTestedSourceMockRecord({
      ...baseSource,
      id: String(baseSource?.id || sourceKey).trim(),
      directoryStats: {
        ...(baseSource?.directoryStats || {}),
        sessionsLogged: parseSourceDirectoryMetricNumber(baseSource?.directoryStats?.sessionsLogged) || communitySessions,
        varietiesLogged: parseSourceDirectoryMetricNumber(baseSource?.directoryStats?.varietiesLogged),
        lastLoggedAt: String(baseSource?.directoryStats?.lastLoggedAt || fallbackLastActivity || "").trim(),
      },
    }));
  });

  const rankedRecords = mergedRecords
    .filter(Boolean)
    .sort((left, right) => {
      const sessionDelta = parseSourceDirectoryMetricNumber(right?.directoryStats?.sessionsLogged)
        - parseSourceDirectoryMetricNumber(left?.directoryStats?.sessionsLogged);
      if (sessionDelta !== 0) {
        return sessionDelta;
      }
      return String(left?.name || "").localeCompare(String(right?.name || ""));
    })
    .map((record, index) => normalizeTestedSourceMockRecord({
      ...record,
      community: {
        ...(record?.community || {}),
        rank: index + 1,
      },
    }));

  return rankedRecords;
}

function normalizePersistedSessionImageEntry(image) {
  return normalizePersistedSessionImages(image ? [image] : [])[0] || null;
}

function parseSourceDirectoryMetricNumber(value = "") {
  const digitsOnly = String(value || "").replace(/[^0-9.]/g, "");
  const parsed = Number(digitsOnly);
  return Number.isFinite(parsed) ? parsed : 0;
}

function parseSourceDirectoryMonthYearToTime(value = "") {
  const normalized = String(value || "").trim();
  if (!normalized || normalized.toLowerCase() === "not tested") {
    return 0;
  }
  const parsed = Date.parse(`${normalized} 01`);
  return Number.isFinite(parsed) ? parsed : 0;
}

function getSourceDirectoryCstpPreview(source = {}) {
  const publishedCertification = getPublishedAdminCstpCertificationForSource(source);
  if (!publishedCertification) {
    return null;
  }

  const qualificationResult = normalizeAdminCstpQualificationResult(publishedCertification.qualificationResult);
  const qualificationLabel = getAdminCstpQualificationLabel(qualificationResult);
  return {
    filterKey: qualificationResult,
    publishedAt: publishedCertification.publishedAt || "",
    label: `CSTP ${qualificationLabel}`,
    badgeAsset: qualificationResult === "gold" ? SOURCE_PROFILE_CSTP_BADGE_ASSETS.gold : SOURCE_PROFILE_CSTP_BADGE_ASSETS.silver,
    badgeAlt: `CSTP ${qualificationLabel} badge`,
    isExpired: false,
    testedTime: Date.parse(publishedCertification.publishedAt || publishedCertification.completedAt || "") || 0,
  };
}

function getSourceDirectoryCstpReportHash(source = {}) {
  const sourceId = String(source?.id || "").trim();
  return sourceId ? `#sources/${encodeURIComponent(sourceId)}/cstp-report` : "";
}

function hasKnownSourceDirectoryRouteSource(sourceId = "") {
  const normalizedId = String(sourceId || "").trim().toLowerCase();
  if (!normalizedId) {
    return false;
  }
  if (normalizedId === String(SOURCE_PROFILE_DEFAULT_MOCK_ID || "").trim().toLowerCase()) {
    return true;
  }
  if (getSourceDirectoryPreviewMockRecord(normalizedId)) {
    return true;
  }
  if (findSourceById(normalizedId)) {
    return true;
  }
  if (getSourceDirectoryMockRecords().some((source) => String(source?.id || "").trim().toLowerCase() === normalizedId)) {
    return true;
  }
  return Boolean(getSampleSourceProfileRecord(normalizedId));
}

function getSourceCstpReportSourceProfile(sourceId = "") {
  const normalizedId = String(sourceId || "").trim().toLowerCase();
  if (!normalizedId) {
    return null;
  }

  const directoryRecord = getSourceDirectoryMockRecords()
    .find((source) => String(source?.id || "").trim().toLowerCase() === normalizedId) || null;
  return directoryRecord
    || getSourceDirectoryPreviewMockRecord(normalizedId)
    || (hasKnownSourceDirectoryRouteSource(normalizedId) ? getSourceProfileRecord(normalizedId) : null);
}

function getSourceDirectoryCstpCardState(source = {}) {
  const publishedPreview = getSourceDirectoryCstpPreview(source);
  if (publishedPreview) {
    return {
      kind: "certified",
      qualificationResult: publishedPreview.filterKey,
      qualificationLabel: getAdminCstpQualificationLabel(publishedPreview.filterKey),
      labelText: "CSTP Certified",
      noteText: "Report Available",
      testedAt: publishedPreview.publishedAt || "",
      hasReport: true,
      href: getSourceDirectoryCstpReportHash(source),
    };
  }

  const cstp = source?.cstp && typeof source.cstp === "object" ? source.cstp : {};
  const normalizedStatus = String(cstp.status || "").trim().toLowerCase();
  if (!normalizedStatus || normalizedStatus === "not-tested") {
    return null;
  }

  const qualificationResult = ["gold", "silver"].includes(normalizedStatus)
    ? normalizedStatus
    : "";
  if (qualificationResult) {
    return {
      kind: "certified",
      qualificationResult,
      qualificationLabel: getAdminCstpQualificationLabel(qualificationResult),
      labelText: "CSTP Certified",
      noteText: "Report Available",
      testedAt: String(cstp.testedDate || cstp.validUntil || "").trim(),
      hasReport: true,
      href: getSourceDirectoryCstpReportHash(source),
    };
  }

  const isExpired = normalizedStatus === "expired";
  return {
    kind: isExpired ? "expired" : "tested",
    qualificationResult: "",
    qualificationLabel: "",
    labelText: isExpired ? "Previously Tested" : "CSTP Tested",
    noteText: "Report Unavailable",
    testedAt: String(cstp.testedDate || "").trim(),
    hasReport: false,
    href: "",
  };
}

function renderSourceDirectoryCstpCardBadgeMarkup(cstpState = {}) {
  if (!cstpState) {
    return "";
  }

  if (cstpState.qualificationResult && cstpState.testedAt) {
    return renderPublishedCstpCertifiedSealMarkup(cstpState.qualificationResult, cstpState.testedAt, {
      shellClassName: "source-directory-cstp-status cstp-certified-seal cstp-certified-seal--compact",
      imageClassName: "source-directory-cstp-badge cstp-certified-seal-image",
      copyClassName: "cstp-certified-seal-copy",
      labelClassName: "cstp-certified-seal-label",
      titleClassName: "cstp-certified-seal-title",
      noteClassName: "cstp-certified-seal-note",
      labelText: cstpState.labelText || "CSTP Certified",
      noteText: cstpState.noteText || cstpState.qualificationLabel || "",
    });
  }

  return `
    <div class="source-directory-cstp-tested-chip is-${escapeHtml(cstpState.kind || "tested")}">
      <span class="source-directory-cstp-tested-mark" aria-hidden="true">C</span>
      <span class="source-directory-cstp-tested-copy">
        <strong>${escapeHtml(cstpState.labelText || "CSTP Tested")}</strong>
        <span>${escapeHtml(cstpState.noteText || "No public certification")}</span>
      </span>
    </div>
  `;
}

