function buildContactSubmissionPayload(reasonKey = "", formData) {
  const getValue = (key) => String(formData.get(key) || "").trim();
  const baseMessage = getValue("message");

  switch (reasonKey) {
    case "app-support":
      return {
        type: "App Support",
        reporterName: getValue("reporterName"),
        userEmail: getValue("userEmail"),
        subject: getValue("appIssueType") || "App Support",
        bucket: "support",
        routedTo: "growsupport@cannakan.com",
        message: [
          "Reason: App Support",
          `Issue Type: ${getValue("appIssueType") || "Not provided"}`,
          "",
          baseMessage,
        ].join("\n"),
      };
    case "order-support":
      return {
        type: "Order / Product Support",
        reporterName: getValue("reporterName"),
        userEmail: getValue("userEmail"),
        subject: `Order ${getValue("orderNumber")} - ${getValue("productName")}`,
        bucket: "support",
        routedTo: "growsupport@cannakan.com",
        message: [
          "Reason: Order / Product Support",
          `Order Number: ${getValue("orderNumber")}`,
          `Product: ${getValue("productName")}`,
          "",
          baseMessage,
        ].join("\n"),
      };
    case "cstp-request":
      return {
        type: "CSTP Testing Request",
        reporterName: getValue("reporterName"),
        userEmail: getValue("userEmail"),
        company: getValue("companyName"),
        website: getValue("websiteUrl"),
        subject: `CSTP Testing Request - ${getValue("companyName")}`,
        bucket: "cstp",
        routedTo: "cstp@cannakan.com",
        message: [
          "Reason: CSTP Testing Request",
          `Company / Source Name: ${getValue("companyName")}`,
          `Website: ${getValue("websiteUrl") || "Not provided"}`,
          `Seed Type / Category: ${getSeedTypeLabel(getValue("seedCategory")) || getValue("seedCategory")}`,
          `Batch or Lot Info: ${getValue("batchInfo")}`,
          `Approximate Seeds Available: ${getValue("seedCount")}`,
          "",
          baseMessage,
        ].join("\n"),
      };
    case "source-correction":
      return {
        type: "Source Correction / Directory Issue",
        reporterName: "",
        userEmail: "",
        website: getValue("proofLink"),
        subject: `Source Correction - ${getValue("shownSourceName") || "Directory Issue"}`,
        bucket: "source-corrections",
        routedTo: "growsupport@cannakan.com",
        message: [
          "Reason: Source Correction / Directory Issue",
          `Source Name Shown: ${getValue("shownSourceName")}`,
          `Correct Source Name: ${getValue("correctSourceName")}`,
          `Website / Proof Link: ${getValue("proofLink") || "Not provided"}`,
          "",
          baseMessage,
        ].join("\n"),
      };
    case "partnership":
      return {
        type: "Partnership / Business Inquiry",
        reporterName: getValue("reporterName"),
        userEmail: getValue("userEmail"),
        company: getValue("companyName"),
        website: getValue("websiteUrl"),
        subject: `${getValue("inquiryType") || "Business Inquiry"} - ${getValue("companyName")}`,
        bucket: "support",
        routedTo: "growsupport@cannakan.com",
        message: [
          "Reason: Partnership / Business Inquiry",
          `Company: ${getValue("companyName")}`,
          `Website: ${getValue("websiteUrl") || "Not provided"}`,
          `Inquiry Type: ${getValue("inquiryType")}`,
          "",
          baseMessage,
        ].join("\n"),
      };
    case "other":
    default:
      return {
        type: "Other",
        reporterName: getValue("reporterName"),
        userEmail: getValue("userEmail"),
        subject: "Other",
        bucket: "support",
        routedTo: "growsupport@cannakan.com",
        message: [
          "Reason: Other",
          "",
          baseMessage,
        ].join("\n"),
      };
  }
}

