function bindAdminFallbackContentSection() {
  const form = app.querySelector("#admin-fallback-content-form");
  if (!(form instanceof HTMLFormElement)) {
    return;
  }

  const batchField = form.elements.fallbackBatch;
  const message = form.querySelector("#admin-fallback-content-message");
  const exportButton = form.querySelector("#admin-fallback-content-export");
  const clearButton = form.querySelector("#admin-fallback-content-clear");
  const submitButton = form.querySelector('button[type="submit"]');

  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    if (submitButton instanceof HTMLButtonElement) {
      submitButton.disabled = true;
    }

    const parsedBatch = parseFallbackContentBatchInput(batchField?.value || "");
    if (!parsedBatch.jokes.length && !parsedBatch.facts.length) {
      if (message) {
        message.textContent = "No valid jokes or grow facts were found in that batch.";
      }
      if (submitButton instanceof HTMLButtonElement) {
        submitButton.disabled = false;
      }
      return;
    }

    try {
      const nextStoredJokes = mergeUniqueFallbackJokes(readStoredFallbackJokes(), parsedBatch.jokes);
      const nextStoredFacts = mergeUniqueFallbackFacts(readStoredFallbackFacts(), parsedBatch.facts);
      writeStoredFallbackJokes(nextStoredJokes);
      writeStoredFallbackFacts(nextStoredFacts);
      localStorage.removeItem(RECENT_FALLBACK_ITEMS_STORAGE_KEY);
      appState.fallbackContentAdminMessage = `Imported ${parsedBatch.jokes.length} joke${parsedBatch.jokes.length === 1 ? "" : "s"} and ${parsedBatch.facts.length} grow fact${parsedBatch.facts.length === 1 ? "" : "s"}.`;
      safeRender();
    } catch (error) {
      console.error("Failed to import fallback content batch", error);
      if (message) {
        message.textContent = "Could not import fallback content.";
      }
    } finally {
      if (submitButton instanceof HTMLButtonElement) {
        submitButton.disabled = false;
      }
    }
  });

  exportButton?.addEventListener("click", async () => {
    const exportValue = serializeFallbackContentForExport();
    if (batchField) {
      batchField.value = exportValue;
      batchField.focus();
      batchField.select();
    }

    let exportMessage = "Fallback content exported to the batch field.";
    try {
      await navigator.clipboard.writeText(exportValue);
      exportMessage = "Fallback content exported to the batch field and copied to the clipboard.";
    } catch (error) {
      console.warn("Could not copy fallback content export to clipboard", error);
    }

    if (message) {
      message.textContent = exportMessage;
    }
    appState.fallbackContentAdminMessage = exportMessage;
  });

  clearButton?.addEventListener("click", () => {
    try {
      clearStoredFallbackContent();
      appState.fallbackContentAdminMessage = "Custom jokes and grow facts cleared. Seeded defaults remain available.";
      safeRender();
    } catch (error) {
      if (message) {
        message.textContent = error.message || "Could not clear fallback content.";
      }
    }
  });
}

function getAdminSectionOpenState(storageKey, defaultOpen = false) {
  try {
    const storedValue = localStorage.getItem(storageKey);
    if (storedValue === null) {
      return Boolean(defaultOpen);
    }

    return storedValue === "true";
  } catch (error) {
    console.warn("Could not read admin section state", { storageKey, error });
    return Boolean(defaultOpen);
  }
}

function getAdminCollapsibleSectionStorageKeys() {
  return [
    ADMIN_MEMBERS_OPEN_STORAGE_KEY,
    ADMIN_SOURCES_OPEN_STORAGE_KEY,
    ADMIN_SOURCE_REVIEW_OPEN_STORAGE_KEY,
    ADMIN_MESSAGE_BOARD_OPEN_STORAGE_KEY,
    ADMIN_USER_REPORTS_OPEN_STORAGE_KEY,
    ADMIN_ANALYTICS_OPEN_STORAGE_KEY,
    ADMIN_VISITOR_ANALYTICS_OPEN_STORAGE_KEY,
    ADMIN_TUTORIAL_MANAGEMENT_OPEN_STORAGE_KEY,
    ADMIN_COMMUNICATIONS_OPEN_STORAGE_KEY,
    ADMIN_CSTP_LAB_OPEN_STORAGE_KEY,
    ADMIN_DEV_ACCESS_OPEN_STORAGE_KEY,
  ];
}

function setAdminSectionOpenState(storageKey, isOpen) {
  try {
    localStorage.setItem(storageKey, isOpen ? "true" : "false");
  } catch (error) {
    console.warn("Could not save admin section state", { storageKey, error });
  }
}

function resetAdminCollapsibleSectionStates() {
  getAdminCollapsibleSectionStorageKeys().forEach((storageKey) => {
    setAdminSectionOpenState(storageKey, false);
  });
}

function normalizeAdminDashboardSectionOrder(sectionOrder = []) {
  const normalizedKeys = [];
  const allowedKeys = new Set(ADMIN_DASHBOARD_SECTION_DEFAULT_ORDER);
  (Array.isArray(sectionOrder) ? sectionOrder : []).forEach((entry) => {
    const normalizedKey = String(entry || "").trim();
    if (!normalizedKey || !allowedKeys.has(normalizedKey) || normalizedKeys.includes(normalizedKey)) {
      return;
    }
    normalizedKeys.push(normalizedKey);
  });
  return normalizedKeys;
}

function getAdminDashboardSectionOrder() {
  try {
    const storedValue = localStorage.getItem(ADMIN_SECTION_ORDER_STORAGE_KEY);
    if (!storedValue) {
      return [];
    }
    return normalizeAdminDashboardSectionOrder(JSON.parse(storedValue));
  } catch (error) {
    return [];
  }
}

function setAdminDashboardSectionOrder(sectionOrder = []) {
  try {
    const normalizedOrder = normalizeAdminDashboardSectionOrder(sectionOrder);
    if (!normalizedOrder.length) {
      localStorage.removeItem(ADMIN_SECTION_ORDER_STORAGE_KEY);
      return;
    }
    localStorage.setItem(ADMIN_SECTION_ORDER_STORAGE_KEY, JSON.stringify(normalizedOrder));
  } catch (error) {}
}

function resetAdminDashboardSectionOrder() {
  try {
    localStorage.removeItem(ADMIN_SECTION_ORDER_STORAGE_KEY);
  } catch (error) {}
}

function getOrderedAdminDashboardPanels(panels = []) {
  const availablePanels = (Array.isArray(panels) ? panels : []).filter((panel) => String(panel?.markup || "").trim());
  const panelMap = new Map(
    availablePanels.map((panel) => [String(panel?.key || "").trim(), panel]).filter(([key]) => Boolean(key)),
  );
  const orderedPanels = [];
  const seenKeys = new Set();

  getAdminDashboardSectionOrder().forEach((key) => {
    const panel = panelMap.get(key);
    if (!panel || seenKeys.has(key)) {
      return;
    }
    seenKeys.add(key);
    orderedPanels.push(panel);
  });

  ADMIN_DASHBOARD_SECTION_DEFAULT_ORDER.forEach((key) => {
    const panel = panelMap.get(key);
    if (!panel || seenKeys.has(key)) {
      return;
    }
    seenKeys.add(key);
    orderedPanels.push(panel);
  });

  availablePanels.forEach((panel) => {
    const key = String(panel?.key || "").trim();
    if (!key || seenKeys.has(key)) {
      return;
    }
    seenKeys.add(key);
    orderedPanels.push(panel);
  });

  return orderedPanels;
}

function renderAdminDashboardPanelMarkup({ key = "", markup = "" } = {}) {
  const normalizedKey = String(key || "").trim();
  const normalizedMarkup = String(markup || "").trim();
  if (!normalizedKey || !normalizedMarkup) {
    return "";
  }

  return `
    <div class="admin-dashboard-panel" data-admin-panel-key="${escapeHtml(normalizedKey)}">
      <button
        type="button"
        class="admin-panel-drag-handle"
        data-admin-panel-drag-handle="true"
        aria-label="Drag to reorder admin section"
        title="Drag to reorder"
      >
        <span class="admin-panel-drag-grip" aria-hidden="true"></span>
      </button>
      ${normalizedMarkup}
    </div>
  `;
}

function renderAdminCollapsibleSectionMarkup({
  eyebrow,
  title,
  description,
  storageKey,
  contentId,
  bodyMarkup,
  defaultOpen = false,
  sectionClassName = "card admin-section-card",
  iconType = "admin",
}) {
  const isOpen = getAdminSectionOpenState(storageKey, defaultOpen);

  return `
    <section class="${escapeHtml(sectionClassName)} admin-collapsible-section${isOpen ? " is-open" : " is-collapsed"}">
      <button
        type="button"
        class="admin-collapsible-toggle"
        data-admin-section-toggle="true"
        data-admin-section-storage-key="${escapeHtml(storageKey)}"
        data-admin-section-content-id="${escapeHtml(contentId)}"
        aria-controls="${escapeHtml(contentId)}"
        aria-expanded="${isOpen ? "true" : "false"}"
      >
        <span class="section-title-with-icon app-section-header-main admin-collapsible-header-main">
          ${renderAppSectionHeaderIcon(iconType)}
          <div class="admin-collapsible-copy">
            <span class="eyebrow">${escapeHtml(eyebrow)}</span>
            <span class="admin-collapsible-title" role="heading" aria-level="3">${escapeHtml(title)}</span>
            <span class="muted admin-collapsible-description">${escapeHtml(description)}</span>
          </div>
        </span>
        <span class="admin-collapsible-chevron" aria-hidden="true"></span>
      </button>
      <div id="${escapeHtml(contentId)}" class="admin-collapsible-content"${isOpen ? "" : " hidden"}>
        ${bodyMarkup}
      </div>
    </section>
  `;
}

function syncAdminCollapsibleSection(button, content, isOpen) {
  if (!button || !content) {
    return;
  }

  button.setAttribute("aria-expanded", isOpen ? "true" : "false");
  content.hidden = !isOpen;
  const section = button.closest(".admin-collapsible-section");
  section?.classList.toggle("is-open", isOpen);
  section?.classList.toggle("is-collapsed", !isOpen);
}

function scrollElementIntoViewAfterLayout(element, options = {}) {
  if (!(element instanceof Element)) {
    return;
  }

  const {
    delayMs = 140,
    behavior = "smooth",
    block = "start",
  } = options;

  window.setTimeout(() => {
    element.scrollIntoView({ behavior, block });
  }, Math.max(0, Number(delayMs) || 0));
}

function scrollToSessionDashboardSection(sectionId = "", options = {}) {
  const normalizedId = String(sectionId || "").trim();
  if (!normalizedId) {
    return false;
  }

  const target = document.getElementById(normalizedId);
  if (!(target instanceof Element)) {
    return false;
  }

  scrollElementIntoViewAfterLayout(target, {
    delayMs: 80,
    block: "start",
    ...options,
  });
  return true;
}

function flushPendingSessionDashboardScrollTarget() {
  const targetId = String(appState.sessionDashboardScrollTarget || "").trim();
  if (!targetId) {
    return;
  }

  if (targetId === "session-history") {
    appState.sessionHistoryExpanded = true;
  }
  if (scrollToSessionDashboardSection(targetId)) {
    appState.sessionDashboardScrollTarget = "";
  }
}

function bindAdminCollapsibleSections(scope = app) {
  if (!scope) {
    return;
  }

  scope.querySelectorAll("[data-admin-section-toggle='true']").forEach((button) => {
    if (button.dataset.adminSectionBound === "true") {
      return;
    }

    button.dataset.adminSectionBound = "true";
    button.addEventListener("click", () => {
      const storageKey = String(button.dataset.adminSectionStorageKey || "").trim();
      const contentId = String(button.dataset.adminSectionContentId || "").trim();
      const content = contentId ? document.getElementById(contentId) : null;
      if (!storageKey || !content) {
        return;
      }

      const isOpen = button.getAttribute("aria-expanded") !== "true";
      syncAdminCollapsibleSection(button, content, isOpen);
      setAdminSectionOpenState(storageKey, isOpen);
      if (isOpen) {
        const section = button.closest(".admin-collapsible-section");
        scrollElementIntoViewAfterLayout(section || content, { delayMs: 140 });
      }
    });
  });
}

function syncCommunityGrowAdminReviewSection(section, isOpen) {
  if (!(section instanceof Element)) {
    return;
  }

  const toggle = section.querySelector("[data-gallery-admin-review-toggle='true']");
  const contentShell = section.querySelector(".gallery-inline-review-collapse-shell");
  toggle?.setAttribute("aria-expanded", isOpen ? "true" : "false");
  section.classList.toggle("is-open", isOpen);
  section.classList.toggle("is-collapsed", !isOpen);
  if (contentShell instanceof HTMLElement) {
    contentShell.setAttribute("aria-hidden", isOpen ? "false" : "true");
    if (isOpen) {
      contentShell.removeAttribute("inert");
    } else {
      contentShell.setAttribute("inert", "");
    }
  }
}

function bindCommunityGrowAdminReviewSection(section) {
  if (!(section instanceof Element)) {
    return;
  }

  const toggle = section.querySelector("[data-gallery-admin-review-toggle='true']");
  if (!(toggle instanceof HTMLButtonElement) || toggle.dataset.galleryAdminReviewBound === "true") {
    return;
  }

  toggle.dataset.galleryAdminReviewBound = "true";
  toggle.addEventListener("click", () => {
    const isOpen = toggle.getAttribute("aria-expanded") !== "true";
    syncCommunityGrowAdminReviewSection(section, isOpen);
    setAdminSectionOpenState(COMMUNITY_GROW_ADMIN_REVIEW_OPEN_STORAGE_KEY, isOpen);
    if (isOpen) {
      scrollElementIntoViewAfterLayout(section, { delayMs: 120 });
    }
  });
}

function bindAdminDashboardSectionReordering(scope = app) {
  if (!scope) {
    return;
  }

  const container = scope.querySelector("[data-admin-dashboard-sections='true']");
  if (!(container instanceof HTMLElement)) {
    return;
  }

  const dragEnabled = window.matchMedia ? window.matchMedia("(min-width: 861px) and (pointer: fine)").matches : true;
  container.classList.toggle("is-reorder-disabled", !dragEnabled);

  const resetButton = scope.querySelector("[data-admin-reset-layout='true']");
  if (resetButton instanceof HTMLButtonElement && resetButton.dataset.adminResetLayoutBound !== "true") {
    resetButton.dataset.adminResetLayoutBound = "true";
    resetButton.addEventListener("click", () => {
      resetAdminDashboardSectionOrder();
      safeRender();
    });
  }

  const handles = Array.from(container.querySelectorAll("[data-admin-panel-drag-handle='true']"));
  const panels = Array.from(container.querySelectorAll(".admin-dashboard-panel"));
  let draggedPanel = null;
  let armedPanel = null;

  const clearArmedPanels = () => {
    panels.forEach((panel) => {
      if (!(panel instanceof HTMLElement)) {
        return;
      }
      panel.draggable = false;
      delete panel.dataset.adminDragArmed;
    });
    armedPanel = null;
  };

  handles.forEach((handle) => {
    if (!(handle instanceof HTMLButtonElement)) {
      return;
    }
    handle.disabled = !dragEnabled;
    handle.setAttribute("aria-disabled", dragEnabled ? "false" : "true");
    if (handle.dataset.adminPanelDragBound === "true") {
      return;
    }
    handle.dataset.adminPanelDragBound = "true";
    handle.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
    });
    const armPanelDrag = (event) => {
      event.stopPropagation();
      const panel = handle.closest(".admin-dashboard-panel");
      if (!(panel instanceof HTMLElement) || !dragEnabled) {
        return;
      }
      clearArmedPanels();
      panel.draggable = true;
      panel.dataset.adminDragArmed = "true";
      armedPanel = panel;
    };
    handle.addEventListener("mousedown", armPanelDrag);
    handle.addEventListener("pointerdown", armPanelDrag);
    handle.addEventListener("keydown", (event) => {
      if (event.key === "Enter" || event.key === " ") {
        armPanelDrag(event);
      }
    });
  });

  if (container.dataset.adminReorderBound === "true") {
    return;
  }
  container.dataset.adminReorderBound = "true";

  const clearDropIndicators = () => {
    container.querySelectorAll(".admin-dashboard-panel.is-drop-before, .admin-dashboard-panel.is-drop-after").forEach((panel) => {
      panel.classList.remove("is-drop-before", "is-drop-after");
    });
  };

  const persistCurrentOrder = () => {
    const currentOrder = Array.from(container.querySelectorAll(".admin-dashboard-panel"))
      .map((panel) => String(panel.dataset.adminPanelKey || "").trim())
      .filter(Boolean);
    setAdminDashboardSectionOrder(currentOrder);
  };

  container.addEventListener("dragstart", (event) => {
    const panel = event.target instanceof Element ? event.target.closest(".admin-dashboard-panel") : null;
    if (!(panel instanceof HTMLElement) || !dragEnabled || panel.dataset.adminDragArmed !== "true") {
      event.preventDefault();
      return;
    }

    draggedPanel = panel;
    draggedPanel.classList.add("is-dragging");
    container.classList.add("is-reordering");
    if (event.dataTransfer) {
      event.dataTransfer.effectAllowed = "move";
      try {
        event.dataTransfer.setData("text/plain", String(panel.dataset.adminPanelKey || ""));
      } catch (error) {}
    }
  });

  container.addEventListener("dragover", (event) => {
    if (!dragEnabled || !(draggedPanel instanceof HTMLElement)) {
      return;
    }

    const targetPanel = event.target instanceof Element ? event.target.closest(".admin-dashboard-panel") : null;
    if (!(targetPanel instanceof HTMLElement) || targetPanel === draggedPanel || !container.contains(targetPanel)) {
      return;
    }

    event.preventDefault();
    const panelRect = targetPanel.getBoundingClientRect();
    const shouldInsertBefore = event.clientY < (panelRect.top + (panelRect.height / 2));
    clearDropIndicators();
    targetPanel.classList.add(shouldInsertBefore ? "is-drop-before" : "is-drop-after");

    if (shouldInsertBefore) {
      if (targetPanel !== draggedPanel.nextElementSibling) {
        container.insertBefore(draggedPanel, targetPanel);
      }
      return;
    }

    if (targetPanel.nextElementSibling !== draggedPanel) {
      container.insertBefore(draggedPanel, targetPanel.nextElementSibling);
    }
  });

  container.addEventListener("drop", (event) => {
    if (!dragEnabled || !(draggedPanel instanceof HTMLElement)) {
      return;
    }
    event.preventDefault();
    clearDropIndicators();
    persistCurrentOrder();
  });

  container.addEventListener("dragend", () => {
    if (draggedPanel instanceof HTMLElement) {
      draggedPanel.classList.remove("is-dragging");
      draggedPanel.draggable = false;
    }
    draggedPanel = null;
    clearDropIndicators();
    container.classList.remove("is-reordering");
    clearArmedPanels();
    persistCurrentOrder();
  });

  container.addEventListener("mouseup", () => {
    if (!draggedPanel) {
      clearArmedPanels();
    }
  });

  container.addEventListener("mouseleave", () => {
    if (!draggedPanel) {
      clearArmedPanels();
    }
  });
}

function getSiteVisitorAnalyticsFilterOptions() {
  return [
    { key: "today", label: "Today" },
    { key: "last7", label: "Last 7 days" },
    { key: "last30", label: "Last 30 days" },
  ];
}

function getSiteVisitorAnalyticsFilterLabel(filterKey = SITE_ANALYTICS_DEFAULT_FILTER) {
  return getSiteVisitorAnalyticsFilterOptions().find((option) => option.key === filterKey)?.label || "Today";
}

function formatSiteVisitorShortId(value, fallback = "Unknown") {
  const normalizedValue = String(value || "").trim();
  if (!normalizedValue) {
    return fallback;
  }

  return normalizedValue.length > 14
    ? `${normalizedValue.slice(0, 6)}…${normalizedValue.slice(-4)}`
    : normalizedValue;
}

function formatSiteVisitorRelativeTime(value) {
  const parsedDate = parseCompletedAtValue(value);
  if (!parsedDate) {
    return "Not available";
  }

  const diffMs = Date.now() - parsedDate.getTime();
  if (diffMs < 15000) {
    return "Just now";
  }
  if (diffMs < 60000) {
    return `${Math.max(1, Math.round(diffMs / 1000))}s ago`;
  }
  if (diffMs < 3600000) {
    return `${Math.max(1, Math.round(diffMs / 60000))}m ago`;
  }
  if (diffMs < 86400000) {
    return `${Math.max(1, Math.round(diffMs / 3600000))}h ago`;
  }

  return formatTimingDateTime(parsedDate);
}

function getTodaySiteVisitorAnalyticsRows(rows = appState.siteVisitorAnalyticsRows) {
  const filteredRows = Array.isArray(rows) ? rows : [];
  const todayStart = new Date();
  todayStart.setHours(0, 0, 0, 0);
  return filteredRows.filter((row) => {
    const occurredAt = parseCompletedAtValue(row?.occurredAt);
    return occurredAt && occurredAt.getTime() >= todayStart.getTime();
  });
}

function getSiteVisitorAnalyticsFriendlyErrorMessage() {
  if (!SITE_ANALYTICS_ENABLED) {
    return "Analytics tracking is currently disabled";
  }
  if (!appState.supabase) {
    return "Analytics are unavailable in this environment.";
  }
  if (appState.siteVisitorAnalyticsTableUnavailable) {
    return "Analytics history is not set up yet. Apply the site analytics migration to populate this dashboard.";
  }
  if (appState.siteVisitorAnalyticsTrackingBlocked) {
    return "Site analytics are currently disabled for this session.";
  }
  return String(appState.siteVisitorAnalyticsError || "").trim();
}

function getSiteVisitorAnalyticsSummary(rows = appState.siteVisitorAnalyticsRows) {
  const todayRows = getTodaySiteVisitorAnalyticsRows(rows);
  const pageViewsToday = todayRows.filter((row) => row.eventType === "page_view");
  const visitorKeys = new Set(todayRows.map((row) => (
    String(row?.visitorId || row?.userId || row?.visitId || row?.id || "").trim()
  )).filter(Boolean));

  return {
    liveVisitors: getActiveSiteVisitorPresenceEntries().length,
    uniqueVisitorsToday: visitorKeys.size,
    pageViewsToday: pageViewsToday.length,
    totalEventsToday: todayRows.length,
  };
}

function getSiteVisitorIdentityLabel(entry) {
  const userId = String(entry?.userId || "").trim();
  if (userId && isAdminUser()) {
    const adminMember = getAdminMemberById(userId);
    if (userId === appState.user?.id) {
      return getDisplayName(
        {
          id: userId,
          username: appState.profile?.username || "",
        },
        { fallbackLabel: "User" },
      );
    }
    return getDisplayName(
      {
        id: userId,
        profileName: adminMember?.profileName || "",
      },
      { fallbackLabel: "User" },
    );
  }

  return `Anonymous • ${formatSiteVisitorShortId(entry?.visitorId, "Visitor")}`;
}

function getSiteVisitorAnalyticsPageLabel(entry) {
  return String(
    entry?.pageLabel
    || entry?.pagePath
    || entry?.pageKey
    || entry?.pageGroup
    || "Unknown",
  ).trim();
}

function formatSiteAnalyticsEventTypeLabel(value = "page_view") {
  return capitalize(normalizeSiteAnalyticsEventType(value).replace(/_/g, " "));
}

function getSiteVisitorAnalyticsUserDisplay(entry) {
  const profileName = String(entry?.profileName || "").trim();
  const userId = String(entry?.userId || "").trim();
  if (profileName || userId) {
    return {
      primary: getDisplayName(
        {
          id: userId,
          profileName,
        },
        { fallbackLabel: "User" },
      ),
      secondary: "",
    };
  }

  if (userId && isAdminUser()) {
    const adminMember = getAdminMemberById(userId);
    return {
      primary: getDisplayName(
        {
          id: userId,
          profileName: adminMember?.profileName || "",
        },
        { fallbackLabel: "User" },
      ),
      secondary: "",
    };
  }

  return { primary: "", secondary: "" };
}

function getSiteVisitorAnalyticsAnonymousDisplay(entry) {
  const userDisplay = getSiteVisitorAnalyticsUserDisplay(entry);
  const visitId = String(entry?.visitId || "").trim();
  const visitorId = String(entry?.visitorId || "").trim();
  const idParts = [];
  if (visitId) {
    idParts.push(`Session ${formatSiteVisitorShortId(visitId, "Session")}`);
  }
  if (visitorId) {
    idParts.push(`Visitor ${formatSiteVisitorShortId(visitorId, "Visitor")}`);
  }

  if (!userDisplay.primary) {
    return {
      primary: idParts.length ? "Anonymous" : "—",
      secondary: idParts.join(" • "),
    };
  }

  return {
    primary: idParts[0] || "—",
    secondary: idParts.slice(1).join(" • "),
  };
}

function renderSiteVisitorAnalyticsCellMarkup(primary = "", secondary = "") {
  const normalizedPrimary = String(primary || "").trim();
  const normalizedSecondary = String(secondary || "").trim();
  if (!normalizedPrimary && !normalizedSecondary) {
    return "—";
  }

  if (!normalizedSecondary) {
    return `<span class="site-visitor-activity-inline">${escapeHtml(normalizedPrimary)}</span>`;
  }

  return `
    <div class="site-visitor-activity-cell">
      <strong>${escapeHtml(normalizedPrimary)}</strong>
      <span>${escapeHtml(normalizedSecondary)}</span>
    </div>
  `;
}

function stopHomeAnnouncementFallbackRotation() {
  if (appState.homeAnnouncementRotationTimeoutId) {
    window.clearTimeout(appState.homeAnnouncementRotationTimeoutId);
    appState.homeAnnouncementRotationTimeoutId = 0;
  }
  if (appState.homeAnnouncementRotationFadeTimeoutId) {
    window.clearTimeout(appState.homeAnnouncementRotationFadeTimeoutId);
    appState.homeAnnouncementRotationFadeTimeoutId = 0;
  }
}

function stepHomeAnnouncementFeedIndex(step = 1) {
  ensureHomeAnnouncementFeedItems();
  const feedItems = getLoadedHomeAnnouncementSlidePaths();
  if (!feedItems.length) {
    appState.homeAnnouncementFeedIndex = 0;
    return null;
  }

  const currentIndex = Math.max(0, Number(appState.homeAnnouncementFeedIndex) || 0);
  appState.homeAnnouncementFeedIndex = ((currentIndex + step) % feedItems.length + feedItems.length) % feedItems.length;
  return feedItems[appState.homeAnnouncementFeedIndex] || feedItems[0] || null;
}

function replaceHomeAnnouncementFeedCard(scope = app, step = 1) {
  const currentCard = scope?.querySelector?.('[data-home-announcement-card="true"]');
  if (!(currentCard instanceof HTMLElement)) {
    stopHomeAnnouncementFallbackRotation();
    return;
  }

  currentCard.classList.add("is-transitioning");
  preloadHomeAnnouncementSlides().then((loadedSlides) => {
    if (!loadedSlides.length) {
      currentCard.classList.remove("is-transitioning");
      stopHomeAnnouncementFallbackRotation();
      return;
    }

    const currentIndex = Math.max(0, Number(appState.homeAnnouncementFeedIndex) || 0);
    const currentSlidePath = getHomeAnnouncementSlidePathForIndex(currentIndex);
    const nextItem = stepHomeAnnouncementFeedIndex(step);
    if (!nextItem || nextItem === currentSlidePath) {
      currentCard.classList.remove("is-transitioning");
      stopHomeAnnouncementFallbackRotation();
      return;
    }

    appState.homeAnnouncementRotationFadeTimeoutId = window.setTimeout(() => {
      const nextCardMarkup = renderHomeAnnouncementCard(getHomeAnnouncementCardData(new Date()));
      const nextCardHost = document.createElement("div");
      nextCardHost.innerHTML = nextCardMarkup.trim();
      const nextCard = nextCardHost.firstElementChild;
      if (!(nextCard instanceof HTMLElement)) {
        currentCard.classList.remove("is-transitioning");
        stopHomeAnnouncementFallbackRotation();
        return;
      }

      nextCard.classList.add("is-entering");
      currentCard.replaceWith(nextCard);
      bindMessageBoardImageFallbacks(scope);
      window.requestAnimationFrame(() => {
        window.requestAnimationFrame(() => {
          nextCard.classList.remove("is-entering");
        });
      });
      bindHomeAnnouncementFallbackRotation(scope);
    }, HOME_ANNOUNCEMENT_ROTATION_FADE_MS);
  }).catch((error) => {
    console.warn("[Cannakan Feed] Could not prepare the next slide for rotation.", error);
    currentCard.classList.remove("is-transitioning");
    stopHomeAnnouncementFallbackRotation();
  });
}

function bindHomeAnnouncementFallbackRotation(scope = app) {
  stopHomeAnnouncementFallbackRotation();
  if (!scope?.querySelector) {
    return;
  }

  const card = scope.querySelector('[data-home-announcement-rotation="true"]');
  if (!(card instanceof HTMLElement)) {
    return;
  }

  ensureHomeAnnouncementFeedItems();
  preloadHomeAnnouncementSlides().then((loadedSlides) => {
    if (!loadedSlides.length) {
      return;
    }

    const normalizedIndex = Math.max(0, Number(card.dataset.homeAnnouncementSequenceIndex) || 0);
    appState.homeAnnouncementFeedIndex = normalizedIndex % loadedSlides.length;

    const scheduleNext = () => {
      if (appState.homeAnnouncementRotationPaused) {
        return;
      }

      if (appState.homeAnnouncementRotationTimeoutId) {
        window.clearTimeout(appState.homeAnnouncementRotationTimeoutId);
        appState.homeAnnouncementRotationTimeoutId = 0;
      }
      const activeDelay = getRandomHomeAnnouncementRotationDelayMs();
      appState.homeAnnouncementRotationTimeoutId = window.setTimeout(() => {
        if (appState.homeAnnouncementRotationPaused) {
          return;
        }

        replaceHomeAnnouncementFeedCard(scope, 1);
      }, activeDelay);
    };

    if (window.matchMedia?.("(hover: hover) and (pointer: fine)")?.matches) {
      card.addEventListener("mouseenter", () => {
        appState.homeAnnouncementRotationPaused = true;
        stopHomeAnnouncementFallbackRotation();
      });

      card.addEventListener("mouseleave", () => {
        appState.homeAnnouncementRotationPaused = false;
        scheduleNext();
      });
    }

    card.addEventListener("touchstart", (event) => {
      const touch = event.changedTouches?.[0];
      if (!touch) {
        return;
      }

      appState.homeAnnouncementTouchStartX = touch.clientX;
      appState.homeAnnouncementTouchStartY = touch.clientY;
      appState.homeAnnouncementTouchStartTime = Date.now();
      appState.homeAnnouncementRotationPaused = true;
      stopHomeAnnouncementFallbackRotation();
    }, { passive: true });

    card.addEventListener("touchend", (event) => {
      const touch = event.changedTouches?.[0];
      if (!touch) {
        appState.homeAnnouncementRotationPaused = false;
        scheduleNext();
        return;
      }

      const deltaX = touch.clientX - appState.homeAnnouncementTouchStartX;
      const deltaY = touch.clientY - appState.homeAnnouncementTouchStartY;
      const elapsed = Date.now() - appState.homeAnnouncementTouchStartTime;
      appState.homeAnnouncementRotationPaused = false;
      if (Math.abs(deltaX) >= 48 && Math.abs(deltaY) <= 60 && elapsed <= 900) {
        replaceHomeAnnouncementFeedCard(scope, deltaX < 0 ? 1 : -1);
        return;
      }

      scheduleNext();
    }, { passive: true });

    card.addEventListener("touchcancel", () => {
      appState.homeAnnouncementRotationPaused = false;
      scheduleNext();
    }, { passive: true });

    scheduleNext();
  }).catch((error) => {
    console.warn("[Cannakan Feed] Could not start slide rotation because the default slides were not ready.", error);
  });
}

function stopAdminAnnouncementPreviewRotation() {
  if (appState.adminAnnouncementPreviewRotationTimeoutId) {
    window.clearTimeout(appState.adminAnnouncementPreviewRotationTimeoutId);
    appState.adminAnnouncementPreviewRotationTimeoutId = 0;
  }
  if (appState.adminAnnouncementPreviewRotationFadeTimeoutId) {
    window.clearTimeout(appState.adminAnnouncementPreviewRotationFadeTimeoutId);
    appState.adminAnnouncementPreviewRotationFadeTimeoutId = 0;
  }
}

function bindAdminAnnouncementPreviewRotation(scope = app) {
  stopAdminAnnouncementPreviewRotation();
  if (!scope?.querySelector) {
    return;
  }

  const card = scope.querySelector('[data-home-announcement-preview-rotation="true"]');
  if (!(card instanceof HTMLElement)) {
    return;
  }

  preloadHomeAnnouncementSlides().then((loadedSlides) => {
    if (loadedSlides.length <= 1) {
      return;
    }

    const image = card.querySelector('[data-home-announcement-image="true"]');
    if (!(image instanceof HTMLImageElement)) {
      return;
    }

    const scheduleNext = () => {
      if (appState.adminAnnouncementPreviewRotationPaused) {
        return;
      }

      if (appState.adminAnnouncementPreviewRotationTimeoutId) {
        window.clearTimeout(appState.adminAnnouncementPreviewRotationTimeoutId);
        appState.adminAnnouncementPreviewRotationTimeoutId = 0;
      }
      appState.adminAnnouncementPreviewRotationTimeoutId = window.setTimeout(() => {
        if (appState.adminAnnouncementPreviewRotationPaused) {
          return;
        }

        const currentIndex = Math.max(0, Number(card.dataset.homeAnnouncementSequenceIndex) || 0) % loadedSlides.length;
        const nextIndex = (currentIndex + 1) % loadedSlides.length;
        const nextSlidePath = loadedSlides[nextIndex];
        if (!nextSlidePath) {
          scheduleNext();
          return;
        }

        card.classList.add("is-transitioning");
        appState.adminAnnouncementPreviewRotationFadeTimeoutId = window.setTimeout(() => {
          image.src = nextSlidePath;
          image.hidden = false;
          image.classList.remove("is-hidden");
          image.dataset.fallbackApplied = "false";
          image.dataset.imageFailed = "false";
          card.dataset.homeAnnouncementSequenceIndex = String(nextIndex);
          appState.adminAnnouncementPreviewSlideIndex = nextIndex;
          card.classList.add("is-entering");
          window.requestAnimationFrame(() => {
            window.requestAnimationFrame(() => {
              card.classList.remove("is-transitioning");
              card.classList.remove("is-entering");
            });
          });
          scheduleNext();
        }, HOME_ANNOUNCEMENT_ROTATION_FADE_MS);
      }, getAdminAnnouncementPreviewRotationDelayMs());
    };

    if (window.matchMedia?.("(hover: hover) and (pointer: fine)")?.matches) {
      card.addEventListener("mouseenter", () => {
        appState.adminAnnouncementPreviewRotationPaused = true;
        stopAdminAnnouncementPreviewRotation();
      });

      card.addEventListener("mouseleave", () => {
        appState.adminAnnouncementPreviewRotationPaused = false;
        scheduleNext();
      });
    }

    appState.adminAnnouncementPreviewRotationPaused = false;
    appState.adminAnnouncementPreviewSlideIndex = Math.max(0, Number(card.dataset.homeAnnouncementSequenceIndex) || 0) % loadedSlides.length;
    scheduleNext();
  }).catch((error) => {
    console.warn("[Cannakan Feed] Could not start the admin announcement preview rotation.", error);
  });
}

function getActiveSiteVisitorPresenceEntries() {
  const cutoffTime = Date.now() - SITE_ANALYTICS_ACTIVE_WINDOW_MS;

  return Object.entries(appState.siteVisitorPresenceState || {})
    .flatMap(([presenceKey, presences]) => {
      const normalizedPresences = Array.isArray(presences) ? presences : [];
      const latestPresence = normalizedPresences
        .map((presence) => ({
          presenceKey,
          visitorId: String(presence?.visitorId || "").trim(),
          visitId: String(presence?.visitId || "").trim(),
          userId: String(presence?.userId || "").trim(),
          pageKey: String(presence?.pageKey || "").trim(),
          pageLabel: String(presence?.pageLabel || "").trim(),
          pagePath: String(presence?.pagePath || "").trim(),
          deviceType: String(presence?.deviceType || "").trim().toLowerCase(),
          browserName: String(presence?.browserName || "").trim(),
          lastSeen: String(presence?.lastSeen || "").trim(),
        }))
        .sort((left, right) => new Date(right.lastSeen || 0).getTime() - new Date(left.lastSeen || 0).getTime())[0];

      if (!latestPresence) {
        return [];
      }

      const seenAt = parseCompletedAtValue(latestPresence.lastSeen);
      if (!seenAt || seenAt.getTime() < cutoffTime) {
        return [];
      }

      return [latestPresence];
    })
    .sort((left, right) => new Date(right.lastSeen || 0).getTime() - new Date(left.lastSeen || 0).getTime());
}

function renderSiteVisitorAnalyticsFilterMarkup() {
  return `
    <div class="site-visitor-analytics-toolbar" aria-label="Site visitor analytics date range">
      ${getSiteVisitorAnalyticsFilterOptions().map((option) => `
        <button
          type="button"
          class="button ${appState.siteVisitorAnalyticsFilter === option.key ? "button-primary" : "button-secondary"}"
          data-site-analytics-filter="${escapeHtml(option.key)}"
        >
          ${escapeHtml(option.label)}
        </button>
      `).join("")}
    </div>
  `;
}

function renderSiteVisitorAnalyticsSummaryMarkup() {
  const summary = getSiteVisitorAnalyticsSummary();
  const isLoading = Boolean(appState.supabase && !appState.siteVisitorAnalyticsLoaded);
  const historyUnavailable = Boolean(
    getSiteVisitorAnalyticsFriendlyErrorMessage()
    && !appState.siteVisitorAnalyticsRows.length
    && (appState.siteVisitorAnalyticsLoaded || !appState.supabase),
  );
  const formatLiveValue = (value) => (isLoading ? "--" : String(value));
  const formatHistoryValue = (value) => (isLoading ? "--" : (historyUnavailable ? "—" : String(value)));

  return `
    <div class="summary-grid admin-overview-grid site-visitor-analytics-summary-grid">
      ${renderAdminOverviewCardMarkup({
        label: "Live Visitors",
        value: formatLiveValue(summary.liveVisitors),
        subtext: "active in the last 5 minutes",
      })}
      ${renderAdminOverviewCardMarkup({
        label: "Visitors Today",
        value: formatHistoryValue(summary.uniqueVisitorsToday),
        subtext: "distinct visitor IDs today",
      })}
      ${renderAdminOverviewCardMarkup({
        label: "Page Views Today",
        value: formatHistoryValue(summary.pageViewsToday),
        subtext: "tracked route views today",
      })}
      ${renderAdminOverviewCardMarkup({
        label: "Total Events Today",
        value: formatHistoryValue(summary.totalEventsToday),
        subtext: "all recorded events today",
      })}
    </div>
  `;
}

function renderSiteVisitorLiveVisitorsCardMarkup() {
  if (!SITE_ANALYTICS_ENABLED) {
    return `
      <section class="meta-card site-visitor-live-card">
        <div class="site-visitor-live-head">
          <div>
            <strong>Live Visitors</strong>
            <p class="muted">Visitors active in the last 5 minutes</p>
          </div>
          <span class="site-visitor-live-count">0</span>
        </div>
        <div class="empty-state">
          <p>Analytics tracking is currently disabled</p>
        </div>
      </section>
    `;
  }
  const activeVisitors = getActiveSiteVisitorPresenceEntries();
  const unavailableMessage = !appState.siteVisitorPresenceAvailable && appState.siteVisitorPresenceError
    ? appState.siteVisitorPresenceError
    : "";

  return `
    <section class="meta-card site-visitor-live-card">
      <div class="site-visitor-live-head">
        <div>
          <strong>Live Visitors</strong>
          <p class="muted">Visitors active in the last 5 minutes</p>
        </div>
        <span class="site-visitor-live-count">${escapeHtml(String(activeVisitors.length))}</span>
      </div>
      ${unavailableMessage ? `
        <div class="empty-state">
          <p>${escapeHtml(unavailableMessage)}</p>
        </div>
      ` : activeVisitors.length ? `
        <div class="site-visitor-live-table-shell">
          <table class="leaderboard-audit-table site-visitor-live-table">
            <thead>
              <tr>
                <th>Visitor</th>
                <th>Session ID</th>
                <th>Page</th>
                <th>Device</th>
                <th>Browser</th>
                <th>Last Seen</th>
              </tr>
            </thead>
            <tbody>
              ${activeVisitors.map((entry) => `
                <tr>
                  <td>${escapeHtml(getSiteVisitorIdentityLabel(entry))}</td>
                  <td>${escapeHtml(formatSiteVisitorShortId(entry.visitId || entry.presenceKey, "Session"))}</td>
                  <td>${escapeHtml(entry.pageLabel || entry.pageKey || "Unknown")}</td>
                  <td>${escapeHtml(capitalize(entry.deviceType || "unknown"))}</td>
                  <td>${escapeHtml(entry.browserName || "Unknown")}</td>
                  <td>${escapeHtml(formatSiteVisitorRelativeTime(entry.lastSeen))}</td>
                </tr>
              `).join("")}
            </tbody>
          </table>
        </div>
      ` : `
        <div class="empty-state">
          <p>No active visitors right now.</p>
        </div>
      `}
    </section>
  `;
}

function renderSiteVisitorRecentActivityMarkup() {
  const rows = (appState.siteVisitorAnalyticsRows || []).slice(0, 50);
  const isLoading = Boolean(appState.supabase && !appState.siteVisitorAnalyticsLoaded);
  const friendlyErrorMessage = getSiteVisitorAnalyticsFriendlyErrorMessage();

  if (isLoading) {
    return `
      <div class="leaderboard-audit-empty-state">
        <strong>Loading analytics</strong>
        <p>Pulling recent site activity for ${escapeHtml(getSiteVisitorAnalyticsFilterLabel(appState.siteVisitorAnalyticsFilter))}.</p>
      </div>
    `;
  }

  if (friendlyErrorMessage && !rows.length) {
    return `
      <div class="leaderboard-audit-empty-state">
        <strong>Analytics unavailable</strong>
        <p>${escapeHtml(friendlyErrorMessage)}</p>
      </div>
    `;
  }

  if (!rows.length) {
    return `
      <div class="leaderboard-audit-empty-state">
        <strong>No visitor activity yet</strong>
        <p>Recent site activity will appear here once analytics events are recorded for this date range.</p>
      </div>
    `;
  }

  return `
    <div class="leaderboard-audit-table-shell">
      <table class="leaderboard-audit-table site-visitor-analytics-table">
        <thead>
          <tr>
            <th>Time</th>
            <th>Event Type</th>
            <th>Page</th>
            <th>User / Email</th>
            <th>Anonymous / Session</th>
          </tr>
        </thead>
        <tbody>
          ${rows.map((row) => {
            const userDisplay = getSiteVisitorAnalyticsUserDisplay(row);
            const anonymousDisplay = getSiteVisitorAnalyticsAnonymousDisplay(row);
            return `
              <tr>
                <td>${escapeHtml(parseCompletedAtValue(row.occurredAt) ? formatTimingDateTime(parseCompletedAtValue(row.occurredAt)) : "Not available")}</td>
                <td>${escapeHtml(formatSiteAnalyticsEventTypeLabel(row.eventType))}</td>
                <td>${escapeHtml(getSiteVisitorAnalyticsPageLabel(row))}</td>
                <td>${renderSiteVisitorAnalyticsCellMarkup(userDisplay.primary, userDisplay.secondary)}</td>
                <td>${renderSiteVisitorAnalyticsCellMarkup(anonymousDisplay.primary, anonymousDisplay.secondary)}</td>
              </tr>
            `;
          }).join("")}
        </tbody>
      </table>
    </div>
  `;
}

