      appState.siteVisitorAnalyticsFilter = nextFilter;
      appState.siteVisitorAnalyticsLoaded = false;
      appState.siteVisitorAnalyticsLoadedFilter = "";
      appState.siteVisitorAnalyticsError = "";
      safeRender();
