function generateAdminCstpReportImageRecord(session = null, kind = "") {
  const normalizedSession = normalizeAdminCstpAssignedSessionRecord(session);
  const normalizedKind = String(kind || "").trim().toLowerCase();
  if (!normalizedSession || !normalizedKind) {
    return null;
  }

  const generatedAt = new Date().toISOString();
  const capturedAt = normalizedKind === "first-germinated"
    ? generatedAt
    : (normalizedSession.completedAt || normalizedSession.reportPreparedAt || generatedAt);

  return {
    kind: normalizedKind,
    label: normalizedKind === "first-germinated" ? "Germination Started" : "Completed Test Snapshot",
    capturedAt,
    generatedAt,
  };
}

function updateAdminCstpReportImageRecord(sessionId = "", kind = "", options = {}) {
  const existingSession = getAdminCstpTestSessionById(sessionId);
  const normalizedKind = String(kind || "").trim().toLowerCase();
  if (!existingSession || !normalizedKind) {
    return null;
  }

  const record = generateAdminCstpReportImageRecord(existingSession, normalizedKind);
  if (!record) {
    return null;
  }

  const nextReportImages = {
    ...(existingSession.reportImages || {}),
    ...(options.reportImages || {}),
  };
  if (normalizedKind === "first-germinated") {
    nextReportImages.firstGerminated = record;
  } else if (normalizedKind === "completed-test-snapshot") {
    nextReportImages.completedTestSnapshot = record;
  }

  return updateAdminCstpAssignedSession(sessionId, {
    ...existingSession,
    reportImages: nextReportImages,
  });
}

function ensureAdminCstpCompletedTestSnapshot(sessionId = "", reason = "") {
  const existingSession = getAdminCstpTestSessionById(sessionId);
  if (!existingSession) {
    return null;
  }

  const normalizedStatus = normalizeAdminCstpTestSessionStatus(existingSession.status);
  const canGenerate = Boolean(existingSession.completedAt || existingSession.reportPreparedAt)
    || ["completed", "report-prepared", "published"].includes(normalizedStatus);
  if (!canGenerate || existingSession.reportImages?.completedTestSnapshot) {
    return existingSession;
  }

  return updateAdminCstpReportImageRecord(sessionId, "completed-test-snapshot", {
    reason,
  }) || existingSession;
}

function buildAdminCstpLabBaseRecordFromCommunication(record = {}) {
  const sourceName = String(record.company || extractLabeledMessageValue(record.message, "Company / Source Name") || record.subject || "Source not provided").trim();
  const variety = String(extractLabeledMessageValue(record.message, "Seed Type / Category") || "").trim();
  const batchLot = String(extractLabeledMessageValue(record.message, "Batch or Lot Info") || "").trim();
  const seedsAvailable = String(extractLabeledMessageValue(record.message, "Approximate Seeds Available") || "").trim();
  const website = String(record.website || extractLabeledMessageValue(record.message, "Website") || "").trim();
  return {
    id: `cstp-lab-${String(record.id || "").trim()}`,
    requestId: String(record.id || "").trim(),
    submittedAt: String(record.submittedAt || record.submitted_at || "").trim(),
    assignedSessionId: "",
    assignedTesterId: "",
    assignedTesterName: "",
    assignedTesterEmail: "",
    assignedAt: "",
    assignedBy: "",
    testPerformedBy: "",
    sourceName,
    contactName: String(record.name || "").trim(),
    email: String(record.email || "").trim(),
    website,
    variety,
    batchLot,
    seedsAvailable,
    message: String(record.message || "").trim(),
    status: "request-received",
    internalNotes: "",
    acceptedAt: "",
    seedsReceivedAt: "",
    testScheduledAt: "",
    testStartedAt: "",
    testCompletedAt: "",
    reportPreparedAt: "",
    publishedAt: "",
    declinedAt: "",
    moreInfoRequestedAt: "",
    testSession: normalizeAdminCstpTestSession({
      sourceName,
      variety,
      batchLot,
    }),
  };
}

function normalizeAdminCstpLabRecord(record = null, fallbackRecord = {}) {
  const source = record && typeof record === "object" && !Array.isArray(record) ? record : {};
  const fallback = fallbackRecord && typeof fallbackRecord === "object" && !Array.isArray(fallbackRecord) ? fallbackRecord : {};
  const id = String(source.id || fallback.id || "").trim();
  if (!id) {
    return null;
  }

  const sourceName = String(source.sourceName || source.source_name || fallback.sourceName || fallback.source_name || "").trim();
  const variety = String(source.variety || fallback.variety || "").trim();
  const batchLot = String(source.batchLot || source.batch_lot || fallback.batchLot || fallback.batch_lot || "").trim();

  return {
    id,
    requestId: String(source.requestId || source.request_id || fallback.requestId || fallback.request_id || "").trim(),
    submittedAt: String(source.submittedAt || source.submitted_at || fallback.submittedAt || fallback.submitted_at || "").trim(),
    assignedSessionId: String(source.assignedSessionId || source.assigned_session_id || fallback.assignedSessionId || fallback.assigned_session_id || "").trim(),
    assignedTesterId: String(source.assignedTesterId || source.assigned_tester_id || fallback.assignedTesterId || fallback.assigned_tester_id || "").trim(),
    assignedTesterName: String(source.assignedTesterName || source.assigned_tester_name || fallback.assignedTesterName || fallback.assigned_tester_name || "").trim(),
    assignedTesterEmail: String(source.assignedTesterEmail || source.assigned_tester_email || fallback.assignedTesterEmail || fallback.assigned_tester_email || "").trim(),
    assignedAt: String(source.assignedAt || source.assigned_at || fallback.assignedAt || fallback.assigned_at || "").trim(),
    assignedBy: String(source.assignedBy || source.assigned_by || fallback.assignedBy || fallback.assigned_by || "").trim(),
    testPerformedBy: String(source.testPerformedBy || source.test_performed_by || fallback.testPerformedBy || fallback.test_performed_by || "").trim(),
    sourceName,
    contactName: String(source.contactName || source.contact_name || fallback.contactName || fallback.contact_name || "").trim(),
    email: String(source.email || fallback.email || "").trim(),
    website: String(source.website || fallback.website || "").trim(),
    variety,
    batchLot,
    seedsAvailable: String(source.seedsAvailable || source.seeds_available || fallback.seedsAvailable || fallback.seeds_available || "").trim(),
    message: String(source.message || fallback.message || "").trim(),
    status: normalizeAdminCstpLabStatus(source.status || fallback.status || ""),
    internalNotes: String(source.internalNotes || source.internal_notes || fallback.internalNotes || fallback.internal_notes || "").trim(),
    acceptedAt: String(source.acceptedAt || source.accepted_at || fallback.acceptedAt || fallback.accepted_at || "").trim(),
    seedsReceivedAt: String(source.seedsReceivedAt || source.seeds_received_at || fallback.seedsReceivedAt || fallback.seeds_received_at || "").trim(),
    testScheduledAt: String(source.testScheduledAt || source.test_scheduled_at || fallback.testScheduledAt || fallback.test_scheduled_at || "").trim(),
    testStartedAt: String(source.testStartedAt || source.test_started_at || fallback.testStartedAt || fallback.test_started_at || "").trim(),
    testCompletedAt: String(source.testCompletedAt || source.test_completed_at || fallback.testCompletedAt || fallback.test_completed_at || "").trim(),
    reportPreparedAt: String(source.reportPreparedAt || source.report_prepared_at || fallback.reportPreparedAt || fallback.report_prepared_at || "").trim(),
    publishedAt: String(source.publishedAt || source.published_at || fallback.publishedAt || fallback.published_at || "").trim(),
    declinedAt: String(source.declinedAt || source.declined_at || fallback.declinedAt || fallback.declined_at || "").trim(),
    moreInfoRequestedAt: String(source.moreInfoRequestedAt || source.more_info_requested_at || fallback.moreInfoRequestedAt || fallback.more_info_requested_at || "").trim(),
    testSession: normalizeAdminCstpTestSession(
      source.testSession || source.test_session || {},
      fallback.testSession || fallback.test_session || {
        sourceName,
        variety,
        batchLot,
      },
    ),
  };
}

function loadAdminCstpLabRecordsFromStorage() {
  try {
    const rawValue = localStorage.getItem(ADMIN_CSTP_LAB_STORAGE_KEY);
    if (!rawValue) {
      return [];
    }
    const parsed = JSON.parse(rawValue);
    if (!Array.isArray(parsed)) {
      return [];
    }
    return parsed
      .map((record) => normalizeAdminCstpLabRecord(record))
      .filter(Boolean);
  } catch (error) {
    console.error("Failed to read CSTP lab records from localStorage", error);
    return [];
  }
}

function saveAdminCstpLabRecordsToStorage(records = []) {
  try {
    localStorage.setItem(ADMIN_CSTP_LAB_STORAGE_KEY, JSON.stringify(records || []));
  } catch (error) {
    console.error("Failed to write CSTP lab records to localStorage", error);
  }
}

function loadAdminCstpTestSessionsFromStorage() {
  try {
    const rawValue = localStorage.getItem(ADMIN_CSTP_TEST_SESSIONS_STORAGE_KEY);
    if (!rawValue) {
      return [];
    }
    const parsed = JSON.parse(rawValue);
    if (!Array.isArray(parsed)) {
      return [];
    }
    return parsed
      .map((record) => normalizeAdminCstpAssignedSessionRecord(record))
      .filter(Boolean);
  } catch (error) {
    console.error("Failed to read CSTP test sessions from localStorage", error);
    return [];
  }
}

function saveAdminCstpTestSessionsToStorage(records = []) {
  try {
    localStorage.setItem(ADMIN_CSTP_TEST_SESSIONS_STORAGE_KEY, JSON.stringify(records || []));
  } catch (error) {
    console.error("Failed to write CSTP test sessions to localStorage", error);
  }
}

function getAdminCstpTestSessions() {
  return loadAdminCstpTestSessionsFromStorage()
    .sort((left, right) => (Date.parse(right.createdAt || "") || 0) - (Date.parse(left.createdAt || "") || 0));
}

function getAdminCstpTestSessionById(sessionId = "") {
  const normalizedSessionId = String(sessionId || "").trim();
  return getAdminCstpTestSessions().find((session) => session.id === normalizedSessionId) || null;
}

function upsertAdminCstpTestSession(record = null) {
  const normalizedRecord = normalizeAdminCstpAssignedSessionRecord(record);
  if (!normalizedRecord) {
    return null;
  }

  const nextRecords = loadAdminCstpTestSessionsFromStorage()
    .filter((entry) => entry.id !== normalizedRecord.id);
  nextRecords.push(normalizedRecord);
  saveAdminCstpTestSessionsToStorage(nextRecords);
  return normalizedRecord;
}

function getAdminCstpTesterById(testerId = "") {
  const normalizedTesterId = String(testerId || "").trim();
  return ADMIN_CSTP_TESTER_OPTIONS.find((tester) => tester.id === normalizedTesterId) || null;
}

function getAdminCstpAssignmentActorLabel() {
  return String(getProfileDisplayName() || "Admin").trim() || "Admin";
}

function assignAdminCstpTester(record = null, testerId = "") {
  const normalizedRecord = normalizeAdminCstpLabRecord(record);
  const tester = getAdminCstpTesterById(testerId);
  if (!normalizedRecord || !tester) {
    return null;
  }

  const timestamp = new Date().toISOString();
  const assignment = {
    assignedTesterId: tester.id,
    assignedTesterName: tester.name,
    assignedTesterEmail: tester.email,
    assignedAt: timestamp,
    assignedBy: getAdminCstpAssignmentActorLabel(),
    testPerformedBy: tester.name,
  };

  const updatedRecord = upsertAdminCstpLabRecord({
    ...normalizedRecord,
    ...assignment,
  });

  const assignedSession = getAdminCstpAssignedSessionForRecord(updatedRecord || normalizedRecord);
  if (assignedSession) {
    updateAdminCstpAssignedSession(assignedSession.id, {
      ...assignedSession,
      ...assignment,
    });
  }

  return updatedRecord;
}

function unassignAdminCstpTester(record = null) {
  const normalizedRecord = normalizeAdminCstpLabRecord(record);
  if (!normalizedRecord) {
    return null;
  }

  const clearedAssignment = {
    assignedTesterId: "",
    assignedTesterName: "",
    assignedTesterEmail: "",
    assignedAt: "",
    assignedBy: "",
    testPerformedBy: "",
  };

  const updatedRecord = upsertAdminCstpLabRecord({
    ...normalizedRecord,
    ...clearedAssignment,
  });

  const assignedSession = getAdminCstpAssignedSessionForRecord(updatedRecord || normalizedRecord);
  if (assignedSession) {
    updateAdminCstpAssignedSession(assignedSession.id, {
      ...assignedSession,
      ...clearedAssignment,
    });
  }

  return updatedRecord;
}

function deleteAdminCstpTestSession(sessionId = "") {
  const normalizedSessionId = String(sessionId || "").trim();
  if (!normalizedSessionId) {
    return false;
  }

  const existingSession = getAdminCstpTestSessionById(normalizedSessionId);
  if (!existingSession) {
    return false;
  }

  const nextRecords = loadAdminCstpTestSessionsFromStorage()
    .filter((entry) => entry.id !== normalizedSessionId);
  saveAdminCstpTestSessionsToStorage(nextRecords);

  getAdminCstpLabRecords()
    .filter((record) => String(record.assignedSessionId || "").trim() === normalizedSessionId)
    .forEach((record) => {
      upsertAdminCstpLabRecord({
        ...record,
        assignedSessionId: "",
      });
    });

  return true;
}

function createAssignedAdminCstpTestSession(record = null) {
  const normalizedRecord = normalizeAdminCstpLabRecord(record);
  if (!normalizedRecord) {
    return null;
  }
  if (normalizedRecord.assignedSessionId) {
    return getAdminCstpTestSessionById(normalizedRecord.assignedSessionId);
  }

  const timestamp = new Date().toISOString();
  const sessionId = `cstp-session-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`;
  const sessionStatus = ["test-scheduled", "active-test", "completed", "report-prepared", "published"].includes(normalizedRecord.status)
    ? "scheduled"
    : "draft";
  const createdSession = upsertAdminCstpTestSession({
    id: sessionId,
    requestId: normalizedRecord.requestId,
    sourceName: normalizedRecord.sourceName,
    variety: normalizedRecord.variety,
    batchLot: normalizedRecord.batchLot,
    sampleSize: normalizedRecord.testSession?.sampleSize || normalizedRecord.seedsAvailable || "",
    deviceId: normalizedRecord.testSession?.deviceId || "",
    testMethod: normalizedRecord.testSession?.testMethod || "",
    temperature: normalizedRecord.testSession?.temperature || "",
    seedAgeTrackingEnabled: Boolean(normalizedRecord.testSession?.seedAgeTrackingEnabled),
    seedAgeMode: normalizeSeedAgeMode(normalizedRecord.testSession?.seedAgeMode || "") || null,
    sessionSeedAgeYears: normalizeSeedAgeYears(normalizedRecord.testSession?.sessionSeedAgeYears),
    systemType: "KAN",
    unitId: normalizedRecord.testSession?.deviceId || "A",
    status: sessionStatus,
    startedAt: "",
    completedAt: "",
    reportPreparedAt: "",
    publishedAt: "",
    certificationPublished: false,
    assignedTesterId: normalizedRecord.assignedTesterId || "",
    assignedTesterName: normalizedRecord.assignedTesterName || "",
    assignedTesterEmail: normalizedRecord.assignedTesterEmail || "",
    assignedAt: normalizedRecord.assignedAt || "",
    assignedBy: normalizedRecord.assignedBy || "",
    testPerformedBy: normalizedRecord.testPerformedBy || normalizedRecord.assignedTesterName || "",
    germinatedCount: normalizedRecord.testSession?.germinatedCount || "",
    finalGerminationPercent: normalizedRecord.testSession?.finalGerminationPercent || "",
    totalGerminationTime: normalizedRecord.testSession?.totalGerminationTime || "",
    qualificationResult: normalizedRecord.testSession?.qualificationResult || "",
    observations: normalizedRecord.testSession?.observations || "",
    sessionImages: [],
    cstpDeviceImages: normalizeAdminCstpDeviceImages(),
    partitions: buildAdminCstpDefaultPartitions({
      systemType: "KAN",
      sourceName: normalizedRecord.sourceName,
      variety: normalizedRecord.variety,
      sampleSize: normalizedRecord.testSession?.sampleSize || normalizedRecord.seedsAvailable || "",
      germinatedCount: normalizedRecord.testSession?.germinatedCount || "",
    }),
    createdAt: timestamp,
  });

  upsertAdminCstpLabRecord({
    ...normalizedRecord,
    assignedSessionId: createdSession?.id || "",
  });

  return createdSession;
}

function disconnectAssignedAdminCstpTestSession(record = null) {
  const normalizedRecord = normalizeAdminCstpLabRecord(record);
  if (!normalizedRecord?.assignedSessionId) {
    return null;
  }

  const existingSession = getAdminCstpTestSessionById(normalizedRecord.assignedSessionId);
  if (existingSession) {
    upsertAdminCstpTestSession({
      ...existingSession,
      requestId: "",
    });
  }

  return upsertAdminCstpLabRecord({
    ...normalizedRecord,
    assignedSessionId: "",
  });
}

function getAdminCstpLabRecords() {
  if (!appState.adminCstpLabRecordsLoaded) {
    appState.adminCstpLabRecords = loadAdminCstpLabRecordsFromStorage();
    appState.adminCstpLabRecordsLoaded = true;
  }

  const storedRecords = Array.isArray(appState.adminCstpLabRecords) ? appState.adminCstpLabRecords : [];
  const baseRecords = getAdminCommunicationRows("cstp")
    .map((record) => buildAdminCstpLabBaseRecordFromCommunication(record))
    .filter(Boolean);
  const storedMap = new Map(storedRecords.map((record) => [record.id, record]));
  const mergedRecords = baseRecords.map((baseRecord) => (
    normalizeAdminCstpLabRecord(storedMap.get(baseRecord.id) || {}, baseRecord)
  ));

  storedRecords.forEach((storedRecord) => {
    if (!baseRecords.some((baseRecord) => baseRecord.id === storedRecord.id)) {
      mergedRecords.push(normalizeAdminCstpLabRecord(storedRecord));
    }
  });

  return mergedRecords
    .filter(Boolean)
    .sort((left, right) => {
      const rightTimestamp = Date.parse(
        right.publishedAt
        || right.reportPreparedAt
        || right.testCompletedAt
        || right.testStartedAt
        || right.seedsReceivedAt
        || right.acceptedAt
        || right.submittedAt
        || "",
      ) || 0;
      const leftTimestamp = Date.parse(
        left.publishedAt
        || left.reportPreparedAt
        || left.testCompletedAt
        || left.testStartedAt
        || left.seedsReceivedAt
        || left.acceptedAt
        || left.submittedAt
        || "",
      ) || 0;
      return rightTimestamp - leftTimestamp;
    });
}

function upsertAdminCstpLabRecord(record = null) {
  const normalizedRecord = normalizeAdminCstpLabRecord(record);
  if (!normalizedRecord) {
    return null;
  }

  const nextRecords = loadAdminCstpLabRecordsFromStorage()
    .filter((entry) => entry.id !== normalizedRecord.id);
  nextRecords.push(normalizedRecord);
  saveAdminCstpLabRecordsToStorage(nextRecords);
  appState.adminCstpLabRecords = nextRecords;
  appState.adminCstpLabRecordsLoaded = true;
  return normalizedRecord;
}

function getFilteredAdminCstpLabRecords(statusFilter = "all") {
  const normalizedFilter = String(statusFilter || "all").trim().toLowerCase();
  return getAdminCstpLabRecords()
    .filter((record) => {
      if (normalizedFilter === "all") {
        return true;
      }
      if (record.status === normalizedFilter) {
        return true;
      }

      const certificationState = getAdminCstpLabCertificationState(record);
      if (!certificationState.isPublishedSeal) {
        return false;
      }

      if (normalizedFilter === "gold" || normalizedFilter === "silver") {
        return certificationState.qualificationResult === normalizedFilter;
      }
      if (normalizedFilter === "active-certification") {
        return certificationState.isActive;
      }
      if (normalizedFilter === "expiring-soon") {
        return certificationState.isExpiringSoon;
      }
      if (normalizedFilter === "expired") {
        return certificationState.isExpired;
      }
      return false;
    });
}

function getAdminCstpAssignedSessionForRecord(record = null) {
  const normalizedRecord = normalizeAdminCstpLabRecord(record);
  if (!normalizedRecord?.assignedSessionId) {
    return null;
  }

  const assignedSession = getAdminCstpTestSessionById(normalizedRecord.assignedSessionId);
  if (!assignedSession) {
    return null;
  }

  if (String(assignedSession.requestId || "").trim() !== String(normalizedRecord.requestId || "").trim()) {
    return null;
  }

  return assignedSession;
}

function canPrepareAdminCstpReport(session = null) {
  const normalizedStatus = normalizeAdminCstpTestSessionStatus(session?.status || "");
  return Boolean(
    session
    && (
      Boolean(session.completedAt)
      || ["completed", "report-prepared", "published"].includes(normalizedStatus)
    ),
  );
}

function canPublishAdminCstpCertification(session = null) {
  const normalizedStatus = normalizeAdminCstpTestSessionStatus(session?.status || "");
  return Boolean(
    session
    && Boolean(session.completedAt)
    && Boolean(session.reportPreparedAt)
    && isAdminCstpCertificationEligible(session.qualificationResult)
    && normalizedStatus !== "published"
    && session.certificationPublished !== true,
  );
}

function publishAdminCstpCertification(sessionId = "") {
  const existingSession = getAdminCstpTestSessionById(sessionId);
  if (!existingSession || !canPublishAdminCstpCertification(existingSession)) {
    return null;
  }

  const timestamp = existingSession.publishedAt || new Date().toISOString();
  const updatedSession = updateAdminCstpAssignedSession(sessionId, {
    ...existingSession,
    status: "published",
    publishedAt: timestamp,
    certificationPublished: true,
  });

  const linkedRecord = getAdminCstpLabRecords().find((record) => record.assignedSessionId === sessionId) || null;
  if (linkedRecord) {
    upsertAdminCstpLabRecord({
      ...linkedRecord,
      status: "published",
      publishedAt: linkedRecord.publishedAt || timestamp,
    });
  }

  return updatedSession;
}

function prepareAdminCstpReportSession(sessionId = "") {
  const existingSession = getAdminCstpTestSessionById(sessionId);
  if (!existingSession) {
    return null;
  }

  const normalizedStatus = normalizeAdminCstpTestSessionStatus(existingSession.status || "");
  if (!canPrepareAdminCstpReport(existingSession) || normalizedStatus === "published" || normalizedStatus === "report-prepared") {
    return existingSession;
  }

  const timestamp = existingSession.reportPreparedAt || new Date().toISOString();
  const updatedSession = updateAdminCstpAssignedSession(sessionId, {
    ...existingSession,
    status: "report-prepared",
    reportPreparedAt: timestamp,
  });
  ensureAdminCstpCompletedTestSnapshot(sessionId, "prepare-report-session");
  return updatedSession;
}

function getAdminCstpLabQualificationResult(record = null) {
  const assignedSession = getAdminCstpAssignedSessionForRecord(record);
  if (assignedSession?.qualificationResult) {
    return normalizeAdminCstpQualificationResult(assignedSession.qualificationResult);
  }
  return normalizeAdminCstpQualificationResult(record?.testSession?.qualificationResult || "");
}

function getAdminCstpLabCertificationState(record = null) {
  const assignedSession = getAdminCstpAssignedSessionForRecord(record);
  const qualificationResult = assignedSession?.qualificationResult
    || record?.testSession?.qualificationResult
    || "";
  const publishedAt = assignedSession?.publishedAt
    || record?.publishedAt
    || "";
  return getAdminCstpCertificationLifecycleState({
    qualificationResult,
    publishedAt,
  });
}

function getAdminCstpCertificationMetrics() {
  return getAdminCstpTestSessions().reduce((metrics, session) => {
    const certificationState = getAdminCstpCertificationLifecycleState(session);
    if (!certificationState.isPublishedSeal) {
      return metrics;
    }

    metrics.totalPublishedSeals += 1;
    if (certificationState.qualificationResult === "gold") {
      metrics.goldSeals += 1;
    } else if (certificationState.qualificationResult === "silver") {
      metrics.silverSeals += 1;
    }
    if (certificationState.isExpiringSoon) {
      metrics.expiringSoon += 1;
    }
    if (certificationState.isExpired) {
      metrics.expired += 1;
    }
    return metrics;
  }, {
    totalPublishedSeals: 0,
    goldSeals: 0,
    silverSeals: 0,
    expiringSoon: 0,
    expired: 0,
  });
}

function normalizeComparableSourceKey(value = "") {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function getPublishedAdminCstpCertificationForSourceIdentity(sourceIdentity = {}) {
  return getLatestPublishedAdminCstpCertificationForSourceIdentity(sourceIdentity, { activeOnly: true });
}

function getLatestPublishedAdminCstpCertificationForSourceIdentity(sourceIdentity = {}, options = {}) {
  const { activeOnly = false } = options;
  const candidateKeys = new Set(
    [
      sourceIdentity?.sourceId,
      sourceIdentity?.sourceName,
      sourceIdentity?.sourceLabel,
    ]
      .map((value) => normalizeComparableSourceKey(value))
      .filter(Boolean),
  );
  if (!candidateKeys.size) {
    return null;
  }

  const matchingSession = getAdminCstpTestSessions()
    .filter((session) => (
      session?.certificationPublished === true
      && (!activeOnly || getAdminCstpCertificationLifecycleState(session).isActive)
      && candidateKeys.has(normalizeComparableSourceKey(session?.sourceName || ""))
    ))
    .sort((left, right) => (Date.parse(right.publishedAt || "") || 0) - (Date.parse(left.publishedAt || "") || 0))[0] || null;

  if (!matchingSession) {
    return null;
  }

  return {
    id: matchingSession.id,
    qualificationResult: normalizeAdminCstpQualificationResult(matchingSession.qualificationResult),
    sourceName: matchingSession.sourceName,
    variety: matchingSession.variety,
    batchLot: matchingSession.batchLot,
    deviceId: matchingSession.deviceId,
    testMethod: matchingSession.testMethod,
    temperature: matchingSession.temperature,
    startedAt: matchingSession.startedAt,
    publishedAt: matchingSession.publishedAt,
    sampleSize: matchingSession.sampleSize,
    completedAt: matchingSession.completedAt,
    germinatedCount: matchingSession.germinatedCount,
    finalGerminationPercent: matchingSession.finalGerminationPercent,
    totalGerminationTime: matchingSession.totalGerminationTime,
    observations: matchingSession.observations,
    seedAgeTrackingEnabled: Boolean(matchingSession.seedAgeTrackingEnabled),
    seedAgeMode: normalizeSeedAgeMode(matchingSession.seedAgeMode || ""),
    sessionSeedAgeYears: normalizeSeedAgeYears(matchingSession.sessionSeedAgeYears),
    seedAgeSummaryKey: getSessionSeedAgeMetadata(matchingSession).summaryKey === "disabled"
      ? "unknown"
      : getSessionSeedAgeMetadata(matchingSession).summaryKey,
    seedAgeSummaryLabel: buildSeedAgeDisplayLabel(matchingSession, {
      samePrefix: "Same age",
      mixedLabel: "Mixed ages",
      unknownLabel: "Unknown",
      disabledLabel: DEFAULT_UNTRACKED_SEED_AGE_LABEL,
    }),
  };
}

function getPublishedAdminCstpCertificationForSource(sourceProfile = {}) {
  return getPublishedAdminCstpCertificationForSourceIdentity({
    sourceId: sourceProfile?.id || "",
    sourceName: sourceProfile?.name || "",
  });
}

function getLatestPublishedAdminCstpCertificationForSource(sourceProfile = {}, options = {}) {
  return getLatestPublishedAdminCstpCertificationForSourceIdentity({
    sourceId: sourceProfile?.id || "",
    sourceName: sourceProfile?.name || "",
  }, options);
}

function getPublishedAdminCstpCertificationForSnapshot(snapshot = null) {
  if (!snapshot) {
    return null;
  }

  const managedSource = getManagedSourceRecordForSnapshot(snapshot, { includeHidden: true });
  return getPublishedAdminCstpCertificationForSourceIdentity({
    sourceId: managedSource?.id || snapshot?.sourceId || "",
    sourceName: managedSource?.name || snapshot?.sourceName || "",
    sourceLabel: snapshot?.sourceName || "",
  });
}

function syncAdminCstpLabRecordFromAssignedSession(record = null, session = null) {
  const normalizedRecord = normalizeAdminCstpLabRecord(record);
  const normalizedSession = normalizeAdminCstpAssignedSessionRecord(session);
  if (!normalizedRecord || !normalizedSession) {
    return null;
  }

  let nextStatus = normalizedRecord.status;
  if (normalizedSession.status === "active-test") {
    nextStatus = "active-test";
  } else if (normalizedSession.status === "completed") {
    nextStatus = "completed";
  } else if (normalizedSession.status === "report-prepared") {
    nextStatus = "report-prepared";
  } else if (normalizedSession.status === "published") {
    nextStatus = "published";
  } else if (normalizedSession.status === "scheduled" && ["request-received", "accepted-awaiting-seeds", "seeds-received"].includes(normalizedRecord.status)) {
    nextStatus = "test-scheduled";
  }

  return upsertAdminCstpLabRecord({
    ...normalizedRecord,
    assignedSessionId: normalizedSession.id,
    assignedTesterId: normalizedSession.assignedTesterId || normalizedRecord.assignedTesterId,
    assignedTesterName: normalizedSession.assignedTesterName || normalizedRecord.assignedTesterName,
    assignedTesterEmail: normalizedSession.assignedTesterEmail || normalizedRecord.assignedTesterEmail,
    assignedAt: normalizedSession.assignedAt || normalizedRecord.assignedAt,
    assignedBy: normalizedSession.assignedBy || normalizedRecord.assignedBy,
    testPerformedBy: normalizedSession.testPerformedBy || normalizedRecord.testPerformedBy,
    status: nextStatus,
    testStartedAt: normalizedSession.startedAt || normalizedRecord.testStartedAt,
    testCompletedAt: normalizedSession.completedAt || normalizedRecord.testCompletedAt,
    reportPreparedAt: normalizedSession.reportPreparedAt
      || (normalizedSession.status === "report-prepared" ? (normalizedRecord.reportPreparedAt || new Date().toISOString()) : normalizedRecord.reportPreparedAt),
    publishedAt: normalizedSession.publishedAt || normalizedRecord.publishedAt,
    testSession: {
      ...normalizedRecord.testSession,
      sourceName: normalizedSession.sourceName,
      variety: normalizedSession.variety,
      batchLot: normalizedSession.batchLot,
      sampleSize: normalizedSession.sampleSize,
      deviceId: normalizedSession.deviceId,
      seedAgeTrackingEnabled: Boolean(normalizedSession.seedAgeTrackingEnabled),
      seedAgeMode: normalizeSeedAgeMode(normalizedSession.seedAgeMode || ""),
      sessionSeedAgeYears: normalizeSeedAgeYears(normalizedSession.sessionSeedAgeYears),
      testMethod: normalizedSession.testMethod,
      temperature: normalizedSession.temperature,
      startDateTime: normalizedSession.startedAt || normalizedRecord.testSession?.startDateTime || "",
      observations: normalizedSession.observations,
      germinatedCount: normalizedSession.germinatedCount,
      finalGerminationPercent: normalizedSession.finalGerminationPercent,
      totalGerminationTime: normalizedSession.totalGerminationTime,
      qualificationResult: normalizedSession.qualificationResult,
      assignedTesterId: normalizedSession.assignedTesterId || normalizedRecord.testSession?.assignedTesterId || "",
      assignedTesterName: normalizedSession.assignedTesterName || normalizedRecord.testSession?.assignedTesterName || "",
      assignedTesterEmail: normalizedSession.assignedTesterEmail || normalizedRecord.testSession?.assignedTesterEmail || "",
      assignedAt: normalizedSession.assignedAt || normalizedRecord.testSession?.assignedAt || "",
      assignedBy: normalizedSession.assignedBy || normalizedRecord.testSession?.assignedBy || "",
      testPerformedBy: normalizedSession.testPerformedBy || normalizedRecord.testSession?.testPerformedBy || "",
    },
  });
}

function renderAdminCstpLabStatusPillMarkup(status = "") {
  const normalizedStatus = normalizeAdminCstpLabStatus(status);
  return `<span class="admin-source-review-status-pill is-${escapeHtml(normalizedStatus)}">${escapeHtml(getAdminCstpLabStatusLabel(normalizedStatus))}</span>`;
}

function renderAdminCstpTestSessionStatusPillMarkup(status = "") {
  const normalizedStatus = normalizeAdminCstpTestSessionStatus(status);
  return `<span class="admin-source-review-status-pill is-${escapeHtml(normalizedStatus)}">${escapeHtml(getAdminCstpTestSessionStatusLabel(normalizedStatus))}</span>`;
}

function renderAdminCstpCertificationMetricCardMarkup(label = "", value = 0) {
  return `
    <article class="meta-card admin-cstp-metric-card">
      <span class="stat-label">${escapeHtml(label)}</span>
      <strong>${escapeHtml(String(value))}</strong>
    </article>
  `;
}

function renderAdminCstpCertificationMetricsMarkup() {
  const metrics = getAdminCstpCertificationMetrics();
  return `
    <div class="summary-grid admin-cstp-metrics-grid">
      ${renderAdminCstpCertificationMetricCardMarkup("Total Published Seals", metrics.totalPublishedSeals)}
      ${renderAdminCstpCertificationMetricCardMarkup("Gold Seals", metrics.goldSeals)}
      ${renderAdminCstpCertificationMetricCardMarkup("Silver Seals", metrics.silverSeals)}
      ${renderAdminCstpCertificationMetricCardMarkup("Expiring Soon", metrics.expiringSoon)}
      ${renderAdminCstpCertificationMetricCardMarkup("Expired", metrics.expired)}
    </div>
  `;
}

function renderAdminCstpLabFiltersMarkup(activeStatus = "all") {
  return ADMIN_CSTP_LAB_STATUS_OPTIONS.map((option) => `
    <button
      type="button"
      class="source-directory-filter-pill ${option.key === activeStatus ? "is-active" : ""}"
      data-admin-cstp-lab-filter="${escapeHtml(option.key)}"
      aria-pressed="${option.key === activeStatus ? "true" : "false"}"
    >
      ${escapeHtml(option.label)}
    </button>
  `).join("");
}

function renderAdminCstpCertificationStatePillMarkup(state = null) {
  if (!state?.isPublishedSeal) {
    return "";
  }
  const qualificationLabel = getAdminCstpQualificationLabel(state.qualificationResult);
  const toneClass = state.qualificationResult === "gold"
    ? "is-gold"
    : (state.qualificationResult === "silver" ? "is-silver" : "");
  const stateClass = state.isExpired
    ? "is-expired"
    : (state.isExpiringSoon ? "is-expiring" : "is-active");
  const label = state.isExpired
    ? `${qualificationLabel} Expired`
    : (state.isExpiringSoon
      ? `${qualificationLabel} Expiring Soon`
      : `${qualificationLabel} Active Certification`);
  const tooltipLabel = state.isExpiringSoon
    ? "Expiring Soon"
    : (state.isActive ? "Active Certification" : qualificationLabel);
  const tooltipCopy = getCstpTooltipCopy(tooltipLabel);
  return `<span class="admin-cstp-certification-pill ${toneClass} ${stateClass}"${tooltipCopy ? ` title="${escapeHtml(tooltipCopy)}"` : ""}>${escapeHtml(label)}</span>`;
}

function normalizeAdminCstpRequestQueueStatus(status = "") {
  const normalizedStatus = String(status || "all").trim().toLowerCase();
  return ADMIN_CSTP_REQUEST_QUEUE_STATUS_OPTIONS.some((option) => option.key === normalizedStatus)
    ? normalizedStatus
    : "all";
}

function getAdminCstpRequestQueueStatusLabel(status = "") {
  const normalizedStatus = normalizeAdminCstpRequestQueueStatus(status);
  return ADMIN_CSTP_REQUEST_QUEUE_STATUS_OPTIONS.find((option) => option.key === normalizedStatus)?.label || "All Active";
}

function normalizeAdminCstpRequestQueueRecord(row = null) {
  if (!row || typeof row !== "object" || Array.isArray(row)) {
    return null;
  }

  const id = String(row.id || "").trim();
  if (!id) {
    return null;
  }

  return {
    id,
    sourceId: String(row.source_id || row.sourceId || "").trim(),
    contactName: String(row.contact_name || row.contactName || "").trim(),
    contactEmail: String(row.contact_email || row.contactEmail || "").trim(),
    website: String(row.website || "").trim(),
    varietyName: String(row.variety_name || row.varietyName || "").trim(),
    seedType: String(row.seed_type || row.seedType || "").trim(),
    breederName: String(row.breeder_name || row.breederName || "").trim(),
    batchLot: String(row.batch_lot || row.batchLot || "").trim(),
    requestedSeedCount: Number.isFinite(Number(row.requested_seed_count || row.requestedSeedCount))
      ? Number(row.requested_seed_count || row.requestedSeedCount)
      : null,
    requestMessage: String(row.request_message || row.requestMessage || "").trim(),
    status: normalizeAdminCstpRequestQueueStatus(row.status || "received"),
    archived: row.archived === true,
    createdAt: String(row.created_at || row.createdAt || "").trim(),
    updatedAt: String(row.updated_at || row.updatedAt || "").trim(),
  };
}

function buildAdminCstpRequestQueueUrl(options = {}) {
  const filter = {
    ...appState.adminCstpRequestQueueFilter,
    ...(options || {}),
  };
  const status = normalizeAdminCstpRequestQueueStatus(filter.status);
  const page = Math.max(1, Number(filter.page) || 1);
  const pageSize = Math.max(1, Math.min(ADMIN_CSTP_REQUEST_QUEUE_PAGE_SIZE, Number(filter.pageSize) || ADMIN_CSTP_REQUEST_QUEUE_PAGE_SIZE));
  const params = new URLSearchParams({
    page: String(page),
    pageSize: String(pageSize),
    sortBy: "created_at",
    sortDirection: "desc",
  });

  if (status === "archived") {
    params.set("archived", "true");
  } else {
    params.set("includeArchived", filter.includeArchived === true ? "true" : "false");
    if (status !== "all") {
      params.set("status", status);
    }
  }

  return `${ADMIN_CSTP_REQUEST_QUEUE_API_PATH}?${params.toString()}`;
}

function buildAdminCstpRequestDetailUrl(requestId = "") {
  return `${ADMIN_CSTP_REQUEST_DETAIL_API_PATH}?requestId=${encodeURIComponent(String(requestId || "").trim())}`;
}

async function loadAdminCstpRequestQueue(options = {}) {
  if (!isAdminUser()) {
    return [];
  }

  const accessToken = getCurrentAuthAccessToken();
  if (!accessToken) {
    throw new Error("Sign in as an admin to load the CSTP request queue.");
  }

  const response = await fetch(buildAdminCstpRequestQueueUrl(options), {
    method: "GET",
    headers: {
      Accept: "application/json",
      Authorization: `Bearer ${accessToken}`,
    },
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok || payload?.ok !== true) {
    const detail = payload?.error || payload?.message || payload?.status || `Request queue returned ${response.status}.`;
    throw new Error(detail);
  }

  appState.adminCstpRequestQueueFilter = {
    ...appState.adminCstpRequestQueueFilter,
    ...(payload.filters || {}),
    page: Number(payload.pagination?.page || options.page || appState.adminCstpRequestQueueFilter.page) || 1,
    pageSize: Number(payload.pagination?.pageSize || options.pageSize || appState.adminCstpRequestQueueFilter.pageSize) || ADMIN_CSTP_REQUEST_QUEUE_PAGE_SIZE,
    status: normalizeAdminCstpRequestQueueStatus(options.status || appState.adminCstpRequestQueueFilter.status),
  };

  return (Array.isArray(payload.requests) ? payload.requests : [])
    .map((row) => normalizeAdminCstpRequestQueueRecord(row))
    .filter(Boolean);
}

async function loadAdminCstpRequestDetail(requestId = "") {
  const normalizedRequestId = String(requestId || "").trim();
  if (!isAdminUser()) {
    return null;
  }
  if (!normalizedRequestId) {
    throw new Error("Choose a CSTP request before loading details.");
  }

  const accessToken = getCurrentAuthAccessToken();
  if (!accessToken) {
    throw new Error("Sign in as an admin to load CSTP request details.");
  }

  const response = await fetch(buildAdminCstpRequestDetailUrl(normalizedRequestId), {
    method: "GET",
    headers: {
      Accept: "application/json",
      Authorization: `Bearer ${accessToken}`,
    },
  });
  const payload = await response.json().catch(() => ({}));
  if (response.status === 404) {
    const error = new Error(payload?.error || "CSTP request was not found.");
    error.code = "CSTP_REQUEST_DETAIL_NOT_FOUND";
    throw error;
  }
  if (!response.ok || payload?.ok !== true) {
    const detail = payload?.error || payload?.message || payload?.status || `Request detail returned ${response.status}.`;
    throw new Error(detail);
  }

  return normalizeAdminCstpRequestQueueRecord(payload.request);
}

async function refreshAdminCstpRequestQueue(options = {}) {
  const { force = false } = options || {};
  if (!isAdminUser()) {
    appState.adminCstpRequestQueueRows = [];
    appState.adminCstpRequestQueueLoaded = true;
    appState.adminCstpRequestQueueLoading = false;
    appState.adminCstpRequestQueueError = "";
    return [];
  }

  if (!force && appState.adminCstpRequestQueueLoaded && !appState.adminCstpRequestQueueRefreshPromise) {
    return appState.adminCstpRequestQueueRows;
  }

  if (!force && appState.adminCstpRequestQueueRefreshPromise) {
    return appState.adminCstpRequestQueueRefreshPromise;
  }

  appState.adminCstpRequestQueueLoading = true;
  appState.adminCstpRequestQueueError = "";
  const refreshPromise = (async () => {
    try {
      const rows = await loadAdminCstpRequestQueue(options);
      appState.adminCstpRequestQueueRows = rows;
      appState.adminCstpRequestQueueLoaded = true;
      appState.adminCstpRequestQueueError = "";
      return rows;
    } catch (error) {
      appState.adminCstpRequestQueueRows = [];
      appState.adminCstpRequestQueueLoaded = true;
      appState.adminCstpRequestQueueError = error?.message || "Could not load CSTP requests.";
      return [];
    } finally {
      appState.adminCstpRequestQueueLoading = false;
    }
  })();

  appState.adminCstpRequestQueueRefreshPromise = refreshPromise;

  try {
    return await refreshPromise;
  } finally {
    appState.adminCstpRequestQueueRefreshPromise = null;
  }
}

async function refreshAdminCstpRequestDetail(requestId = appState.adminCstpRequestDetailSelectedId) {
  const normalizedRequestId = String(requestId || "").trim();
  if (!normalizedRequestId) {
    appState.adminCstpRequestDetailSelectedId = "";
    appState.adminCstpRequestDetailRecord = null;
    appState.adminCstpRequestDetailLoading = false;
    appState.adminCstpRequestDetailError = "";
    return null;
  }

  appState.adminCstpRequestDetailSelectedId = normalizedRequestId;
  appState.adminCstpRequestDetailLoading = true;
  appState.adminCstpRequestDetailError = "";

  try {
    const record = await loadAdminCstpRequestDetail(normalizedRequestId);
    appState.adminCstpRequestDetailRecord = record;
    appState.adminCstpRequestDetailError = "";
    return record;
  } catch (error) {
    appState.adminCstpRequestDetailRecord = null;
    appState.adminCstpRequestDetailError = error?.message || "Could not load CSTP request details.";
    return null;
  } finally {
    appState.adminCstpRequestDetailLoading = false;
  }
}

function getAdminCstpRequestStatusActionConfigs(record = null) {
  const status = normalizeAdminCstpRequestQueueStatus(record?.status || "");
  if (!record || record.archived || status === "archived") {
    return [];
  }

  const actions = [];
  if (status === "received") {
    actions.push(
      { nextStatus: "accepted", label: "Accept Request", tone: "secondary" },
      { nextStatus: "declined", label: "Decline Request", tone: "warning" },
    );
  }
  if (status === "accepted") {
    actions.push({ nextStatus: "awaiting_seeds", label: "Mark Awaiting Seeds", tone: "secondary" });
  }
  if (status === "awaiting_seeds") {
    actions.push({ nextStatus: "accepted", label: "Return to Accepted", tone: "secondary" });
  }

  actions.push({ nextStatus: "archived", label: "Archive Request", tone: "warning" });
  return actions;
}

async function updateAdminCstpRequestStatus(requestId = "", currentStatus = "", nextStatus = "") {
  const normalizedRequestId = String(requestId || "").trim();
  const normalizedCurrentStatus = normalizeAdminCstpRequestQueueStatus(currentStatus);
  const normalizedNextStatus = normalizeAdminCstpRequestQueueStatus(nextStatus);
  if (!normalizedRequestId || normalizedCurrentStatus === "all" || normalizedNextStatus === "all") {
    throw new Error("Choose a valid CSTP request status action.");
  }

  const accessToken = getCurrentAuthAccessToken();
  if (!accessToken) {
    throw new Error("Sign in as an admin to update CSTP request status.");
  }

  const response = await fetch(ADMIN_CSTP_REQUEST_STATUS_UPDATE_API_PATH, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Accept: "application/json",
      Authorization: `Bearer ${accessToken}`,
    },
    body: JSON.stringify({
      requestId: normalizedRequestId,
      currentStatus: normalizedCurrentStatus,
      nextStatus: normalizedNextStatus,
      eventNotes: `Status changed from ${normalizedCurrentStatus} to ${normalizedNextStatus} in the internal admin UI.`,
      metadata: {
        uiSurface: "admin_cstp_request_detail",
      },
    }),
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok || payload?.ok !== true) {
    const detail = payload?.error || payload?.message || payload?.status || `Request status update returned ${response.status}.`;
    throw new Error(detail);
  }

  return payload;
}

async function updateAdminCstpRequestStatusAndRender(scope = app, requestId = "", currentStatus = "", nextStatus = "") {
  appState.adminCstpRequestStatusSaving = true;
  appState.adminCstpRequestStatusMessage = "";
  appState.adminCstpRequestStatusError = "";
  appState.adminCstpTestCreateMessage = "";
  appState.adminCstpTestCreateError = "";
  renderAdminCstpRequestQueueInto(scope);

  try {
    const result = await updateAdminCstpRequestStatus(requestId, currentStatus, nextStatus);
    const auditCommitted = result?.transaction?.auditMutationCommitted === true;
    appState.adminCstpRequestStatusMessage = auditCommitted
      ? "Request status updated."
      : "Request status updated. Audit event requires admin review.";
    await Promise.all([
      refreshAdminCstpRequestQueue({ force: true, ...appState.adminCstpRequestQueueFilter }),
      refreshAdminCstpRequestDetail(requestId),
    ]);
  } catch (error) {
    appState.adminCstpRequestStatusError = error?.message || "Could not update CSTP request status.";
  } finally {
    appState.adminCstpRequestStatusSaving = false;
    renderAdminCstpRequestQueueInto(scope);
  }
}

function canCreateAdminCstpTestFromRequest(record = null) {
  const status = normalizeAdminCstpRequestQueueStatus(record?.status || "");
  return Boolean(
    record
    && !record.archived
    && (status === "accepted" || status === "awaiting_seeds")
  );
}

async function createAdminCstpTestFromRequest(record = null) {
  if (!canCreateAdminCstpTestFromRequest(record)) {
    throw new Error("This CSTP request is not in an eligible state for test creation.");
  }

  const accessToken = getCurrentAuthAccessToken();
  if (!accessToken) {
    throw new Error("Sign in as an admin to create CSTP tests.");
  }

  const response = await fetch(ADMIN_CSTP_TEST_CREATE_API_PATH, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Accept: "application/json",
      Authorization: `Bearer ${accessToken}`,
    },
    body: JSON.stringify({
      requestId: record.id,
      sourceId: record.sourceId || undefined,
      status: "pending",
      internalState: "created_from_request_detail",
      eventNotes: "CSTP test created from the internal request detail workflow.",
      metadata: {
        uiSurface: "admin_cstp_request_detail",
        requestStatus: record.status,
        varietyName: record.varietyName,
        breederName: record.breederName,
        batchLot: record.batchLot,
      },
    }),
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok || payload?.ok !== true) {
    const detail = payload?.error || payload?.message || payload?.status || `CSTP test creation returned ${response.status}.`;
    throw new Error(detail);
  }

  return payload;
}

async function createAdminCstpTestFromRequestAndRender(scope = app, requestId = "") {
  const record = appState.adminCstpRequestDetailRecord;
  if (!record || record.id !== requestId) {
    appState.adminCstpTestCreateError = "Reload the CSTP request before creating a test.";
    renderAdminCstpRequestQueueInto(scope);
    return;
  }

  appState.adminCstpTestCreateSaving = true;
  appState.adminCstpTestCreateMessage = "";
  appState.adminCstpTestCreateError = "";
  renderAdminCstpRequestQueueInto(scope);

  try {
    const result = await createAdminCstpTestFromRequest(record);
    const testId = String(result?.test?.record?.id || "").trim();
    const auditCommitted = result?.transaction?.auditMutationCommitted === true;
    appState.adminCstpTestCreateMessage = [
      testId ? `CSTP test created: ${testId}.` : "CSTP test created.",
      auditCommitted ? "" : "Audit event requires admin review.",
    ].filter(Boolean).join(" ");
    await Promise.all([
      refreshAdminCstpRequestDetail(requestId),
      refreshAdminCstpTestsList({ force: true, ...appState.adminCstpTestManagementFilter }),
    ]);
  } catch (error) {
    appState.adminCstpTestCreateError = error?.message || "Could not create CSTP test.";
  } finally {
    appState.adminCstpTestCreateSaving = false;
    renderAdminCstpRequestQueueInto(scope);
    renderAdminCstpTestManagementInto(scope);
  }
}

function normalizeAdminCstpTestManagementStatus(status = "") {
  const normalizedStatus = String(status || "all").trim().toLowerCase();
  return ADMIN_CSTP_TEST_MANAGEMENT_STATUS_OPTIONS.some((option) => option.key === normalizedStatus)
    ? normalizedStatus
    : "all";
}

function getAdminCstpTestManagementStatusLabel(status = "") {
  const normalizedStatus = normalizeAdminCstpTestManagementStatus(status);
  return ADMIN_CSTP_TEST_MANAGEMENT_STATUS_OPTIONS.find((option) => option.key === normalizedStatus)?.label || "All Active";
}

function normalizeAdminCstpTestManagementRecord(row = null) {
  if (!row || typeof row !== "object" || Array.isArray(row)) {
    return null;
  }

  const id = String(row.id || "").trim();
  if (!id) {
    return null;
  }

  return {
    id,
    sourceId: String(row.source_id || row.sourceId || "").trim(),
    requestId: String(row.request_id || row.requestId || "").trim(),
    status: normalizeAdminCstpTestManagementStatus(row.status || "pending"),
    internalState: String(row.internal_state || row.internalState || "").trim(),
    createdBy: String(row.created_by || row.createdBy || "").trim(),
    archived: row.archived === true,
    startedAt: String(row.started_at || row.startedAt || "").trim(),
    completedAt: String(row.completed_at || row.completedAt || "").trim(),
    reportPreparedAt: String(row.report_prepared_at || row.reportPreparedAt || "").trim(),
    publishedAt: String(row.published_at || row.publishedAt || "").trim(),
    createdAt: String(row.created_at || row.createdAt || "").trim(),
    updatedAt: String(row.updated_at || row.updatedAt || "").trim(),
  };
}

