function applyAdminCstpLabAction(record = null, actionKey = "") {
  if (!record) {
    return null;
  }

  const timestamp = new Date().toISOString();
  const nextRecord = normalizeAdminCstpLabRecord(record) || record;
  const assignedSession = getAdminCstpAssignedSessionForRecord(nextRecord);
  switch (String(actionKey || "").trim()) {
    case "accept":
      nextRecord.status = "accepted-awaiting-seeds";
      nextRecord.acceptedAt = nextRecord.acceptedAt || timestamp;
      break;
    case "decline":
      nextRecord.status = "declined";
      nextRecord.declinedAt = timestamp;
      break;
    case "request-more-info": {
      const existingNotes = String(nextRecord.internalNotes || "").trim();
      const noteLine = `Requested more info on ${formatAdminTimestamp(timestamp)}.`;
      nextRecord.moreInfoRequestedAt = timestamp;
      nextRecord.internalNotes = existingNotes ? `${existingNotes}\n${noteLine}` : noteLine;
      break;
    }
    case "seeds-received":
      nextRecord.status = "seeds-received";
      nextRecord.seedsReceivedAt = timestamp;
      break;
    case "schedule-test":
      nextRecord.status = "test-scheduled";
      nextRecord.testScheduledAt = timestamp;
      if (assignedSession) {
        upsertAdminCstpTestSession({
          ...assignedSession,
          status: "scheduled",
        });
      }
      break;
    case "start-test":
      nextRecord.status = "active-test";
      nextRecord.testStartedAt = timestamp;
      if (!nextRecord.testSession.startDateTime) {
        nextRecord.testSession.startDateTime = formatAdminTimestamp(timestamp);
      }
      if (assignedSession) {
        upsertAdminCstpTestSession({
          ...assignedSession,
          status: "active-test",
          startedAt: assignedSession.startedAt || timestamp,
        });
      }
      break;
    case "mark-completed":
      nextRecord.status = "completed";
      nextRecord.testCompletedAt = timestamp;
      if (assignedSession) {
        upsertAdminCstpTestSession({
          ...assignedSession,
          status: "completed",
          completedAt: assignedSession.completedAt || timestamp,
        });
        ensureAdminCstpCompletedTestSnapshot(assignedSession.id, "lab-mark-completed");
      }
      break;
    case "prepare-report":
      if (assignedSession && canPrepareAdminCstpReport(assignedSession)) {
        nextRecord.status = "report-prepared";
        nextRecord.reportPreparedAt = nextRecord.reportPreparedAt || timestamp;
        upsertAdminCstpTestSession({
          ...assignedSession,
          status: "report-prepared",
          reportPreparedAt: assignedSession.reportPreparedAt || timestamp,
        });
        ensureAdminCstpCompletedTestSnapshot(assignedSession.id, "lab-prepare-report");
      }
      break;
    case "publish":
      if (["gold", "silver"].includes(normalizeAdminCstpQualificationResult(nextRecord.testSession.qualificationResult))) {
        nextRecord.status = "published";
        nextRecord.publishedAt = nextRecord.publishedAt || timestamp;
      }
      break;
    default:
      break;
  }

  return upsertAdminCstpLabRecord(nextRecord);
}

function bindAdminCstpRequestQueue(scope = app) {
  if (!scope?.querySelectorAll || !isAdminUser()) {
    return;
  }

  /*
   * Internal admin-only CSTP UI boundary.
   * This request queue is API-driven and intentionally avoids direct Supabase
   * access, frontend lifecycle decisions, audit construction, and public CSTP
   * report/certification exposure.
   */
  scope.querySelectorAll("[data-admin-cstp-request-queue-status]").forEach((button) => {
    if (!(button instanceof HTMLButtonElement) || button.dataset.adminCstpRequestQueueBound === "true") {
      return;
    }
    button.dataset.adminCstpRequestQueueBound = "true";
    button.addEventListener("click", () => {
      appState.adminCstpRequestQueueFilter.status = normalizeAdminCstpRequestQueueStatus(button.dataset.adminCstpRequestQueueStatus || "all");
      appState.adminCstpRequestQueueFilter.page = 1;
      clearAdminCstpRequestDetail(app);
      refreshAdminCstpRequestQueueAndRender(app, {
        status: appState.adminCstpRequestQueueFilter.status,
        page: 1,
      });
    });
  });

  scope.querySelectorAll("[data-admin-cstp-request-queue-page]").forEach((button) => {
    if (!(button instanceof HTMLButtonElement) || button.dataset.adminCstpRequestQueueBound === "true") {
      return;
    }
    button.dataset.adminCstpRequestQueueBound = "true";
    button.addEventListener("click", () => {
      const nextPage = Math.max(1, Number(button.dataset.adminCstpRequestQueuePage) || 1);
      appState.adminCstpRequestQueueFilter.page = nextPage;
      clearAdminCstpRequestDetail(app);
      refreshAdminCstpRequestQueueAndRender(app, {
        page: nextPage,
        status: appState.adminCstpRequestQueueFilter.status,
      });
    });
  });

  const refreshButton = scope.querySelector("[data-admin-cstp-request-queue-refresh='true']");
  if (refreshButton instanceof HTMLButtonElement && refreshButton.dataset.adminCstpRequestQueueBound !== "true") {
    refreshButton.dataset.adminCstpRequestQueueBound = "true";
    refreshButton.addEventListener("click", () => {
      refreshAdminCstpRequestQueueAndRender(app, {
        ...appState.adminCstpRequestQueueFilter,
      });
    });
  }

  scope.querySelectorAll("[data-admin-cstp-request-detail-open]").forEach((button) => {
    if (!(button instanceof HTMLButtonElement) || button.dataset.adminCstpRequestQueueBound === "true") {
      return;
    }
    button.dataset.adminCstpRequestQueueBound = "true";
    button.addEventListener("click", () => {
      const requestId = String(button.dataset.adminCstpRequestDetailOpen || "").trim();
      refreshAdminCstpRequestDetailAndRender(app, requestId);
    });
  });

  scope.querySelectorAll("[data-admin-cstp-request-detail-back]").forEach((button) => {
    if (!(button instanceof HTMLButtonElement) || button.dataset.adminCstpRequestQueueBound === "true") {
      return;
    }
    button.dataset.adminCstpRequestQueueBound = "true";
    button.addEventListener("click", () => {
      clearAdminCstpRequestDetail(app);
    });
  });

  scope.querySelectorAll("[data-admin-cstp-request-status-action]").forEach((button) => {
    if (!(button instanceof HTMLButtonElement) || button.dataset.adminCstpRequestQueueBound === "true") {
      return;
    }
    button.dataset.adminCstpRequestQueueBound = "true";
    button.addEventListener("click", () => {
      const requestId = String(button.dataset.adminCstpRequestId || "").trim();
      const currentStatus = normalizeAdminCstpRequestQueueStatus(button.dataset.adminCstpRequestCurrentStatus || "");
      const nextStatus = normalizeAdminCstpRequestQueueStatus(button.dataset.adminCstpRequestStatusAction || "");
      if (nextStatus === "archived" && !window.confirm("Archive this CSTP request? It will leave the internal workflow queue but remain available through the Archived filter.")) {
        return;
      }
      updateAdminCstpRequestStatusAndRender(app, requestId, currentStatus, nextStatus);
    });
  });

  scope.querySelectorAll("[data-admin-cstp-test-create-from-request]").forEach((button) => {
    if (!(button instanceof HTMLButtonElement) || button.dataset.adminCstpRequestQueueBound === "true") {
      return;
    }
    button.dataset.adminCstpRequestQueueBound = "true";
    button.addEventListener("click", () => {
      const requestId = String(button.dataset.adminCstpTestCreateFromRequest || "").trim();
      createAdminCstpTestFromRequestAndRender(app, requestId);
    });
  });
}

