function saveAdminTutorialCollectionAssignmentsForTutorial(tutorialId = "", selectedCollectionIds = []) {
  const normalizedTutorialId = String(tutorialId || "").trim();
  if (!normalizedTutorialId) {
    return;
  }

  const selectedSet = new Set(normalizeLearnTutorialTextList(selectedCollectionIds));
  getLearnTutorialCollections().forEach((collection) => {
    const currentTutorialIds = normalizeLearnTutorialTextList(collection.tutorialIds);
    const currentSet = new Set(currentTutorialIds);
    const shouldBeAssigned = selectedSet.has(collection.id);
    const isAssigned = currentSet.has(normalizedTutorialId);
    if (shouldBeAssigned === isAssigned) {
      return;
    }

    const nextTutorialIds = shouldBeAssigned
      ? [...currentTutorialIds, normalizedTutorialId]
      : currentTutorialIds.filter((collectionTutorialId) => collectionTutorialId !== normalizedTutorialId);
    saveAdminTutorialCollectionDraft(collection.id, {
      tutorialIds: nextTutorialIds,
      custom: Boolean(collection.custom),
    });
  });
}

function saveAdminTutorialFormDraft(form, statusOverride = "") {
  if (!(form instanceof HTMLFormElement)) {
    return "";
  }

  const tutorialId = form.dataset.adminTutorialForm || "";
  const formData = new FormData(form);
  const relatedTutorialIds = formData.getAll("relatedTutorialIds").map((value) => String(value || "").trim()).filter(Boolean);
  const collectionIds = formData.getAll("collectionIds").map((value) => String(value || "").trim()).filter(Boolean);
  const videoProvider = normalizeTutorialVideoProvider(formData.get("videoProvider"));
  const featuredOrderValue = Number(formData.get("featuredOrder"));
  const visibilityStatus = getTutorialVisibilityStatus({
    status: statusOverride || formData.get("visibilityStatus"),
    scheduled: formData.get("scheduled") === "on",
  });
  saveAdminTutorialDraft(tutorialId, {
    title: String(formData.get("title") || "").trim(),
    description: String(formData.get("description") || "").trim(),
    categoryId: normalizeTutorialCategoryId(formData.get("categoryId")),
    duration: String(formData.get("duration") || "").trim(),
    difficulty: String(formData.get("difficulty") || "Beginner").trim(),
    status: visibilityStatus,
    visibilityStatus,
    audience: normalizeLearnAudience(formData.get("audience")),
    isPublic: formData.get("isPublic") === "on",
    visibilityNote: String(formData.get("visibilityNote") || "").trim(),
    qrLabel: String(formData.get("qrLabel") || "").trim(),
    qrDescription: String(formData.get("qrDescription") || "").trim(),
    qrCampaignTag: String(formData.get("qrCampaignTag") || "").trim(),
    qrDestinationUrl: String(formData.get("qrDestinationUrl") || "").trim(),
    scheduled: formData.get("scheduled") === "on",
    releaseDate: String(formData.get("releaseDate") || "").trim(),
    comingSoonLabel: String(formData.get("comingSoonLabel") || "").trim(),
    thumbnailUrl: String(formData.get("thumbnailUrl") || "").trim(),
    order: Math.max(1, Number(formData.get("order")) || 1),
    featured: formData.get("featured") === "on",
    featuredOrder: Number.isFinite(featuredOrderValue) && featuredOrderValue > 0 ? featuredOrderValue : "",
    featuredLabel: String(formData.get("featuredLabel") || "").trim(),
    onboardingPriority: formData.get("onboardingPriority") === "on",
    relatedTutorialIds,
    videoProvider,
    cloudflareStreamId: String(formData.get("cloudflareStreamId") || "").trim(),
    mp4Url: String(formData.get("mp4Url") || "").trim(),
    embedUrl: String(formData.get("embedUrl") || "").trim(),
    posterUrl: String(formData.get("posterUrl") || "").trim(),
    transcriptUrl: String(formData.get("transcriptUrl") || "").trim(),
    captionsUrl: String(formData.get("captionsUrl") || "").trim(),
    video: {
      videoProvider,
      provider: videoProvider,
      mp4Url: String(formData.get("mp4Url") || "").trim(),
      cloudflareStreamId: String(formData.get("cloudflareStreamId") || "").trim(),
      embedUrl: String(formData.get("embedUrl") || "").trim(),
      transcriptUrl: String(formData.get("transcriptUrl") || "").trim(),
      captionsUrl: String(formData.get("captionsUrl") || "").trim(),
      posterUrl: String(formData.get("posterUrl") || "").trim(),
      poster: String(formData.get("posterUrl") || "").trim(),
    },
  });
  saveAdminTutorialCollectionAssignmentsForTutorial(tutorialId, collectionIds);
  return tutorialId;
}

function saveAdminTutorialCollectionFormDraft(form) {
  if (!(form instanceof HTMLFormElement)) {
    return "";
  }

  const collectionId = String(form.dataset.adminCollectionForm || "").trim();
  const formData = new FormData(form);
  const tutorialIds = formData.getAll("tutorialIds").map((value) => String(value || "").trim()).filter(Boolean);
  saveAdminTutorialCollectionDraft(collectionId, {
    title: String(formData.get("title") || "").trim(),
    subtitle: String(formData.get("subtitle") || "").trim(),
    description: String(formData.get("description") || "").trim(),
    posterUrl: String(formData.get("posterUrl") || "").trim(),
    tutorialIds,
    featured: formData.get("featured") === "on",
    visibilityStatus: getTutorialVisibilityStatus({
      status: formData.get("visibilityStatus"),
      scheduled: formData.get("scheduled") === "on",
    }),
    audience: normalizeLearnAudience(formData.get("audience")),
    isPublic: formData.get("isPublic") === "on",
    visibilityNote: String(formData.get("visibilityNote") || "").trim(),
    qrLabel: String(formData.get("qrLabel") || "").trim(),
    qrDescription: String(formData.get("qrDescription") || "").trim(),
    qrCampaignTag: String(formData.get("qrCampaignTag") || "").trim(),
    qrDestinationUrl: String(formData.get("qrDestinationUrl") || "").trim(),
    status: getTutorialVisibilityStatus({
      status: formData.get("visibilityStatus"),
      scheduled: formData.get("scheduled") === "on",
    }),
    scheduled: formData.get("scheduled") === "on",
    releaseDate: String(formData.get("releaseDate") || "").trim(),
    comingSoonLabel: String(formData.get("comingSoonLabel") || "").trim(),
    order: Math.max(1, Number(formData.get("order")) || 1),
    difficulty: String(formData.get("difficulty") || "Beginner").trim(),
    estimatedDuration: String(formData.get("estimatedDuration") || "").trim(),
    custom: collectionId.startsWith("custom-learning-path-"),
  });
  return collectionId;
}

function bindAdminTutorialManagementSection(scope = app) {
  bindLearnShareControls(scope);

  scope.querySelector("[data-admin-collection-create='true']")?.addEventListener("click", () => {
    createAdminTutorialCollectionDraft();
    refreshAdminTutorialManagementSection();
  });

  scope.querySelectorAll("[data-admin-collection-edit]").forEach((button) => {
    button.addEventListener("click", () => {
      appState.adminTutorialCollectionEditingId = button.dataset.adminCollectionEdit || "";
      refreshAdminTutorialManagementSection();
    });
  });

  scope.querySelectorAll("[data-admin-collection-preview]").forEach((button) => {
    button.addEventListener("click", () => {
      const form = button.closest(".admin-tutorial-collection-editor")?.querySelector("[data-admin-collection-form]");
      if (form instanceof HTMLFormElement) {
        const collectionId = saveAdminTutorialCollectionFormDraft(form);
        appState.adminTutorialCollectionEditingId = collectionId;
        refreshAdminTutorialManagementSection();
        openLearnCollectionModal(collectionId);
        return;
      }
      openLearnCollectionModal(button.dataset.adminCollectionPreview || "");
    });
  });

  scope.querySelectorAll("[data-admin-collection-form]").forEach((form) => {
    form.addEventListener("submit", (event) => {
      event.preventDefault();
      const collectionId = saveAdminTutorialCollectionFormDraft(form);
      appState.adminTutorialCollectionEditingId = collectionId;
      refreshAdminTutorialManagementSection();
    });
  });

  scope.querySelectorAll("[data-admin-tutorial-edit]").forEach((button) => {
    button.addEventListener("click", () => {
      appState.adminTutorialEditingId = button.dataset.adminTutorialEdit || "";
      refreshAdminTutorialManagementSection();
    });
  });

  scope.querySelectorAll("[data-admin-tutorial-move]").forEach((button) => {
    if (!(button instanceof HTMLButtonElement)) {
      return;
    }
    button.addEventListener("click", () => {
      const moved = moveAdminTutorialOrder(button.dataset.adminTutorialId || "", button.dataset.adminTutorialMove || "");
      if (moved) {
        refreshAdminTutorialManagementSection();
      }
    });
  });

  scope.querySelectorAll("[data-admin-tutorial-preview]").forEach((button) => {
    button.addEventListener("click", () => {
      const form = button.closest("[data-admin-tutorial-editor]")?.querySelector("[data-admin-tutorial-form]");
      if (button.dataset.adminTutorialPreviewForm === "true" && form instanceof HTMLFormElement) {
        const selectedStatus = normalizeTutorialPublishStatus(form.elements.visibilityStatus?.value || "coming-soon");
        const currentStatus = normalizeTutorialPublishStatus(form.dataset.adminTutorialCurrentStatus || "coming-soon");
        const previewStatus = selectedStatus === "published" && currentStatus !== "published"
          ? "draft"
          : selectedStatus;
        const tutorialId = saveAdminTutorialFormDraft(form, previewStatus);
        appState.adminTutorialEditingId = tutorialId;
        refreshAdminTutorialManagementSection();
        openLearnTutorialModal(tutorialId, { source: "Tutorial Management preview" });
        return;
      }
      openLearnTutorialModal(button.dataset.adminTutorialPreview || "", { source: "Tutorial Management preview" });
    });
  });

  scope.querySelectorAll("[data-admin-tutorial-reset]").forEach((button) => {
    button.addEventListener("click", () => {
      resetAdminTutorialDraft(button.dataset.adminTutorialReset || "");
      refreshAdminTutorialManagementSection();
    });
  });

  scope.querySelectorAll("[data-admin-tutorial-form]").forEach((form) => {
    form.addEventListener("submit", (event) => {
      event.preventDefault();
      const statusOverride = event.submitter instanceof HTMLElement
        ? event.submitter.dataset.adminTutorialSaveStatus || ""
        : "";
      const tutorialId = saveAdminTutorialFormDraft(form, statusOverride);
      appState.adminTutorialEditingId = tutorialId;
      refreshAdminTutorialManagementSection();
    });
  });
}

