function renderSeedVaultPanelIntoSection(seedVaultSection) {
  if (!(seedVaultSection instanceof HTMLElement)) {
    return;
  }

  const entryIds = new Set((appState.seedVaultEntries || []).map((entry) => String(entry.id || "").trim()).filter(Boolean));
  getSeedVaultExpandedEntryIds().forEach((entryId) => {
    if (!entryIds.has(entryId)) {
      appState.seedVaultExpandedEntryIds.delete(entryId);
    }
  });
  seedVaultSection.innerHTML = renderMySeedVaultPanelMarkup(appState.seedVaultEntries || []);
  hydrateAppIconSlots(seedVaultSection);
  normalizeSectionHeaderLayouts(seedVaultSection);
  applySupplyStatusToSessionEntryButtons(seedVaultSection);
}

function bindSeedVaultPanelControls(seedVaultSection, renderSeedVaultSection = () => {}) {
  if (!(seedVaultSection instanceof HTMLElement) || seedVaultSection.dataset.seedVaultPanelBound === "true") {
    return;
  }

  seedVaultSection.dataset.seedVaultPanelBound = "true";
  seedVaultSection.addEventListener("click", async (event) => {
    const target = event.target;
    if (!(target instanceof Element)) {
      return;
    }

    const addButton = target.closest("[data-seed-vault-add='true']");
    if (addButton) {
      event.preventDefault();
      openSeedVaultEntryModal();
      return;
    }

    const toggleButton = target.closest("[data-seed-vault-toggle]");
    if (toggleButton) {
      event.preventDefault();
      const entryId = String(toggleButton.getAttribute("data-seed-vault-toggle") || "").trim();
      const expandedEntryIds = getSeedVaultExpandedEntryIds();
      if (expandedEntryIds.has(entryId)) {
        expandedEntryIds.delete(entryId);
      } else if (entryId) {
        expandedEntryIds.add(entryId);
      }
      renderSeedVaultSection();
      return;
    }

    const editButton = target.closest("[data-seed-vault-edit]");
    if (editButton) {
      event.preventDefault();
      const entryId = String(editButton.getAttribute("data-seed-vault-edit") || "").trim();
      const entry = (appState.seedVaultEntries || []).find((candidate) => candidate.id === entryId);
      if (entry) {
        openSeedVaultEntryModal(entry);
      }
      return;
    }

    const favoriteButton = target.closest("[data-seed-vault-favorite]");
    if (favoriteButton) {
      event.preventDefault();
      const entryId = String(favoriteButton.getAttribute("data-seed-vault-favorite") || "").trim();
      const entry = (appState.seedVaultEntries || []).find((candidate) => candidate.id === entryId);
      await updateSeedVaultEntryFlag(entryId, { isFavorite: !entry?.isFavorite });
      return;
    }

    const archiveButton = target.closest("[data-seed-vault-archive]");
    if (archiveButton) {
      event.preventDefault();
      const entryId = String(archiveButton.getAttribute("data-seed-vault-archive") || "").trim();
      const entry = (appState.seedVaultEntries || []).find((candidate) => candidate.id === entryId);
      const nextArchived = !entry?.isArchived;
      await updateSeedVaultEntryFlag(entryId, {
        isArchived: nextArchived,
        archivedAt: nextArchived ? new Date().toISOString() : "",
      });
      return;
    }

    const startSessionButton = target.closest("[data-seed-vault-start-session]");
    if (startSessionButton) {
      event.preventDefault();
      const entryId = String(startSessionButton.getAttribute("data-seed-vault-start-session") || "").trim();
      startNewSessionFromSeedVaultEntry(entryId);
      return;
    }

    const deleteButton = target.closest("[data-seed-vault-delete]");
    if (deleteButton) {
      event.preventDefault();
      const entryId = String(deleteButton.getAttribute("data-seed-vault-delete") || "").trim();
      await deleteSeedVaultEntry(entryId);
    }
  });

  seedVaultSection.addEventListener("input", (event) => {
    const target = event.target;
    if (!(target instanceof HTMLInputElement) || target.getAttribute("data-seed-vault-search") !== "true") {
      return;
    }

    appState.seedVaultSearchQuery = target.value || "";
    renderSeedVaultSection();
    const nextSearch = seedVaultSection.querySelector("[data-seed-vault-search='true']");
    if (nextSearch instanceof HTMLInputElement) {
      nextSearch.focus({ preventScroll: true });
      const valueLength = nextSearch.value.length;
      nextSearch.setSelectionRange(valueLength, valueLength);
    }
  });

  seedVaultSection.addEventListener("change", (event) => {
    const target = event.target;
    if (!(target instanceof HTMLSelectElement)) {
      return;
    }

    if (target.getAttribute("data-seed-vault-favorite-filter") === "true") {
      appState.seedVaultFavoriteFilter = normalizeSeedVaultFavoriteFilter(target.value);
      renderSeedVaultSection();
      return;
    }

    if (target.getAttribute("data-seed-vault-status-filter") === "true") {
      appState.seedVaultStatusFilter = normalizeSeedVaultStatusFilter(target.value);
      renderSeedVaultSection();
      return;
    }

    if (target.getAttribute("data-seed-vault-source-filter") === "true") {
      appState.seedVaultSourceFilter = normalizeSeedVaultDropdownFilter(target.value);
      renderSeedVaultSection();
      return;
    }

    if (target.getAttribute("data-seed-vault-type-filter") === "true") {
      appState.seedVaultTypeFilter = normalizeSeedVaultDropdownFilter(target.value);
      renderSeedVaultSection();
      return;
    }

    if (target.getAttribute("data-seed-vault-sex-filter") === "true") {
      appState.seedVaultSexFilter = normalizeSeedVaultDropdownFilter(target.value);
      renderSeedVaultSection();
      return;
    }

    if (target.getAttribute("data-seed-vault-sort") === "true") {
      appState.seedVaultSort = normalizeSeedVaultSort(target.value);
      renderSeedVaultSection();
    }
  });
}

function formatPrivateAnalyticsNumber(value = 0) {
  return Math.max(0, Number(value) || 0).toLocaleString();
}

function formatPrivateAnalyticsPercent(value = null, fallback = "Not enough data") {
  return value === null || value === undefined || !Number.isFinite(Number(value))
    ? fallback
    : `${String(Number(Number(value).toFixed(1))).replace(/\.0$/, "")}%`;
}

function formatPrivateAnalyticsDuration(value = null) {
  return formatDurationMsShort(value) || "Not enough data";
}

function formatPrivateAnalyticsDateLabel(value = "", fallback = "No activity yet") {
  const parsedDate = parseCompletedAtValue(value);
  return parsedDate ? formatPublicMemberJoinedDateLabel(parsedDate.toISOString()) : fallback;
}

function getPrivateAnalyticsCompletedSessions(sessions = []) {
  return sortSessionsNewestFirst((sessions || []).filter(isCompletedValidSessionForAnalytics));
}

function getPrivateAnalyticsActiveSessions(sessions = []) {
  return sortActiveSessionsNewestFirst(
    (sessions || []).filter((session) => normalizeGrowSessionLifecycleState(session) === "active"),
  );
}

function getPrivateAnalyticsSessionDate(session = null) {
  return parseCompletedAtValue(
    session?.completedAt
    || session?.completed_at
    || getSessionStartedAtIso(session)
    || session?.createdAt
    || session?.created_at
    || "",
  );
}

function buildPrivateAnalyticsMonthlyRows(sessions = []) {
  const monthBuckets = new Map();
  (sessions || []).forEach((session) => {
    const date = getPrivateAnalyticsSessionDate(session);
    if (!date) {
      return;
    }
    const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}`;
    const existing = monthBuckets.get(key) || {
      key,
      label: new Intl.DateTimeFormat("en-US", { month: "short", year: "numeric" }).format(date),
      count: 0,
      sortTime: new Date(date.getFullYear(), date.getMonth(), 1).getTime(),
    };
    existing.count += 1;
    monthBuckets.set(key, existing);
  });

  const rows = [...monthBuckets.values()]
    .sort((left, right) => left.sortTime - right.sortTime)
    .slice(-6);
  const maxCount = Math.max(...rows.map((row) => row.count), 1);
  return rows.map((row, index) => ({
    label: row.label,
    fillWidth: `${Math.round((row.count / maxCount) * 100)}%`,
    totalWidth: "100%",
    value: `${row.count} session${row.count === 1 ? "" : "s"}`,
    tone: ["green-lime", "green-blue", "orange-green", "gold-green"][index % 4],
  }));
}

function buildPrivateAnalyticsMonthlyTrendData(sessions = []) {
  const buckets = new Map();
  (sessions || []).forEach((session) => {
    const date = getPrivateAnalyticsSessionDate(session);
    if (!date) {
      return;
    }
    const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}`;
    const bucket = buckets.get(key) || {
      key,
      label: new Intl.DateTimeFormat("en-US", { month: "short", year: "numeric" }).format(date),
      sortTime: new Date(date.getFullYear(), date.getMonth(), 1).getTime(),
      totalSessions: 0,
      completedSessions: 0,
      activeSessions: 0,
      totalSeeds: 0,
      totalGerminated: 0,
    };
    bucket.totalSessions += 1;
    const lifecycleState = normalizeGrowSessionLifecycleState(session);
    if (lifecycleState === "completed") {
      bucket.completedSessions += 1;
    }
    if (lifecycleState === "active") {
      bucket.activeSessions += 1;
    }
    if (isCompletedValidSessionForAnalytics(session)) {
      const totals = getSessionSeedTotals(session);
      bucket.totalSeeds += Math.max(0, Number(totals.totalSeeds) || 0);
      bucket.totalGerminated += Math.max(0, Number(totals.totalGerminated || totals.totalPlanted) || 0);
    }
    buckets.set(key, bucket);
  });

  return [...buckets.values()]
    .sort((left, right) => left.sortTime - right.sortTime)
    .slice(-8)
    .map((bucket) => ({
      ...bucket,
      germinationRate: bucket.totalSeeds > 0 ? Math.round((bucket.totalGerminated / bucket.totalSeeds) * 100) : null,
      completionRate: bucket.totalSessions > 0 ? Math.round((bucket.completedSessions / bucket.totalSessions) * 100) : null,
    }));
}

function buildPrivateAnalyticsSessionTrendRows(sessions = []) {
  return getPrivateAnalyticsCompletedSessions(sessions).slice(0, 6).map((session, index) => {
    const totals = getSessionSeedTotals(session);
    const rate = totals.totalSeeds > 0 ? getSessionSuccessRate(session) : 0;
    return {
      label: formatSessionLabel(session),
      fillWidth: `${rate}%`,
      totalWidth: "100%",
      value: `${rate}%`,
      tone: ["green-lime", "green-blue", "orange-green", "gold-green"][index % 4],
    };
  });
}

function createPrivateAnalyticsRollup(label = "") {
  return {
    label,
    totalSeeds: 0,
    totalGerminated: 0,
    sessionIds: new Set(),
    bestRate: null,
  };
}

function buildPrivateAnalyticsPerformanceRollups(sessions = [], groupType = "source") {
  const rollups = new Map();
  getPrivateAnalyticsCompletedSessions(sessions).forEach((session) => {
    const summary = getSessionResultSummary(session);
    const groups = groupType === "variety" ? summary.varietyGroups : summary.sourceGroups;
    (groups || []).forEach((group) => {
      const label = String(group?.label || "").trim() || "Not shared";
      const key = String(group?.key || label).trim().toLowerCase();
      const rollup = rollups.get(key) || createPrivateAnalyticsRollup(label);
      const totalSeeds = Math.max(0, Number(group.totalSeeds) || 0);
      const totalGerminated = Math.max(0, Number(group.totalGerminated || group.totalPlanted) || 0);
      rollup.totalSeeds += totalSeeds;
      rollup.totalGerminated += totalGerminated;
      if (session?.id) {
        rollup.sessionIds.add(String(session.id));
      }
      const rate = totalSeeds > 0 ? Math.round((totalGerminated / totalSeeds) * 100) : null;
      if (rate !== null) {
        rollup.bestRate = rollup.bestRate === null ? rate : Math.max(rollup.bestRate, rate);
      }
      rollups.set(key, rollup);
    });
  });

  return [...rollups.values()].map((rollup) => {
    const averageRate = rollup.totalSeeds > 0
      ? Math.round((rollup.totalGerminated / rollup.totalSeeds) * 100)
      : null;
    return {
      label: rollup.label,
      totalSeeds: rollup.totalSeeds,
      totalGerminated: rollup.totalGerminated,
      completedSessions: rollup.sessionIds.size,
      averageRate,
      bestRate: rollup.bestRate,
      fillWidth: `${averageRate || 0}%`,
      totalWidth: "100%",
      value: averageRate === null
        ? "No result"
        : `${averageRate}% · ${rollup.totalGerminated}/${rollup.totalSeeds}`,
    };
  }).sort((left, right) => (
    (right.averageRate ?? -1) - (left.averageRate ?? -1)
    || right.totalSeeds - left.totalSeeds
    || left.label.localeCompare(right.label)
  ));
}

function buildPrivateAnalyticsAgeBucketRows(vaultAnalytics = null, mode = "performance") {
  const buckets = vaultAnalytics?.ageIntelligence?.buckets || [];
  return buckets
    .filter((bucket) => mode === "inventory" ? bucket.quantity > 0 || bucket.entryCount > 0 : bucket.performance?.totalSeedsTested > 0)
    .map((bucket, index) => {
      const rate = bucket.performance?.averageGerminationRate;
      const quantity = Math.max(0, Number(bucket.quantity) || 0);
      const fill = mode === "inventory"
        ? Math.min(100, quantity > 0 ? Math.max(8, quantity) : 0)
        : Math.max(0, Number(rate) || 0);
      return {
        label: bucket.label,
        fillWidth: `${Math.min(100, Math.round(fill))}%`,
        totalWidth: "100%",
        value: mode === "inventory"
          ? `${quantity} seed${quantity === 1 ? "" : "s"}`
          : `${formatPrivateAnalyticsPercent(rate)} · ${bucket.performance.totalSeedsTested} tested`,
        tone: ["green-lime", "green-blue", "orange-green", "gold-green"][index % 4],
      };
    });
}

function buildPrivateAnalyticsSourceAgeRows(vaultAnalytics = null) {
  return (vaultAnalytics?.ageIntelligence?.sourceAgeCorrelations || [])
    .filter((source) => source.quantity > 0 || source.performance?.totalSeedsTested > 0)
    .slice(0, 6)
    .map((source, index) => {
      const rate = source.performance?.averageGerminationRate;
      const averageAgeLabel = source.averageAge === null || source.averageAge === undefined
        ? "Unknown age"
        : `${formatSeedAgeYearsLabel(source.averageAge)} avg`;
      return {
        label: source.label,
        fillWidth: `${Math.max(0, Number(rate) || 0)}%`,
        totalWidth: "100%",
        value: `${formatPrivateAnalyticsPercent(rate)} · ${averageAgeLabel}`,
        tone: ["green-lime", "green-blue", "orange-green", "gold-green"][index % 4],
      };
    });
}

function buildPrivateAnalyticsVaultDistributionRows(rollups = []) {
  const rows = (rollups || []).filter((rollup) => rollup.quantity > 0).slice(0, 6);
  const maxQuantity = Math.max(...rows.map((row) => Math.max(0, Number(row.quantity) || 0)), 1);
  return rows.map((row, index) => {
    const quantity = Math.max(0, Number(row.quantity) || 0);
    return {
      label: row.label,
      fillWidth: `${Math.round((quantity / maxQuantity) * 100)}%`,
      totalWidth: "100%",
      value: `${quantity} seed${quantity === 1 ? "" : "s"}`,
      tone: ["green-lime", "green-blue", "orange-green", "gold-green"][index % 4],
    };
  });
}

function buildPrivateAnalyticsQuantityRowsFromAgeBuckets(vaultAnalytics = null) {
  const buckets = vaultAnalytics?.ageIntelligence?.buckets || [];
  const maxQuantity = Math.max(...buckets.map((bucket) => Math.max(0, Number(bucket.quantity) || 0)), 1);
  return buckets
    .filter((bucket) => bucket.quantity > 0 || bucket.entryCount > 0)
    .map((bucket, index) => {
      const quantity = Math.max(0, Number(bucket.quantity) || 0);
      return {
        label: bucket.label,
        metric: quantity,
        valueLabel: `${quantity} seed${quantity === 1 ? "" : "s"}`,
        detail: `${bucket.entryCount} entr${bucket.entryCount === 1 ? "y" : "ies"}`,
        fillWidth: `${Math.round((quantity / maxQuantity) * 100)}%`,
        tone: ["green-lime", "green-blue", "orange-green", "gold-green"][index % 4],
      };
    });
}

function buildPrivateAnalyticsPerformanceChartRows(rows = [], options = {}) {
  const metricKey = options.metricKey || "averageRate";
  const maxMetric = Math.max(...(rows || []).map((row) => Math.max(0, Number(row[metricKey]) || 0)), metricKey === "averageRate" ? 100 : 1);
  return (rows || []).map((row, index) => {
    const metric = Math.max(0, Number(row[metricKey]) || 0);
    const fillWidth = metricKey === "averageRate"
      ? `${Math.min(100, Math.round(metric))}%`
      : `${maxMetric > 0 ? Math.round((metric / maxMetric) * 100) : 0}%`;
    const valueLabel = options.valueFormatter
      ? options.valueFormatter(row)
      : metricKey === "averageRate"
        ? formatPrivateAnalyticsPercent(row.averageRate)
        : formatPrivateAnalyticsNumber(metric);
    return {
      label: row.label,
      metric,
      valueLabel,
      detail: options.detailFormatter ? options.detailFormatter(row) : "",
      fillWidth,
      tone: ["green-lime", "green-blue", "orange-green", "gold-green"][index % 4],
    };
  });
}

function buildPrivateAnalyticsInsightCards(state = {}) {
  const vaultAnalytics = state.vaultAnalytics || {};
  const bestAgeInsight = (vaultAnalytics.ageIntelligence?.insights || []).find((insight) => insight.key === "best-performing-age-range");
  const topSource = (state.sourcePerformanceRows || [])[0] || null;
  const mostTestedGenetics = (state.varietyPerformanceRows || []).length
    ? [...state.varietyPerformanceRows].sort((left, right) => right.totalSeeds - left.totalSeeds)[0]
    : null;
  const oldestSuccessful = vaultAnalytics.ageIntelligence?.oldestSuccessfulGermination || null;
  const lowInventory = Math.max(0, Number(vaultAnalytics.overview?.lowInventoryEntries) || 0);
  const unknownAgeCount = Math.max(0, Number(vaultAnalytics.overview?.unknownAgeCount) || 0);
  const oldestSuccessfulDetail = oldestSuccessful
    ? [oldestSuccessful.source, oldestSuccessful.variety].filter(Boolean).join(" · ") || "Linked Vault Entry"
    : "Linked completed sessions with known age will unlock this.";

  return [
    {
      key: "best-performing-age-range",
      label: "Best Performing Age Range",
      value: bestAgeInsight?.value || "Not enough linked data",
      detail: bestAgeInsight?.detail || "More linked completed sessions will strengthen this signal.",
    },
    {
      key: "most-reliable-source",
      label: "Most Reliable Source",
      value: topSource ? `${topSource.label} · ${formatPrivateAnalyticsPercent(topSource.averageRate)}` : "Not enough source data",
      detail: topSource ? `${formatPrivateAnalyticsNumber(topSource.totalSeeds)} seeds tested across ${formatPrivateAnalyticsNumber(topSource.completedSessions)} completed session${topSource.completedSessions === 1 ? "" : "s"}.` : "Source-labeled completed sessions will unlock this.",
    },
    {
      key: "most-tested-genetics",
      label: "Most Tested Genetics",
      value: mostTestedGenetics ? mostTestedGenetics.label : "Not enough variety data",
      detail: mostTestedGenetics ? `${formatPrivateAnalyticsNumber(mostTestedGenetics.totalSeeds)} seeds tested · ${formatPrivateAnalyticsPercent(mostTestedGenetics.averageRate)}` : "Variety-labeled completed sessions will unlock this.",
    },
    {
      key: "inventory-needs-attention",
      label: "Inventory Needs Attention",
      value: lowInventory || unknownAgeCount ? `${formatPrivateAnalyticsNumber(lowInventory)} low · ${formatPrivateAnalyticsNumber(unknownAgeCount)} unknown age` : "Inventory looks balanced",
      detail: lowInventory || unknownAgeCount ? "Review low-stock entries and add age data where available." : "No low-stock or unknown-age Vault pressure surfaced.",
    },
    {
      key: "oldest-successful-germination",
      label: "Oldest Successful Germination",
      value: oldestSuccessful ? `${formatSeedAgeYearsLabel(oldestSuccessful.ageYears)} · ${formatPrivateAnalyticsPercent(oldestSuccessful.rate)}` : "No linked result yet",
      detail: oldestSuccessfulDetail,
    },
  ];
}

function getPrivateAnalyticsBestSession(sessions = []) {
  return getPrivateAnalyticsCompletedSessions(sessions)
    .map((session) => ({
      session,
      rate: getSessionSuccessRate(session),
      totals: getSessionSeedTotals(session),
      durationMs: getSessionCompletedDurationMs(session),
    }))
    .filter((entry) => entry.totals.totalSeeds > 0)
    .sort((left, right) => (
      right.rate - left.rate
      || right.totals.totalSeeds - left.totals.totalSeeds
      || (getSessionSortTime(right.session) - getSessionSortTime(left.session))
    ))[0] || null;
}

function getPrivateAnalyticsAverageSession(sessions = []) {
  const completedSessions = getPrivateAnalyticsCompletedSessions(sessions)
    .filter((session) => getSessionSeedTotals(session).totalSeeds > 0);
  if (!completedSessions.length) {
    return null;
  }
  const averageRate = Math.round(
    completedSessions.reduce((sum, session) => sum + getSessionSuccessRate(session), 0) / completedSessions.length,
  );
  return {
    label: `${completedSessions.length} completed session${completedSessions.length === 1 ? "" : "s"}`,
    rate: averageRate,
  };
}

function buildPrivateAnalyticsCommunitySnapshotSummary(memberId = "") {
  const snapshots = getApprovedPublicSnapshotsForMember(memberId, getApprovedPublicGallerySnapshots());
  const analytics = calculateProfileAnalyticsFromPublicSnapshots(snapshots);
  const recentSnapshots = sortGallerySnapshotsNewestFirst(snapshots).slice(0, 4);
  const lastContribution = recentSnapshots[0] ? getProfileSnapshotActivityDate(recentSnapshots[0]) : "";
  return {
    snapshots,
    recentSnapshots,
    analytics,
    lastContribution,
  };
}

function buildPrivateAnalyticsCommunityInsightsHooks(state = {}) {
  return {
    privacyBoundary: "owner-only",
    futurePublicCommunityInsights: {
      sourcePerformanceRows: (state.sourcePerformanceRows || []).map(({ label, totalSeeds, totalGerminated, averageRate }) => ({
        label,
        totalSeeds,
        totalGerminated,
        averageRate,
      })),
      varietyPerformanceRows: (state.varietyPerformanceRows || []).map(({ label, totalSeeds, totalGerminated, averageRate }) => ({
        label,
        totalSeeds,
        totalGerminated,
        averageRate,
      })),
      ageBucketPerformanceRows: (state.agePerformanceRows || []).map(({ label, value }) => ({ label, value })),
      publicContributionStats: {
        approvedPublicSnapshots: state.communitySummary?.analytics?.totalPublicSnapshots || 0,
        bestPublicResult: state.communitySummary?.analytics?.bestGerminationRate ?? null,
      },
    },
  };
}

function buildPrivateAnalyticsDashboardState() {
  const visibleSessions = getVisibleUserSessions(getSessions());
  const ownerAnalytics = calculateProfileAnalyticsFromOwnerSessions(visibleSessions);
  const completedSessions = getPrivateAnalyticsCompletedSessions(visibleSessions);
  const activeSessions = getPrivateAnalyticsActiveSessions(visibleSessions);
  const vaultAnalytics = buildSeedVaultAnalytics(appState.seedVaultEntries || [], visibleSessions);
  const communitySummary = buildPrivateAnalyticsCommunitySnapshotSummary(appState.user?.id || "");
  const sourcePerformanceRows = buildPrivateAnalyticsPerformanceRollups(completedSessions, "source");
  const varietyPerformanceRows = buildPrivateAnalyticsPerformanceRollups(completedSessions, "variety");
  const agePerformanceRows = buildPrivateAnalyticsAgeBucketRows(vaultAnalytics, "performance");
  const ageInventoryRows = buildPrivateAnalyticsAgeBucketRows(vaultAnalytics, "inventory");
  const sourceAgeRows = buildPrivateAnalyticsSourceAgeRows(vaultAnalytics);
  const state = {
    privacyBoundary: "owner-only",
    sessions: visibleSessions,
    completedSessions,
    activeSessions,
    ownerAnalytics,
    vaultAnalytics,
    communitySummary,
    bestSession: getPrivateAnalyticsBestSession(completedSessions),
    averageSession: getPrivateAnalyticsAverageSession(completedSessions),
    sessionTimelineRows: buildPrivateAnalyticsMonthlyRows(visibleSessions),
    germinationTrendRows: buildPrivateAnalyticsSessionTrendRows(completedSessions),
    monthlyTrendData: buildPrivateAnalyticsMonthlyTrendData(visibleSessions),
    sourcePerformanceRows,
    varietyPerformanceRows,
    agePerformanceRows,
    ageInventoryRows,
    sourceAgeRows,
    sourceDistributionRows: buildPrivateAnalyticsVaultDistributionRows(vaultAnalytics.rollups?.sources || []),
    varietyDistributionRows: buildPrivateAnalyticsVaultDistributionRows(vaultAnalytics.rollups?.varieties || []),
    ageQuantityRows: buildPrivateAnalyticsQuantityRowsFromAgeBuckets(vaultAnalytics),
  };
  state.insightCards = buildPrivateAnalyticsInsightCards(state);
  state.futureCommunityInsightsHooks = buildPrivateAnalyticsCommunityInsightsHooks(state);
  return state;
}

