function ensureSourceCatalogDatalist() {
  if (!(document.body instanceof HTMLBodyElement)) {
    return null;
  }

  let datalist = document.querySelector(`#${SOURCE_CATALOG_DATALIST_ID}`);
  if (!(datalist instanceof HTMLDataListElement)) {
    datalist = document.createElement("datalist");
    datalist.id = SOURCE_CATALOG_DATALIST_ID;
    document.body.appendChild(datalist);
  }

  datalist.innerHTML = getSourceCatalogRecords()
    .map((source) => `<option value="${escapeHtml(source.name)}"></option>`)
    .join("");

  return datalist;
}

function getPartitionIdentityKindConfig(kind = "") {
  if (kind === "source") {
    return {
      kind: "source",
      label: "Source",
      normalize: normalizeSourceNameForMatching,
      getPartitionLabel: formatPartitionSource,
      getPartitionCanonicalId: (partition) => partition?.sourceCanonicalId || partition?.source_canonical_id || "",
      getPartitionCanonicalName: (partition) => partition?.sourceCanonicalName || partition?.source_canonical_name || formatPartitionSource(partition),
      catalogRecords: () => getSourceCatalogRecords().map((source) => ({
        label: source?.name || "",
        canonicalId: source?.id || "",
        canonicalName: source?.name || "",
        priority: 3,
        origin: "Known source",
      })),
    };
  }

  return {
    kind: "seedVariety",
    label: "Seed Variety",
    normalize: normalizeSeedVarietyNameForMatching,
    getPartitionLabel: formatPartitionSeedVariety,
    getPartitionCanonicalId: (partition) => partition?.seedVarietyCanonicalId || partition?.seed_variety_canonical_id || "",
    getPartitionCanonicalName: (partition) => partition?.seedVarietyCanonicalName || partition?.seed_variety_canonical_name || formatPartitionSeedVariety(partition),
    catalogRecords: () => [],
  };
}

function addPartitionIdentitySuggestionRecord(records, config, label = "", options = {}) {
  const displayLabel = String(label || "").trim();
  const normalizedKey = config.normalize(displayLabel);
  if (!displayLabel || !normalizedKey) {
    return;
  }

  const existingRecord = records.get(normalizedKey) || {
    label: displayLabel,
    normalizedKey,
    canonicalId: getPartitionIdentityCanonicalId(config.kind, normalizedKey, options.canonicalId),
    canonicalName: String(options.canonicalName || displayLabel).trim(),
    usageCount: 0,
    priority: 0,
    origins: new Set(),
  };
  const priority = Number(options.priority) || 0;
  const previousPriority = existingRecord.priority;
  existingRecord.usageCount += Math.max(1, Number(options.usageCount) || 1);
  existingRecord.priority = Math.max(existingRecord.priority, priority);
  if (options.origin) {
    existingRecord.origins.add(String(options.origin));
  }
  if (options.canonicalId && !existingRecord.canonicalId) {
    existingRecord.canonicalId = String(options.canonicalId).trim();
  }
  if (options.canonicalName && !existingRecord.canonicalName) {
    existingRecord.canonicalName = String(options.canonicalName).trim();
  }
  if (
    priority > previousPriority
    || (priority === previousPriority && displayLabel.length < existingRecord.label.length)
  ) {
    existingRecord.label = displayLabel;
    existingRecord.canonicalName = String(options.canonicalName || displayLabel).trim();
  }
  records.set(normalizedKey, existingRecord);
}

function shouldUseSessionForPartitionIdentitySuggestions(session = null) {
  return !(
    isSessionSoftDeleted(session)
    || session?.isMock
    || session?.is_mock
    || session?.isTest
    || session?.is_test
    || session?.excludedFromAnalytics
    || session?.excluded_from_analytics
  );
}

function addSessionPartitionIdentitySuggestionRecords(records, config, session = null, options = {}) {
  if (!shouldUseSessionForPartitionIdentitySuggestions(session)) {
    return;
  }

  normalizeSessionPartitions(session?.partitions || []).forEach((partition) => {
    addPartitionIdentitySuggestionRecord(records, config, config.getPartitionLabel(partition), {
      canonicalId: config.getPartitionCanonicalId(partition),
      canonicalName: config.getPartitionCanonicalName(partition),
      priority: options.priority,
      usageCount: options.usageCount,
      origin: options.origin,
    });
  });
}

function addGallerySnapshotIdentitySuggestionRecords(records, config, snapshot = null) {
  if (
    !snapshot
    || isMockGallerySnapshot(snapshot)
    || snapshot?.isMock
    || snapshot?.is_mock
    || snapshot?.analyticsExcluded
    || snapshot?.analytics_excluded
  ) {
    return;
  }

  if (config.kind === "source") {
    addPartitionIdentitySuggestionRecord(records, config, snapshot.sourceName || snapshot.source_name || "", {
      canonicalId: snapshot.sourceId || snapshot.source_id || "",
      canonicalName: snapshot.sourceName || snapshot.source_name || "",
      priority: 2.5,
      origin: "Previous global sessions",
    });
    return;
  }

  addPartitionIdentitySuggestionRecord(records, config, snapshot.seedVarietyName || snapshot.seed_variety_name || "", {
    canonicalId: snapshot.seedVarietyCanonicalId || snapshot.seed_variety_canonical_id || "",
    canonicalName: snapshot.seedVarietyName || snapshot.seed_variety_name || "",
    priority: 2.5,
    origin: "Previous global sessions",
  });
}

function getPartitionIdentitySuggestionReason(record = null) {
  const origins = Array.isArray(record?.origins) ? record.origins : [];
  if (origins.includes("Known source")) {
    return "Known source";
  }
  if (origins.includes("Previous global sessions")) {
    return "Previous global sessions";
  }
  return origins[0] || "Previous sessions";
}

function getPartitionIdentitySuggestionRecords(kind = "") {
  const config = getPartitionIdentityKindConfig(kind);
  const records = new Map();

  config.catalogRecords().forEach((record) => {
    addPartitionIdentitySuggestionRecord(records, config, record.label, {
      canonicalId: record.canonicalId,
      canonicalName: record.canonicalName,
      priority: record.priority,
      origin: record.origin,
    });
  });

  (appState.sourceReviewSessionRows || []).forEach((sessionRow) => {
    addSessionPartitionIdentitySuggestionRecords(records, config, sessionRow, {
      priority: 2.5,
      origin: "Previous global sessions",
    });
  });

  getGallerySnapshotsForDisplay(appState.gallerySnapshots || []).forEach((snapshot) => {
    addGallerySnapshotIdentitySuggestionRecords(records, config, snapshot);
  });

  (getSessions() || []).forEach((session) => {
    addSessionPartitionIdentitySuggestionRecords(records, config, session, {
      priority: 2,
      origin: "Previous sessions",
    });
  });

  return [...records.values()].map((record) => ({
    ...record,
    origins: [...record.origins],
  }));
}

function getBestPartitionIdentityCandidate(kind = "", normalizedKey = "") {
  const key = String(normalizedKey || "").trim();
  if (!key) {
    return null;
  }

  const candidates = getPartitionIdentitySuggestionRecords(kind);
  const exactMatch = candidates.find((candidate) => candidate.normalizedKey === key);
  if (exactMatch) {
    return {
      ...exactMatch,
      confidence: 1,
      confidenceBand: "exact",
    };
  }

  return candidates
    .map((candidate) => ({
      ...candidate,
      confidence: getPartitionIdentitySimilarity(key, candidate.normalizedKey),
      confidenceBand: isHighConfidencePartitionIdentityTypoMatch(key, candidate.normalizedKey)
        ? "high"
        : (isMediumConfidencePartitionIdentityMatch(key, candidate.normalizedKey) ? "medium" : "low"),
    }))
    .filter((candidate) => candidate.confidenceBand !== "low")
    .sort((left, right) => {
      const bandRank = { high: 0, medium: 1, low: 2 };
      return bandRank[left.confidenceBand] - bandRank[right.confidenceBand]
        || right.confidence - left.confidence
        || right.priority - left.priority
        || right.usageCount - left.usageCount
        || left.label.localeCompare(right.label, "en", { sensitivity: "base" });
    })[0] || null;
}

function buildPartitionIdentityMatch(kind = "", displayValue = "", options = {}) {
  const config = getPartitionIdentityKindConfig(kind);
  const displayName = String(displayValue || "").trim();
  const normalizedKey = config.normalize(displayName);
  const selectedCandidate = options.selectedCandidate && typeof options.selectedCandidate === "object"
    ? options.selectedCandidate
    : null;

  if (!displayName || !normalizedKey) {
    return {
      displayName,
      normalizedKey,
      canonicalId: "",
      canonicalName: displayName,
      matchStatus: "new",
      matchConfidence: 0,
      reviewCandidateId: "",
      reviewCandidateName: "",
    };
  }

  if (selectedCandidate?.canonicalId && selectedCandidate?.normalizedKey === normalizedKey) {
    return {
      displayName,
      normalizedKey,
      canonicalId: selectedCandidate.canonicalId,
      canonicalName: selectedCandidate.canonicalName || selectedCandidate.label || displayName,
      matchStatus: "selected",
      matchConfidence: 1,
      reviewCandidateId: "",
      reviewCandidateName: "",
    };
  }

  const bestCandidate = getBestPartitionIdentityCandidate(config.kind, normalizedKey);
  if (!bestCandidate) {
    return {
      displayName,
      normalizedKey,
      canonicalId: "",
      canonicalName: displayName,
      matchStatus: "new",
      matchConfidence: 0,
      reviewCandidateId: "",
      reviewCandidateName: "",
    };
  }

  if (bestCandidate.confidenceBand === "exact" || bestCandidate.confidenceBand === "high") {
    return {
      displayName,
      normalizedKey,
      canonicalId: bestCandidate.canonicalId,
      canonicalName: bestCandidate.canonicalName || bestCandidate.label || displayName,
      matchStatus: "auto_matched",
      matchConfidence: bestCandidate.confidence,
      reviewCandidateId: "",
      reviewCandidateName: "",
    };
  }

  return {
    displayName,
    normalizedKey,
    canonicalId: "",
    canonicalName: displayName,
    matchStatus: "needs_review",
    matchConfidence: bestCandidate.confidence,
    reviewCandidateId: bestCandidate.canonicalId,
    reviewCandidateName: bestCandidate.canonicalName || bestCandidate.label || "",
  };
}

function getPartitionIdentitySuggestions(kind = "", query = "") {
  const config = getPartitionIdentityKindConfig(kind);
  const normalizedQuery = config.normalize(query);
  const displayQuery = String(query || "").trim();
  if (normalizedQuery.length < PARTITION_IDENTITY_AUTOCOMPLETE_MIN_CHARS) {
    return [];
  }

  const records = getPartitionIdentitySuggestionRecords(config.kind);
  const allowTypoSuggestions = normalizedQuery.length >= PARTITION_IDENTITY_TYPO_SUGGESTION_MIN_CHARS;

  return records
    .map((record) => {
      let rank = 99;
      if (record.normalizedKey === normalizedQuery) {
        rank = 0;
      } else if (record.normalizedKey.startsWith(normalizedQuery)) {
        rank = 1;
      } else if (record.normalizedKey.includes(normalizedQuery)) {
        rank = 2;
      } else if (allowTypoSuggestions && isHighConfidencePartitionIdentityTypoMatch(normalizedQuery, record.normalizedKey)) {
        rank = 3;
      } else if (allowTypoSuggestions && isMediumConfidencePartitionIdentityMatch(normalizedQuery, record.normalizedKey)) {
        rank = 4;
      }

      const isLikelyDuplicate = rank === 0 && normalizeIdentityPunctuation(record.label).toLowerCase() !== normalizeIdentityPunctuation(displayQuery).toLowerCase();
      return {
        ...record,
        rank,
        isLikelyDuplicate,
        reason: isLikelyDuplicate ? "Use existing name" : getPartitionIdentitySuggestionReason(record),
      };
    })
    .filter((record) => record.rank < 99)
    .sort((left, right) => left.rank - right.rank || Number(right.isLikelyDuplicate) - Number(left.isLikelyDuplicate) || right.priority - left.priority || right.usageCount - left.usageCount || left.label.localeCompare(right.label, "en", { sensitivity: "base" }))
    .slice(0, PARTITION_IDENTITY_AUTOCOMPLETE_LIMIT);
}

function closePartitionIdentitySuggestions(field) {
  const suggestions = field?.querySelector?.("[data-identity-suggestions]");
  if (suggestions instanceof HTMLElement) {
    suggestions.hidden = true;
    suggestions.innerHTML = "";
  }
  field?.removeAttribute?.("data-identity-active-index");
}

function applyPartitionIdentitySuggestion(input, suggestion) {
  if (!(input instanceof HTMLInputElement) || !suggestion?.label) {
    return;
  }

  input.dataset.applyingIdentitySuggestion = "true";
  input.value = suggestion.label;
  input.dataset.canonicalId = suggestion.canonicalId || "";
  input.dataset.canonicalLabel = suggestion.canonicalName || suggestion.label;
  input.dataset.normalizedKey = suggestion.normalizedKey || "";
  input.dataset.matchStatus = "selected";
  input.dataset.matchConfidence = "1";
  input.dataset.reviewCandidateId = "";
  input.dataset.reviewCandidateName = "";
  input.dispatchEvent(new Event("input", { bubbles: true }));
  input.dispatchEvent(new Event("change", { bubbles: true }));
  delete input.dataset.applyingIdentitySuggestion;
  closePartitionIdentitySuggestions(input.closest("[data-identity-autocomplete]"));
}

function renderPartitionIdentitySuggestions(field) {
  if (!(field instanceof HTMLElement)) {
    return;
  }

  const input = field.querySelector("[data-session-identity-input]");
  const panel = field.querySelector("[data-identity-suggestions]");
  const kind = field.dataset.identityAutocomplete || "";
  if (!(input instanceof HTMLInputElement) || !(panel instanceof HTMLElement) || input.disabled || input.readOnly) {
    closePartitionIdentitySuggestions(field);
    return;
  }

  const suggestions = getPartitionIdentitySuggestions(kind, input.value);
  if (!suggestions.length) {
    closePartitionIdentitySuggestions(field);
    return;
  }

  const activeIndex = Math.min(
    Math.max(0, Number(field.dataset.identityActiveIndex) || 0),
    suggestions.length - 1,
  );
  field.dataset.identityActiveIndex = String(activeIndex);
  panel.innerHTML = suggestions.map((suggestion, index) => `
    <button type="button" class="partition-identity-suggestion${index === activeIndex ? " is-active" : ""}" data-suggestion-index="${index}" data-suggestion-label="${escapeHtml(suggestion.label)}" data-suggestion-key="${escapeHtml(suggestion.normalizedKey)}">
      <span>${escapeHtml(suggestion.label)}</span>
      <small>${escapeHtml(suggestion.reason)}</small>
    </button>
  `).join("");
  panel.hidden = false;
}

function initializePartitionIdentityAutocompletes(scope) {
  if (!(scope instanceof Element)) {
    return;
  }

  scope.querySelectorAll("[data-identity-autocomplete]").forEach((field) => {
    if (!(field instanceof HTMLElement) || field.dataset.identityAutocompleteBound === "true") {
      return;
    }

    const input = field.querySelector("[data-session-identity-input]");
    const panel = field.querySelector("[data-identity-suggestions]");
    if (!(input instanceof HTMLInputElement) || !(panel instanceof HTMLElement)) {
      return;
    }

    input.addEventListener("input", () => {
      const config = getPartitionIdentityKindConfig(field.dataset.identityAutocomplete || "");
      if (input.dataset.applyingIdentitySuggestion !== "true") {
        const match = buildPartitionIdentityMatch(config.kind, input.value);
        input.dataset.canonicalId = match.canonicalId;
        input.dataset.canonicalLabel = match.canonicalName;
        input.dataset.normalizedKey = match.normalizedKey;
        input.dataset.matchStatus = match.matchStatus;
        input.dataset.matchConfidence = String(match.matchConfidence);
        input.dataset.reviewCandidateId = match.reviewCandidateId;
        input.dataset.reviewCandidateName = match.reviewCandidateName;
      }
      field.dataset.identityActiveIndex = "0";
      renderPartitionIdentitySuggestions(field);
    });
    input.addEventListener("focus", () => renderPartitionIdentitySuggestions(field));
    input.addEventListener("blur", () => {
      window.setTimeout(() => closePartitionIdentitySuggestions(field), 120);
    });
    input.addEventListener("keydown", (event) => {
      const suggestions = getPartitionIdentitySuggestions(field.dataset.identityAutocomplete || "", input.value);
      if (!suggestions.length) {
        return;
      }

      const currentIndex = Math.min(Math.max(0, Number(field.dataset.identityActiveIndex) || 0), suggestions.length - 1);
      if (event.key === "ArrowDown") {
        event.preventDefault();
        field.dataset.identityActiveIndex = String(Math.min(currentIndex + 1, suggestions.length - 1));
        renderPartitionIdentitySuggestions(field);
      } else if (event.key === "ArrowUp") {
        event.preventDefault();
        field.dataset.identityActiveIndex = String(Math.max(currentIndex - 1, 0));
        renderPartitionIdentitySuggestions(field);
      } else if (event.key === "Enter" && !panel.hidden) {
        event.preventDefault();
        applyPartitionIdentitySuggestion(input, suggestions[currentIndex]);
      } else if (event.key === "Escape") {
        closePartitionIdentitySuggestions(field);
      }
    });
    panel.addEventListener("mousedown", (event) => {
      event.preventDefault();
    });
    panel.addEventListener("click", (event) => {
      const button = event.target instanceof Element
        ? event.target.closest("[data-suggestion-index]")
        : null;
      if (!(button instanceof HTMLButtonElement)) {
        return;
      }
      const suggestions = getPartitionIdentitySuggestions(field.dataset.identityAutocomplete || "", input.value);
      const suggestion = suggestions[Number(button.dataset.suggestionIndex) || 0];
      applyPartitionIdentitySuggestion(input, suggestion);
    });
    field.dataset.identityAutocompleteBound = "true";
  });
}

function renderPartitionRows(form, systemType, sessionStatus) {
  const partitionFields = form.querySelector("#partition-fields");
  const formMessage = form.querySelector("#form-message");
  const seedAgeState = getSeedAgeSettingsFromForm(form);
  const showSeedAgeField = seedAgeState.trackingEnabled;
  const seedAgeReadOnly = seedAgeState.mode === "same";
  const previousMode = getSeedAgeModeForForm(form);
  const existingPartitions = getCurrentPartitionValues(form);

  if (previousMode === "mixed") {
    persistMixedSeedAgeDrafts(form, existingPartitions);
  } else if (seedAgeState.mode === "same") {
    form.__mixedSeedAgeDrafts = {};
  }

  const sessionSeedAgeAutofillValue = showSeedAgeField
    ? getSessionSeedAgeValueForForm(form)
    : null;
  const partitions = createPartitionsForSystem(systemType).map((partition, index) => ({
    ...partition,
    ...existingPartitions[index],
    id: partition.id,
  }));
  applySeedAgeValuesToPartitions(partitions, {
    trackingEnabled: seedAgeState.trackingEnabled,
    mode: seedAgeState.mode,
    sessionSeedAgeYears: sessionSeedAgeAutofillValue,
    mixedSeedAgeDrafts: getMixedSeedAgeDrafts(form),
  });

  partitionFields.innerHTML = "";
  if (systemType === "TRA") {
    renderTraPartitionSections(partitionFields, partitions, {
      showSeedAgeField,
      seedAgeReadOnly,
      shouldShowSeedAgeInput: (partition) => shouldShowPartitionSeedAgeFieldForPartition(partition),
    });
  } else {
    partitions.forEach((partition, index) => {
      partitionFields.appendChild(buildPartitionFormCard(partition, index, {
        showSeedAgeField,
        showSeedAgeInput: showSeedAgeField && shouldShowPartitionSeedAgeFieldForPartition(partition),
        seedAgeReadOnly,
      }));
      hydratePartitionRow(partitionFields.lastElementChild, partition);
    });
  }
  form.__partitionDraftValues = partitions.map((partition) => ({ ...partition }));

  initializeCustomSelects(partitionFields);
  initializePartitionIdentityAutocompletes(partitionFields);
  bindPartitionRowVisualState(partitionFields);
  attachPartitionValidation(form, formMessage);
  applySessionStatusLayout(
    form.querySelector("#partition-chart-shell"),
    form.querySelector("#partition-chart-header"),
    partitionFields,
    sessionStatus,
  );
  applyPartitionSeedAgeLayout(
    form.querySelector("#partition-chart-shell"),
    form.querySelector("#partition-chart-header"),
    partitionFields,
    seedAgeState.mode,
  );
  syncPartitionButtonStates(partitionFields, sessionStatus);
  updateGrowthStageLock(form, sessionStatus);
  clearActiveSystemLayout(form);
}

function updateGrowthStageLock(form, sessionStatus) {
  if (!form) {
    return;
  }

  const normalizedStatus = normalizeSessionStatus(sessionStatus);
  const trigger = form.querySelector("#session-status-trigger, #detail-session-status-trigger");

  appState.growthStage = normalizedStatus === "unselected" ? null : normalizedStatus;

  if (trigger) {
    trigger.classList.toggle("growth-stage-attention", normalizedStatus === "unselected");
  }
}

function applyStageEditingMode(scope, sessionStatus, options = {}) {
  if (!scope) {
    return;
  }

  const normalizedStatus = normalizeSessionStatus(sessionStatus);
  const isUnselected = normalizedStatus === "unselected";
  const allowFullEditing = normalizedStatus === "soaking" || isUnselected;
  const allowGerminationOnlyEditing = normalizedStatus === "germinating";
  const isCompleted = normalizedStatus === "completed";
  const allowAnyEditing = allowFullEditing || allowGerminationOnlyEditing;

  const saveButtons = [
    ...scope.querySelectorAll('button[type="submit"]'),
    ...scope.querySelectorAll('#detail-save-shortcut, #detail-save-session'),
  ];

  const timelineSaveShortcut = scope.querySelector(".timeline-save-shortcut");
  if (timelineSaveShortcut) {
    timelineSaveShortcut.hidden = isCompleted && !timelineSaveShortcut.classList.contains("detail-session-action-bar");
  }

  saveButtons.forEach((button) => {
    const isDetailActionShortcut = Boolean(button.closest(".detail-session-action-bar"));
    button.hidden = isCompleted && !isDetailActionShortcut;
    button.disabled = false;
  });

  const textFields = scope.querySelectorAll([
    'input[name="date"]',
    'input[name="timeDisplay"]',
  ].join(", "));

  textFields.forEach((field) => {
    field.disabled = !allowFullEditing;
  });

  scope.querySelectorAll('select[name="systemType"]').forEach((field) => {
    field.disabled = !allowFullEditing;
  });

  scope.querySelectorAll('input[name="seedAgeTrackingEnabled"], input[name="seedAgeMode"], input[name="sessionSeedAgeYears"]').forEach((field) => {
    field.disabled = !allowFullEditing;
  });

  scope.querySelectorAll('#detail-session-notes, #session-notes').forEach((field) => {
    field.readOnly = false;
    field.disabled = false;
  });

  scope.querySelectorAll('.partition-row input[name^="source-"], .partition-row input[name^="seedVariety-"], .partition-row select[name^="seedType-"], .partition-row select[name^="feminized-"], .partition-row input[name^="seedCount-"], .partition-row input[name^="seedAgeYears-"]').forEach((field) => {
    field.disabled = isCompleted || allowGerminationOnlyEditing;
  });

  scope.querySelectorAll('.partition-row input[name="plantedCount"]').forEach((field) => {
    field.disabled = isCompleted || isUnselected;
  });

  scope.querySelectorAll('select[data-custom-select]').forEach((field) => {
    syncCustomSelect(field);
  });

  const imageInput = scope.querySelector('#session-images-input, #detail-session-images-input');
  if (imageInput) {
    imageInput.disabled = false;
  }

  scope.querySelectorAll(".session-image-remove").forEach((button) => {
    button.disabled = false;
    button.hidden = false;
  });

  const imageUpload = scope.querySelector(".session-images-upload");
  if (imageUpload) {
    imageUpload.classList.remove("is-disabled");
    const fileUploadControl = imageUpload.querySelector(".file-upload-control");
    if (fileUploadControl) {
      fileUploadControl.setAttribute("tabindex", "0");
      fileUploadControl.setAttribute("aria-disabled", "false");
    }
  }
}

function closeGrowthStageModal() {
  const overlay = document.querySelector("#growth-stage-modal-overlay");
  const modal = overlay?.querySelector(".growth-stage-modal");

  if (!overlay || overlay.dataset.closing === "true") {
    return;
  }

  overlay.dataset.closing = "true";
  overlay.classList.add("closing");
  modal?.classList.add("closing");

  appState.growthStageModalOpen = false;
  appState.growthStageModalDismissed = true;
  appState.pendingGrowthStageInput = null;
  document.body.classList.remove("modal-open");
  appState.growthStageModalSuppressedUntil = Date.now() + 180;

  window.setTimeout(() => {
    overlay.hidden = true;
    overlay.classList.remove("is-open", "closing");
    overlay.dataset.closing = "false";
    modal?.classList.remove("closing");
    overlay.remove();
  }, 180);
}

function bindGrowthStageModalCloseControls(overlay) {
  if (!overlay || overlay.dataset.closeControlsBound === "true") {
    return;
  }

  overlay.addEventListener("click", (event) => {
    const closeButton = event.target instanceof Element
      ? event.target.closest("[data-growth-stage-modal-close]")
      : null;
    if (closeButton || event.target === overlay) {
      event.preventDefault();
      event.stopPropagation();
      closeGrowthStageModal();
    }
  });

  overlay.dataset.closeControlsBound = "true";
}

function ensureGrowthStageModal() {
  let overlay = document.querySelector("#growth-stage-modal-overlay");
  if (overlay) {
    bindGrowthStageModalCloseControls(overlay);
    return overlay;
  }

  overlay = document.createElement("div");
  overlay.id = "growth-stage-modal-overlay";
  overlay.className = "growth-stage-modal-overlay";
  overlay.hidden = true;
  overlay.dataset.closing = "false";
  overlay.innerHTML = `
    <div class="growth-stage-modal" role="dialog" aria-modal="true" aria-labelledby="growth-stage-modal-title" aria-describedby="growth-stage-modal-helper">
      <button type="button" class="modal-close" data-growth-stage-modal-close aria-label="Close">×</button>
      <div class="growth-stage-modal-copy">
        <h2 id="growth-stage-modal-title">Choose Growth Stage</h2>
        <p id="growth-stage-modal-helper" class="growth-stage-modal-helper" data-growth-stage-modal-helper hidden></p>
      </div>
      <div class="growth-stage-modal-actions" id="growth-stage-modal-actions"></div>
    </div>
  `;

  bindGrowthStageModalCloseControls(overlay);

  if (!ensureGrowthStageModal.escapeBound) {
    document.addEventListener("keydown", (event) => {
      if (event.key === "Escape" && appState.growthStageModalOpen) {
        closeGrowthStageModal();
      }
    });
    ensureGrowthStageModal.escapeBound = true;
  }

  document.body.appendChild(overlay);
  return overlay;
}

function getSessionStageLabel(value) {
  return SESSION_STAGE_OPTIONS.find((option) => option.value === value)?.label || "Select Growth Stage";
}

function getSessionStageDisplayLabel(value) {
  return SESSION_STAGE_OPTIONS.find((option) => option.value === value)?.label || "Not Started";
}

function getCanonicalSessionStageDisplayLabel(stageKey = "", options = {}) {
  const normalizedKey = String(stageKey || "").trim().toLowerCase().replace(/_/g, "-");
  let label = "Not Started";

  switch (normalizedKey) {
    case "soaking":
      label = "Soaking";
      break;
    case "germination":
    case "germinating":
      label = "Germinating";
      break;
    case "first-germinated":
    case "first germinated":
    case "germination-started":
    case "germination started":
      label = "Germination Started";
      break;
    case "completed":
      label = "Completed";
      break;
    case "unselected":
    case "":
    default:
      label = "Not Started";
      break;
  }

  return options.uppercase ? label.toUpperCase() : label;
}

function getSessionStageButtonLabel(value) {
  return value ? "Update Growth Stage" : "Select Growth Stage";
}

function getSessionProgressDisplayLabel(progressKey, value) {
  if (progressKey) {
    return getCanonicalSessionStageDisplayLabel(progressKey);
  }
  return getSessionStageDisplayLabel(value);
}

function getSessionStageProgressionState(control) {
  const progressKey = getSessionStatusProgressKey(control);
  const normalizedStatus = normalizeSessionStatus(control?.value || "");
  const stageOrder = ["soaking", "germination", "first-germinated", "completed"];
  const currentKey = progressKey || (normalizedStatus === "unselected" ? "not-started" : normalizedStatus);
  const currentIndex = stageOrder.indexOf(currentKey);
  const resolvedCurrentKey = currentKey === "not-started"
    ? "not-started"
    : (currentIndex >= 0 ? currentKey : "not-started");
  const nextKey = resolvedCurrentKey === "not-started"
    ? "soaking"
    : resolvedCurrentKey === "completed"
    ? "session-complete"
    : stageOrder[Math.min(stageOrder.indexOf(resolvedCurrentKey) + 1, stageOrder.length - 1)];

  const labelByKey = {
    "not-started": "Not Started",
    soaking: "Soaking",
    germination: "Germinating",
    "first-germinated": "Germination Started",
    completed: "Completed",
    "session-complete": "Session Complete",
  };
  const toneByKey = {
    "not-started": "not-started",
    soaking: "soaking",
    germination: "germinating",
    "first-germinated": "first-germinated",
    completed: "completed",
    "session-complete": "session-complete",
  };
  const iconKeyByStage = {
    "not-started": "header",
    soaking: "stage-soaking",
    germination: "stage-germination",
    "first-germinated": "stage-first-germinated",
    completed: "stage-completed",
    "session-complete": "stage-completed",
  };
  const iconClassByStage = {
    "not-started": "detail-stage-progress-icon detail-stage-progress-icon--not-started",
    soaking: "detail-stage-progress-icon command-icon--stage command-icon--stage-soaking",
    germination: "detail-stage-progress-icon command-icon--stage command-icon--stage-germination",
    "first-germinated": "detail-stage-progress-icon command-icon--stage command-icon--stage-first-germinated",
    completed: "detail-stage-progress-icon command-icon--stage command-icon--stage-completed",
    "session-complete": "detail-stage-progress-icon command-icon--stage command-icon--stage-completed",
  };

  return {
    currentKey: resolvedCurrentKey,
    currentLabel: labelByKey[resolvedCurrentKey] || getSessionProgressDisplayLabel(progressKey, control?.value || ""),
    currentTone: toneByKey[resolvedCurrentKey] || "soaking",
    currentIconKey: iconKeyByStage[resolvedCurrentKey] || "stage-soaking",
    currentIconClass: iconClassByStage[resolvedCurrentKey] || iconClassByStage.soaking,
    nextKey,
    nextLabel: labelByKey[nextKey] || "Germinating",
    nextTone: toneByKey[nextKey] || "germinating",
    nextIconKey: iconKeyByStage[nextKey] || "stage-germination",
    nextIconClass: iconClassByStage[nextKey] || iconClassByStage.germination,
    actionLabel: resolvedCurrentKey === "not-started"
      ? "Start Soaking"
      : (resolvedCurrentKey === "completed" ? "Session Complete" : "Update Stage"),
    isComplete: resolvedCurrentKey === "completed",
  };
}

function syncDetailSessionActionBar(control) {
  const actionBar = document.querySelector(".detail-session-action-bar");
  if (!actionBar) {
    return;
  }

  const state = getSessionStageProgressionState(control);
  const currentStageElement = actionBar.querySelector("[data-detail-action-current-stage]");
  const nextStageElement = actionBar.querySelector("[data-detail-action-next-stage]");
  const currentLabelElement = actionBar.querySelector("[data-detail-action-current-label]");
  const nextLabelElement = actionBar.querySelector("[data-detail-action-next-label]");
  const currentIconElement = actionBar.querySelector("[data-detail-action-current-icon]");
  const nextIconElement = actionBar.querySelector("[data-detail-action-next-icon]");
  const stageTrigger = actionBar.querySelector("[data-detail-stage-progress-trigger]");
  const stageActionLabel = actionBar.querySelector("[data-detail-stage-progress-action-label]");
  const stageActionArrow = actionBar.querySelector("[data-detail-stage-progress-action-arrow]");
  const stageCard = actionBar.querySelector("[data-detail-stage-progress-card]");

  if (currentStageElement) {
    currentStageElement.textContent = state.isComplete ? "Session Completed" : state.currentLabel;
  }
  if (nextStageElement) {
    nextStageElement.textContent = state.nextLabel;
  }
  if (currentLabelElement) {
    currentLabelElement.textContent = state.isComplete ? "Final Stage" : "Current Stage";
  }
  if (nextLabelElement) {
    nextLabelElement.textContent = "Next Stage";
  }
  if (currentIconElement) {
    currentIconElement.innerHTML = renderCommandCenterIconMarkup(state.currentIconKey, state.currentIconClass);
  }
  if (nextIconElement) {
    nextIconElement.innerHTML = renderCommandCenterIconMarkup(state.nextIconKey, state.nextIconClass);
  }
  if (stageActionLabel) {
    stageActionLabel.textContent = state.actionLabel;
  }
  if (stageActionArrow) {
    stageActionArrow.hidden = state.isComplete;
  }

  actionBar.dataset.currentStageTone = state.currentTone;
  actionBar.dataset.nextStageTone = state.nextTone;
  actionBar.dataset.currentStageKey = state.currentKey;
  actionBar.dataset.nextStageKey = state.nextKey;
  actionBar.dataset.stageActionState = state.isComplete ? "complete" : "available";

  if (stageCard) {
    stageCard.classList.toggle("is-session-complete", state.isComplete);
    stageCard.setAttribute(
      "aria-label",
      state.isComplete
        ? "Session completed"
        : `Current stage ${state.currentLabel}. Next stage ${state.nextLabel}.`,
    );
  }

  if (stageTrigger) {
    stageTrigger.disabled = state.isComplete;
    stageTrigger.setAttribute(
      "aria-label",
      state.isComplete
        ? "Session complete"
        : `${state.actionLabel}. Current stage ${state.currentLabel}. Next stage ${state.nextLabel}.`,
    );
  }
}

function syncSessionStatusControlDatasets(control, source = {}) {
  if (!control) {
    return;
  }

  control.dataset.sessionStatus = normalizeSessionStatus(control.value);
  control.dataset.startedAt = source.startedAt || "";
  control.dataset.germinationStartedAt = source.germinationStartedAt || "";
  control.dataset.firstPlantedAt = source.firstPlantedAt || "";
  control.dataset.completedAt = source.completedAt || "";
}

function getSessionStatusVisualState(control) {
  const value = control?.value || "";
  const normalizedStatus = normalizeSessionStatus(value);
  const progressKey = getSessionStatusProgressKey(control);
  const effectiveStage = progressKey || normalizedStatus;
  const timestampKeyByStage = {
    soaking: "startedAt",
    germination: "germinationStartedAt",
    "first-germinated": "firstPlantedAt",
    completed: "completedAt",
  };
  const iconKeyByStage = {
    soaking: "soaking",
    germination: "germination",
    "first-germinated": "first-germinated",
    completed: "completed",
  };

  switch (effectiveStage) {
    case "soaking":
      {
        const startedAtValue = control?.dataset?.[timestampKeyByStage.soaking] || "";
        const startedAtDate = parseCompletedAtValue(startedAtValue);
        const setupGraceActive = isSetupGracePeriodActive(startedAtDate);
        return {
          normalizedStatus,
          progressKey,
          tone: "soaking",
          label: "Soaking",
          helperText: setupGraceActive ? "Setup grace period" : "Currently soaking",
          iconKey: iconKeyByStage.soaking,
          timestampLabel: setupGraceActive
            ? formatSetupGraceStartsIn(startedAtDate)
            : formatSessionStatusTimestampLabel(startedAtValue),
        };
      }
    case "germination":
    case "germinating":
      return {
        normalizedStatus,
        progressKey,
        tone: "germinating",
        label: "Germinating",
        helperText: "Germination underway",
        iconKey: iconKeyByStage.germination,
        timestampLabel: formatSessionStatusTimestampLabel(control?.dataset?.[timestampKeyByStage.germination] || ""),
      };
    case "first-germinated":
    case "germination-started":
      return {
        normalizedStatus,
        progressKey,
        tone: "first-germinated",
        label: "Germination Started",
        helperText: "First sprout recorded",
        iconKey: iconKeyByStage["first-germinated"],
        timestampLabel: formatSessionStatusTimestampLabel(control?.dataset?.[timestampKeyByStage["first-germinated"]] || ""),
      };
    case "completed":
      return {
        normalizedStatus,
        progressKey,
        tone: "completed",
        label: "Completed",
        helperText: "Session successfully completed",
        iconKey: iconKeyByStage.completed,
        timestampLabel: formatSessionStatusTimestampLabel(control?.dataset?.[timestampKeyByStage.completed] || ""),
      };
    case "unselected":
    case "":
    default:
      return {
        normalizedStatus,
        progressKey,
        tone: "unselected",
        label: "Not Started",
        helperText: "Update the stage as your seeds progress through the session.",
        iconKey: "",
        timestampLabel: "Not recorded yet",
      };
  }
}

function formatSessionStatusTimestampLabel(value = "") {
  const parsedValue = parseCompletedAtValue(value);
  return parsedValue ? formatTimingDateTime(parsedValue) : "Not recorded yet";
}

function renderSessionStatusStageIconMarkup(stageIconKey = "", variant = "pill") {
  if (!stageIconKey) {
    return `
      <span class="session-status-stage-icon session-status-stage-icon--${escapeHtml(variant)}" aria-hidden="true">
        ${renderCommandCenterIconMarkup("header", "session-status-stage-icon-symbol")}
      </span>
    `;
  }

  return `
    <span class="session-status-stage-icon session-status-stage-icon--${escapeHtml(variant)}" aria-hidden="true">
      ${renderCommandCenterIconMarkup(`stage-${stageIconKey}`, `session-status-stage-icon-symbol command-icon--stage command-icon--stage-${stageIconKey}`)}
    </span>
  `;
}

function getPartitionChartTitle(systemType) {
  return systemType === "TRA" ? "TRā™ Partition Chart" : "KAN® Partition Chart";
}

function updatePartitionWorkHeading(titleElement, systemType) {
  if (!titleElement) {
    return;
  }

  const normalizedSystemType = systemType === "TRA" ? "TRA" : "KAN";
  const titleText = titleElement.querySelector("[data-partition-title-text]");
  const titleIcon = titleElement.querySelector("[data-partition-title-icon]");

  if (titleText) {
    titleText.textContent = getPartitionChartTitle(normalizedSystemType);
  } else {
    titleElement.textContent = getPartitionChartTitle(normalizedSystemType);
  }

  if (titleIcon) {
    const iconAsset = PARTITION_HEADER_ICON_ASSETS[normalizedSystemType] || "";
    if (iconAsset) {
      titleIcon.src = iconAsset;
    }
    titleIcon.alt = normalizedSystemType === "TRA" ? "TRA partition icon" : "KAN partition icon";
    titleIcon.dataset.systemType = normalizedSystemType;
  }
}

function openGrowthStageModal({ stageField, stageTrigger, message = "", focusStageOptions = false } = {}) {
  if (!stageField) {
    return false;
  }

  if (appState.growthStageModalOpen) {
    return true;
  }

  const overlay = ensureGrowthStageModal();
  const actions = overlay.querySelector("#growth-stage-modal-actions");
  const helper = overlay.querySelector("[data-growth-stage-modal-helper]");
  const currentProgressKey = getSessionStatusProgressKey(stageField);
  if (!actions) {
    return false;
  }

  if (helper) {
    helper.textContent = String(message || "").trim();
    helper.hidden = !helper.textContent;
  }

  actions.innerHTML = SESSION_STAGE_OPTIONS.map((option) => `
    <button
      type="button"
      class="stage-button ${option.tone} stage-button--${escapeHtml(option.progressKey || option.value)} ${currentProgressKey === (option.progressKey || option.value) ? "is-active" : ""}"
      data-growth-stage-value="${option.value}"
      data-growth-stage-progress="${escapeHtml(option.progressKey || option.value)}"
    >
      <span>${escapeHtml(option.modalLabel)}</span>
      ${currentProgressKey === (option.progressKey || option.value) ? '<span class="stage-option-check" aria-hidden="true">✓</span>' : ""}
    </button>
  `).join("");

  actions.querySelectorAll("[data-growth-stage-value]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const nextValue = button.getAttribute("data-growth-stage-value") || "";
      const nextProgressKey = String(button.getAttribute("data-growth-stage-progress") || "").trim();
      const timestamp = new Date().toISOString();
      if (nextProgressKey === "soaking") {
        stageField.dataset.germinationStartedAt = "";
        stageField.dataset.firstPlantedAt = "";
        stageField.dataset.completedAt = "";
      } else if (nextProgressKey === "germination") {
        stageField.dataset.germinationStartedAt = stageField.dataset.germinationStartedAt || timestamp;
        stageField.dataset.firstPlantedAt = "";
        stageField.dataset.completedAt = "";
      } else if (nextProgressKey === "first-germinated") {
        stageField.dataset.germinationStartedAt = stageField.dataset.germinationStartedAt || timestamp;
        stageField.dataset.firstPlantedAt = stageField.dataset.firstPlantedAt || timestamp;
        stageField.dataset.completedAt = "";
      } else if (nextProgressKey === "completed") {
        stageField.dataset.germinationStartedAt = stageField.dataset.germinationStartedAt || timestamp;
        stageField.dataset.firstPlantedAt = stageField.dataset.firstPlantedAt || timestamp;
        stageField.dataset.completedAt = stageField.dataset.completedAt || timestamp;
      }
      appState.growthStageModalDismissed = false;
      appState.growthStage = nextValue || null;
      stageField.value = nextValue;
      syncSessionStatusControlDatasets(stageField, {
        germinationStartedAt: stageField.dataset.germinationStartedAt || "",
        firstPlantedAt: stageField.dataset.firstPlantedAt || "",
        completedAt: stageField.dataset.completedAt || "",
      });
      updateSessionStatusAppearance(stageField, stageTrigger);
      stageField.dispatchEvent(new Event("change", { bubbles: true }));
      closeGrowthStageModal();
    });
  });

  overlay.__stageContext = { stageField, stageTrigger };
  appState.growthStageModalOpen = true;
  appState.pendingGrowthStageInput = stageField.name || stageField.id || "sessionStatus";
  overlay.hidden = false;
  overlay.classList.add("is-open");
  document.body.classList.add("modal-open");
  const focusTarget = focusStageOptions
    ? overlay.querySelector("[data-growth-stage-value]")
    : overlay.querySelector(".modal-close");
  focusTarget?.focus();
  return true;
}

function maybePromptGrowthStage(form, stageField, stageTrigger) {
  if (!form || normalizeSessionStatus(stageField?.value) !== "unselected") {
    return false;
  }

  if (appState.growthStageModalOpen) {
    return true;
  }

  if (Date.now() < (appState.growthStageModalSuppressedUntil || 0)) {
    return false;
  }

  return openGrowthStageModal({ stageField, stageTrigger });
}

function renderTraPartitionSections(container, partitions, options = {}) {
  const sections = [
    { label: "A", start: 0, end: 4 },
    { label: "B", start: 4, end: 8 },
    { label: "C", start: 8, end: 12 },
    { label: "D", start: 12, end: 16 },
  ];
  const shouldShowSeedAgeInput = typeof options.shouldShowSeedAgeInput === "function"
    ? options.shouldShowSeedAgeInput
    : (() => Boolean(options.showSeedAgeField));

  sections.forEach((section) => {
    const wrapper = document.createElement("section");
    wrapper.className = "tra-section";
    wrapper.innerHTML = `
      <div class="tra-section-label">Section ${section.label}</div>
      <div class="tra-section-body"></div>
    `;

    const body = wrapper.querySelector(".tra-section-body");
    partitions.slice(section.start, section.end).forEach((partition, localIndex) => {
      const index = section.start + localIndex;
      body.appendChild(buildPartitionFormCard(partition, index, {
        ...options,
        showSeedAgeInput: shouldShowSeedAgeInput(partition, index),
      }));
      hydratePartitionRow(body.lastElementChild, partition);
    });

    container.appendChild(wrapper);
  });
}

function hydratePartitionRow(row, partition) {
  const sourceInput = row.querySelector('input[name^="source-"]');
  const varietyInput = row.querySelector('input[name^="seedVariety-"]');
  if (sourceInput instanceof HTMLInputElement) {
    const match = buildPartitionIdentityMatch("source", formatPartitionSource(partition), {
      selectedCandidate: partition?.sourceCanonicalId || partition?.source_canonical_id ? {
        canonicalId: partition?.sourceCanonicalId || partition?.source_canonical_id,
        canonicalName: partition?.sourceCanonicalName || partition?.source_canonical_name || formatPartitionSource(partition),
        normalizedKey: partition?.sourceNormalizedName || partition?.source_normalized_name || normalizeSourceNameForMatching(formatPartitionSource(partition)),
        label: partition?.sourceCanonicalName || partition?.source_canonical_name || formatPartitionSource(partition),
      } : null,
    });
    sourceInput.value = formatPartitionSource(partition);
    sourceInput.dataset.canonicalId = partition?.sourceCanonicalId || partition?.source_canonical_id || match.canonicalId;
    sourceInput.dataset.canonicalLabel = partition?.sourceCanonicalName || partition?.source_canonical_name || match.canonicalName || sourceInput.value;
    sourceInput.dataset.normalizedKey = partition?.sourceNormalizedName || partition?.source_normalized_name || match.normalizedKey;
    sourceInput.dataset.matchStatus = normalizePartitionIdentityMatchStatus(partition?.sourceMatchStatus || partition?.source_match_status || match.matchStatus);
    sourceInput.dataset.matchConfidence = String(Number(partition?.sourceMatchConfidence ?? partition?.source_match_confidence ?? match.matchConfidence) || 0);
    sourceInput.dataset.reviewCandidateId = partition?.sourceReviewCandidateId || partition?.source_review_candidate_id || match.reviewCandidateId || "";
    sourceInput.dataset.reviewCandidateName = partition?.sourceReviewCandidateName || partition?.source_review_candidate_name || match.reviewCandidateName || "";
  }
  if (varietyInput instanceof HTMLInputElement) {
    const match = buildPartitionIdentityMatch("seedVariety", formatPartitionSeedVariety(partition), {
      selectedCandidate: partition?.seedVarietyCanonicalId || partition?.seed_variety_canonical_id ? {
        canonicalId: partition?.seedVarietyCanonicalId || partition?.seed_variety_canonical_id,
        canonicalName: partition?.seedVarietyCanonicalName || partition?.seed_variety_canonical_name || formatPartitionSeedVariety(partition),
        normalizedKey: partition?.seedVarietyNormalizedName || partition?.seed_variety_normalized_name || normalizeSeedVarietyNameForMatching(formatPartitionSeedVariety(partition)),
        label: partition?.seedVarietyCanonicalName || partition?.seed_variety_canonical_name || formatPartitionSeedVariety(partition),
      } : null,
    });
    varietyInput.value = formatPartitionSeedVariety(partition);
    varietyInput.dataset.canonicalId = partition?.seedVarietyCanonicalId || partition?.seed_variety_canonical_id || match.canonicalId;
    varietyInput.dataset.canonicalLabel = partition?.seedVarietyCanonicalName || partition?.seed_variety_canonical_name || match.canonicalName || varietyInput.value;
    varietyInput.dataset.normalizedKey = partition?.seedVarietyNormalizedName || partition?.seed_variety_normalized_name || match.normalizedKey;
    varietyInput.dataset.matchStatus = normalizePartitionIdentityMatchStatus(partition?.seedVarietyMatchStatus || partition?.seed_variety_match_status || match.matchStatus);
    varietyInput.dataset.matchConfidence = String(Number(partition?.seedVarietyMatchConfidence ?? partition?.seed_variety_match_confidence ?? match.matchConfidence) || 0);
    varietyInput.dataset.reviewCandidateId = partition?.seedVarietyReviewCandidateId || partition?.seed_variety_review_candidate_id || match.reviewCandidateId || "";
    varietyInput.dataset.reviewCandidateName = partition?.seedVarietyReviewCandidateName || partition?.seed_variety_review_candidate_name || match.reviewCandidateName || "";
  }
  row.querySelector('select[name^="seedType-"]').value = normalizeSeedTypeId(partition.seedType || "");
  row.querySelector('select[name^="feminized-"]').value = partition.feminized || "";
  row.querySelector('input[name^="seedCount-"]').value = partition.seedCount > 0 ? partition.seedCount : "";
  const seedAgeField = row.querySelector('input[name^="seedAgeYears-"]');
  if (seedAgeField) {
    seedAgeField.value = formatSeedAgeInputValue(partition.seedAgeYears);
    if (partition?.seedAgeAutoFilledFromSession) {
      seedAgeField.dataset.autoFilledFromSessionAge = "true";
      seedAgeField.dataset.seedAgeAutofillApplied = "true";
    } else {
      delete seedAgeField.dataset.autoFilledFromSessionAge;
      delete seedAgeField.dataset.seedAgeAutofillApplied;
    }
  }
  row.querySelector('input[name="plantedCount"]').value = partition.plantedCount || "";
  if (partition.seedVaultEntryId) {
    row.dataset.seedVaultEntryId = partition.seedVaultEntryId;
  }
  if (partition.seedVaultEntrySnapshot) {
    row.dataset.seedVaultEntrySnapshot = JSON.stringify(partition.seedVaultEntrySnapshot);
  }
}

function getCurrentPartitionValues(form) {
  const previousValues = Array.isArray(form?.__partitionDraftValues) ? form.__partitionDraftValues : [];
  return [...form.querySelectorAll(".partition-row")].map((row, index) => {
    const sourceInput = row.querySelector('input[name^="source-"]');
    const varietyInput = row.querySelector('input[name^="seedVariety-"]');
    const sourceValue = sourceInput?.value.trim() || "";
    const varietyValue = varietyInput?.value.trim() || "";
    const sourceMatch = buildPartitionIdentityMatch("source", sourceValue, {
      selectedCandidate: sourceInput?.dataset.matchStatus === "selected" ? {
        canonicalId: sourceInput.dataset.canonicalId || "",
        canonicalName: sourceInput.dataset.canonicalLabel || sourceValue,
        normalizedKey: sourceInput.dataset.normalizedKey || normalizeSourceNameForMatching(sourceValue),
        label: sourceInput.dataset.canonicalLabel || sourceValue,
      } : null,
    });
    const varietyMatch = buildPartitionIdentityMatch("seedVariety", varietyValue, {
      selectedCandidate: varietyInput?.dataset.matchStatus === "selected" ? {
        canonicalId: varietyInput.dataset.canonicalId || "",
        canonicalName: varietyInput.dataset.canonicalLabel || varietyValue,
        normalizedKey: varietyInput.dataset.normalizedKey || normalizeSeedVarietyNameForMatching(varietyValue),
        label: varietyInput.dataset.canonicalLabel || varietyValue,
      } : null,
    });

    return {
      id: Number(row.dataset.partitionId) || index + 1,
      source: sourceValue,
      sourceCanonicalName: sourceMatch.canonicalName,
      sourceCanonicalId: sourceMatch.canonicalId,
      sourceNormalizedName: sourceMatch.normalizedKey,
      sourceMatchStatus: sourceMatch.matchStatus,
      sourceMatchConfidence: sourceMatch.matchConfidence,
      sourceReviewCandidateId: sourceMatch.reviewCandidateId,
      sourceReviewCandidateName: sourceMatch.reviewCandidateName,
      seedVariety: varietyValue,
      seedVarietyCanonicalName: varietyMatch.canonicalName,
      seedVarietyCanonicalId: varietyMatch.canonicalId,
      seedVarietyNormalizedName: varietyMatch.normalizedKey,
      seedVarietyMatchStatus: varietyMatch.matchStatus,
      seedVarietyMatchConfidence: varietyMatch.matchConfidence,
      seedVarietyReviewCandidateId: varietyMatch.reviewCandidateId,
      seedVarietyReviewCandidateName: varietyMatch.reviewCandidateName,
      breeder: "",
      seedType: normalizeSeedTypeId(row.querySelector('select[name^="seedType-"]')?.value || ""),
      feminized: row.querySelector('select[name^="feminized-"]')?.value || "",
      seedCount: Number(row.querySelector('input[name^="seedCount-"]')?.value) || 0,
      plantedCount: row.querySelector('input[name="plantedCount"]')?.value.trim() || "",
      seedAgeYears: normalizeSeedAgeYears(
        row.querySelector('input[name^="seedAgeYears-"]')?.value
        ?? previousValues[index]?.seedAgeYears,
      ),
      seedVaultEntryId: String(row.dataset.seedVaultEntryId || previousValues[index]?.seedVaultEntryId || "").trim(),
      seedVaultEntrySnapshot: readPartitionSeedVaultSnapshotFromRow(row) || previousValues[index]?.seedVaultEntrySnapshot || null,
    };
  });
}

function getSeedAgeModeForForm(form) {
  return normalizeSeedAgeMode(form?.dataset?.seedAgeMode || "");
}

function getSessionSeedAgeValueForForm(form) {
  const seedAgeDraft = getSeedAgeDraftState(form);
  return normalizeSeedAgeYears(form?.elements?.sessionSeedAgeYears?.value ?? seedAgeDraft.sessionSeedAgeYears);
}

function persistMixedSeedAgeDrafts(form, partitions = []) {
  if (!(form instanceof HTMLFormElement)) {
    return {};
  }

  const nextDrafts = {};
  partitions.forEach((partition, index) => {
    const partitionId = String(partition?.id ?? index + 1);
    nextDrafts[partitionId] = normalizeSeedAgeYears(partition?.seedAgeYears ?? partition?.seed_age_years);
  });
  form.__mixedSeedAgeDrafts = nextDrafts;
  return nextDrafts;
}

function getMixedSeedAgeDrafts(form) {
  if (!(form instanceof HTMLFormElement)) {
    return {};
  }

  if (!form.__mixedSeedAgeDrafts || typeof form.__mixedSeedAgeDrafts !== "object") {
    form.__mixedSeedAgeDrafts = {};
  }

  return form.__mixedSeedAgeDrafts;
}

function hasPartitionCoreValues(values = {}) {
  return getPartitionBaseRowState({
    sourceValue: values.sourceValue ?? values.source ?? "",
    varietyValue: values.varietyValue ?? values.seedVariety ?? "",
    typeValue: values.typeValue ?? values.seedType ?? "",
    sexValue: values.sexValue ?? values.feminized ?? "",
    seedValue: values.seedValue ?? values.seedCount ?? "",
    plantedValue: values.plantedValue ?? values.plantedCount ?? "",
  }) !== "empty";
}

function shouldShowPartitionSeedAgeFieldForValues(values = {}) {
  return hasPartitionCoreValues(values);
}

function shouldShowPartitionSeedAgeFieldForPartition(partition = {}) {
  return shouldShowPartitionSeedAgeFieldForValues({
    source: partition.source,
    seedVariety: partition.seedVariety,
    seedType: normalizeSeedTypeId(partition.seedType || ""),
    feminized: partition.feminized,
    seedCount: partition.seedCount,
    plantedCount: partition.plantedCount,
    seedAgeYears: partition.seedAgeYears ?? partition.seed_age_years,
  });
}

function autofillMixedPartitionSeedAgeYears(partitions = [], sessionSeedAgeYears = null) {
  const normalizedSessionSeedAgeYears = normalizeSeedAgeYears(sessionSeedAgeYears);
  if (!Array.isArray(partitions) || normalizedSessionSeedAgeYears === null) {
    return partitions;
  }

  partitions.forEach((partition) => {
    if (!partition || !hasPartitionCoreValues(partition)) {
      return;
    }
    if (normalizeSeedAgeYears(partition.seedAgeYears ?? partition.seed_age_years) !== null) {
      return;
    }
    partition.seedAgeYears = normalizedSessionSeedAgeYears;
    partition.seedAgeAutoFilledFromSession = true;
  });

  return partitions;
}

function applySeedAgeValuesToPartitions(partitions = [], options = {}) {
  const trackingEnabled = Boolean(options.trackingEnabled);
  const mode = normalizeSeedAgeMode(options.mode || "");
  const sessionSeedAgeYears = normalizeSeedAgeYears(options.sessionSeedAgeYears);
  const mixedSeedAgeDrafts = options.mixedSeedAgeDrafts && typeof options.mixedSeedAgeDrafts === "object"
    ? options.mixedSeedAgeDrafts
    : {};

  if (!Array.isArray(partitions)) {
    return partitions;
  }

  partitions.forEach((partition, index) => {
    if (!partition) {
      return;
    }

    const partitionId = String(partition.id ?? index + 1);
    const isActive = hasPartitionCoreValues(partition);
    const mixedDraftValue = normalizeSeedAgeYears(mixedSeedAgeDrafts[partitionId]);
    const currentValue = normalizeSeedAgeYears(partition.seedAgeYears ?? partition.seed_age_years);

    partition.seedAgeAutoFilledFromSession = false;

    if (!trackingEnabled) {
      partition.seedAgeYears = null;
      return;
    }

    if (mode === "same") {
      partition.seedAgeYears = isActive ? sessionSeedAgeYears : null;
      partition.seedAgeAutoFilledFromSession = isActive && sessionSeedAgeYears !== null;
      return;
    }

    if (mode === "mixed") {
      if (!isActive) {
        partition.seedAgeYears = mixedDraftValue ?? currentValue;
        return;
      }

      if (mixedDraftValue !== null) {
        partition.seedAgeYears = mixedDraftValue;
        return;
      }

      if (currentValue !== null) {
        partition.seedAgeYears = currentValue;
        return;
      }

      partition.seedAgeYears = sessionSeedAgeYears;
      partition.seedAgeAutoFilledFromSession = sessionSeedAgeYears !== null;
      return;
    }

    partition.seedAgeYears = currentValue;
  });

  return partitions;
}

function getEffectivePartitionSeedAgeFromRow(row, seedAgeState = {}) {
  if (!(row instanceof Element) || !seedAgeState?.trackingEnabled) {
    return null;
  }

  const isActive = hasPartitionCoreValues({
    sourceValue: row.querySelector('input[name^="source-"]')?.value || "",
    varietyValue: row.querySelector('input[name^="seedVariety-"]')?.value || "",
    typeValue: row.querySelector('select[name^="seedType-"]')?.value || "",
    sexValue: row.querySelector('select[name^="feminized-"]')?.value || "",
    seedValue: row.querySelector('input[name^="seedCount-"]')?.value || "",
    plantedValue: row.querySelector('input[name="plantedCount"]')?.value || "",
  });

  if (!isActive) {
    return null;
  }

  if (seedAgeState.mode === "same") {
    return normalizeSeedAgeYears(seedAgeState.sessionSeedAgeYears);
  }

  if (seedAgeState.mode === "mixed") {
    return normalizeSeedAgeYears(row.querySelector('input[name^="seedAgeYears-"]')?.value);
  }

  return null;
}

function renderSessionsList() {
  app.replaceChildren(cloneTemplate(templates.sessions));
  initializeCustomSelects(app);
  applySupplyStatusToSessionEntryButtons(app);
  if (!["all", "active", "completed", "attention"].includes(appState.sessionHistoryFilter || "")) {
    appState.sessionHistoryFilter = "all";
  }
  appState.sessionHistoryVisibleCount = Math.max(6, Number(appState.sessionHistoryVisibleCount) || 6);
  const sessions = sortSessionsNewestFirst(getSessions());
  const visibleSessions = getVisibleUserSessions(sessions);
  const historySessions = visibleSessions;
  const hasSessionHistory = historySessions.length > 0;
  if (String(appState.sessionDashboardScrollTarget || "").trim() === "session-history") {
    appState.sessionHistoryExpanded = true;
  }
  const activeSessionsSection = document.querySelector("#active-sessions-section");
  const seedVaultSection = document.querySelector("#seed-vault-section");
  const seedVaultShortcutSection = document.querySelector("#seed-vault-shortcut-section");
  const recentCompletedSection = document.querySelector("#recent-completed-sessions-section");
  const historySection = document.querySelector("#session-history-section");
  const analyticsSection = document.querySelector("#session-analytics-section");

  const activeSessions = sortActiveSessionsNewestFirst(
    visibleSessions.filter((session) => normalizeGrowSessionLifecycleState(session) === "active"),
  );
  const completedSessions = visibleSessions.filter((session) => normalizeGrowSessionLifecycleState(session) === "completed");
  mountSharedSessionCommandCenter(activeSessionsSection, {
    activeSessions,
    sessions: visibleSessions,
    aggregateSessions: sessions,
    hasSessionHistory,
    requiresSignIn: !appState.user,
  });

  if (seedVaultShortcutSection) {
    seedVaultShortcutSection.innerHTML = renderMySessionsSeedVaultShortcutMarkup();
  }

  const renderSeedVaultSection = () => {
    if (!seedVaultSection) {
      return;
    }

    const entryIds = new Set((appState.seedVaultEntries || []).map((entry) => String(entry.id || "").trim()).filter(Boolean));
    getSeedVaultExpandedEntryIds().forEach((entryId) => {
      if (!entryIds.has(entryId)) {
        appState.seedVaultExpandedEntryIds.delete(entryId);
      }
    });
    seedVaultSection.innerHTML = renderMySeedVaultPanelMarkup(appState.seedVaultEntries || []);
    hydrateAppIconSlots(seedVaultSection);
    normalizeSectionHeaderLayouts(seedVaultSection);
    applySupplyStatusToSessionEntryButtons(seedVaultSection);
  };

  const renderRecentCompletedSection = () => {
    if (!recentCompletedSection) {
      return;
    }

    recentCompletedSection.innerHTML = renderMySessionsRecentCompletedPanelMarkup(completedSessions.slice(0, 2));
    applySupplyStatusToSessionEntryButtons(recentCompletedSection);
  };

  const renderHistorySessions = () => {
    if (!historySection) {
      return;
    }

    const historySource = visibleSessions;
    const summaryCounts = historySource.reduce((counts, session) => {
      counts.total += 1;
      const lifecycleState = normalizeGrowSessionLifecycleState(session);
      if (lifecycleState === "active") {
        counts.active += 1;
      } else if (lifecycleState === "completed") {
        counts.completed += 1;
      }
      if (["needs_attention", "stale", "abandoned"].includes(getGrowSessionLifecycleHealth(session).classification)) {
        counts.attention += 1;
      }
      return counts;
    }, { total: 0, active: 0, completed: 0, attention: 0 });
    const filteredSessions = filterMySessionsHistorySessions(historySource, appState.sessionHistoryFilter || "all");
    const sortedSessions = sortSessionHistorySessions(filteredSessions, appState.sessionHistorySort);
    historySection.innerHTML = renderMySessionsHistoryPanelMarkup(sortedSessions, {
      filterValue: appState.sessionHistoryFilter || "all",
      sortValue: appState.sessionHistorySort || "date",
      visibleCount: appState.sessionHistoryVisibleCount || 6,
      hasAnySessions: historySessions.length > 0,
      focusSessionId: appState.sessionHistoryFocusSessionId || "",
      expanded: appState.sessionHistoryExpanded === true,
      summaryCounts,
    });
    applySupplyStatusToSessionEntryButtons(historySection);
    const focusSessionId = String(appState.sessionHistoryFocusSessionId || "").trim();
    if (focusSessionId && appState.sessionHistoryExpanded === true) {
      const highlightedRow = historySection.querySelector(`[data-session-history-row="${CSS.escape(focusSessionId)}"]`);
      if (highlightedRow instanceof Element) {
        scrollElementIntoViewAfterLayout(highlightedRow, {
          delayMs: 80,
          block: "center",
        });
      }
    }
  };

  const renderAnalyticsSection = () => {
    if (!analyticsSection) {
      return;
    }

    analyticsSection.innerHTML = renderMySessionsAnalyticsPanelMarkup(visibleSessions, {
      aggregateSessions: sessions,
    });
    applySupplyStatusToSessionEntryButtons(analyticsSection);
  };

  if (recentCompletedSection && recentCompletedSection.dataset.sessionsPanelBound !== "true") {
    recentCompletedSection.dataset.sessionsPanelBound = "true";
    recentCompletedSection.addEventListener("click", (event) => {
      const target = event.target;
      if (!(target instanceof Element)) {
        return;
      }

      const filterLink = target.closest("[data-history-filter-link]");
      if (!filterLink) {
        return;
      }

      event.preventDefault();
      appState.sessionHistoryFilter = String(filterLink.getAttribute("data-history-filter-link") || "completed");
      appState.sessionHistoryExpanded = true;
      renderHistorySessions();
      if (historySection) {
        scrollElementIntoViewAfterLayout(historySection, { delayMs: 80, block: "start" });
      }
    });
  }

  if (seedVaultSection && seedVaultSection.dataset.seedVaultPanelBound !== "true") {
    seedVaultSection.dataset.seedVaultPanelBound = "true";
    seedVaultSection.addEventListener("click", async (event) => {
      const target = event.target;
      if (!(target instanceof Element)) {
        return;
      }

      const addButton = target.closest("[data-seed-vault-add='true']");
      if (addButton) {
        event.preventDefault();
        openSeedVaultEntryModal();
        return;
      }

      const toggleButton = target.closest("[data-seed-vault-toggle]");
      if (toggleButton) {
        event.preventDefault();
        const entryId = String(toggleButton.getAttribute("data-seed-vault-toggle") || "").trim();
        const expandedEntryIds = getSeedVaultExpandedEntryIds();
        if (expandedEntryIds.has(entryId)) {
          expandedEntryIds.delete(entryId);
        } else if (entryId) {
          expandedEntryIds.add(entryId);
        }
        renderSeedVaultSection();
        return;
      }

      const favoriteButton = target.closest("[data-seed-vault-favorite]");
      if (favoriteButton) {
        event.preventDefault();
        const entryId = String(favoriteButton.getAttribute("data-seed-vault-favorite") || "").trim();
        const entry = (appState.seedVaultEntries || []).find((candidate) => candidate.id === entryId);
        await updateSeedVaultEntryFlag(entryId, { isFavorite: !entry?.isFavorite });
        return;
      }

      const archiveButton = target.closest("[data-seed-vault-archive]");
      if (archiveButton) {
        event.preventDefault();
        const entryId = String(archiveButton.getAttribute("data-seed-vault-archive") || "").trim();
        const entry = (appState.seedVaultEntries || []).find((candidate) => candidate.id === entryId);
        await updateSeedVaultEntryFlag(entryId, { isArchived: !entry?.isArchived });
        return;
      }

      const startSessionButton = target.closest("[data-seed-vault-start-session]");
      if (startSessionButton) {
        event.preventDefault();
        const entryId = String(startSessionButton.getAttribute("data-seed-vault-start-session") || "").trim();
        startNewSessionFromSeedVaultEntry(entryId);
        return;
      }

      const deleteButton = target.closest("[data-seed-vault-delete]");
      if (deleteButton) {
        event.preventDefault();
        const entryId = String(deleteButton.getAttribute("data-seed-vault-delete") || "").trim();
        await deleteSeedVaultEntry(entryId);
      }
    });

    seedVaultSection.addEventListener("input", (event) => {
      const target = event.target;
      if (!(target instanceof HTMLInputElement) || target.getAttribute("data-seed-vault-search") !== "true") {
        return;
      }

      appState.seedVaultSearchQuery = target.value || "";
      renderSeedVaultSection();
      const nextSearch = seedVaultSection.querySelector("[data-seed-vault-search='true']");
      if (nextSearch instanceof HTMLInputElement) {
        nextSearch.focus({ preventScroll: true });
        const valueLength = nextSearch.value.length;
        nextSearch.setSelectionRange(valueLength, valueLength);
      }
    });

    seedVaultSection.addEventListener("change", (event) => {
      const target = event.target;
      if (!(target instanceof HTMLSelectElement)) {
        return;
      }

      if (target.getAttribute("data-seed-vault-favorite-filter") === "true") {
        appState.seedVaultFavoriteFilter = normalizeSeedVaultFavoriteFilter(target.value);
        renderSeedVaultSection();
        return;
      }

      if (target.getAttribute("data-seed-vault-status-filter") === "true") {
        appState.seedVaultStatusFilter = normalizeSeedVaultStatusFilter(target.value);
        renderSeedVaultSection();
        return;
      }

      if (target.getAttribute("data-seed-vault-source-filter") === "true") {
        appState.seedVaultSourceFilter = normalizeSeedVaultDropdownFilter(target.value);
        renderSeedVaultSection();
        return;
      }

      if (target.getAttribute("data-seed-vault-type-filter") === "true") {
        appState.seedVaultTypeFilter = normalizeSeedVaultDropdownFilter(target.value);
        renderSeedVaultSection();
        return;
      }

      if (target.getAttribute("data-seed-vault-sex-filter") === "true") {
        appState.seedVaultSexFilter = normalizeSeedVaultDropdownFilter(target.value);
        renderSeedVaultSection();
        return;
      }

      if (target.getAttribute("data-seed-vault-sort") === "true") {
        appState.seedVaultSort = normalizeSeedVaultSort(target.value);
        renderSeedVaultSection();
      }
    });
  }

  if (historySection && historySection.dataset.sessionsPanelBound !== "true") {
    historySection.dataset.sessionsPanelBound = "true";
    historySection.addEventListener("click", async (event) => {
      const target = event.target;
      if (!(target instanceof Element)) {
        return;
      }

      const toggleButton = target.closest("[data-session-history-toggle='true']");
      if (toggleButton) {
        event.preventDefault();
        appState.sessionHistoryExpanded = appState.sessionHistoryExpanded !== true;
        renderHistorySessions();
        return;
      }

      const filterButton = target.closest("[data-session-history-filter]");
      if (filterButton) {
        event.preventDefault();
        appState.sessionHistoryExpanded = true;
        appState.sessionHistoryFilter = String(filterButton.getAttribute("data-session-history-filter") || "all");
        appState.sessionHistoryVisibleCount = 6;
        renderHistorySessions();
        return;
      }

      const seeMoreButton = target.closest("[data-session-history-see-more]");
      if (seeMoreButton) {
        event.preventDefault();
        appState.sessionHistoryExpanded = true;
        appState.sessionHistoryVisibleCount = Math.max(6, Number(appState.sessionHistoryVisibleCount) || 6) + 6;
        renderHistorySessions();
        return;
      }

      const deleteButton = target.closest("[data-session-delete]");
      if (!deleteButton) {
        return;
      }

      event.preventDefault();
      event.stopPropagation();
      const sessionId = String(deleteButton.getAttribute("data-session-delete") || "");
      const session = sessions.find((entry) => String(entry.id) === sessionId);
      if (!sessionId || !session) {
        return;
      }

      const deleteAction = await confirmSessionArchive(session);
      if (!deleteAction || deleteAction.action === "cancel") {
        return;
      }

      try {
        const deleteResult = await performSessionDeleteAction(session, deleteAction);
        if (!deleteResult) {
          return;
        }
        appState.sessionHistoryFocusSessionId = sessionId;
        appState.sessionHistoryFilter = "all";
        appState.sessionHistoryExpanded = true;
        renderSessionsList();
      } catch (error) {
        window.alert(error.message || "Could not delete session.");
      }
    });

    historySection.addEventListener("change", (event) => {
      const target = event.target;
      if (!(target instanceof HTMLSelectElement) || target.getAttribute("data-session-history-sort") !== "true") {
        return;
      }

      appState.sessionHistorySort = target.value || "date";
      appState.sessionHistoryVisibleCount = 6;
      appState.sessionHistoryExpanded = true;
      renderHistorySessions();
    });
  }

  renderSeedVaultSection();
  renderRecentCompletedSection();
  renderHistorySessions();
  renderAnalyticsSection();
  flushPendingSessionDashboardScrollTarget();
}

function renderActiveSessionsPage() {
  const sessions = sortSessionsNewestFirst(getSessions());
  const visibleSessions = getVisibleUserSessions(sessions);
  const activeSessions = sortActiveSessionsNewestFirst(
    visibleSessions.filter((session) => normalizeGrowSessionLifecycleState(session) === "active"),
  );

  app.innerHTML = `
    <section class="active-sessions-page">
      <section id="active-sessions-page-command-center" class="active-sessions-command-center"></section>
    </section>
  `;

  const host = document.querySelector("#active-sessions-page-command-center");
  mountSharedSessionCommandCenter(host, {
    activeSessions,
    sessions: visibleSessions,
    aggregateSessions: sessions,
    hasSessionHistory: visibleSessions.length > 0,
    requiresSignIn: !appState.user,
    compact: true,
    showMetrics: false,
    showViewAllLink: false,
    headerEyebrow: "ACTIVE SESSIONS",
    headerTitle: "Active Sessions",
    headerDescription: "Track every session currently in progress and continue exactly where you left off.",
    headerActionHref: "#sessions",
    headerActionLabel: "← Back to My Sessions",
  });
}

function renderPublicSessionDetail(snapshotId) {
  const snapshot = getApprovedPublicGallerySnapshotById(snapshotId);
  const isLoadingSnapshot = Boolean(appState.galleryRefreshPromise) || (!isMockDataEnabled() && !appState.gallerySnapshots.length);

  if (!snapshot) {
    app.innerHTML = `
      <section class="card public-session-card">
        <div class="section-heading app-section-header">
          <div class="section-title-with-icon app-section-header-main">
            ${renderAppSectionHeaderIcon("public-session")}
            <div>
              <p class="eyebrow">Public Session</p>
              <h2>Grow session view</h2>
              <p class="muted">${isLoadingSnapshot ? "Loading public grow session..." : "This public grow session is unavailable."}</p>
            </div>
          </div>
          <div class="inline-actions">
            <a class="button button-secondary" href="#gallery">Back to Community Grow</a>
          </div>
        </div>
      </section>
    `;
    return;
  }

  const activeMockScenario = getActiveMockPublicSessionScenario(snapshot);
  const publicDetails = activeMockScenario
    ? getMockPublicSessionDetails(snapshot, activeMockScenario)
    : getGallerySnapshotPublicSessionDetails(snapshot);
  const sharedProfileMarkup = renderGallerySharedProfileMarkup(snapshot);
  const sessionTitle = activeMockScenario ? activeMockScenario.name : snapshot.title;
  const facts = [
    { label: "System", value: publicDetails.systemLabel },
    { label: "Source", value: publicDetails.sourceLabel },
    { label: "Seed Variety", value: publicDetails.seedVarietyLabel },
    { label: "Type", value: publicDetails.seedTypeLabel },
    { label: "Sex", value: publicDetails.sexLabel },
    { label: "Seed Age", value: publicDetails.seedAgeLabel },
    { label: "Seed Count", value: publicDetails.seedCountLabel },
    { label: "Germinated", value: publicDetails.germinatedLabel },
    { label: "Germination Rate", value: publicDetails.germinationRateLabel },
    { label: "Session Date", value: publicDetails.sessionDateLabel },
  ];
  const mockScenarioSelectorMarkup = activeMockScenario
    ? `
      <div class="inline-actions" aria-label="Mock public session scenarios">
        ${MOCK_PUBLIC_SESSION_SCENARIOS.map((scenario) => `
          <button
            type="button"
            class="button ${scenario.key === activeMockScenario.key ? "button-primary" : "button-secondary"}"
            data-mock-public-session-scenario="${escapeHtml(scenario.key)}"
            aria-pressed="${scenario.key === activeMockScenario.key ? "true" : "false"}"
          >${escapeHtml(scenario.name)}</button>
        `).join("")}
      </div>
    `
    : "";

  app.innerHTML = `
    <section class="card public-session-card">
      <div class="section-heading app-section-header">
        <div class="section-title-with-icon app-section-header-main">
          ${renderAppSectionHeaderIcon("public-session")}
          <div>
            <p class="eyebrow">Public Session</p>
            <h2>${escapeHtml(sessionTitle)}</h2>
            <p class="muted">Read-only grow session view</p>
            ${mockScenarioSelectorMarkup}
          </div>
        </div>
        <div class="inline-actions">
          <button type="button" class="button button-secondary" data-contact-admin-open="true" data-contact-admin-type="Report content">Report / Contact Admin</button>
          <a class="button button-secondary" href="#gallery">Back to Community Grow</a>
        </div>
      </div>
      ${sharedProfileMarkup ? `<div class="public-session-profile">${sharedProfileMarkup}</div>` : ""}
      <div class="public-session-layout">
        <div class="public-session-media">
          ${renderGallerySnapshotMediaMarkup(snapshot, getGallerySnapshotFeedDetails(snapshot))}
          ${renderPublicSessionPartitionResultsMarkup(publicDetails.resultSummary, { systemType: snapshot.systemType })}
        </div>
        <div class="public-session-details">
          <div class="public-session-readonly-note">
            <strong>Read-only</strong>
            <p>Public viewers can explore shared grow results here without editing sessions, notes, images, or gallery settings.</p>
          </div>
          <div class="public-session-meta-grid">
            ${facts.map((fact) => `
              <article class="meta-card public-session-meta-card">
                <strong>${escapeHtml(fact.label)}</strong>
                <p>${escapeHtml(fact.value)}</p>
              </article>
            `).join("")}
          </div>
          ${!activeMockScenario && publicDetails.resultSummary ? renderSessionResultBreakdownMarkup(publicDetails.resultSummary, { compact: true, maxPartitions: 16, maxGroups: 4 }) : ""}
          ${renderPublicSessionTimelineSection(snapshot)}
        </div>
      </div>
    </section>
  `;

  app.querySelectorAll("[data-mock-public-session-scenario]").forEach((button) => {
    button.addEventListener("click", () => {
      setActiveMockPublicSessionScenario(button.dataset.mockPublicSessionScenario || "");
      renderPublicSessionDetail(snapshotId);
    });
  });
}

function renderPublicMemberProfile(memberId) {
  const profileKey = String(memberId || "").trim();
  const normalizedId = resolvePublicMemberProfileId(profileKey) || (isUuidLike(profileKey) ? profileKey : "");
  const normalizedHandle = !isUuidLike(profileKey) ? normalizePublicProfileHandle(decodeURIComponent(profileKey)) : "";
  if (!normalizedId && normalizedHandle && !appState.publicMemberProfilesRefreshPromises[normalizedHandle]) {
    void loadPublicMemberProfile(normalizedHandle, { reason: "route:public-member-profile-handle" }).then((profile) => {
      const resolvedId = String(profile?.id || "").trim();
      if (resolvedId && normalizeNavigationHash(window.location.hash || "#home").startsWith("#members/")) {
        renderPublicMemberProfile(resolvedId);
      }
    });
  }
  const isLoadingSnapshots = Boolean(appState.galleryRefreshPromise) || (!isMockDataEnabled() && !appState.gallerySnapshotsLoaded);
  const isLoadingProfile = Boolean(appState.publicMemberProfilesRefreshPromises[normalizedId] || appState.publicMemberProfilesRefreshPromises[normalizedHandle]);
  const isOwnProfile = isViewingOwnPublicMemberProfile(normalizedId);
  const approvedSnapshots = sortGallerySnapshotsNewestFirst(getApprovedPublicSnapshotsForMember(normalizedId));
  const profile = getPublicMemberProfile(normalizedId);
  const canShowPublicProfileData = Boolean(profile && (profile.isPublicVisible !== false || isOwnProfile || isAdminUser()));
  const publicStats = calculatePublicProfileStats({
    memberId: normalizedId,
    snapshots: approvedSnapshots,
    includeOwnerPrivate: isOwnProfile,
  });

  if (!normalizedId && !normalizedHandle) {
    app.innerHTML = `
      <section class="card public-member-profile-page">
        <div class="section-heading app-section-header">
          <div class="section-title-with-icon app-section-header-main">
            ${renderAppSectionHeaderIcon("members")}
            <div>
              <p class="eyebrow">Community Member</p>
              <h2>Public profile</h2>
              <p class="muted">This public member profile is unavailable.</p>
            </div>
          </div>
          <div class="inline-actions">
            <a class="button button-secondary" href="#gallery">Back to Community Grow</a>
          </div>
        </div>
      </section>
    `;
    return;
  }

  if (!profile && !approvedSnapshots.length) {
    app.innerHTML = `
      <section class="card public-member-profile-page">
        <div class="section-heading app-section-header">
          <div class="section-title-with-icon app-section-header-main">
            ${renderAppSectionHeaderIcon("members")}
            <div>
              <p class="eyebrow">Community Member</p>
              <h2>Public grow profile</h2>
              <p class="muted">${isLoadingSnapshots || isLoadingProfile ? "Loading public member profile..." : "This public member profile is unavailable."}</p>
            </div>
          </div>
          <div class="inline-actions">
            <a class="button button-secondary" href="#gallery">Back to Community Grow</a>
          </div>
        </div>
      </section>
    `;
    return;
  }

  const displayName = getDisplayName(
    {
      id: normalizedId,
      displayName: canShowPublicProfileData ? profile?.displayName || "" : "",
    },
    { fallbackLabel: "Community grower" },
  );
  const avatarUrl = canShowPublicProfileData ? profile?.avatarUrl || "" : "";
  const joinedLabel = formatPublicMemberJoinedDateLabel(profile?.joinedAt || "");
  const roundedAverageRate = publicStats.averageGerminationRate === null
    ? ""
    : String(Number(publicStats.averageGerminationRate.toFixed(1))).replace(/\.0$/, "");
  const bestRateLabel = publicStats.bestGerminationRate === null
    ? ""
    : getProfileAnalyticsRateLabel(publicStats.bestGerminationRate);
  const publicHandleLabel = profile?.publicHandle ? `@${profile.publicHandle}` : "";
  const locationRegionLabel = canShowPublicProfileData ? profile?.locationRegion || "" : "";
  const profileBio = canShowPublicProfileData ? profile?.bio || "" : "";
  const showPublicStats = isOwnProfile || profile?.showGrowStatsPublicly !== false;
  const publicAnalytics = publicStats.publicAnalytics || calculateProfileAnalyticsFromPublicSnapshots(approvedSnapshots);
  const profileMilestones = buildProfileMilestones({
    analytics: publicStats,
    profile,
    publicSnapshots: approvedSnapshots,
    ownerSessions: isOwnProfile ? getSessions() : [],
    includeOwnerPrivate: isOwnProfile,
  });
  const participationHistory = buildProfileParticipationHistory(approvedSnapshots, publicStats);
  const reputationFoundation = buildProfileReputationFoundation({
    profile,
    analytics: publicStats,
    publicSnapshots: approvedSnapshots,
  });
  const trustHooks = buildProfileTrustHooks(profile);
  const trustIndicators = buildProfileTrustIndicators(trustHooks);
  const performanceCards = buildProfilePerformanceHighlights(publicAnalytics);
  const activitySummary = buildProfileActivitySummary({
    profile,
    analytics: publicStats,
    publicSnapshots: approvedSnapshots,
    ownerSessions: isOwnProfile ? getSessions() : [],
    includeOwnerPrivate: isOwnProfile,
  });
  const stats = [
    {
      label: "Public Snapshots",
      value: publicStats.totalPublicSnapshots.toLocaleString(),
      detail: approvedSnapshots.length === 1 ? "approved public snapshot" : "approved public snapshots",
    },
    !showPublicStats
      ? null
      : {
        label: "Completed Sessions",
        value: publicStats.completedSessions.toLocaleString(),
        detail: isOwnProfile ? "eligible completed sessions" : "public-safe completed sessions",
      },
    !showPublicStats || publicStats.averageGerminationRate === null
      ? null
      : {
        label: "Avg Germination",
        value: `${roundedAverageRate}%`,
        detail: "based on approved public snapshots",
      },
    !showPublicStats || !bestRateLabel
      ? null
      : {
        label: "Best Result",
        value: bestRateLabel,
        detail: "best approved public result",
      },
    !showPublicStats || !publicStats.favoriteSource
      ? null
      : {
        label: "Favorite Source",
        value: publicStats.favoriteSource,
        detail: "most common public source",
      },
    !showPublicStats || !publicStats.favoriteVariety
      ? null
      : {
        label: "Favorite Variety",
        value: publicStats.favoriteVariety,
        detail: "most common public genetics",
      },
    joinedLabel
      ? {
        label: "Joined",
        value: joinedLabel,
        detail: "member since",
      }
      : null,
  ].filter(Boolean);

  app.innerHTML = `
    <section class="card public-member-profile-page">
      <div class="public-member-profile-header">
        <div class="public-member-profile-identity">
          <div class="public-member-profile-avatar-shell">
            ${renderPublicMemberAvatarMarkup(displayName, avatarUrl)}
          </div>
        <div class="public-member-profile-copy">
          <p class="eyebrow">Community Member</p>
          <h2>${escapeHtml(displayName)}</h2>
            <p class="muted">${escapeHtml(publicHandleLabel || "Public grow profile")}</p>
            ${trustIndicators.length ? `
              <div class="public-member-profile-trust-row" aria-label="Profile trust indicators">
                ${trustIndicators.map((indicator) => `<span class="public-member-profile-trust-chip">${escapeHtml(indicator.label)}</span>`).join("")}
              </div>
            ` : ""}
            ${locationRegionLabel ? `<p class="public-member-profile-region">${escapeHtml(locationRegionLabel)}</p>` : ""}
            ${joinedLabel ? `<p class="public-member-profile-joined">Joined ${escapeHtml(joinedLabel)}</p>` : ""}
            ${profileBio ? `<p class="public-member-profile-bio">${escapeHtml(profileBio)}</p>` : ""}
            ${isOwnProfile && profile?.isPublicVisible === false ? `<p class="public-member-profile-owner-note">Your profile is private. Other viewers see a community grower fallback.</p>` : ""}
          </div>
        </div>
        <div class="inline-actions">
          ${isOwnProfile ? '<a class="button button-secondary" href="#profile">Edit Profile</a>' : ""}
          <button type="button" class="button button-secondary" data-contact-admin-open="true" data-contact-admin-type="Report content">Report / Contact Admin</button>
          <a class="button button-secondary" href="#gallery">Back to Community Grow</a>
        </div>
      </div>
      <div class="public-member-profile-stats">
        ${stats.map((stat) => `
          <article class="meta-card public-member-profile-stat-card">
            ${stat.listType ? `
              <button
                type="button"
                class="public-member-profile-stat-button"
                data-public-member-open-list="${escapeHtml(stat.listType)}"
                aria-label="${escapeHtml(`Open ${stat.label.toLowerCase()} list for ${displayName}`)}"
              >
                <strong>${escapeHtml(stat.label)}</strong>
                <p class="public-member-profile-stat-value">${escapeHtml(stat.value)}</p>
                <p class="public-member-profile-stat-detail">${escapeHtml(stat.detail)}</p>
              </button>
            ` : `
              <strong>${escapeHtml(stat.label)}</strong>
              <p class="public-member-profile-stat-value">${escapeHtml(stat.value)}</p>
              <p class="public-member-profile-stat-detail">${escapeHtml(stat.detail)}</p>
            `}
          </article>
        `).join("")}
      </div>
      ${showPublicStats ? `
        <section
          class="public-member-profile-performance"
          data-profile-analytics-framework="${escapeHtml(reputationFoundation.scoreEnabled === false && trustHooks ? "ready" : "pending")}"
        >
          <div class="section-heading app-section-header">
            <div class="section-title-with-icon app-section-header-main">
              ${renderAppSectionHeaderIcon("analytics")}
              <div>
                <p class="eyebrow">Cultivation History</p>
                <h3>Performance highlights</h3>
                <p class="muted">Approved public results only. Owner-only session analytics stay private.</p>
              </div>
            </div>
          </div>
          <div class="public-member-profile-performance-grid">
            ${performanceCards.map((card) => `
              <article class="meta-card public-member-profile-performance-card">
                <strong>${escapeHtml(card.label)}</strong>
                <p class="public-member-profile-stat-value">${escapeHtml(card.value)}</p>
                <p class="public-member-profile-stat-detail">${escapeHtml(card.detail)}</p>
              </article>
            `).join("")}
          </div>
          <div class="public-member-profile-history-grid">
            <article class="public-member-profile-history-card">
              <strong>Professional milestones</strong>
              <div class="public-member-profile-milestone-list">
                ${profileMilestones.map((milestone) => `
                  <div class="public-member-profile-milestone${milestone.achieved ? " is-achieved" : ""}">
                    <span>${escapeHtml(milestone.label)}</span>
                    <small>${escapeHtml(milestone.detail)}</small>
                  </div>
                `).join("")}
              </div>
            </article>
            <article class="public-member-profile-history-card">
              <strong>Participation history</strong>
              <p>${escapeHtml(participationHistory.latestPublicActivityLabel)}</p>
              <p>${escapeHtml(`${participationHistory.publicSnapshotCount.toLocaleString()} public snapshot${participationHistory.publicSnapshotCount === 1 ? "" : "s"} recorded`)}</p>
              ${isOwnProfile ? `<p>${escapeHtml(`${participationHistory.activeSessionCount.toLocaleString()} active owner session${participationHistory.activeSessionCount === 1 ? "" : "s"}`)}</p>` : ""}
            </article>
          </div>
        </section>
      ` : ""}
      <section class="public-member-profile-activity">
        <div class="section-heading app-section-header">
          <div class="section-title-with-icon app-section-header-main">
            ${renderAppSectionHeaderIcon("activity")}
            <div>
              <p class="eyebrow">Activity</p>
              <h3>Profile activity summary</h3>
              <p class="muted">Recent approved Community Grow activity and public participation dates.</p>
            </div>
          </div>
        </div>
        <div class="public-member-profile-activity-grid">
          <article class="public-member-profile-history-card">
            <strong>Participation summary</strong>
            <p>${escapeHtml(activitySummary.publicParticipationSummary)}</p>
            <p>${escapeHtml(`Last public contribution: ${activitySummary.lastPublicContributionLabel}`)}</p>
            <p>${escapeHtml(`Member since: ${activitySummary.memberSinceLabel}`)}</p>
          </article>
          <article class="public-member-profile-history-card">
            <strong>Recent public snapshots</strong>
            ${activitySummary.recentPublicSnapshots.length ? `
              <div class="public-member-profile-activity-list">
                ${activitySummary.recentPublicSnapshots.map((entry) => `
                  <a class="public-member-profile-activity-item" href="${escapeHtml(entry.href || "#gallery")}">
                    <span>${escapeHtml(entry.label)}</span>
                    <small>${escapeHtml(`${entry.detail} · ${entry.dateLabel}`)}</small>
                  </a>
                `).join("")}
              </div>
            ` : "<p>No approved public snapshot activity yet.</p>"}
          </article>
          ${isOwnProfile ? `
            <article class="public-member-profile-history-card">
              <strong>Recent completed sessions</strong>
              ${activitySummary.recentOwnerCompletedSessions.length ? `
                <div class="public-member-profile-activity-list">
                  ${activitySummary.recentOwnerCompletedSessions.map((entry) => `
                    <a class="public-member-profile-activity-item" href="${escapeHtml(entry.href || "#sessions")}">
                      <span>${escapeHtml(entry.label)}</span>
                      <small>${escapeHtml(`${entry.detail} · ${entry.dateLabel}`)}</small>
                    </a>
                  `).join("")}
                </div>
              ` : "<p>No eligible completed owner sessions yet.</p>"}
            </article>
          ` : ""}
        </div>
      </section>
      <section class="public-member-profile-snapshots">
        <div class="section-heading app-section-header">
          <div class="section-title-with-icon app-section-header-main">
            ${renderAppSectionHeaderIcon("snapshots")}
            <div>
              <p class="eyebrow">Shared Sessions</p>
              <h3>Public snapshots</h3>
              <p class="muted">Only approved Community Grow snapshots are shown here.</p>
            </div>
          </div>
        </div>
        ${approvedSnapshots.length
          ? '<div id="public-member-profile-grid" class="gallery-grid"></div>'
          : `
            <div class="empty-state gallery-empty-state public-member-profile-empty-state">
              <p>This member has not shared any public sessions yet.</p>
            </div>
          `}
      </section>
    </section>
  `;
  app.querySelectorAll("[data-public-member-open-list]").forEach((button) => {
    button.addEventListener("click", () => {
      openPublicMemberConnectionsModal(normalizedId, button.dataset.publicMemberOpenList || "followers");
    });
  });

  const profileGrid = app.querySelector("#public-member-profile-grid");
  if (!profileGrid) {
    return;
  }

  approvedSnapshots.forEach((snapshot) => {
    const card = document.createElement("article");
    card.className = "gallery-card gallery-card--compact-preview";
    card.dataset.gallerySnapshotId = snapshot.id;
    card.innerHTML = renderGallerySnapshotCardMarkup(snapshot, {
      allowOwnerManagement: false,
      linkSharedProfile: false,
      alwaysShowPublicSessionAction: true,
      showFollowAction: false,
      compactPreview: true,
    });
    profileGrid.appendChild(card);
  });

  bindGallerySnapshotCardInteractions(profileGrid, approvedSnapshots, () => renderPublicMemberProfile(normalizedId));
}

function renderGrowNetworkPage() {
  const followingEntries = getGrowNetworkFollowingEntries();
  const useMockNotifications = shouldUseMockGrowNetworkNotifications();
  const useMockPresentation = isMockDataEnabled() || useMockNotifications;
  const activeTab = useMockPresentation ? getGrowNetworkActiveTab() : "following";
  const isLoadingNetworkActivity = !useMockPresentation && (Boolean(appState.growNetworkActivityRefreshPromise) || (!appState.growNetworkActivityLoaded && Boolean(appState.user?.id)));
  const activities = getGrowNetworkActivityEntries();
  const isLoadingFollowing = !useMockPresentation && (Boolean(appState.growNetworkFollowingRefreshPromise) || (!appState.growNetworkFollowingLoaded && Boolean(appState.user?.id)));
  const hasNoFollows = !isLoadingFollowing && !followingEntries.length;
  const mockMembers = useMockPresentation ? buildMockGrowNetworkMemberCards(activeTab) : [];
  const mockNotificationGroups = useMockNotifications
    ? buildMockGrowNetworkNotificationFeedGroups(getMockGrowNetworkNotifications())
    : [];
  const showPreviewStats = useMockPresentation;
  const unseenNotificationCount = useMockNotifications ? getUnseenMockGrowNetworkNotificationCount() : 0;

  const memberPanelCopy = (() => {
    if (!useMockPresentation) {
      return {
        eyebrow: "Following",
        title: "People You Follow",
        subtitle: "Public growers you follow, with quick access to profile stats and shared activity.",
      };
    }

    if (activeTab === "discover") {
      return {
        eyebrow: "Discover",
        title: "Discover Growers",
        subtitle: "Explore performance-focused mock profiles and test follow interactions visually.",
      };
    }

    if (activeTab === "followers") {
      return {
        eyebrow: "Followers",
        title: "Members Following You",
        subtitle: "See who's following you in the Grow Network and how they are performing.",
      };
    }

    return {
      eyebrow: "Following",
      title: "People You Follow",
      subtitle: "Your followed growers, with enough mock depth to test card behavior and spacing.",
    };
  })();

  const notificationPanelCopy = {
    eyebrow: useMockNotifications ? "Notifications" : "Activity",
    title: useMockNotifications ? "Activity Notifications" : "Network Activity",
    subtitle: useMockNotifications
      ? "Real-time activity from your network. Mock alerts stay isolated from production data."
      : "Recent public grow activity from the growers in your network.",
  };
  const currentUserFollowSummary = appState.user?.id ? getPublicMemberFollowSummary(appState.user.id) : null;
  const headerFollowersValue = useMockPresentation
    ? "128"
    : (currentUserFollowSummary ? currentUserFollowSummary.followerCount.toLocaleString() : "0");
  const headerLikesValue = useMockPresentation
    ? "2.4K"
    : "0";
  const headerStats = [
    { label: "Total Followers", value: headerFollowersValue },
    { label: "Total Likes", value: headerLikesValue },
  ];

  const renderGrowNetworkNotificationTypeIcon = (type = "follow") => {
    if (type === "like") {
      return renderAppIconSvgMarkup("heartLike");
    }

    if (type === "system") {
      return renderAppIconSvgMarkup("chart");
    }

    return renderAppIconSvgMarkup("growNetworkNodes");
  };

  const renderMockTabsMarkup = () => {
    if (!useMockPresentation) {
      return "";
    }

    const tabs = [
      { key: "following", label: "Following" },
      { key: "discover", label: "Discover Growers" },
      { key: "followers", label: "Followers" },
    ];

    return `
      <div class="grow-network-tabs" role="tablist" aria-label="Grow Network views">
        ${tabs.map((tab) => {
          const isActive = activeTab === tab.key;
          return `
            <button
              type="button"
              class="grow-network-tab${isActive ? " is-active" : ""}"
              data-grow-network-tab="${escapeHtml(tab.key)}"
              role="tab"
              aria-selected="${isActive ? "true" : "false"}"
            >${escapeHtml(tab.label)}</button>
          `;
        }).join("")}
      </div>
    `;
  };

  const renderMemberMetaMarkup = (member) => `
    <p class="grow-network-member-caption">${escapeHtml(`${member.averageGermination}% avg germination · ${member.favoriteSeedType} · ${member.favoriteSource || "Grow Network"}`)}</p>
    <div class="grow-network-member-stats" aria-label="${escapeHtml(`${member.displayName} performance`)}">
      <span class="grow-network-member-stat-chip">${escapeHtml(`${member.approvedSnapshots} approved`)}</span>
      <span class="grow-network-member-stat-chip">${escapeHtml(`${member.likes} likes`)}</span>
    </div>
  `;

  const renderMembersFooterMarkup = () => {
    if (useMockPresentation) {
      const footerTab = activeTab === "discover" ? "discover" : (activeTab === "following" ? "following" : "followers");
      const footerLabel = activeTab === "discover"
        ? "Discover More Growers"
        : (activeTab === "following" ? "View All Following" : "View All Followers");
      return `
        <button
          type="button"
          class="grow-network-panel-footer grow-network-panel-footer-button"
          data-grow-network-tab="${escapeHtml(footerTab)}"
        >
          <span>${escapeHtml(footerLabel)}</span>
          <span class="grow-network-panel-footer-arrow" aria-hidden="true">›</span>
        </button>
      `;
    }

    return `
      <a class="grow-network-panel-footer" href="#gallery">
        <span>Browse Community Grow</span>
        <span class="grow-network-panel-footer-arrow" aria-hidden="true">›</span>
      </a>
    `;
  };

  const renderNotificationFooterMarkup = () => `
    <a class="grow-network-panel-footer" href="#network">
      <span>View All Notifications</span>
      <span class="grow-network-panel-footer-arrow" aria-hidden="true">›</span>
    </a>
  `;

  const recentWindowMs = 14 * 24 * 60 * 60 * 1000;
  const nowMs = Date.now();
  const currentUserId = String(appState.user?.id || "").trim();
  const currentUserFollowList = currentUserId ? getPublicMemberFollowList(currentUserId, "followers") : null;
  const approvedPublicSnapshots = getApprovedPublicGallerySnapshots();
  const currentUserPublicSnapshots = approvedPublicSnapshots.filter((snapshot) => (
    String(snapshot?.userId || "").trim() === currentUserId
  ));
  const isWithinRecentWindow = (value = "") => {
    const dateMs = parseCompletedAtValue(value)?.getTime() || 0;
    return dateMs > 0 && (nowMs - dateMs) <= recentWindowMs;
  };
  const formatGrowNetworkStatValue = (value = 0) => {
    const normalizedValue = Math.max(0, Number(value) || 0);
    if (normalizedValue >= 1000) {
      return new Intl.NumberFormat("en-US", {
        notation: "compact",
        maximumFractionDigits: 1,
      }).format(normalizedValue);
    }
    return normalizedValue.toLocaleString();
  };

  let totalFollowersCount = 0;
  let activeGrowersCount = 0;
  let likesReceivedCount = 0;
  let sessionsTrendingCount = 0;

  if (showPreviewStats) {
    const mockPrimaryProfile = getMockGrowNetworkProfiles().find((profile) => profile.id === "mock-seedsman-lab")
      || getMockGrowNetworkProfiles()[0]
      || null;
    const mockActivityEntries = buildMockGrowNetworkActivityEntries();
    const mockRecentNotifications = getMockGrowNetworkNotifications().filter((notification) => isWithinRecentWindow(notification.occurredAt));

    // Temporary preview fallback: until live social aggregates exist for the signed-in account,
    // Grow Network preview mode uses the canonical mock profile and mock notification feed.
    totalFollowersCount = Math.max(0, Number(mockPrimaryProfile?.followerCount) || 0);
    likesReceivedCount = Math.max(0, Number(mockPrimaryProfile?.likes) || 0);
    activeGrowersCount = new Set(mockActivityEntries.map((activity) => activity.memberId).filter(Boolean)).size;
    sessionsTrendingCount = new Set(mockRecentNotifications
      .filter((notification) => (
        ["like", "system"].includes(String(notification?.type || "").trim().toLowerCase())
        && ["session", "snapshot"].includes(String(notification?.targetType || "").trim().toLowerCase())
        && String(notification?.targetId || "").trim()
      ))
      .map((notification) => String(notification.targetId || "").trim())).size;
  } else {
    totalFollowersCount = currentUserFollowSummary
      ? Math.max(0, Number(currentUserFollowSummary.followerCount) || 0)
      : (Array.isArray(currentUserFollowList) ? currentUserFollowList.length : 0);

    const recentActivityEntries = activities.filter((activity) => isWithinRecentWindow(activity.occurredAt));
    const recentApprovedSnapshots = approvedPublicSnapshots.filter((snapshot) => (
      isWithinRecentWindow(snapshot.publishedAt || snapshot.createdAt || "")
    ));
    activeGrowersCount = recentActivityEntries.length
      ? new Set(recentActivityEntries.map((activity) => activity.memberId).filter(Boolean)).size
      : new Set(recentApprovedSnapshots.map((snapshot) => String(snapshot?.userId || "").trim()).filter(Boolean)).size;

    likesReceivedCount = currentUserPublicSnapshots.reduce((sum, snapshot) => (
      sum + Math.max(0, Number(snapshot?.likeCount) || 0)
    ), 0);

    // Temporary engagement proxy: the app does not yet store like timestamps, so "trending"
    // uses recently published public snapshots with at least one like.
    sessionsTrendingCount = currentUserPublicSnapshots.filter((snapshot) => (
      isWithinRecentWindow(snapshot.publishedAt || snapshot.createdAt || "")
      && Math.max(0, Number(snapshot?.likeCount) || 0) > 0
    )).length;
  }

  const growNetworkStats = [
    {
      icon: "members",
      tone: "blue",
      value: formatGrowNetworkStatValue(totalFollowersCount),
      label: "Total Followers",
      detail: showPreviewStats ? "preview network reach" : "following your profile",
    },
    {
      icon: "plant",
      tone: "green",
      value: formatGrowNetworkStatValue(activeGrowersCount),
      label: "Active Growers",
      detail: showPreviewStats ? "with recent public activity" : "recent public growers",
    },
    {
      icon: "heart",
      tone: "red",
      value: formatGrowNetworkStatValue(likesReceivedCount),
      label: "Likes Received",
      detail: appState.gallerySnapshotLikesTableUnavailable ? "likes fallback active" : "across your public grow",
    },
    {
      icon: "trending",
      tone: "gold",
      value: formatGrowNetworkStatValue(sessionsTrendingCount),
      label: "Sessions Trending",
      detail: showPreviewStats ? "recent engagement signals" : "recent public sessions with likes",
    },
  ];

  const renderFollowingListMarkup = () => {
    if (isLoadingFollowing) {
      return `
        <div class="empty-state gallery-empty-state grow-network-empty-state grow-network-panel-empty">
          <p>Loading your Grow Network...</p>
        </div>
      `;
    }

    if (appState.growNetworkFollowingError) {
      return `
        <div class="empty-state gallery-empty-state grow-network-empty-state grow-network-panel-empty">
          <p>Follow members to build your Grow Network.</p>
        </div>
      `;
    }

    if (useMockPresentation) {
      if (!mockMembers.length) {
        return `
          <div class="empty-state gallery-empty-state grow-network-empty-state grow-network-panel-empty">
            <p>Follow members to build your Grow Network.</p>
          </div>
        `;
      }

      return `
        <div class="grow-network-member-list grow-network-member-list--mock">
          ${mockMembers.map((member) => `
            <article class="grow-network-member-card grow-network-member-card--mock">
              <a class="grow-network-member-identity" href="${escapeHtml(getPublicMemberProfileRoute(member.id))}">
                <span class="grow-network-member-avatar-shell">
                  ${renderPublicMemberAvatarMarkup(
                    member.displayName,
                    getPublicMemberProfile(member.id)?.avatarUrl || "",
                    "grow-network-member-avatar",
                  )}
                </span>
                <div class="grow-network-member-copy">
                  <strong>${escapeHtml(member.displayName)}</strong>
                  ${renderMemberMetaMarkup(member)}
                </div>
              </a>
              <div class="grow-network-member-actions">
                <a class="button button-secondary" href="${escapeHtml(getPublicMemberProfileRoute(member.id))}">View Profile</a>
                <button
                  type="button"
                  class="button ${member.isFollowing ? "button-secondary" : "button-primary"} grow-network-mock-follow-button grow-network-member-follow-button${member.isFollowing ? " is-following" : ""}"
                  data-grow-network-mock-follow="${escapeHtml(member.id)}"
                  aria-pressed="${member.isFollowing ? "true" : "false"}"
                >${escapeHtml(member.isFollowing ? "Following" : "Follow")}</button>
              </div>
            </article>
          `).join("")}
        </div>
      `;
    }

    if (!followingEntries.length) {
      return `
        <div class="empty-state gallery-empty-state grow-network-empty-state grow-network-panel-empty">
          <p>Follow members to build your Grow Network.</p>
        </div>
      `;
    }

    return `
      <div class="grow-network-member-list">
        ${followingEntries.map((entry) => {
          const memberId = entry.memberId;
          const isMockEntry = Boolean(entry.isMock);
          const profile = getPublicMemberProfile(memberId);
          const displayName = getDisplayName(
            {
              id: memberId,
              displayName: profile?.displayName || "",
            },
            { fallbackLabel: "User" },
          );
          const avatarUrl = profile?.avatarUrl || "";
          const followSummary = appState.publicMemberFollowSummaries[memberId] || null;
          const publicSnapshotCount = getApprovedPublicSnapshotsForMember(memberId).length;
          const publicSnapshotLabel = isLoadingNetworkActivity
            ? "Public snapshot count loading..."
            : (publicSnapshotCount === 1
              ? "1 public snapshot"
              : `${publicSnapshotCount.toLocaleString()} public snapshots`);
          return `
            <article class="grow-network-member-card">
              <a class="grow-network-member-identity" href="${escapeHtml(getPublicMemberProfileRoute(memberId))}">
                <span class="grow-network-member-avatar-shell">
                  ${renderPublicMemberAvatarMarkup(displayName, avatarUrl, "grow-network-member-avatar")}
                </span>
                <div class="grow-network-member-copy">
                  <strong>${escapeHtml(displayName)}</strong>
                  <span class="grow-network-member-caption">${escapeHtml(publicSnapshotLabel)}</span>
                  <div class="grow-network-member-stats">
                    <span class="grow-network-member-stat-chip">${escapeHtml(`${publicSnapshotCount.toLocaleString()} approved`)}</span>
                    ${followSummary ? `<span class="grow-network-member-stat-chip">${escapeHtml(`${followSummary.followerCount.toLocaleString()} followers`)}</span>` : ""}
                    <span class="grow-network-member-stat-chip">Community Grow</span>
                  </div>
                </div>
              </a>
              <div class="grow-network-member-actions">
                <a class="button button-secondary" href="${escapeHtml(getPublicMemberProfileRoute(memberId))}">View Profile</a>
                ${isMockEntry
                  ? ""
                  : `
                    <button
                      type="button"
                      class="button button-secondary grow-network-unfollow-button grow-network-member-follow-button is-following"
                      data-grow-network-unfollow="${escapeHtml(memberId)}"
                      aria-pressed="true"
                      ${isPublicMemberFollowPending(memberId) ? "disabled" : ""}
                    >Following</button>
                  `}
              </div>
            </article>
          `;
        }).join("")}
      </div>
    `;
  };

  const renderActivityFeedMarkup = () => {
    if (hasNoFollows) {
      return `
        <div class="empty-state gallery-empty-state grow-network-empty-state grow-network-panel-empty">
          <p>Follow members to build your Grow Network.</p>
        </div>
      `;
    }

    if (appState.growNetworkActivityError) {
      return `
        <div class="empty-state gallery-empty-state grow-network-empty-state grow-network-panel-empty">
          <p>No public activity from your Grow Network yet.</p>
        </div>
      `;
    }

    if (isLoadingNetworkActivity) {
      return `
        <div class="empty-state gallery-empty-state grow-network-empty-state grow-network-panel-empty">
          <p>Loading public activity from your Grow Network...</p>
        </div>
      `;
    }

    if (!activities.length) {
      return `
        <div class="empty-state gallery-empty-state grow-network-empty-state grow-network-panel-empty">
          <p>No public activity from your Grow Network yet.</p>
        </div>
      `;
    }

    return `
      <div class="grow-network-feed-list">
        ${activities.map((activity) => `
          <article class="grow-network-feed-card">
            <div class="grow-network-feed-card-head">
              <a class="grow-network-feed-member" href="${escapeHtml(activity.profileRoute)}">
                <span class="grow-network-feed-avatar-shell">
                  ${renderPublicMemberAvatarMarkup(activity.displayName, activity.avatarUrl, "grow-network-feed-avatar")}
                </span>
                <div class="grow-network-feed-member-copy">
                  <strong>${escapeHtml(activity.displayName)}</strong>
                  <span>${escapeHtml(activity.typeLabel)}</span>
                </div>
              </a>
              <span class="grow-network-feed-time">${escapeHtml(getGallerySnapshotSubmittedDateTimeLabel({ publishedAt: activity.occurredAt, createdAt: activity.occurredAt }))}</span>
            </div>
            <div class="grow-network-feed-body">
              <strong class="grow-network-feed-title">${escapeHtml(activity.title)}</strong>
              ${activity.summary ? `<p class="muted">${escapeHtml(activity.summary)}</p>` : ""}
              <div class="grow-network-feed-meta">
                <span class="gallery-card-chip">${escapeHtml(activity.typeLabel)}</span>
                <span class="gallery-card-chip">${escapeHtml(`${activity.germinationRateLabel} germination`)}</span>
                ${activity.sourceLabel && activity.sourceLabel !== "Unknown source" ? `<span class="gallery-card-chip">${escapeHtml(activity.sourceLabel)}</span>` : ""}
                ${activity.seedAgeLabel ? `<span class="gallery-card-chip">${escapeHtml(activity.seedAgeLabel)}</span>` : ""}
                ${activity.typeMeta ? `<span class="gallery-card-chip">${escapeHtml(activity.typeMeta)}</span>` : ""}
              </div>
            </div>
            <div class="grow-network-feed-actions">
              <a class="button button-secondary" href="${escapeHtml(activity.profileRoute)}">Profile</a>
              <a class="button button-secondary" href="${escapeHtml(activity.sessionRoute)}">View Public Session</a>
            </div>
          </article>
        `).join("")}
      </div>
    `;
  };

  const renderMockNotificationFeedMarkup = () => {
    if (!mockNotificationGroups.length) {
      return `
        <div class="empty-state gallery-empty-state grow-network-empty-state grow-network-notification-empty-state grow-network-panel-empty">
          <strong>No activity yet</strong>
          <p>Follow growers and share sessions to start seeing activity</p>
        </div>
      `;
    }

    return `
      <div class="grow-network-notification-list" aria-label="Mock Grow Network notifications">
        ${mockNotificationGroups.map((notificationGroup) => `
          <${notificationGroup.isGrouped ? "button" : "article"}
            ${notificationGroup.isGrouped ? 'type="button"' : ""}
            class="grow-network-notification-card${notificationGroup.isUnseen ? " is-unseen" : ""}${notificationGroup.isGrouped ? " is-interactive grow-network-notification-button" : ""}"
            ${notificationGroup.isGrouped ? `data-grow-network-notification-group="${escapeHtml(notificationGroup.id)}"` : ""}
          >
            <span class="grow-network-notification-avatar-shell">
              <span class="${escapeHtml(notificationGroup.avatarMembers.length > 1 || notificationGroup.overflowAvatarCount ? "grow-network-notification-avatar-stack" : "grow-network-notification-avatar-stack is-single")}">
                ${notificationGroup.avatarMembers.map((member) => `
                  <span class="grow-network-notification-avatar-stack-item">
                    ${renderPublicMemberAvatarMarkup(member.displayName, member.avatarUrl, "grow-network-notification-avatar")}
                  </span>
                `).join("")}
                ${notificationGroup.overflowAvatarCount ? `
                  <span class="grow-network-notification-avatar-stack-item grow-network-notification-avatar-stack-count" aria-hidden="true">
                    <span class="grow-network-notification-avatar grow-network-notification-avatar-count">+${escapeHtml(String(notificationGroup.overflowAvatarCount))}</span>
                  </span>
                ` : ""}
              </span>
            </span>
            <div class="grow-network-notification-main">
              <div class="grow-network-notification-copy">
                <p class="grow-network-notification-text">
                  <strong>${escapeHtml(notificationGroup.actorText)}</strong>
                  <span>${escapeHtml(notificationGroup.actionText)}</span>
                </p>
                ${notificationGroup.targetName ? `<p class="grow-network-notification-target">${escapeHtml(notificationGroup.targetName)}</p>` : ""}
              </div>
              <div class="grow-network-notification-meta">
                <span class="grow-network-notification-time">${escapeHtml(notificationGroup.timeLabel)}</span>
                <span class="grow-network-notification-type-icon is-${escapeHtml(notificationGroup.type)}" aria-hidden="true">
                  ${renderGrowNetworkNotificationTypeIcon(notificationGroup.type)}
                </span>
              </div>
            </div>
          </${notificationGroup.isGrouped ? "button" : "article"}>
        `).join("")}
      </div>
    `;
  };

  app.innerHTML = `
    <section class="card grow-network-page">
      <div class="grow-network-page-glow" aria-hidden="true"></div>
      <div class="grow-network-page-heading">
        <div class="grow-network-page-header">
          <div class="grow-network-page-header-main">
            ${renderAppSectionHeaderIcon("community")}
            <div class="grow-network-page-copy">
              <p class="eyebrow">Community</p>
              <h2>Grow Network</h2>
              <p class="muted">Follow members and see public grow activity from your network.</p>
            </div>
          </div>
          <div class="grow-network-page-actions">
            <a class="button button-secondary grow-network-hero-button" href="#gallery">Browse Community Grow</a>
          </div>
        </div>
        <div class="grow-network-header-stats" aria-label="Grow Network quick stats">
          ${headerStats.map((stat) => `
            <article class="grow-network-header-stat">
              <strong>${escapeHtml(stat.value)}</strong>
              <span>${escapeHtml(stat.label)}</span>
            </article>
          `).join("")}
        </div>
      </div>
      <div class="grow-network-layout">
        <section class="grow-network-panel grow-network-panel--members grow-network-section">
          ${renderMockTabsMarkup()}
          <div class="grow-network-section-heading">
            <div class="grow-network-panel-header">
              <div class="grow-network-panel-icon" aria-hidden="true">
                ${renderAppSectionHeaderIcon("following")}
              </div>
              <div>
                <p class="eyebrow">${escapeHtml(memberPanelCopy.eyebrow)}</p>
                <h3>${escapeHtml(memberPanelCopy.title)}</h3>
                <p class="muted grow-network-section-subtitle">${escapeHtml(memberPanelCopy.subtitle)}</p>
              </div>
            </div>
          </div>
          ${renderFollowingListMarkup()}
          ${renderMembersFooterMarkup()}
        </section>
        <section class="grow-network-panel grow-network-panel--notifications grow-network-section">
          <div class="grow-network-section-heading grow-network-section-heading--featured">
            <div class="grow-network-panel-header">
              <div class="grow-network-panel-icon" aria-hidden="true">
                ${renderAppSectionHeaderIcon("activity")}
              </div>
              <div>
                <p class="eyebrow">${escapeHtml(notificationPanelCopy.eyebrow)}</p>
                <h3>${escapeHtml(notificationPanelCopy.title)}</h3>
                <p class="muted grow-network-section-subtitle">${escapeHtml(notificationPanelCopy.subtitle)}</p>
              </div>
            </div>
            ${useMockNotifications ? `
              <button
                type="button"
                class="button button-secondary grow-network-mark-read-button"
                data-grow-network-mark-all-read="true"
                ${unseenNotificationCount ? "" : "disabled"}
              >
                <span aria-hidden="true">✓</span>
                <span>Mark all as read</span>
              </button>
            ` : ""}
          </div>
          ${useMockNotifications ? renderMockNotificationFeedMarkup() : renderActivityFeedMarkup()}
          ${renderNotificationFooterMarkup()}
        </section>
      </div>
      <div class="grow-network-stats-strip" aria-label="Grow Network highlights">
        ${growNetworkStats.map((stat) => `
          <article class="grow-network-stat-card">
            <div class="grow-network-stat-icon icon-${escapeHtml(stat.tone || "green")}" aria-hidden="true">
              ${renderAppSectionHeaderIcon(stat.icon)}
            </div>
            <div class="grow-network-stat-copy">
              <strong>${escapeHtml(stat.value)}</strong>
              <span>${escapeHtml(stat.label)}</span>
              <p>${escapeHtml(stat.detail)}</p>
            </div>
          </article>
        `).join("")}
      </div>
    </section>
  `;

  app.querySelectorAll("[data-grow-network-unfollow]").forEach((button) => {
    button.addEventListener("click", async () => {
      try {
        await togglePublicMemberFollow(button.dataset.growNetworkUnfollow || "");
      } catch (error) {
        window.alert(error.message || "Could not update this follow right now.");
      }
    });
  });

  app.querySelectorAll("[data-grow-network-tab]").forEach((button) => {
    button.addEventListener("click", () => {
      setGrowNetworkActiveTab(button.dataset.growNetworkTab || "following");
      renderGrowNetworkPage();
    });
  });

  app.querySelectorAll("[data-grow-network-mock-follow]").forEach((button) => {
    button.addEventListener("click", () => {
      toggleMockGrowNetworkFollowState(button.dataset.growNetworkMockFollow || "");
      renderGrowNetworkPage();
    });
  });

  app.querySelector("[data-grow-network-mark-all-read='true']")?.addEventListener("click", () => {
    markAllMockGrowNetworkNotificationsSeen();
    renderGrowNetworkPage();
  });

  app.querySelectorAll("[data-grow-network-notification-group]").forEach((button) => {
    button.addEventListener("click", () => {
      const notificationGroup = mockNotificationGroups.find((entry) => entry.id === (button.dataset.growNetworkNotificationGroup || ""));
      if (notificationGroup) {
        openGrowNetworkNotificationGroupModal(notificationGroup);
      }
    });
  });

  updateNavState();
}

