function getSessionDetailSaveButtons(detail) {
  return [detail?.saveShortcutButton, detail?.saveButton]
    .filter((button) => button instanceof HTMLButtonElement);
}

function clearSessionDetailSaveButtonTimer(detail) {
  if (detail?.__saveButtonStateTimer) {
    window.clearTimeout(detail.__saveButtonStateTimer);
    detail.__saveButtonStateTimer = null;
  }
}

function setSessionDetailSaveButtonState(detail, state = "default", options = {}) {
  const buttons = getSessionDetailSaveButtons(detail);
  if (buttons.length === 0) {
    return;
  }

  clearSessionDetailSaveButtonTimer(detail);
  const isSaved = state === "saved";
  buttons.forEach((button) => {
    button.classList.toggle("is-saved", isSaved);
    button.setAttribute("data-save-state", isSaved ? "saved" : "default");
    button.disabled = isSaved;
    setSessionSaveButtonLabel(button, isSaved ? SESSION_SAVE_BUTTON_SAVED_LABEL : NEW_SESSION_SAVE_BUTTON_DEFAULT_LABEL);
  });

  if (isSaved && options.persist !== true) {
    detail.__saveButtonStateTimer = window.setTimeout(() => {
      setSessionDetailSaveButtonState(detail, "default");
    }, SESSION_SAVE_BUTTON_SAVED_RESET_MS);
  }
}

function isSessionCreateMode(session = null) {
  return !String(session?.id || "").trim();
}

function removeSessionLayoutPreview(elements = null) {
  const layoutSection = elements?.layoutSection || elements?.layoutReference?.closest(".system-layout-block") || null;
  if (!layoutSection) {
    return;
  }

  layoutSection.remove();
  if (elements && typeof elements === "object") {
    elements.layoutSection = null;
    elements.layoutReference = null;
  }
}

function renderSessionDetailMetaCards(container, cards = []) {
  if (!container) {
    return;
  }

  container.innerHTML = cards.map((card) => `
    <article class="meta-card ${escapeHtml(card.className || "").trim()}">
      <strong>${escapeHtml(card.label || "")}</strong>
      <p>${escapeHtml(card.value || "")}</p>
    </article>
  `).join("");
}

function getSessionDetailEditableName(session = null) {
  const customName = String(session?.customSessionName || "").trim();
  if (customName) {
    return customName;
  }

  const sessionName = String(session?.sessionName || "").trim();
  const sessionDate = String(session?.date || "").trim();
  if (!sessionName) {
    return "";
  }

  const dateSuffix = sessionDate ? ` - ${formatSessionNameDate(sessionDate)}` : "";
  if (dateSuffix && sessionName.endsWith(dateSuffix)) {
    return sessionName.slice(0, -dateSuffix.length).trim();
  }

  return sessionName;
}

function buildSessionDetailMetaCards(session = null) {
  const seedAgeMetadata = getSessionSeedAgeMetadata(session);
  const cards = [
    { label: "Status", value: capitalize(normalizeSessionStatus(session?.sessionStatus || "")).replace("Unselected", "Not started") },
    { label: "System Type", value: session?.systemType || "Not set" },
    { label: "Unit ID", value: normalizeUnitIdValue(session?.unitId) },
    { label: "Date", value: session?.date || "Not set" },
    { label: "Time", value: formatStoredTime(session?.time || "") || "Not set" },
  ];

  if (seedAgeMetadata.trackingEnabled) {
    cards.push({
      label: "Seed Age",
      value: seedAgeMetadata.summaryLabel,
    });
  }

  return cards;
}

function populateSessionDetailEditorForm(form, session = null) {
  if (!(form instanceof HTMLFormElement)) {
    return;
  }

  const sessionNameField = form.elements.sessionName;
  if (!(sessionNameField instanceof HTMLInputElement)) {
    return;
  }

  sessionNameField.value = getSessionDetailEditableName(session);
  sessionNameField.setCustomValidity("");

  const unitIdField = form.elements.unitId;
  if (unitIdField instanceof HTMLSelectElement) {
    const unitId = normalizeUnitIdValue(session?.unitId || "", "");
    if (unitId && ![...unitIdField.options].some((option) => option.value === unitId)) {
      unitIdField.add(new Option(unitId, unitId));
    }
    unitIdField.value = unitId;
  }
}

function setSessionDetailEditorOpen(detail, isOpen) {
  if (!detail?.detailsPanel) {
    return;
  }

  detail.detailsPanel.hidden = !isOpen;
  if (detail.editButton) {
    detail.editButton.setAttribute("aria-expanded", isOpen ? "true" : "false");
    detail.editButton.classList.toggle("is-active", isOpen);
  }
}

function clearSessionDetailEditorMessage(detail) {
  if (!detail?.detailsMessage) {
    return;
  }

  setFeedbackMessage(detail.detailsMessage, "");
}

function canCurrentUserEditSessionTimes(session = null) {
  if (!session) {
    return false;
  }
  if (!canManuallyEditGrowSessionTimestamps()) {
    return false;
  }
  if (isLocalDevQaBypassActive() || !appState.supabase) {
    return true;
  }

  const currentUserId = String(appState.user?.id || "").trim();
  const ownerUserId = String(session.userId || session.user_id || "").trim();
  return Boolean(currentUserId && ownerUserId && currentUserId === ownerUserId);
}

function getSessionStartedAtIso(session = null) {
  return parseCompletedAtValue(session?.sessionStartedAt || session?.session_started_at || "")?.toISOString()
    || parseSessionStartDateTime(session?.date, session?.time)?.toISOString()
    || "";
}

function getSessionSoakStartedAtIso(session = null) {
  return parseCompletedAtValue(session?.soakStartedAt || session?.soak_started_at || session?.timerStartAt || session?.timer_start_at || "")?.toISOString()
    || getSessionStartedAtIso(session);
}

function formatDateTimeLocalInputValue(value = "") {
  const parsedDate = parseCompletedAtValue(value);
  if (!parsedDate) {
    return "";
  }

  const year = parsedDate.getFullYear();
  const month = String(parsedDate.getMonth() + 1).padStart(2, "0");
  const day = String(parsedDate.getDate()).padStart(2, "0");
  const hours = String(parsedDate.getHours()).padStart(2, "0");
  const minutes = String(parsedDate.getMinutes()).padStart(2, "0");
  return `${year}-${month}-${day}T${hours}:${minutes}`;
}

function parseDateTimeLocalInputIso(value = "") {
  const normalizedValue = String(value || "").trim();
  if (!normalizedValue) {
    return "";
  }

  const parsedDate = new Date(normalizedValue);
  if (Number.isNaN(parsedDate.getTime())) {
    return null;
  }

  return parsedDate.toISOString();
}

function validateGrowSessionTimelineOrder(timestamps = {}, options = {}) {
  const sessionStartedDate = parseCompletedAtValue(timestamps.sessionStartedAt || "");
  const soakStartedDate = parseCompletedAtValue(timestamps.soakStartedAt || "");
  const germinationStartedDate = parseCompletedAtValue(timestamps.germinationStartedAt || "");
  const completedDate = parseCompletedAtValue(timestamps.completedAt || "");

  if (options.requireSessionStarted !== false && !sessionStartedDate) {
    return { isValid: false, message: "Session start time is required." };
  }
  if (options.requireSoakStarted !== false && !soakStartedDate) {
    return { isValid: false, message: "Soak start time is required." };
  }
  if (options.requireCompleted && !completedDate) {
    return { isValid: false, message: "Completed sessions need a completed time." };
  }
  if (sessionStartedDate && soakStartedDate && soakStartedDate < sessionStartedDate) {
    return { isValid: false, message: "Soak start cannot be before session start." };
  }
  if (soakStartedDate && germinationStartedDate && soakStartedDate > germinationStartedDate) {
    return { isValid: false, message: "Soak start cannot be after germination start." };
  }
  if (completedDate && germinationStartedDate && germinationStartedDate > completedDate) {
    return { isValid: false, message: "Germination start cannot be after completed time." };
  }
  if (completedDate && sessionStartedDate && completedDate < sessionStartedDate) {
    return { isValid: false, message: "Completed time cannot be before session start." };
  }

  return { isValid: true, message: "" };
}

function isCompletedValidSessionForAnalytics(session = null) {
  return isGrowSessionAnalyticsEligible(session);
}

function populateSessionTimesForm(form, session = null) {
  if (!(form instanceof HTMLFormElement)) {
    return;
  }

  form.elements.sessionStartedAt.value = formatDateTimeLocalInputValue(getSessionStartedAtIso(session));
  form.elements.soakStartedAt.value = formatDateTimeLocalInputValue(getSessionSoakStartedAtIso(session));
  form.elements.germinationStartedAt.value = formatDateTimeLocalInputValue(session?.germinationStartedAt || "");
  form.elements.completedAt.value = formatDateTimeLocalInputValue(session?.completedAt || "");
}

function setSessionTimesEditorOpen(detail, isOpen) {
  if (!detail?.timesPanel) {
    return;
  }

  detail.timesPanel.hidden = !isOpen;
  if (detail.timesEditButton) {
    detail.timesEditButton.setAttribute("aria-expanded", isOpen ? "true" : "false");
    detail.timesEditButton.classList.toggle("is-active", isOpen);
  }
}

function clearSessionTimesEditorMessage(detail) {
  if (!detail?.timesMessage) {
    return;
  }

  setFeedbackMessage(detail.timesMessage, "");
}

function setSessionTimesEditorMessage(detail, message = "", isError = false) {
  if (!detail?.timesMessage) {
    return;
  }

  setFeedbackMessage(detail.timesMessage, message, isError ? "error" : (message ? "success" : ""));
}

function getSessionTimesFormPayload(form, session = null) {
  if (!(form instanceof HTMLFormElement)) {
    return { isValid: false, message: "Session time form is unavailable." };
  }

  const sessionStartedValue = String(form.elements.sessionStartedAt?.value || "").trim();
  const soakStartedValue = String(form.elements.soakStartedAt?.value || "").trim();
  const germinationStartedValue = String(form.elements.germinationStartedAt?.value || "").trim();
  const completedValue = String(form.elements.completedAt?.value || "").trim();
  const sessionStartedAt = parseDateTimeLocalInputIso(sessionStartedValue);
  const soakStartedAt = parseDateTimeLocalInputIso(soakStartedValue);
  const germinationStartedAt = parseDateTimeLocalInputIso(germinationStartedValue);
  const completedAt = parseDateTimeLocalInputIso(completedValue);

  if (sessionStartedAt === null || soakStartedAt === null || germinationStartedAt === null || completedAt === null) {
    return { isValid: false, message: "Enter valid date and time values." };
  }
  const timelineValidation = validateGrowSessionTimelineOrder({
    sessionStartedAt,
    soakStartedAt,
    germinationStartedAt,
    completedAt,
  }, {
    requireCompleted: normalizeSessionStatus(session?.sessionStatus || "") === "completed",
  });
  if (!timelineValidation.isValid) {
    return timelineValidation;
  }

  return {
    isValid: true,
    sessionStartedAt,
    soakStartedAt,
    germinationStartedAt,
    completedAt,
    sessionDate: sessionStartedValue.slice(0, 10),
    sessionTime: sessionStartedValue.slice(11, 16),
  };
}

function syncSessionDetailHeaderMeta(detail, session) {
  applySessionDetailHeaderOptions(detail, {
    title: formatSessionLabel(session),
  });
  renderSessionDetailMetaCards(detail.meta, buildSessionDetailMetaCards(session));
}

function applySessionDetailEditorValues(form, session) {
  if (!(form instanceof HTMLFormElement)) {
    return true;
  }

  const sessionNameField = form.elements.sessionName;
  if (!(sessionNameField instanceof HTMLInputElement)) {
    return false;
  }
  const unitIdField = form.elements.unitId;
  if (!(unitIdField instanceof HTMLSelectElement)) {
    return false;
  }

  const nextCustomSessionName = String(sessionNameField.value || "").trim();
  const nextUnitId = normalizeUnitIdValue(unitIdField.value || session?.unitId || "");
  const maxSessionNameLength = Number(sessionNameField.maxLength) > 0
    ? Number(sessionNameField.maxLength)
    : 80;

  sessionNameField.setCustomValidity(nextCustomSessionName ? "" : "Please enter a session name.");

  if (!nextCustomSessionName) {
    sessionNameField.focus();
    return false;
  }

  if (!form.reportValidity()) {
    return false;
  }

  const firstPartition = normalizeSessionPartitions(session?.partitions || [])[0];
  const safeCustomSessionName = nextCustomSessionName.slice(0, maxSessionNameLength);

  sessionNameField.value = safeCustomSessionName;
  sessionNameField.setCustomValidity("");
  unitIdField.value = nextUnitId;
  session.customSessionName = safeCustomSessionName;
  session.unitId = nextUnitId;
  session.sessionName = buildFinalSessionName(safeCustomSessionName, firstPartition, session?.date);
  return true;
}

function applySessionDetailHeaderOptions(elements, options = {}) {
  if (!elements) {
    return;
  }

  if (elements.title && Object.prototype.hasOwnProperty.call(options, "title")) {
    elements.title.textContent = options.title || "Session";
  }
  if (elements.headerEyebrow && Object.prototype.hasOwnProperty.call(options, "eyebrow")) {
    elements.headerEyebrow.textContent = options.eyebrow || "";
  }
  if (elements.headerCopy && Object.prototype.hasOwnProperty.call(options, "description")) {
    const existingDescription = elements.headerCopy.querySelector("[data-session-detail-description='true']");
    if (existingDescription) {
      existingDescription.remove();
    }
    if (options.description) {
      const description = document.createElement("p");
      description.className = "muted";
      description.dataset.sessionDetailDescription = "true";
      description.textContent = options.description;
      elements.headerCopy.appendChild(description);
    }
  }

  [elements.topBackLink, elements.bottomBackLink].forEach((link) => {
    if (!link) {
      return;
    }
    if (Object.prototype.hasOwnProperty.call(options, "backLabel")) {
      link.textContent = options.backLabel || "Back";
    }
    if (Object.prototype.hasOwnProperty.call(options, "backHref")) {
      link.setAttribute("href", options.backHref || "#sessions");
    }
    if (Array.isArray(options.backClasses) && options.backClasses.length) {
      link.classList.add(...options.backClasses);
    }
  });

  if (elements.deleteButton && options.hideDeleteButton === true) {
    elements.deleteButton.hidden = true;
  }
  if (elements.lifecycleDebug && options.hideLifecycleDebug === true) {
    elements.lifecycleDebug.hidden = true;
  }
  if (elements.snapshotSection && options.hideSnapshotSection === true) {
    elements.snapshotSection.hidden = true;
  }
}

function applySessionDetailNotesOptions(elements, options = {}) {
  if (!elements) {
    return;
  }

  if (elements.notesLabel && Object.prototype.hasOwnProperty.call(options, "label")) {
    elements.notesLabel.textContent = options.label || "";
  }
  if (elements.notesField && Object.prototype.hasOwnProperty.call(options, "value")) {
    elements.notesField.value = options.value || "";
  }
  if (elements.notesField && Object.prototype.hasOwnProperty.call(options, "placeholder")) {
    elements.notesField.placeholder = options.placeholder || "";
  }
  if (elements.notesHelp && Object.prototype.hasOwnProperty.call(options, "helpText")) {
    elements.notesHelp.textContent = options.helpText || "";
  }
  if (elements.notesSaveButton && Object.prototype.hasOwnProperty.call(options, "buttonText")) {
    elements.notesSaveButton.textContent = options.buttonText || "";
  }
  if (elements.notesSaveButton && Array.isArray(options.buttonClasses) && options.buttonClasses.length) {
    elements.notesSaveButton.classList.add(...options.buttonClasses);
  }
}

function applySessionDetailImageOptions(elements, options = {}) {
  if (!elements) {
    return;
  }

  if (elements.imageHeading && Object.prototype.hasOwnProperty.call(options, "heading")) {
    elements.imageHeading.textContent = options.heading || "";
  }
  if (elements.imageLimit && Object.prototype.hasOwnProperty.call(options, "limitText")) {
    elements.imageLimit.textContent = options.limitText || "";
  }
  if (elements.imageUploadLabel && Object.prototype.hasOwnProperty.call(options, "uploadLabel")) {
    elements.imageUploadLabel.textContent = options.uploadLabel || "";
  }
}

function renderSessionDetail(sessionId) {
  const session = getSessions().find((item) => item.id === sessionId);

  if (!session) {
    window.location.hash = "#sessions";
    return;
  }

  if (isSessionSoftDeleted(session)) {
    openSessionHistoryForSession(session.id);
    return;
  }

  app.replaceChildren(cloneTemplate(templates.detail));
  const detail = getSessionDetailElements(app);
  const isCreateMode = isSessionCreateMode(session);

  syncSessionDetailHeaderMeta(detail, session);
  populateSessionDetailEditorForm(detail.detailsForm, session);
  populateSessionTimesForm(detail.timesForm, session);
  populateSessionSeedAgeForm(detail.seedAgeForm, session);
  setSessionDetailEditorOpen(detail, false);
  setSessionTimesEditorOpen(detail, false);
  clearSessionDetailEditorMessage(detail);
  clearSessionTimesEditorMessage(detail);
  const canEditSessionTimes = canCurrentUserEditSessionTimes(session);
  if (detail.timesEditButton) {
    detail.timesEditButton.hidden = !canEditSessionTimes;
  }
  applySessionDetailNotesOptions(detail, {
    value: session.sessionNotes || "",
  });
  if (isCreateMode && detail.layoutReference) {
    renderSystemLayoutReference(detail.layoutReference, session.systemType);
  } else {
    removeSessionLayoutPreview(detail);
  }
  if (detail.partitionWorkTitle) {
    updatePartitionWorkHeading(detail.partitionWorkTitle, session.systemType);
  }
  if (detail.sessionSequenceLabel) {
    const sessionSequenceNumber = getSessionSequenceNumber(session);
    if (sessionSequenceNumber) {
      const createdDateLabel = getSessionCreatedDateLabel(session);
      const ordinalLabel = formatOrdinalSessionNumber(sessionSequenceNumber);
      detail.sessionSequenceLabel.innerHTML = renderSessionSequenceBadgeMarkup({
        sequenceNumber: sessionSequenceNumber,
        createdDateLabel,
        ordinalLabel,
        href: "#sessions",
      });
      detail.sessionSequenceLabel.hidden = false;
      const sessionSequenceLink = detail.sessionSequenceLabel.querySelector(".session-sequence-badge");
      if (sessionSequenceLink) {
        sessionSequenceLink.addEventListener("click", (event) => {
          event.preventDefault();
          openSessionHistoryForSession(session.id);
        });
      }
    } else {
      detail.sessionSequenceLabel.innerHTML = "";
      detail.sessionSequenceLabel.hidden = true;
    }
  }
  detail.statusField.value = session.sessionStatus || "soaking";
  syncSessionStatusControlDatasets(detail.statusField, {
    startedAt: getSessionStatusStartedAtValue(session),
    germinationStartedAt: session.germinationStartedAt || "",
    firstPlantedAt: session.firstPlantedAt || "",
    completedAt: session.completedAt || "",
  });
  if (detail.seedAgeForm instanceof HTMLFormElement) {
    detail.seedAgeForm.dataset.seedAgeEditingUnlocked = "false";
  }
  const syncDetailSeedAgeVisibility = () => {
    if (!(detail.seedAgeForm instanceof HTMLFormElement)) {
      return false;
    }

    const visible = shouldShowDetailSeedAgeEditor({
      isCreateMode,
      sessionStatus: detail.statusField?.value || "",
      seedAgeEditingUnlocked: detail.seedAgeForm.dataset.seedAgeEditingUnlocked === "true",
    });
    detail.seedAgeForm.hidden = !visible;
    return visible;
  };
  initializeSessionImageState(detail.imageSection, {
    input: detail.imageInput,
    grid: detail.imageGrid,
    message: detail.imageMessage,
    images: session.sessionImages || [],
    editable: true,
    session,
    onImagesChange: async (nextImages) => {
      try {
        session.sessionImages = await persistSessionImages(session, nextImages);
      } catch (error) {
        detail.imageMessage.textContent = error.message || "Could not save session images.";
        detail.imageMessage.classList.add("is-error");
      }
    },
    onRender: () => {
      if (detail.snapshotSection?.__snapshotState) {
        setSnapshotPreview(detail.snapshotSection.__snapshotState, null);
        setSnapshotMessage(detail.snapshotSection.__snapshotState, "");
        renderSnapshotSourceSummary(detail.snapshotSection.__snapshotState);
      }
    },
  });
  initializeSnapshotSection(detail.snapshotSection, {
    picker: detail.snapshotPicker,
    preview: detail.snapshotPreview,
    postActions: detail.snapshotPostActions,
    message: detail.snapshotMessage,
    generateButton: detail.generateSnapshotButton,
    downloadButton: detail.downloadSnapshotButton,
    resetButton: detail.resetSnapshotButton,
    shareButton: detail.shareSnapshotButton,
    usageConsentCheckbox: detail.snapshotUsageConsentCheckbox,
    destinationInputs: detail.snapshotDestinationInputs,
    includeProfileToggle: detail.snapshotIncludeProfileToggle,
    includeProfileToggleRow: detail.snapshotIncludeProfileToggleRow,
    includeProfileDividerRow: detail.snapshotIncludeProfileDividerRow,
    actionRow: detail.snapshotActionRow,
    actionTitle: detail.snapshotActionTitle,
    actionDescription: detail.snapshotActionDescription,
    emptyExploreCard: detail.snapshotEmptyExploreCard,
    galleryNote: detail.snapshotGalleryNote,
    sessionNotesField: detail.notesField,
    publicGrowNoteField: detail.publicGrowNoteField,
    publicGrowNoteToggle: detail.publicGrowNoteToggle,
    publicGrowNoteCount: detail.publicGrowNoteCount,
    publicGrowNoteModeInputs: detail.publicGrowNoteModeInputs,
    unpublishButton: detail.snapshotUnpublishButton,
    canPublish: true,
    getGallerySession: () => session,
    getSnapshotData: () => getSessionSnapshotData(session),
    getImageEntries: () => {
      const imageState = detail.imageSection.__sessionImageState;
      return imageState ? [...imageState.images, ...imageState.pendingFiles] : [];
    },
  });
  updateSessionStatusAppearance(detail.statusField, detail.statusTrigger);
  syncDetailSeedAgeVisibility();
  updateSessionStatusReminder(
    detail.statusReminder,
    session.date,
    session.time,
    detail.statusField.value,
    session.germinationStartedAt || "",
    session.timerStartAt || "",
    getSessionStageReminderOptions(session),
  );

  const partitions = detail.partitions;
  const renderDetailPartitions = () => {
    const currentSeedAgeMetadata = getSessionSeedAgeMetadata(session);
    const normalizedStatus = normalizeSessionStatus(detail.statusField.value);
    const normalizedPartitions = normalizeSessionPartitions(session.partitions || []);
    const completedDisplayPartitions = normalizedStatus === "completed"
      ? getCompletedSessionDisplayPartitions(normalizedPartitions, session)
      : [];

    partitions.innerHTML = "";
    partitions.__partitionDraftValues = normalizedPartitions.map((partition) => ({ ...partition }));
    partitions.dataset.partitionRenderMode = normalizedStatus === "completed"
      ? "completed-report"
      : "editable";

    if (normalizedStatus === "completed") {
      completedDisplayPartitions.forEach((partition) => {
        partitions.appendChild(buildPartitionDetailRow(partition, detail.statusField.value, {
          displayIndex: partition.displayIndex,
          showSeedAgeField: currentSeedAgeMetadata.trackingEnabled,
          session,
        }));
      });
    } else {
      normalizedPartitions.forEach((partition, index) => {
        partitions.appendChild(buildPartitionFormCard(partition, index, {
          showSeedAgeField: currentSeedAgeMetadata.trackingEnabled,
          showSeedAgeInput: currentSeedAgeMetadata.trackingEnabled && shouldShowPartitionSeedAgeFieldForPartition(partition),
          seedAgeReadOnly: currentSeedAgeMetadata.mode === "same",
        }));
        hydratePartitionRow(partitions.lastElementChild, partition);
      });
      ensureSourceCatalogDatalist();
      initializeCustomSelects(partitions);
    }

    bindPartitionRowVisualState(partitions);
    applySessionStatusLayout(detail.chartShell, detail.chartHeader, partitions, detail.statusField.value);
    applyPartitionSeedAgeLayout(detail.chartShell, detail.chartHeader, partitions, currentSeedAgeMetadata.mode);
    syncPartitionButtonStates(partitions, detail.statusField.value);
    syncCompletedSessionPartitionVisibility(partitions, detail.statusField.value);
    return completedDisplayPartitions;
  };
  const bindDetailPartitionInputListeners = () => {
    if (partitions.dataset.partitionRenderMode === "completed-report") {
      return;
    }

    partitions.querySelectorAll(".partition-row").forEach((row) => {
      row.querySelectorAll("input, select").forEach((field) => {
        const eventName = field.tagName === "SELECT" ? "change" : "input";
        field.addEventListener(eventName, () => {
          validatePartitionRow(row);
          applySessionSeedAgeSettingsFromForm(session, detail.seedAgeForm);
          syncSessionPartitionsFromContainer(session, partitions, { form: detail.seedAgeForm });
          captureFirstPlantedEventForSession(session);
          syncSessionStatusControlDatasets(detail.statusField, {
            startedAt: getSessionStatusStartedAtValue(session),
            germinationStartedAt: session.germinationStartedAt || "",
            firstPlantedAt: session.firstPlantedAt || "",
            completedAt: session.completedAt || "",
          });
          updateSessionStatusAppearance(detail.statusField, detail.statusTrigger);
          syncCompletedSessionPartitionVisibility(partitions, detail.statusField.value);
          refreshDetailDerivedViews();
          setFeedbackMessage(detail.saveMessage, "");
          setSessionDetailSaveButtonState(detail, "default");
          refreshDetailUnsavedChanges();
        });
        field.addEventListener("blur", () => {
          validatePartitionRow(row);
          applySessionSeedAgeSettingsFromForm(session, detail.seedAgeForm);
          syncSessionPartitionsFromContainer(session, partitions, { form: detail.seedAgeForm });
          captureFirstPlantedEventForSession(session);
          syncSessionStatusControlDatasets(detail.statusField, {
            startedAt: getSessionStatusStartedAtValue(session),
            germinationStartedAt: session.germinationStartedAt || "",
            firstPlantedAt: session.firstPlantedAt || "",
            completedAt: session.completedAt || "",
          });
          updateSessionStatusAppearance(detail.statusField, detail.statusTrigger);
          syncCompletedSessionPartitionVisibility(partitions, detail.statusField.value);
          refreshDetailDerivedViews();
          refreshDetailUnsavedChanges();
        });
      });
      validatePartitionRow(row);
    });
  };
  renderDetailPartitions();
  bindDetailPartitionInputListeners();
  applyStageEditingMode(app, detail.statusField.value);
  const renderDetailSuppliesCard = () => {
    if (!detail.suppliesAnchor) {
      return;
    }

    detail.suppliesAnchor.innerHTML = renderActiveSessionFilterPaperCardMarkup();
    bindFilterPaperCardActions(detail.suppliesAnchor, {
      onSave: renderDetailSuppliesCard,
    });
  };
  const refreshDetailDerivedViews = () => {
    const progressPartitions = normalizeSessionStatus(detail.statusField.value) === "completed"
      ? getCompletedSessionDisplayPartitions(session.partitions, session).map((partition) => ({
        id: partition.displayIndex,
        seedCount: Number(partition.seedCount) || 0,
        plantedCount: Number(partition.plantedCount) || 0,
      }))
      : normalizeSessionPartitions(session.partitions || []).map((partition) => ({
        id: partition.id,
        seedCount: Number(partition.seedCount) || 0,
        plantedCount: Number(partition.plantedCount) || 0,
      }));
    updatePartitionProgressChart(
      progressPartitions,
      detail.progressChart,
      detail.progressSection,
    );
    updateSessionTimingSummary(
      detail.timingSummary,
      detail.timingSection,
      session.date,
      session.time,
      detail.statusField.value,
      session.completedAt,
      session.timerStartAt || "",
      {
        session,
        sessionDurationStartAt: getSessionDurationStartAt(session)?.toISOString() || "",
      },
    );
    updateRunProgressSummary(
      detail.runProgressSummary,
      detail.runProgressSection,
      detail.statusField.value,
      session.partitions,
    );
    let resultBreakdown = app.querySelector("#detail-session-result-breakdown");
    const resultBreakdownMarkup = renderSessionResultBreakdownMarkup(session, { maxPartitions: 16, maxGroups: 4 });
    if (resultBreakdownMarkup) {
      if (!resultBreakdown) {
        resultBreakdown = document.createElement("div");
        resultBreakdown.id = "detail-session-result-breakdown";
        detail.runProgressSection?.insertAdjacentElement("afterend", resultBreakdown);
      }
      resultBreakdown.innerHTML = resultBreakdownMarkup;
      resultBreakdown.hidden = false;
    } else if (resultBreakdown) {
      resultBreakdown.innerHTML = "";
      resultBreakdown.hidden = true;
    }
    updateSessionLifecycleTimeline(
      detail.lifecycleSummary,
      detail.lifecycleSection,
      buildSessionLifecycleState(session),
    );
    renderDetailSuppliesCard();
  };
  const refreshDetailUnsavedChanges = () => {
    refreshUnsavedChangesState();
  };
  const rerenderDetailSeedAgeState = () => {
    if (!(detail.seedAgeForm instanceof HTMLFormElement)) {
      return;
    }

    if (!syncDetailSeedAgeVisibility()) {
      return;
    }

    applySessionSeedAgeSettingsFromForm(session, detail.seedAgeForm);
    renderDetailPartitions();
    bindDetailPartitionInputListeners();
    refreshDetailDerivedViews();
    setFeedbackMessage(detail.saveMessage, "");
    setSessionDetailSaveButtonState(detail, "default");
    refreshDetailUnsavedChanges();
  };
  refreshDetailDerivedViews();
  if (detail.seedAgeForm instanceof HTMLFormElement && detail.seedAgeForm.dataset.bound !== "true") {
    detail.seedAgeForm.addEventListener("change", (event) => {
      const target = event.target;
      if (!(target instanceof HTMLInputElement)) {
        return;
      }

      if (target.name === "seedAgeTrackingEnabled" || target.name === "seedAgeMode") {
        syncSeedAgeSetupUi(detail.seedAgeForm);
        rerenderDetailSeedAgeState();
      }
    });
    detail.seedAgeForm.addEventListener("input", (event) => {
      const target = event.target;
      if (!(target instanceof HTMLInputElement)) {
        return;
      }

      if (target.name === "sessionSeedAgeYears") {
        setFeedbackMessage(detail.saveMessage, "");
        setSessionDetailSaveButtonState(detail, "default");
        rerenderDetailSeedAgeState();
      }
    });
    detail.seedAgeForm.dataset.bound = "true";
  }
  bindSessionTimelineDebugTools(detail.lifecycleSection, (action) => {
    const previousStatus = session.sessionStatus || "";
    applyDebugEventToSession(session, detail.statusField, action);
    syncSessionDetailHeaderMeta(detail, session);
    syncSessionStatusControlDatasets(detail.statusField, {
      startedAt: getSessionStatusStartedAtValue(session),
      germinationStartedAt: session.germinationStartedAt || "",
      firstPlantedAt: session.firstPlantedAt || "",
      completedAt: session.completedAt || "",
    });
    updateSessionStatusAppearance(detail.statusField, detail.statusTrigger);
    renderDetailPartitions();
    bindDetailPartitionInputListeners();
    applyStageEditingMode(app, detail.statusField.value);
    if (detail.seedAgeForm instanceof HTMLFormElement) {
      detail.seedAgeForm.dataset.seedAgeEditingUnlocked = "false";
    }
    syncDetailSeedAgeVisibility();
    updateSessionStatusReminder(
      detail.statusReminder,
      session.date,
      session.time,
      detail.statusField.value,
      session.germinationStartedAt || "",
      session.timerStartAt || "",
      getSessionStageReminderOptions(session),
    );
    updateRunProgressSummary(
      detail.runProgressSummary,
      detail.runProgressSection,
      detail.statusField.value,
      session.partitions,
    );
    updateSessionLifecycleTimeline(
      detail.lifecycleSummary,
      detail.lifecycleSection,
      buildSessionLifecycleState(session),
    );
    void saveSessionUpdate(session).then((savedSession) => {
      if (savedSession) {
        markUnsavedChangesSaved();
      }
    });
  });
  startSessionTimer(() => {
    updateSessionStatusReminder(
      detail.statusReminder,
      session.date,
      session.time,
      detail.statusField.value,
      session.germinationStartedAt || "",
      session.timerStartAt || "",
      getSessionStageReminderOptions(session),
    );
    updateSessionTimingSummary(
      detail.timingSummary,
      detail.timingSection,
      session.date,
      session.time,
      detail.statusField.value,
      session.completedAt,
      session.timerStartAt || "",
      {
        session,
        sessionDurationStartAt: getSessionDurationStartAt(session)?.toISOString() || "",
      },
    );
    updateRunProgressSummary(
      detail.runProgressSummary,
      detail.runProgressSection,
      detail.statusField.value,
      session.partitions,
    );
    updateSessionLifecycleTimeline(
      detail.lifecycleSummary,
      detail.lifecycleSection,
      buildSessionLifecycleState(session),
    );
  });

    detail.statusTrigger?.addEventListener("click", () => {
      appState.growthStageModalDismissed = false;
      openGrowthStageModal({ stageField: detail.statusField, stageTrigger: detail.statusTrigger });
    });
    detail.actionStageTrigger?.addEventListener("click", () => {
      detail.statusTrigger?.click();
    });

  detail.statusField.addEventListener("change", async () => {
    const previousStatus = session.sessionStatus || "";
    const previousProgressKey = getSessionProgressKeyFromSession(session);
    const selectedProgressKey = getSessionStatusProgressKey(detail.statusField);
    const manuallyRevertedToSoaking = selectedProgressKey === "soaking"
      && previousProgressKey
      && previousProgressKey !== "soaking";
    if (detail.seedAgeForm instanceof HTMLFormElement) {
      detail.seedAgeForm.dataset.seedAgeEditingUnlocked = manuallyRevertedToSoaking ? "true" : "false";
    }
    applySessionSeedAgeSettingsFromForm(session, detail.seedAgeForm);
    syncSessionPartitionsFromContainer(session, partitions, { form: detail.seedAgeForm });
    if (selectedProgressKey === "completed" && previousProgressKey !== "completed" && !areSessionSeedResultsFullyAccountedFor(session)) {
      detail.statusField.value = previousStatus || "";
      syncSessionStatusControlDatasets(detail.statusField, {
        startedAt: getSessionStatusStartedAtValue(session),
        germinationStartedAt: session.germinationStartedAt || "",
        firstPlantedAt: session.firstPlantedAt || "",
        completedAt: session.completedAt || "",
      });
      showSessionCompletionResultsWarning(detail.saveMessage);
      updateSessionStatusAppearance(detail.statusField, detail.statusTrigger);
      return;
    }
    session.sessionStatus = detail.statusField.value;
    session.germinationStartedAt = detail.statusField.dataset.germinationStartedAt || "";
    session.firstPlantedAt = detail.statusField.dataset.firstPlantedAt || "";
    session.completedAt = detail.statusField.dataset.completedAt || "";
    syncSessionDetailHeaderMeta(detail, session);
    if (normalizeSessionStatus(previousStatus) !== "germinating" && normalizeSessionStatus(detail.statusField.value) === "germinating") {
      session.germinationStartedAt = new Date().toISOString();
    }
    if (detail.statusField.value === "completed" && previousStatus !== "completed") {
      session.completedAt = new Date().toISOString();
    }
    if (previousStatus === "completed" && detail.statusField.value !== "completed") {
      session.completedAt = "";
    }
    syncSessionStatusControlDatasets(detail.statusField, {
      startedAt: getSessionStatusStartedAtValue(session),
      germinationStartedAt: session.germinationStartedAt || "",
      firstPlantedAt: session.firstPlantedAt || "",
      completedAt: session.completedAt || "",
    });
    updateSessionStatusAppearance(detail.statusField, detail.statusTrigger);
    updateSessionStatusReminder(
      detail.statusReminder,
      session.date,
      session.time,
      detail.statusField.value,
      session.germinationStartedAt || "",
      session.timerStartAt || "",
      getSessionStageReminderOptions(session),
    );
    renderDetailPartitions();
    bindDetailPartitionInputListeners();
    applyStageEditingMode(app, detail.statusField.value);
    syncDetailSeedAgeVisibility();
    refreshDetailDerivedViews();

    const savedSession = await saveSessionUpdate(session);
    if (savedSession) {
      markUnsavedChangesSaved();
    }
  });

  const persistDetailSession = async () => {
    clearSessionDetailEditorMessage(detail);
    if (!applySessionDetailEditorValues(detail.detailsForm, session)) {
      setFeedbackMessage(detail.detailsMessage, "Please enter a session name to continue.", "error");
      return null;
    }
    const seedAgeValidation = detail.seedAgeForm?.hidden
      ? { isValid: true, message: "", firstInvalidField: null }
      : validateSeedAgeSettings(detail.seedAgeForm);
    if (!seedAgeValidation.isValid) {
      setFeedbackMessage(detail.saveMessage, seedAgeValidation.message, "error");
      seedAgeValidation.firstInvalidField?.focus();
      return null;
    }
    applySessionSeedAgeSettingsFromForm(session, detail.seedAgeForm);
    syncSessionPartitionsFromContainer(session, partitions, { form: detail.seedAgeForm });
    captureFirstPlantedEventForSession(session);
    session.sessionNotes = detail.notesField.value.trim();
    session.snapshotState = normalizePersistedSessionSnapshotState(detail.snapshotSection?.__snapshotState?.pendingSnapshotState);
    setFeedbackMessage(detail.saveMessage, "");
    setSessionDetailSaveButtonState(detail, "default");
    syncSessionDetailHeaderMeta(detail, session);
    if (detail.layoutReference && detail.layoutSection) {
      void renderSystemLayoutReference(detail.layoutReference, session.systemType);
    }
    if (detail.partitionWorkTitle) {
      updatePartitionWorkHeading(detail.partitionWorkTitle, session.systemType);
    }
    syncSessionStatusControlDatasets(detail.statusField, {
      startedAt: getSessionStatusStartedAtValue(session),
      germinationStartedAt: session.germinationStartedAt || "",
      firstPlantedAt: session.firstPlantedAt || "",
      completedAt: session.completedAt || "",
    });
    updateSessionStatusReminder(
      detail.statusReminder,
      session.date,
      session.time,
      detail.statusField.value,
      session.germinationStartedAt || "",
      session.timerStartAt || "",
      getSessionStageReminderOptions(session),
    );
    refreshDetailDerivedViews();
    setSessionDetailSaveButtonState(detail, "default");
    const savedSession = await saveSessionUpdate(session);
    setFeedbackMessage(
      detail.saveMessage,
      savedSession
        ? "Session saved."
        : (appState.unsavedChanges.lastSaveError?.message || "Could not save session."),
      savedSession ? "success" : "error",
    );
    if (savedSession) {
      setSessionDetailSaveButtonState(detail, "saved", {
        persist: normalizeSessionStatus(savedSession.sessionStatus || "") === "completed",
      });
      await refreshUserSessionsAfterSave("session-detail:save");
      detail.statusField.value = session.sessionStatus || "soaking";
      syncSessionStatusControlDatasets(detail.statusField, {
        startedAt: getSessionStatusStartedAtValue(session),
        germinationStartedAt: session.germinationStartedAt || "",
        firstPlantedAt: session.firstPlantedAt || "",
        completedAt: session.completedAt || "",
      });
      updateSessionStatusAppearance(detail.statusField, detail.statusTrigger);
      renderDetailPartitions();
      bindDetailPartitionInputListeners();
      applyStageEditingMode(app, detail.statusField.value);
      refreshDetailDerivedViews();
      syncSessionDetailHeaderMeta(detail, session);
      populateSessionDetailEditorForm(detail.detailsForm, session);
      populateSessionSeedAgeForm(detail.seedAgeForm, session);
      syncDetailSeedAgeVisibility();
      setSessionDetailEditorOpen(detail, false);
      markUnsavedChangesSaved();
    } else if (detail.detailsPanel && !detail.detailsPanel.hidden) {
      setFeedbackMessage(detail.detailsMessage, "Could not save session name.", "error");
    }
    return savedSession;
  };

  registerUnsavedChangesContext({
    pageHash: appState.currentRouteHash,
    contextType: "session",
    getSignature: () => buildSessionDetailDraftSignature(
      session,
      partitions,
      detail.statusField,
      detail.notesField,
      detail.detailsForm,
      detail.seedAgeForm,
    ),
    saveFn: persistDetailSession,
  });

  detail.saveShortcutButton?.addEventListener("click", persistDetailSession);
  detail.saveButton?.addEventListener("click", persistDetailSession);
  detail.detailsForm?.addEventListener("submit", async (event) => {
    event.preventDefault();
    await persistDetailSession();
  });
  detail.timesForm?.addEventListener("submit", async (event) => {
    event.preventDefault();
    clearSessionTimesEditorMessage(detail);
    const payload = getSessionTimesFormPayload(detail.timesForm, session);
    if (!payload.isValid) {
      setSessionTimesEditorMessage(detail, payload.message, true);
      return;
    }

    try {
      const savedSession = await updateOwnerGrowSessionTimes(session, payload);
      Object.assign(session, savedSession);
      syncSessionTimeDependentDetailViews(detail, session, {
        refreshDerivedViews: refreshDetailDerivedViews,
      });
      setSessionTimesEditorMessage(detail, "Session times saved.");
      syncSessionProgressionReminderNotifications(getSessions());
      queueDueGrowReminderEvaluation("session-times:updated");
    } catch (error) {
      console.error("Failed to update session times", error);
      setSessionTimesEditorMessage(detail, error?.message || "Could not save session times.", true);
    }
  });
  detail.editButton?.addEventListener("click", () => {
    if (detail.detailsPanel && !detail.detailsPanel.hidden) {
      detail.detailsForm?.elements?.sessionName?.focus();
      return;
    }

    populateSessionDetailEditorForm(detail.detailsForm, session);
    clearSessionDetailEditorMessage(detail);
    setSessionDetailEditorOpen(detail, true);
    detail.detailsForm?.elements?.sessionName?.focus();
    refreshDetailUnsavedChanges();
  });
  detail.timesEditButton?.addEventListener("click", () => {
    if (!canEditSessionTimes) {
      return;
    }
    if (detail.timesPanel && !detail.timesPanel.hidden) {
      detail.timesForm?.elements?.sessionStartedAt?.focus();
      return;
    }

    populateSessionTimesForm(detail.timesForm, session);
    clearSessionTimesEditorMessage(detail);
    setSessionTimesEditorOpen(detail, true);
    detail.timesForm?.elements?.sessionStartedAt?.focus();
  });
  detail.detailsCancelButton?.addEventListener("click", () => {
    populateSessionDetailEditorForm(detail.detailsForm, session);
    clearSessionDetailEditorMessage(detail);
    setSessionDetailEditorOpen(detail, false);
    refreshDetailUnsavedChanges();
  });
  detail.timesCancelButton?.addEventListener("click", () => {
    populateSessionTimesForm(detail.timesForm, session);
    clearSessionTimesEditorMessage(detail);
    setSessionTimesEditorOpen(detail, false);
  });
  detail.detailsForm?.querySelectorAll("input, select").forEach((field) => {
    const eventName = field instanceof HTMLSelectElement ? "change" : "input";
    field.addEventListener(eventName, () => {
      clearSessionDetailEditorMessage(detail);
      setFeedbackMessage(detail.saveMessage, "");
      setSessionDetailSaveButtonState(detail, "default");
      refreshDetailUnsavedChanges();
    });
  });
  detail.timesForm?.querySelectorAll("input").forEach((field) => {
    field.addEventListener("input", () => {
      clearSessionTimesEditorMessage(detail);
    });
  });

  const persistDetailNote = async () => {
    try {
      session.sessionNotes = detail.notesField.value.trim();
      session.snapshotState = normalizePersistedSessionSnapshotState(detail.snapshotSection?.__snapshotState?.pendingSnapshotState);
      const savedSession = await saveSessionUpdate(session);
      if (!savedSession) {
        throw new Error("Could not save note.");
      }
      Object.assign(session, savedSession);
      if (detail.notesField) {
        detail.notesField.value = session.sessionNotes || "";
      }
      if (detail.snapshotSection?.__snapshotState) {
        detail.snapshotSection.__snapshotState.pendingSnapshotState = normalizePersistedSessionSnapshotState(session.snapshotState);
      }
      patchUnsavedChangesBaseline((baseline, current) => ({
        ...baseline,
        sessionNotes: current.sessionNotes,
        publicGrowNote: normalizePublicGrowNote(current.publicGrowNote || ""),
        includePublicGrowNote: Boolean(current.includePublicGrowNote),
      }));
      setFeedbackMessage(detail.notesMessage, "Note saved.", "success");
    } catch (error) {
      console.error("Failed to save session note", error);
      setFeedbackMessage(detail.notesMessage, "Could not save note.", "error");
    }
  };

  detail.notesSaveButton?.addEventListener("click", persistDetailNote);
  detail.notesField.addEventListener("input", () => {
    refreshDetailUnsavedChanges();
    if (!detail.notesMessage?.textContent) {
      return;
    }

    setFeedbackMessage(detail.notesMessage, "");
  });
  detail.publicGrowNoteField?.addEventListener("input", refreshDetailUnsavedChanges);
  detail.publicGrowNoteToggle?.addEventListener("change", refreshDetailUnsavedChanges);
  detail.publicGrowNoteModeInputs?.forEach((input) => {
    input.addEventListener("change", refreshDetailUnsavedChanges);
    input.addEventListener("change", () => {
      if (!detail.notesMessage?.textContent) {
        return;
      }
      setFeedbackMessage(detail.notesMessage, "");
    });
  });
  detail.publicGrowNoteField?.addEventListener("input", () => {
    if (!detail.notesMessage?.textContent) {
      return;
    }

    setFeedbackMessage(detail.notesMessage, "");
  });
  detail.publicGrowNoteToggle?.addEventListener("change", () => {
    if (!detail.notesMessage?.textContent) {
      return;
    }

    setFeedbackMessage(detail.notesMessage, "");
  });

  detail.deleteButton.addEventListener("click", async () => {
    const deleteAction = await confirmSessionArchive(session);
    if (!deleteAction || deleteAction.action === "cancel") {
      return;
    }

    try {
      const deleteResult = await performSessionDeleteAction(session, deleteAction);
      if (!deleteResult) {
        return;
      }
      appState.sessionHistoryFocusSessionId = sessionId;
      appState.sessionHistoryFilter = "all";
      appState.sessionHistoryExpanded = true;
      navigateWithUnsavedChangesBypass("#sessions");
    } catch (error) {
      window.alert(error.message || "Could not delete session.");
    }
  });
  applyPendingSessionDetailNotificationFocus(session, detail);
  void applyPendingSessionDetailNotificationAction(session, detail);
  scrollElementIntoViewAfterLayout(detail.topBackLink?.closest(".app-section-header") || app.firstElementChild, {
    delayMs: 140,
  });
}

function renderSessionCollection(container, sessions, options) {
  container.innerHTML = "";
  container.classList.toggle("compact-list", options.compact);
  container.classList.toggle("session-history-grid", options.variant === "history-grid");
  container.classList.toggle("active-sessions-grid", options.variant === "active-grid");
  if (options.variant === "active-grid") {
    container.dataset.sessionCount = String(sessions.length);
  } else {
    delete container.dataset.sessionCount;
  }

  if (!sessions.length) {
    const empty = document.createElement("div");
    empty.className = "empty-state";
    empty.innerHTML = `
      <p>${options.emptyMessage}</p>
      <a class="button button-primary" href="#new" data-session-entry="true">${options.emptyActionLabel}</a>
      ${renderLearnEmptyStateCtaMarkup(options.learnTutorialId || "creating-your-first-session", options.learnTutorialLabel || "Creating Your First Session")}
    `;
    container.appendChild(empty);
    applySupplyStatusToSessionEntryButtons(empty);
    return;
  }

  sessions.forEach((session) => {
    const resultSummary = getSessionResultSummary(session);
    const successLabel = formatSessionSuccessLabel(session);
    const stageLabel = capitalize(normalizeSessionStatus(session.sessionStatus)).replace("Unselected", "Not started");
    const mixedResultContext = resultSummary.mixedContext.isMixedSession
      ? resultSummary.sourceGroups.slice(0, 3).map((group) => `${group.label}: ${group.percentageLabel}`).join(" / ")
      : "";
    const row = document.createElement("a");
    row.className = `session-row${options.variant === "history-grid" ? " session-history-card" : ""}`;
    row.href = `#sessions/${session.id}`;
    if (options.variant === "history-grid") {
      row.innerHTML = `
        <div class="session-row-top">
          <strong>${escapeHtml(formatSessionLabel(session))}</strong>
          <div class="session-row-actions">
            <button type="button" class="session-delete-button" data-session-delete="${session.id}" aria-label="Delete ${escapeHtml(formatSessionLabel(session))}">Delete</button>
          </div>
        </div>
        <div class="session-history-meta">
          <div class="session-history-meta-item">
            <span>Date</span>
            <p>${escapeHtml(formatSessionNameDate(session.date))}</p>
          </div>
          <div class="session-history-meta-item">
            <span>System</span>
            <p>${escapeHtml(getSessionSystemSummary(session))}</p>
          </div>
          <div class="session-history-meta-item">
            <span>Status</span>
            <p>${escapeHtml(stageLabel)}</p>
          </div>
        </div>
        <div class="session-history-footer">
          <span class="session-success-pill">${formatSessionRateBadgeLabel(session)}</span>
          ${mixedResultContext ? `<span class="session-mixed-result-context">${escapeHtml(mixedResultContext)}</span>` : ""}
          <span class="session-history-view">Open session</span>
        </div>
      `;
    } else {
      row.innerHTML = `
        <div class="session-row-top">
          <strong>${escapeHtml(formatSessionLabel(session))}</strong>
          <div class="session-row-actions">
            <span class="session-success-pill">${successLabel}</span>
            <button type="button" class="session-delete-button" data-session-delete="${session.id}" aria-label="Delete ${escapeHtml(formatSessionLabel(session))}">Delete</button>
          </div>
        </div>
        <div class="session-row-bottom">
          <p>${escapeHtml(formatSessionNameDate(session.date))}</p>
          <p>${session.systemType}</p>
          <p>${escapeHtml(stageLabel)}</p>
        </div>
      `;
    }
    row.querySelector("[data-session-delete]")?.addEventListener("click", async (event) => {
      event.preventDefault();
      event.stopPropagation();

      const deleteAction = await confirmSessionArchive(session);
      if (!deleteAction || deleteAction.action === "cancel") {
        return;
      }

      try {
        const deleteResult = await performSessionDeleteAction(session, deleteAction);
        if (!deleteResult) {
          return;
        }
        appState.sessionHistoryFocusSessionId = session.id;
        appState.sessionHistoryFilter = "all";
        appState.sessionHistoryExpanded = true;
        renderSessionsList();
      } catch (error) {
        window.alert(error.message || "Could not delete session.");
      }
    });
    container.appendChild(row);
  });
}

function sortSessionHistorySessions(sessions, sortBy = "date") {
  const collator = new Intl.Collator("en", {
    sensitivity: "base",
    numeric: true,
  });

  return [...sessions].sort((left, right) => {
    switch (sortBy) {
      case "name-asc":
        return collator.compare(formatSessionLabel(left), formatSessionLabel(right))
          || (getSessionSortTime(right) - getSessionSortTime(left));
      case "name-desc":
        return collator.compare(formatSessionLabel(right), formatSessionLabel(left))
          || (getSessionSortTime(right) - getSessionSortTime(left));
      case "rate":
        return comparePerformanceByRateSpeedAndRecency(left, right, {
          getRate: getSessionSuccessRate,
          getDurationMs: getSessionCompletedDurationMs,
          getSortTime: getSessionSortTime,
          getFallbackLabel: formatSessionLabel,
          sortDirection: "desc",
        });
      case "date":
      default:
        return getSessionSortTime(right) - getSessionSortTime(left);
    }
  });
}

function getSessionSuccessRate(session) {
  return getSessionResultSummary(session).overall.percentage || 0;
}

function getSessionSystemSummary(session) {
  const systemType = String(session.systemType || "").trim();
  const unitId = normalizeUnitIdValue(session.unitId);

  if (systemType && unitId) {
    return `${systemType} / ${unitId}`;
  }

  return systemType || unitId || "Not provided";
}

function formatSessionRateBadgeLabel(session) {
  const totals = getSessionSeedTotals(session);
  if (totals.totalSeeds <= 0) {
    return "Germination --";
  }

  return `Germination ${getSessionSuccessRate(session)}%`;
}

function formatSessionSuccessLabel(session) {
  const totals = getSessionSeedTotals(session);
  if (totals.totalSeeds <= 0) {
    return "Success --";
  }

  return `Success ${totals.percentage}%`;
}

function getSessionSeedTotals(session) {
  const summary = getSessionResultSummary(session);
  return {
    totalSeeds: summary.overall.totalSeeds,
    totalPlanted: summary.overall.totalGerminated,
    totalGerminated: summary.overall.totalGerminated,
    totalFailed: summary.overall.totalFailed,
    totalUnaccounted: summary.overall.totalUnaccounted,
    totalAccounted: summary.overall.totalAccounted,
    percentage: summary.overall.percentage,
  };
}

function normalizeSessionResultCount(value = null) {
  const normalizedValue = Number(value);
  return Number.isFinite(normalizedValue) ? Math.max(0, normalizedValue) : 0;
}

function normalizeSessionResultLabel(value = "", fallback = "Not shared") {
  const normalizedValue = normalizeLeaderboardLabel(value || "");
  return normalizedValue || fallback;
}

function createEmptySessionResultGroup(key = "", label = "", type = "source") {
  return {
    key,
    type,
    label,
    totalSeeds: 0,
    totalGerminated: 0,
    totalPlanted: 0,
    totalFailed: 0,
    totalUnaccounted: 0,
    totalAccounted: 0,
    percentage: null,
    percentageLabel: "N/A",
    contributingPartitions: [],
    partitionLabels: [],
  };
}

function addPartitionResultToGroup(group, partitionResult) {
  if (!group || !partitionResult) {
    return;
  }

  group.totalSeeds += partitionResult.totalCount;
  group.totalGerminated += partitionResult.germinatedCount;
  group.totalPlanted = group.totalGerminated;
  group.totalFailed += partitionResult.failedCount;
  group.totalUnaccounted += partitionResult.unaccountedCount;
  group.totalAccounted += partitionResult.accountedCount;
  group.contributingPartitions.push(partitionResult);
  group.partitionLabels.push(partitionResult.label);
  group.percentage = group.totalSeeds > 0
    ? Math.round((group.totalGerminated / group.totalSeeds) * 100)
    : null;
  group.percentageLabel = group.percentage === null ? "N/A" : `${group.percentage}%`;
}

function getSessionResultSummary(session = null) {
  const normalizedSession = normalizeStoredSession(session) || session || {};
  const partitions = normalizeSessionPartitions(normalizedSession?.partitions || []);
  const sourceGroups = new Map();
  const varietyGroups = new Map();
  const sourceKeys = new Set();
  const varietyKeys = new Set();
  const partitionResults = partitions.map((partition, index) => {
    const totalCount = normalizeSessionResultCount(partition.seedCount ?? partition.seed_count);
    const plantedRawValue = String(partition.plantedCount ?? partition.planted_count ?? "").trim();
    const plantedCount = Number(plantedRawValue);
    const hasResultValue = plantedRawValue !== "";
    const hasValidResultValue = hasResultValue
      && Number.isFinite(plantedCount)
      && plantedCount >= 0
      && plantedCount <= totalCount;
    const germinatedCount = hasValidResultValue
      ? Math.max(0, Math.min(totalCount, plantedCount))
      : 0;
    const failedCount = hasValidResultValue ? Math.max(0, totalCount - germinatedCount) : 0;
    const unaccountedCount = hasValidResultValue ? 0 : totalCount;
    const accountedCount = hasValidResultValue ? totalCount : 0;
    const percentage = totalCount > 0 && hasValidResultValue
      ? Math.round((germinatedCount / totalCount) * 100)
      : null;
    const sourceLabel = normalizeSessionResultLabel(formatPartitionSource(partition), "");
    const varietyLabel = normalizeSessionResultLabel(formatPartitionSeedVariety(partition), "");
    const sourceKey = sourceLabel ? getPartitionSourceAnalyticsKey(partition) || normalizeComparableSourceKey(sourceLabel) : "";
    const varietyKey = varietyLabel ? getPartitionSeedVarietyAnalyticsKey(partition) || normalizeComparableSourceKey(varietyLabel) : "";
    const seedType = normalizeSeedTypeId(partition.seedType || partition.seed_type || "");
    const seedSex = normalizeSeedSexValue(partition.feminized || partition.seedSex || partition.seed_sex || partition.sex || "");
    const seedAgeYears = getEffectivePartitionSeedAgeYears(partition, normalizedSession);
    const seedAgeLabel = seedAgeYears === null ? "" : buildSeedAgeDisplayLabel({
      seedAgeTrackingEnabled: true,
      seedAgeMode: "same",
      sessionSeedAgeYears: seedAgeYears,
    }, {
      samePrefix: "",
      unknownLabel: "",
      disabledLabel: "",
    });

    if (sourceKey) {
      sourceKeys.add(sourceKey);
    }
    if (varietyKey) {
      varietyKeys.add(varietyKey);
    }

    const result = {
      id: Number(partition.id) || index + 1,
      index,
      label: `P${Number(partition.id) || index + 1}`,
      displayLabel: `Partition ${Number(partition.id) || index + 1}`,
      source: sourceLabel,
      sourceLabel: sourceLabel || "Not shared",
      sourceKey,
      seedVariety: varietyLabel,
      varietyLabel: varietyLabel || "Not shared",
      varietyKey,
      seedType,
      seedTypeLabel: getSeedTypeLabel(seedType) || "",
      sex: seedSex,
      sexLabel: getSeedSexLabel(seedSex) || "",
      seedAgeYears,
      seedAgeLabel: String(seedAgeLabel || "").trim(),
      germinatedCount,
      totalCount,
      totalSeeds: totalCount,
      totalPlanted: germinatedCount,
      failedCount,
      notGerminatedCount: failedCount,
      unaccountedCount,
      accountedCount,
      percentage,
      percentageLabel: percentage === null ? "N/A" : `${percentage}%`,
      hasSeeds: totalCount > 0,
      hasResultValue,
      hasValidResultValue,
      isAccounted: totalCount > 0 && hasValidResultValue,
      rawPartition: partition,
    };

    if (result.hasSeeds && result.sourceKey) {
      const group = sourceGroups.get(result.sourceKey)
        || createEmptySessionResultGroup(result.sourceKey, result.sourceLabel, "source");
      addPartitionResultToGroup(group, result);
      sourceGroups.set(result.sourceKey, group);
    }
    if (result.hasSeeds && result.varietyKey) {
      const group = varietyGroups.get(result.varietyKey)
        || createEmptySessionResultGroup(result.varietyKey, result.varietyLabel, "variety");
      addPartitionResultToGroup(group, result);
      varietyGroups.set(result.varietyKey, group);
    }

    return result;
  });

  const countedPartitions = partitionResults.filter((partition) => partition.hasSeeds);
  const totalSeeds = countedPartitions.reduce((sum, partition) => sum + partition.totalCount, 0);
  const totalGerminated = countedPartitions.reduce((sum, partition) => sum + partition.germinatedCount, 0);
  const totalFailed = countedPartitions.reduce((sum, partition) => sum + partition.failedCount, 0);
  const totalUnaccounted = countedPartitions.reduce((sum, partition) => sum + partition.unaccountedCount, 0);
  const totalAccounted = countedPartitions.reduce((sum, partition) => sum + partition.accountedCount, 0);
  const percentage = totalSeeds > 0 ? Math.round((totalGerminated / totalSeeds) * 100) : null;

  return {
    sessionId: String(normalizedSession?.id || "").trim(),
    overall: {
      totalSeeds,
      totalStarted: totalSeeds,
      totalGerminated,
      totalPlanted: totalGerminated,
      totalFailed,
      totalUnaccounted,
      totalAccounted,
      percentage,
      percentageLabel: percentage === null ? "N/A" : `${percentage}%`,
      hasResults: totalSeeds > 0,
      hasIncompleteResults: countedPartitions.some((partition) => !partition.hasValidResultValue),
      allSeedsAccountedFor: totalSeeds > 0 && totalAccounted === totalSeeds && totalUnaccounted === 0,
    },
    partitions: partitionResults,
    countedPartitions,
    sourceGroups: [...sourceGroups.values()],
    varietyGroups: [...varietyGroups.values()],
    mixedContext: {
      hasMultipleSources: sourceKeys.size > 1,
      hasMultipleVarieties: varietyKeys.size > 1,
      isMixedSession: sourceKeys.size > 1 || varietyKeys.size > 1,
      sourceCount: sourceKeys.size,
      varietyCount: varietyKeys.size,
    },
  };
}

function getSessionSeedResultAccounting(session = null) {
  const summary = getSessionResultSummary(session);
  return {
    totalSeeds: summary.overall.totalSeeds,
    totalGerminated: summary.overall.totalGerminated,
    totalFailed: summary.overall.totalFailed,
    totalAccounted: summary.overall.totalAccounted,
    hasIncompleteResults: summary.overall.hasIncompleteResults,
  };
}

function areSessionSeedResultsFullyAccountedFor(session = null) {
  const accounting = getSessionSeedResultAccounting(session);
  return Boolean(
    accounting.totalSeeds > 0
    && !accounting.hasIncompleteResults
    && accounting.totalAccounted === accounting.totalSeeds
  );
}

function autoCompleteSessionWhenResultsAccounted(session = null, referenceDate = new Date()) {
  if (!session || normalizeSessionStatus(session.sessionStatus || "") === "completed") {
    return false;
  }
  if (!areSessionSeedResultsFullyAccountedFor(session)) {
    return false;
  }

  const completedAt = referenceDate instanceof Date && !Number.isNaN(referenceDate.getTime())
    ? referenceDate.toISOString()
    : new Date().toISOString();
  const totals = getSessionSeedTotals(session);
  session.sessionStatus = "completed";
  session.completedAt = session.completedAt || completedAt;
  session.germinationStartedAt = session.germinationStartedAt || completedAt;
  if (totals.totalPlanted > 0) {
    session.firstPlantedAt = session.firstPlantedAt || completedAt;
  }
  return true;
}

function renderPublicSessionPartitionResultsMarkup(sessionOrSummary = null, options = {}) {
  const summary = sessionOrSummary?.overall && Array.isArray(sessionOrSummary?.partitions)
    ? sessionOrSummary
    : getSessionResultSummary(sessionOrSummary);
  if (!summary?.overall?.hasResults) {
    return "";
  }

  const systemType = String(options.systemType || "").trim().toUpperCase() === "TRA" ? "TRA" : "KAN";
  const maxPartitions = systemType === "TRA" ? 16 : 8;
  const partitions = (summary.partitions || []).slice(0, maxPartitions);
  if (!partitions.length) {
    return "";
  }

  const contextText = summary.mixedContext?.isMixedSession
    ? [
        summary.mixedContext.hasMultipleSources ? `${summary.mixedContext.sourceCount} sources` : "",
        summary.mixedContext.hasMultipleVarieties ? `${summary.mixedContext.varietyCount} varieties` : "",
      ].filter(Boolean).join(" / ")
    : "Partition results";

  return `
    <section class="public-session-partition-results" aria-label="Public session partition results">
      <div class="public-session-partition-results-head">
        <div>
          <p class="eyebrow">PARTITION RESULTS</p>
          <h3>Results below the photo</h3>
          <p>${escapeHtml(contextText || "Partition results")}${summary.mixedContext?.isMixedSession ? " shown independently for fair source context." : ""}</p>
        </div>
        <span>${escapeHtml(summary.overall.percentageLabel)} overall</span>
      </div>
      <div class="public-session-partition-results-grid">
        ${partitions.map((partition) => {
          const hasSeeds = Boolean(partition.hasSeeds);
          const sourceLabel = hasSeeds ? (partition.sourceLabel || partition.source || "N/A") : "N/A";
          const varietyLabel = hasSeeds ? (partition.varietyLabel || partition.seedVariety || "N/A") : "N/A";
          const typeLabel = hasSeeds ? (partition.seedTypeLabel || getSeedTypeLabel(partition.seedType) || "N/A") : "N/A";
          const sexLabel = hasSeeds ? (partition.sexLabel || getSeedSexLabel(partition.sex) || "N/A") : "N/A";
          const seedAgeLabel = hasSeeds ? (partition.seedAgeLabel || "N/A") : "N/A";
          const countLabel = hasSeeds ? `${partition.germinatedCount}/${partition.totalCount}` : "N/A";
          const percentageLabel = hasSeeds ? (partition.percentageLabel || "N/A") : "N/A";

          return `
            <article class="public-session-partition-result${hasSeeds ? "" : " is-empty"}">
              <div class="public-session-partition-result-topline">
                <strong>${escapeHtml(partition.label || "P?")}</strong>
                <span>${escapeHtml(percentageLabel)}</span>
              </div>
              <dl>
                <div>
                  <dt>Source</dt>
                  <dd>${escapeHtml(sourceLabel)}</dd>
                </div>
                <div>
                  <dt>Seed Variety</dt>
                  <dd>${escapeHtml(varietyLabel)}</dd>
                </div>
                <div>
                  <dt>Type</dt>
                  <dd>${escapeHtml(typeLabel)}</dd>
                </div>
                <div>
                  <dt>Sex</dt>
                  <dd>${escapeHtml(sexLabel)}</dd>
                </div>
                <div>
                  <dt>Seed Age</dt>
                  <dd>${escapeHtml(seedAgeLabel)}</dd>
                </div>
                <div>
                  <dt>Germinated</dt>
                  <dd>${escapeHtml(countLabel)}</dd>
                </div>
              </dl>
            </article>
          `;
        }).join("")}
      </div>
    </section>
  `;
}

function showSessionCompletionResultsWarning(messageElement = null) {
  if (messageElement) {
    messageElement.textContent = SESSION_RESULTS_INCOMPLETE_COMPLETION_MESSAGE;
    messageElement.classList?.add("is-error");
  }
  if (typeof showNavigationLockToast === "function") {
    showNavigationLockToast({
      title: "Session Results",
      message: SESSION_RESULTS_INCOMPLETE_COMPLETION_MESSAGE,
    });
  }
}

function renderSessionResultBreakdownMarkup(sessionOrSummary = null, options = {}) {
  const summary = sessionOrSummary?.overall && Array.isArray(sessionOrSummary?.partitions)
    ? sessionOrSummary
    : getSessionResultSummary(sessionOrSummary);
  const maxPartitions = Math.max(0, Number(options.maxPartitions) || 16);
  const maxGroups = Math.max(0, Number(options.maxGroups) || 4);
  const compact = options.compact === true;
  const countedPartitions = summary.partitions.filter((partition) => partition.hasSeeds).slice(0, maxPartitions);
  const sourceGroups = summary.sourceGroups.slice(0, maxGroups);
  const varietyGroups = summary.varietyGroups.slice(0, maxGroups);
  if (!summary.overall.hasResults) {
    return "";
  }

  const contextText = summary.mixedContext.isMixedSession
    ? [
        summary.mixedContext.hasMultipleSources ? `${summary.mixedContext.sourceCount} sources` : "",
        summary.mixedContext.hasMultipleVarieties ? `${summary.mixedContext.varietyCount} varieties` : "",
      ].filter(Boolean).join(" / ")
    : "Single source or variety";

  return `
    <section class="session-result-breakdown${compact ? " session-result-breakdown--compact" : ""}" aria-label="Session result breakdown">
      <div class="session-result-breakdown-head">
        <div>
          <p class="eyebrow">RESULT BREAKDOWN</p>
          <h4>Fair view by partition, source, and variety</h4>
        </div>
        <span class="session-result-breakdown-overall">${escapeHtml(summary.overall.percentageLabel)} overall</span>
      </div>
      <p class="session-result-breakdown-context">${escapeHtml(contextText)}${summary.mixedContext.isMixedSession ? " detected. Weak partitions stay tied to their own source or variety." : ""}</p>
      <div class="session-result-partition-grid">
        ${countedPartitions.map((partition) => `
          <article class="session-result-partition-chip">
            <span>${escapeHtml(partition.label)}</span>
            <strong>${escapeHtml(partition.percentageLabel)}</strong>
            <p>${escapeHtml(`${partition.germinatedCount}/${partition.totalCount} germinated`)}</p>
            <p>${escapeHtml(`${partition.failedCount} not germinated${partition.unaccountedCount ? ` / ${partition.unaccountedCount} unaccounted` : ""}`)}</p>
            ${partition.source ? `<p>${escapeHtml(partition.source)}</p>` : ""}
          </article>
        `).join("")}
      </div>
      ${(sourceGroups.length || varietyGroups.length) ? `
        <div class="session-result-group-grid">
          ${sourceGroups.length ? `
            <div class="session-result-group-list">
              <strong>Sources</strong>
              ${sourceGroups.map((group) => `
                <p><span>${escapeHtml(`${group.label} · ${group.partitionLabels.join(", ")}`)}</span><b>${escapeHtml(`${group.percentageLabel} (${group.totalGerminated}/${group.totalSeeds})`)}</b></p>
              `).join("")}
            </div>
          ` : ""}
          ${varietyGroups.length ? `
            <div class="session-result-group-list">
              <strong>Varieties</strong>
              ${varietyGroups.map((group) => `
                <p><span>${escapeHtml(`${group.label} · ${group.partitionLabels.join(", ")}`)}</span><b>${escapeHtml(`${group.percentageLabel} (${group.totalGerminated}/${group.totalSeeds})`)}</b></p>
              `).join("")}
            </div>
          ` : ""}
        </div>
      ` : ""}
    </section>
  `;
}

function sortSessionsNewestFirst(sessions) {
  return [...sessions].sort((left, right) => {
    const leftTime = getSessionSortTime(left);
    const rightTime = getSessionSortTime(right);
    return rightTime - leftTime;
  });
}

function sortActiveSessionsNewestFirst(sessions) {
  return [...sessions].sort((left, right) => {
    const leftTime = getActiveSessionSortTime(left);
    const rightTime = getActiveSessionSortTime(right);
    return rightTime - leftTime;
  });
}

function getActiveSessionSortTime(session) {
  const updatedAt = parseCompletedAtValue(
    session?.lastUpdatedAt
    || session?.last_updated_at
    || session?.updatedAt
    || session?.updated_at,
  );
  if (updatedAt) {
    return updatedAt.getTime();
  }

  const createdAt = parseCompletedAtValue(session?.createdAt || session?.created_at);
  if (createdAt) {
    return createdAt.getTime();
  }

  const startedAt = parseSessionStartDateTime(session?.date, session?.time);
  return startedAt ? startedAt.getTime() : 0;
}

function getSessionSortTime(session) {
  const createdAt = parseCompletedAtValue(session?.createdAt || session?.created_at);
  if (createdAt) {
    return createdAt.getTime();
  }

  const startedAt = parseSessionStartDateTime(session?.date, session?.time);
  return startedAt ? startedAt.getTime() : 0;
}

function renderSessionSequenceBadgeMarkup({
  sequenceNumber,
  createdDateLabel = "",
  ordinalLabel = "",
  href = "",
  preview = false,
  previewLabel = "Assigned when you save this session.",
} = {}) {
  const normalizedSequenceNumber = Math.max(0, Number(sequenceNumber) || 0);
  if (!normalizedSequenceNumber) {
    return "";
  }

  const resolvedOrdinalLabel = ordinalLabel || formatOrdinalSessionNumber(normalizedSequenceNumber);
  const badgeClassName = `session-sequence-badge${preview ? " session-sequence-badge--preview" : ""}`;
  const labelMarkup = `<span class="session-sequence-badge__label">Session #${escapeHtml(String(normalizedSequenceNumber))}</span>`;

  if (preview) {
    return `
      <span class="${badgeClassName}" title="${escapeHtml(`Session #${normalizedSequenceNumber}. ${previewLabel}`)}">
        ${labelMarkup}
        <span class="session-sequence-badge__tooltip" role="tooltip">
          <strong>Position</strong>
          <span>${escapeHtml(`${resolvedOrdinalLabel} session`)}</span>
          <strong>Status</strong>
          <span>${escapeHtml(previewLabel)}</span>
        </span>
      </span>
    `;
  }

  return `
    <a
      class="${badgeClassName}"
      href="${escapeHtml(href)}"
      aria-label="${escapeHtml(`Session #${normalizedSequenceNumber}. Created ${createdDateLabel}. ${resolvedOrdinalLabel} session. Open Session History.`)}"
      title="${escapeHtml(`Created ${createdDateLabel} - ${resolvedOrdinalLabel} session`)}"
    >
      ${labelMarkup}
      <span class="session-sequence-badge__tooltip" role="tooltip">
        <strong>Created</strong>
        <span>${escapeHtml(createdDateLabel)}</span>
        <strong>Position</strong>
        <span>${escapeHtml(`${resolvedOrdinalLabel} session`)}</span>
      </span>
    </a>
  `;
}

function renderNewSessionSequencePreview(target, sessions = getSessions()) {
  if (!target) {
    return;
  }

  const nextSequenceNumber = (Array.isArray(sessions) ? sessions : []).filter((session) => String(session?.id || "").trim()).length + 1;
  target.innerHTML = renderSessionSequenceBadgeMarkup({
    sequenceNumber: nextSequenceNumber,
    preview: true,
  });
  target.hidden = nextSequenceNumber <= 0;
}

function getSessionSequenceNumber(session = null, sessions = getSessions()) {
  const normalizedSessionId = String(session?.id || "").trim();
  if (!normalizedSessionId) {
    return null;
  }

  const orderedSessions = [...(Array.isArray(sessions) ? sessions : [])]
    .filter((entry) => String(entry?.id || "").trim())
    .sort((left, right) => {
      const timeDifference = getSessionSortTime(left) - getSessionSortTime(right);
      if (timeDifference !== 0) {
        return timeDifference;
      }
      return String(left?.id || "").localeCompare(String(right?.id || ""));
    });

  const sequenceIndex = orderedSessions.findIndex((entry) => String(entry?.id || "").trim() === normalizedSessionId);
  return sequenceIndex >= 0 ? sequenceIndex + 1 : null;
}

function formatOrdinalSessionNumber(value) {
  const numberValue = Math.max(0, Number(value) || 0);
  if (!numberValue) {
    return "";
  }

  const mod100 = numberValue % 100;
  if (mod100 >= 11 && mod100 <= 13) {
    return `${numberValue}th`;
  }

  switch (numberValue % 10) {
    case 1:
      return `${numberValue}st`;
    case 2:
      return `${numberValue}nd`;
    case 3:
      return `${numberValue}rd`;
    default:
      return `${numberValue}th`;
  }
}

function getSessionCreatedDateLabel(session = null, fallback = "Not available") {
  const createdAt = parseCompletedAtValue(session?.createdAt || session?.created_at);
  if (createdAt) {
    return formatSessionNameDate(createdAt.toISOString()) || fallback;
  }

  const startedAt = parseSessionStartDateTime(session?.date, session?.time);
  if (startedAt) {
    return formatSessionNameDate(startedAt.toISOString()) || fallback;
  }

  return fallback;
}

function openSessionHistoryForSession(sessionId = "") {
  const normalizedSessionId = String(sessionId || "").trim();
  if (!normalizedSessionId) {
    return;
  }

  const sessions = sortSessionsNewestFirst(getSessions());
  const filteredSessions = filterMySessionsHistorySessions(sessions, "all");
  const sortedSessions = sortSessionHistorySessions(filteredSessions, "date");
  const sessionIndex = sortedSessions.findIndex((session) => String(session?.id || "").trim() === normalizedSessionId);

  appState.sessionHistoryFocusSessionId = normalizedSessionId;
  appState.sessionHistoryFilter = "all";
  appState.sessionHistorySort = "date";
  appState.sessionHistoryExpanded = true;
  appState.sessionHistoryVisibleCount = Math.max(
    6,
    Number(appState.sessionHistoryVisibleCount) || 6,
    sessionIndex >= 0 ? sessionIndex + 1 : 6,
  );
  window.location.hash = "#sessions";
}

function buildPartitionDetailRow(partition, sessionStatus = "") {
  const options = arguments[2] && typeof arguments[2] === "object" ? arguments[2] : {};
  const displayIndex = Number(options.displayIndex) || Number(partition?.id) || 0;
  const showSeedAgeField = Boolean(options.showSeedAgeField);
  const germinationStatus = getPartitionGerminationDisplay(partition);
  const successDisplay = getPartitionSuccessDisplay(partition);
  const seedAgeValue = getEffectivePartitionSeedAgeYears(partition, options.session || null);
  const sourceLabel = formatPartitionSource(partition);
  const varietyLabel = formatPartitionSeedVariety(partition);
  const seedTypeLabel = getSeedTypeLabel(partition?.seedType || "");
  const sexLabel = partition?.feminized ? capitalize(partition.feminized) : "";
  const seedCountLabel = Number(partition?.seedCount) > 0 ? String(partition.seedCount) : "";
  const seedAgeLabel = seedAgeValue !== null ? formatSeedAgeYearsLabel(seedAgeValue) : "";
  const basePartitionState = getPartitionBaseRowState({
    sourceValue: sourceLabel,
    varietyValue: varietyLabel,
    typeValue: normalizeSeedTypeId(partition?.seedType || ""),
    sexValue: partition?.feminized || "",
    seedValue: seedCountLabel,
    seedAgeValue: seedAgeValue ?? "",
    plantedValue: partition?.plantedCount ?? "",
  });
  const partitionState = getPartitionRowStateFromPartition(partition, sessionStatus);
  const row = document.createElement("article");
  row.className = "chart-row partition-row detail-row";
  row.dataset.partitionRow = "true";
  row.dataset.partitionId = String(partition?.id || displayIndex);
  row.dataset.partitionBaseState = basePartitionState;
  row.dataset.partitionSource = sourceLabel;
  row.dataset.partitionSeedVariety = varietyLabel;
  row.dataset.partitionSeedType = normalizeSeedTypeId(partition?.seedType || "");
  row.dataset.partitionFeminized = partition?.feminized || "";
  row.dataset.partitionSeedCount = seedCountLabel;
  row.dataset.partitionSeedAgeYears = seedAgeValue === null ? "" : String(seedAgeValue);
  row.dataset.partitionPlantedCount = String(partition?.plantedCount ?? "");
  row.innerHTML = `
    <div class="partition-number partition-btn ${getPartitionButtonClassName(partitionState)}" aria-label="Partition ${displayIndex}">${displayIndex}</div>
    <div class="detail-cell">
      <span class="mobile-field-label">Source</span>
      <p>${escapeHtml(sourceLabel)}</p>
    </div>
    <div class="detail-cell">
      <span class="mobile-field-label">Seed Variety</span>
      <p>${escapeHtml(varietyLabel)}</p>
    </div>
    <div class="detail-cell">
      <span class="mobile-field-label">Type</span>
      <p>${escapeHtml(seedTypeLabel)}</p>
    </div>
    <div class="detail-cell">
      <span class="mobile-field-label">Sex</span>
      <p>${escapeHtml(sexLabel)}</p>
    </div>
    <div class="detail-cell">
      <span class="mobile-field-label">Seeds</span>
      <p>${escapeHtml(seedCountLabel)}</p>
    </div>
    ${showSeedAgeField ? `
    <div class="detail-cell">
      <span class="mobile-field-label">Age</span>
      <p>${escapeHtml(seedAgeLabel)}</p>
    </div>
    ` : ""}
    <div class="detail-cell">
      <span class="mobile-field-label">Germinated</span>
      <p class="${germinationStatus.className}">${escapeHtml(germinationStatus.label)}</p>
    </div>
    <div class="detail-cell success-cell">
      <span class="mobile-field-label">Success %</span>
      <p class="${successDisplay.className}">${escapeHtml(successDisplay.label)}</p>
    </div>
  `;
  return row;
}

function getPartitionBaseRowState(values) {
  const sourceValue = String(values?.sourceValue || "").trim();
  const varietyValue = String(values?.varietyValue || "").trim();
  const typeValue = String(values?.typeValue || "").trim();
  const sexValue = String(values?.sexValue || "").trim();
  const seedValue = String(values?.seedValue || "").trim();
  const seedAgeValue = String(values?.seedAgeValue || "").trim();
  const plantedValue = String(values?.plantedValue || "").trim();
  const hasSeedCount = seedValue !== "";
  const hasSeedAge = seedAgeValue !== "";
  const hasPlantedCount = plantedValue !== "";

  if (sourceValue || varietyValue || typeValue || sexValue || hasSeedCount || hasSeedAge || hasPlantedCount) {
    return "in-progress";
  }

  return "empty";
}

function getPartitionRowState(values, sessionStatus = "") {
  const baseState = getPartitionBaseRowState(values);

  if (baseState === "empty") {
    return "empty";
  }

  if (normalizeSessionStatus(sessionStatus) === "completed") {
    return "complete";
  }

  return "in-progress";
}

function getPartitionRowStateFromPartition(partition, sessionStatus = "") {
  return getPartitionRowState({
    sourceValue: formatPartitionSource(partition),
    varietyValue: formatPartitionSeedVariety(partition),
    typeValue: normalizeSeedTypeId(partition?.seedType || ""),
    sexValue: partition?.feminized || "",
    seedValue: partition?.seedCount ?? "",
    plantedValue: partition?.plantedCount ?? "",
  }, sessionStatus);
}

function shouldHideInactivePartitionRowsForStatus(sessionStatus = "") {
  const normalizedStatus = String(sessionStatus || "").trim().toLowerCase();
  return normalizedStatus === "completed" || normalizedStatus === "closed";
}

function getPartitionRowFieldValue(row, fieldName = "") {
  if (!(row instanceof Element)) {
    return "";
  }

  const selectorMap = {
    source: 'input[name^="source-"]',
    seedVariety: 'input[name^="seedVariety-"]',
    seedType: 'select[name^="seedType-"]',
    feminized: 'select[name^="feminized-"]',
    seedCount: 'input[name^="seedCount-"]',
    seedAgeYears: 'input[name^="seedAgeYears-"]',
    plantedCount: 'input[name="plantedCount"]',
  };
  const datasetKeyMap = {
    source: "partitionSource",
    seedVariety: "partitionSeedVariety",
    seedType: "partitionSeedType",
    feminized: "partitionFeminized",
    seedCount: "partitionSeedCount",
    seedAgeYears: "partitionSeedAgeYears",
    plantedCount: "partitionPlantedCount",
  };
  const field = row.querySelector(selectorMap[fieldName]);
  if (field instanceof HTMLInputElement || field instanceof HTMLSelectElement || field instanceof HTMLTextAreaElement) {
    return String(field.value || "");
  }

  return String(row.dataset[datasetKeyMap[fieldName]] || "");
}

function getPartitionBaseRowStateFromRow(row) {
  if (!(row instanceof Element)) {
    return "empty";
  }

  return getPartitionBaseRowState({
    sourceValue: getPartitionRowFieldValue(row, "source"),
    varietyValue: getPartitionRowFieldValue(row, "seedVariety"),
    typeValue: normalizeSeedTypeId(getPartitionRowFieldValue(row, "seedType")),
    sexValue: getPartitionRowFieldValue(row, "feminized"),
    seedValue: getPartitionRowFieldValue(row, "seedCount"),
    seedAgeValue: getPartitionRowFieldValue(row, "seedAgeYears"),
    plantedValue: getPartitionRowFieldValue(row, "plantedCount"),
  });
}

function getSessionSeedAgeAutofillValueForRow(row) {
  const form = row?.closest("form");
  return getSessionSeedAgeValueForForm(form);
}

function syncPartitionSeedAgeFieldState(row) {
  if (!(row instanceof Element)) {
    return;
  }

  const seedAgeLabel = row.querySelector("[data-partition-seed-age-field]");
  const seedAgeInput = row.querySelector('input[name^="seedAgeYears-"]');
  if (!(seedAgeLabel instanceof HTMLElement) || !(seedAgeInput instanceof HTMLInputElement)) {
    return;
  }

  const partitionContainer = row.closest("[data-seed-age-mode]") || row.closest("#partition-fields");
  const seedAgeMode = normalizeSeedAgeMode(partitionContainer?.dataset.seedAgeMode || "");
  const form = row.closest("form");
  const partitionId = String(row.dataset.partitionId || "");
  const mixedSeedAgeDrafts = getMixedSeedAgeDrafts(form);
  const mixedDraftValue = normalizeSeedAgeYears(mixedSeedAgeDrafts[partitionId]);
  const sessionSeedAgeYears = getSessionSeedAgeAutofillValueForRow(row);
  const normalizedInputSeedAge = normalizeSeedAgeYears(seedAgeInput.value);
  const isAutoFilled = seedAgeInput.dataset.autoFilledFromSessionAge === "true";
  const hasCoreValues = getPartitionBaseRowStateFromRow(row) !== "empty";
  const trackingEnabled = seedAgeMode === "same" || seedAgeMode === "mixed";

  if (!trackingEnabled) {
    seedAgeLabel.hidden = true;
    seedAgeInput.value = "";
    seedAgeInput.readOnly = false;
    seedAgeInput.removeAttribute("aria-readonly");
    delete seedAgeInput.dataset.autoFilledFromSessionAge;
    delete seedAgeInput.dataset.seedAgeAutofillApplied;
    return;
  }

  if (seedAgeMode === "same") {
    seedAgeInput.readOnly = true;
    seedAgeInput.setAttribute("aria-readonly", "true");
    seedAgeInput.dataset.seedAgeAutofillApplied = "true";
    seedAgeInput.dataset.autoFilledFromSessionAge = "true";
    seedAgeInput.value = hasCoreValues ? formatSeedAgeInputValue(sessionSeedAgeYears) : "";
    if (!hasCoreValues) {
      delete seedAgeInput.dataset.autoFilledFromSessionAge;
      delete seedAgeInput.dataset.seedAgeAutofillApplied;
    }
  } else {
    seedAgeInput.readOnly = false;
    seedAgeInput.removeAttribute("aria-readonly");
    if (!hasCoreValues) {
      if (normalizedInputSeedAge !== null && partitionId) {
        mixedSeedAgeDrafts[partitionId] = normalizedInputSeedAge;
      }
      seedAgeInput.value = "";
      delete seedAgeInput.dataset.autoFilledFromSessionAge;
      delete seedAgeInput.dataset.seedAgeAutofillApplied;
    }

    if (
      isAutoFilled
      && !hasCoreValues
      && normalizedInputSeedAge === sessionSeedAgeYears
    ) {
      seedAgeInput.value = "";
      delete seedAgeInput.dataset.autoFilledFromSessionAge;
      delete seedAgeInput.dataset.seedAgeAutofillApplied;
    }

    if (
      isAutoFilled
      && normalizedInputSeedAge !== null
      && normalizedInputSeedAge !== sessionSeedAgeYears
    ) {
      delete seedAgeInput.dataset.autoFilledFromSessionAge;
    }

    if (
      hasCoreValues
      && !seedAgeInput.value.trim()
      && mixedDraftValue !== null
    ) {
      seedAgeInput.value = formatSeedAgeInputValue(mixedDraftValue);
      delete seedAgeInput.dataset.autoFilledFromSessionAge;
      delete seedAgeInput.dataset.seedAgeAutofillApplied;
    } else if (
      hasCoreValues
      && !seedAgeInput.value.trim()
      && seedAgeInput.dataset.seedAgeAutofillApplied !== "true"
      && sessionSeedAgeYears !== null
    ) {
      seedAgeInput.value = formatSeedAgeInputValue(sessionSeedAgeYears);
      seedAgeInput.dataset.autoFilledFromSessionAge = "true";
      seedAgeInput.dataset.seedAgeAutofillApplied = "true";
    }

    if (partitionId) {
      mixedSeedAgeDrafts[partitionId] = normalizeSeedAgeYears(seedAgeInput.value);
    }
  }

  const shouldShow = shouldShowPartitionSeedAgeFieldForValues({
    sourceValue: row.querySelector('input[name^="source-"]')?.value || "",
    varietyValue: row.querySelector('input[name^="seedVariety-"]')?.value || "",
    typeValue: normalizeSeedTypeId(row.querySelector('select[name^="seedType-"]')?.value || ""),
    sexValue: row.querySelector('select[name^="feminized-"]')?.value || "",
    seedValue: row.querySelector('input[name^="seedCount-"]')?.value || "",
    plantedValue: row.querySelector('input[name="plantedCount"]')?.value || "",
  });

  seedAgeLabel.hidden = !shouldShow;
}

function syncCompletedSessionPartitionVisibility(partitionContainer, sessionStatus = "") {
  if (!(partitionContainer instanceof Element)) {
    return;
  }

  const shouldHideEmptyRows = shouldHideInactivePartitionRowsForStatus(sessionStatus);
  partitionContainer.querySelectorAll(".partition-row").forEach((row) => {
    const baseState = getPartitionBaseRowStateFromRow(row);
    row.dataset.partitionBaseState = baseState;
    const shouldHide = shouldHideEmptyRows && baseState === "empty";
    row.hidden = shouldHide;
    row.setAttribute("aria-hidden", shouldHide ? "true" : "false");
  });
}

function getPartitionButtonClassName(state) {
  if (state === "complete") {
    return "partition-btn--complete";
  }

  if (state === "in-progress") {
    return "partition-btn--in-progress";
  }

  return "";
}

function updatePartitionButtonState(row, state) {
  const button = row.querySelector(".partition-btn");
  if (!button) {
    return;
  }

  const sessionStatus = row.closest(".partition-table")?.dataset.sessionStatus || row.closest("form")?.dataset.currentStage || "";
  const isCompletedSession = normalizeSessionStatus(sessionStatus) === "completed";
  row.dataset.partitionButtonState = state;
  button.classList.toggle("partition-btn--in-progress", state === "in-progress");
  button.classList.toggle("partition-btn--complete", state === "complete");
  if (isCompletedSession) {
    button.style.setProperty("background", "#363022", "important");
    button.style.setProperty("border-color", "#a56a3f", "important");
    button.style.setProperty("color", "#fff", "important");
    button.style.setProperty("box-shadow", "0 0 0 3px rgba(165, 106, 63, 0.18)", "important");
  } else {
    button.style.removeProperty("background");
    button.style.removeProperty("border-color");
    button.style.removeProperty("color");
    button.style.removeProperty("box-shadow");
  }
}

function applyPartitionRowVisualState(row) {
  if (!row) {
    return;
  }

  const isDarkTheme = document.body.classList.contains("theme-dark");
  const labels = row.querySelectorAll("label, .detail-cell");
  const fields = row.querySelectorAll('input:not([name="plantedCount"]), select, .custom-select-trigger');
  const sessionStatus = row.closest(".partition-table")?.dataset.sessionStatus || row.closest("form")?.dataset.currentStage || "";
  const isCompletedSession = normalizeSessionStatus(sessionStatus) === "completed";
  const isGerminatingSession = normalizeSessionStatus(sessionStatus) === "germinating";
  const isCompletedEmpty = row.classList.contains("row-completed-empty");
  const isInactive = row.classList.contains("partition-row--inactive");

  if (!isDarkTheme) {
    row.style.removeProperty("background");
    row.style.removeProperty("background-image");
    row.style.removeProperty("box-shadow");
    row.style.removeProperty("opacity");
    row.style.removeProperty("filter");
    labels.forEach((node) => {
      node.style.removeProperty("background");
      node.style.removeProperty("background-image");
    });
    fields.forEach((node) => {
      node.style.removeProperty("background");
      node.style.removeProperty("background-image");
      node.style.removeProperty("color");
      node.style.removeProperty("-webkit-text-fill-color");
      node.style.removeProperty("border-color");
      node.style.removeProperty("box-shadow");
      node.style.removeProperty("opacity");
    });
    return;
  }

  const isHovered = row.dataset.hovered === "true";
  const isWarning = row.classList.contains("row-has-warning");
  const isCompleted = row.classList.contains("row--completed");
  const isFilled = row.classList.contains("partition-row--filled");

  let background = "";
  let boxShadow = "";

  if (isHovered) {
    background = "rgba(148, 209, 89, 0.035)";
    boxShadow = "inset 0 0 0 1px rgba(148, 209, 89, 0.10)";
  } else if (isWarning) {
    background = "rgba(221, 128, 69, 0.05)";
    boxShadow = "inset 0 0 0 1px rgba(221, 128, 69, 0.12)";
  } else if (isCompleted) {
    background = "#262D27";
    boxShadow = "inset 0 1px 0 rgba(255, 255, 255, 0.02), inset 0 0 0 1px rgba(148, 209, 89, 0.06)";
  } else if (isFilled) {
    background = "#2A312B";
    boxShadow = "inset 0 0 0 1px rgba(148, 209, 89, 0.05)";
  }

  if (background) {
    row.style.setProperty("background", background, "important");
    row.style.setProperty("background-image", "none", "important");
    row.style.setProperty("box-shadow", boxShadow, "important");
  } else {
    row.style.removeProperty("background");
    row.style.removeProperty("background-image");
    row.style.removeProperty("box-shadow");
  }

  if (isCompletedSession && isCompletedEmpty) {
    row.style.setProperty("opacity", "0.55", "important");
    row.style.setProperty("filter", "grayscale(0.35)", "important");
    row.style.setProperty("background", "#18201b", "important");
    row.style.setProperty("background-image", "none", "important");
    row.style.setProperty("box-shadow", "inset 0 0 0 1px rgba(148, 209, 89, 0.12)", "important");
  } else if (isGerminatingSession && isInactive) {
    row.style.setProperty("opacity", "0.45", "important");
    row.style.setProperty("filter", "grayscale(0.28)", "important");
    row.style.setProperty("background", "#18201b", "important");
    row.style.setProperty("background-image", "none", "important");
    row.style.setProperty("box-shadow", "inset 0 0 0 1px rgba(148, 209, 89, 0.08)", "important");
  } else {
    row.style.removeProperty("opacity");
    row.style.removeProperty("filter");
  }

  labels.forEach((node) => {
    node.style.setProperty("background", "transparent", "important");
    node.style.setProperty("background-image", "none", "important");
  });

  fields.forEach((node) => {
    const fieldBackground = isCompletedSession && isCompletedEmpty
      ? "#202622"
      : (isGerminatingSession && isInactive
        ? "#1b201c"
        : (isFilled || isCompleted ? "#232823" : "#1E221F"));
    node.style.setProperty("background", fieldBackground, "important");
    node.style.setProperty("background-image", "none", "important");
    node.style.setProperty("color", "#f6f8f5", "important");
    node.style.setProperty("-webkit-text-fill-color", "#f6f8f5", "important");
    node.style.setProperty(
      "border-color",
      (isCompletedSession && isCompletedEmpty) || (isGerminatingSession && isInactive)
        ? "rgba(148, 209, 89, 0.12)"
        : "#343a35",
      "important",
    );
    node.style.setProperty("box-shadow", "none", "important");
    if ((isCompletedSession && isCompletedEmpty) || (isGerminatingSession && isInactive)) {
      node.style.setProperty("opacity", "0.88", "important");
    } else {
      node.style.removeProperty("opacity");
    }
  });
}

function bindPartitionRowVisualState(partitionContainer) {
  if (!partitionContainer || partitionContainer.dataset.rowVisualBound === "true") {
    return;
  }

  const setHoverState = (target, hovered) => {
    const row = target instanceof Element ? target.closest(".partition-row") : null;
    if (!row || !partitionContainer.contains(row)) {
      return;
    }

    row.dataset.hovered = hovered ? "true" : "false";
    applyPartitionRowVisualState(row);
  };

  partitionContainer.addEventListener("mouseover", (event) => {
    setHoverState(event.target, true);
  });

  partitionContainer.addEventListener("mouseout", (event) => {
    const row = event.target instanceof Element ? event.target.closest(".partition-row") : null;
    if (!row || !partitionContainer.contains(row)) {
      return;
    }

    const relatedRow = event.relatedTarget instanceof Element ? event.relatedTarget.closest(".partition-row") : null;
    if (relatedRow === row) {
      return;
    }

    row.dataset.hovered = "false";
    applyPartitionRowVisualState(row);
  });

  partitionContainer.dataset.rowVisualBound = "true";
}

function syncPartitionButtonStates(partitionContainer, sessionStatus = "") {
  if (!partitionContainer) {
    return;
  }

  const normalizedStatus = normalizeSessionStatus(sessionStatus);

  partitionContainer.querySelectorAll(".partition-row").forEach((row) => {
    const varietyInput = row.querySelector('input[name^="seedVariety-"]');

    if (varietyInput) {
      validatePartitionRow(row);
      return;
    }

    const baseState = row.dataset.partitionBaseState || "empty";
    const nextState = baseState === "empty"
      ? "empty"
      : normalizedStatus === "completed"
        ? "complete"
        : "in-progress";

    row.classList.toggle("row-complete", normalizedStatus === "completed" && baseState !== "empty");
    updatePartitionButtonState(row, nextState);
    applyPartitionRowVisualState(row);
  });
}

function hasPartitionContent(partition = null) {
  const source = formatPartitionSource(partition).trim();
  const variety = formatPartitionSeedVariety(partition).trim();
  const seedType = normalizeSeedTypeId(partition?.seedType || "");
  const sex = String(partition?.feminized || "").trim();
  const seeds = Number(partition?.seedCount) || 0;
  const plantedRaw = String(partition?.plantedCount ?? "").trim();
  const hasSeedCount = seeds > 0;
  const hasGerminationData = plantedRaw !== "";
  const hasSeedAge = getEffectivePartitionSeedAgeYears(partition) !== null;

  return Boolean(source || variety || seedType || sex || hasSeedCount || hasGerminationData || hasSeedAge);
}

function isPartitionEmpty(partition = null) {
  return !hasPartitionContent(partition);
}

function getCompletedSessionDisplayPartitions(partitions = [], session = null) {
  return normalizeSessionPartitions(partitions)
    .filter((partition) => hasPartitionContent({
      ...partition,
      seedAgeYears: getEffectivePartitionSeedAgeYears(partition, session),
    }))
    .map((partition, index) => ({
      ...partition,
      displayIndex: index + 1,
    }));
}

function getPartitionGerminationDisplay(partition) {
  if (isPartitionEmpty(partition)) {
    return { label: "", className: "is-muted" };
  }

  const plantedRaw = String(partition?.plantedCount ?? "").trim();
  if (plantedRaw === "") {
    return { label: "", className: "" };
  }

  return { label: plantedRaw, className: "" };
}

function getPartitionSuccessDisplay(partition) {
  if (isPartitionEmpty(partition)) {
    return { label: "", className: "is-muted" };
  }

  return {
    label: formatSuccessPercent(partition.seedCount, partition.plantedCount),
    className: "",
  };
}

function attachPartitionValidation(form, formMessage) {
  const rows = form.querySelectorAll(".partition-row");
  rows.forEach((row) => {
    row.querySelectorAll("input, select").forEach((field) => {
      const eventName = field.tagName === "SELECT" ? "change" : "input";
      field.addEventListener(eventName, () => {
        captureFirstPlantedEventForForm(form);
        syncSessionStatusControlDatasets(form.elements.sessionStatus, {
          germinationStartedAt: form.dataset.germinationStartedAt || "",
          firstPlantedAt: form.dataset.firstPlantedAt || "",
          completedAt: form.dataset.completedAt || "",
        });
        updateSessionStatusAppearance(
          form.elements.sessionStatus,
          form.querySelector("#session-status-trigger"),
        );
        validatePartitionRow(row);
        updateSessionSuccessSummary(form, form.querySelector("#session-success-summary"));
        updatePartitionProgressChart(
          getPartitionProgressDataFromForm(form),
          form.querySelector("#partition-progress-chart"),
          form.querySelector("#partition-progress-section"),
        );
        updateRunProgressSummary(
          form.querySelector("#run-progress-summary"),
          form.querySelector("#run-progress-section"),
          form.elements.sessionStatus?.value,
          getPartitionProgressDataFromForm(form),
        );
        updateSessionLifecycleTimeline(
          form.querySelector("#session-lifecycle-progress"),
          form.querySelector("#session-lifecycle-section"),
          buildFormLifecycleState(form),
        );
        if (formMessage.textContent) {
          const validation = validatePartitions(form, { showMessage: false });
          if (validation.isValid) {
            formMessage.textContent = "";
          }
        }
      });
      field.addEventListener("blur", () => {
        captureFirstPlantedEventForForm(form);
        syncSessionStatusControlDatasets(form.elements.sessionStatus, {
          germinationStartedAt: form.dataset.germinationStartedAt || "",
          firstPlantedAt: form.dataset.firstPlantedAt || "",
          completedAt: form.dataset.completedAt || "",
        });
        updateSessionStatusAppearance(
          form.elements.sessionStatus,
          form.querySelector("#session-status-trigger"),
        );
        validatePartitionRow(row);
        updateSessionSuccessSummary(form, form.querySelector("#session-success-summary"));
        updatePartitionProgressChart(
          getPartitionProgressDataFromForm(form),
          form.querySelector("#partition-progress-chart"),
          form.querySelector("#partition-progress-section"),
        );
        updateRunProgressSummary(
          form.querySelector("#run-progress-summary"),
          form.querySelector("#run-progress-section"),
          form.elements.sessionStatus?.value,
          getPartitionProgressDataFromForm(form),
        );
        updateSessionLifecycleTimeline(
          form.querySelector("#session-lifecycle-progress"),
          form.querySelector("#session-lifecycle-section"),
          buildFormLifecycleState(form),
        );
      });
    });

    validatePartitionRow(row);
  });

  updateSessionSuccessSummary(form, form.querySelector("#session-success-summary"));
  updatePartitionProgressChart(
    getPartitionProgressDataFromForm(form),
    form.querySelector("#partition-progress-chart"),
    form.querySelector("#partition-progress-section"),
  );
  updateRunProgressSummary(
    form.querySelector("#run-progress-summary"),
    form.querySelector("#run-progress-section"),
    form.elements.sessionStatus?.value,
    getPartitionProgressDataFromForm(form),
  );
  updateSessionLifecycleTimeline(
    form.querySelector("#session-lifecycle-progress"),
    form.querySelector("#session-lifecycle-section"),
    buildFormLifecycleState(form),
  );
}

async function renderSystemLayoutReference(container, systemType) {
  if (!container) {
    return;
  }

  container.dataset.pendingSystem = systemType;

  if (SYSTEM_LAYOUT_ASSETS[systemType]) {
    const markup = await buildSystemLayoutImage(systemType);
    if (container.dataset.pendingSystem === systemType) {
      container.innerHTML = markup || buildSystemLayoutUnavailableMarkup(systemType);
      attachSystemLayoutReady(container);
    }
    return;
  }

  if (container.dataset.pendingSystem === systemType) {
    container.innerHTML = buildSystemLayoutUnavailableMarkup(systemType);
  }
}

async function buildSystemLayoutImage(systemType) {
  const svgMarkup = await getInlineSvgMarkup(systemType);
  if (!svgMarkup) {
    return "";
  }

  return `
    <div class="system-layout-image system-layout-image-${systemType.toLowerCase()}" data-system-layout="${systemType}">
      ${svgMarkup}
    </div>
  `;
}

function getPartitionCountForSystem(systemType) {
  if (systemType === "TRA") {
    return 16;
  }

  return 8;
}

function createPartitionsForSystem(systemType) {
  return Array.from({ length: getPartitionCountForSystem(systemType) }, (_, index) => ({
    id: index + 1,
    seedVariety: "",
    source: "",
    breeder: "",
    seedType: "",
    feminized: "",
    seedCount: 0,
    plantedCount: "",
    seedAgeYears: null,
  }));
}

function applySessionStatusLayout(chartShell, chartHeader, partitionContainer, sessionStatus) {
  if (!chartShell || !chartHeader || !partitionContainer) {
    return;
  }

  const normalizedStatus = normalizeSessionStatus(sessionStatus);
  chartShell.dataset.sessionStatus = normalizedStatus;
  chartHeader.dataset.sessionStatus = normalizedStatus;
  partitionContainer.dataset.sessionStatus = normalizedStatus;
  applyPlantedColumnDebugStyles(chartHeader, partitionContainer, normalizedStatus);
}

function applyPlantedColumnDebugStyles(chartHeader, partitionContainer, sessionStatus) {
  const isVisible = sessionStatus === "germinating" || sessionStatus === "completed";
  const isDarkTheme = document.body.classList.contains("theme-dark");
  const headerCell = chartHeader.querySelector('[data-partition-header="germinated"]');
  const plantedCells = [...partitionContainer.querySelectorAll('.partition-row label:has(input[name="plantedCount"])')];
  const plantedInputs = [...partitionContainer.querySelectorAll('input[name="plantedCount"]')];

  if (headerCell) {
    headerCell.style.removeProperty("background");
    headerCell.style.removeProperty("color");
  }

  plantedCells.forEach((cell) => {
    if (isVisible) {
      cell.style.setProperty("background", isDarkTheme ? "rgba(148, 209, 89, 0.08)" : "rgba(148, 209, 89, 0.12)", "important");
      cell.style.borderRadius = "10px";
      cell.style.padding = "6px";
    } else {
      cell.style.removeProperty("background");
      cell.style.removeProperty("border-radius");
      cell.style.removeProperty("padding");
    }
  });

  plantedInputs.forEach((input) => {
    if (isVisible) {
      input.style.setProperty("border", "1px solid #94d159", "important");
      input.style.setProperty("background", isDarkTheme ? "#18201c" : "rgba(247, 252, 244, 0.96)", "important");
      input.style.setProperty("box-shadow", isDarkTheme ? "0 0 0 2px rgba(148, 209, 89, 0.14)" : "0 0 0 2px rgba(148, 209, 89, 0.18)", "important");
      if (isDarkTheme) {
        input.style.setProperty("color", "#f3f7f1", "important");
        input.style.setProperty("-webkit-text-fill-color", "#f3f7f1", "important");
        input.style.setProperty("caret-color", "#94d159", "important");
      } else {
        input.style.removeProperty("color");
        input.style.removeProperty("-webkit-text-fill-color");
        input.style.removeProperty("caret-color");
      }
    } else {
      input.style.removeProperty("border");
      input.style.removeProperty("background");
      input.style.removeProperty("box-shadow");
      input.style.removeProperty("color");
      input.style.removeProperty("-webkit-text-fill-color");
      input.style.removeProperty("caret-color");
    }
  });

  window.__plantedColumnDebug = {
    sessionStatus,
    headerSelector: '#partition-chart-header [data-partition-header="germinated"] or #detail-chart-header [data-partition-header="germinated"]',
    cellSelector: '.partition-row label:has(input[name="plantedCount"])',
    inputSelector: 'input[name="plantedCount"]',
    headerFound: Boolean(headerCell),
    cellCount: plantedCells.length,
    inputCount: plantedInputs.length,
  };
}

function normalizeSessionStatus(sessionStatus) {
  const normalizedStatus = String(sessionStatus || "").trim().toLowerCase();
  return normalizedStatus || "unselected";
}

function resolveGrowSessionCurrentProgressKey(source = {}) {
  const normalizedStatus = normalizeSessionStatus(source.sessionStatus || source.status || source.value || "");
  const completedAt = parseCompletedAtValue(source.completedAt || source.completed_at || "");
  const firstPlantedAt = parseCompletedAtValue(source.firstPlantedAt || source.first_planted_at || "");
  const germinationStartedAt = parseCompletedAtValue(source.germinationStartedAt || source.germination_started_at || "");

  if (normalizedStatus === "completed" || completedAt) {
    return "completed";
  }
  if (firstPlantedAt) {
    return "first-germinated";
  }
  if (normalizedStatus === "germinating" || germinationStartedAt) {
    return "germination";
  }
  if (normalizedStatus === "soaking") {
    return "soaking";
  }
  return "";
}

function getSessionStatusProgressKey(control) {
  if (!control) {
    return "";
  }

  return resolveGrowSessionCurrentProgressKey({
    sessionStatus: control.value || "",
    germinationStartedAt: control.dataset.germinationStartedAt || "",
    firstPlantedAt: control.dataset.firstPlantedAt || "",
    completedAt: control.dataset.completedAt || "",
  });
}

function getSessionProgressKeyFromSession(session = {}) {
  return resolveGrowSessionCurrentProgressKey({
    sessionStatus: session?.sessionStatus || session?.session_status || "",
    germinationStartedAt: session?.germinationStartedAt || session?.germination_started_at || "",
    firstPlantedAt: session?.firstPlantedAt || session?.first_planted_at || "",
    completedAt: session?.completedAt || session?.completed_at || "",
  });
}

function shouldShowDetailSeedAgeEditor({
  isCreateMode = false,
  sessionStatus = "",
  seedAgeEditingUnlocked = false,
} = {}) {
  const normalizedStatus = normalizeSessionStatus(sessionStatus);
  return Boolean(isCreateMode || (seedAgeEditingUnlocked && normalizedStatus === "soaking"));
}

function updateSessionStatusAppearance(control, trigger) {
  if (!control && !trigger) {
    return;
  }

  const value = control?.value || "";
  const normalizedStatus = normalizeSessionStatus(value);
  const progressKey = getSessionStatusProgressKey(control);
  const visualState = getSessionStatusVisualState(control);
  const stageOrder = ["soaking", "germination", "first-germinated", "completed"];
  const currentStageIndex = stageOrder.indexOf(progressKey);
  const nextStageIndex = progressKey ? Math.min(currentStageIndex + 1, stageOrder.length - 1) : 0;
  const panel = control?.closest(".session-status-panel") || trigger?.closest(".session-status-panel");
  const currentValueElement = panel?.querySelector(".session-status-current-value");
  const helperTextElement = panel?.querySelector(".session-status-help");
  const metaValueElement = panel?.querySelector(".session-status-meta-value");
  const pillIconElement = panel?.querySelector("[data-session-status-pill-icon]");
  const triggerLabelElement = trigger?.querySelector("[data-session-status-trigger-label]") || panel?.querySelector("[data-session-status-trigger-label]");

  if (control) {
    control.dataset.sessionStatus = normalizedStatus;
  }

  panel?.setAttribute("data-session-status", normalizedStatus);
  panel?.setAttribute("data-session-progress", visualState.progressKey || "unselected");
  panel?.setAttribute("data-session-tone", visualState.tone || "unselected");

  if (currentValueElement) {
    currentValueElement.textContent = visualState.label || getSessionProgressDisplayLabel(progressKey, value);
  }
  if (helperTextElement) {
    helperTextElement.textContent = visualState.helperText || "Update the stage as your seeds progress through the session.";
  }
  if (metaValueElement) {
    metaValueElement.textContent = visualState.timestampLabel || "Not recorded yet";
  }
  if (pillIconElement) {
    pillIconElement.innerHTML = renderSessionStatusStageIconMarkup(visualState.iconKey, "pill");
  }

  panel?.querySelectorAll("[data-stage-step]").forEach((stepElement) => {
    const stepKey = stepElement.dataset.stageStep;
    const stepIndex = stageOrder.indexOf(stepKey);
    const isCurrent = Boolean(progressKey) && stepKey === progressKey;
    const isComplete = currentStageIndex > -1 && stepIndex < currentStageIndex;
    const isNext = !isCurrent && !isComplete && stepIndex === nextStageIndex;

    stepElement.classList.toggle("is-current", isCurrent);
    stepElement.classList.toggle("is-complete", isComplete);
    stepElement.classList.toggle("is-next", isNext);
  });

  if (trigger) {
    trigger.dataset.sessionStatus = normalizedStatus;
    if (triggerLabelElement) {
      triggerLabelElement.textContent = getSessionStageButtonLabel(value);
    } else {
      trigger.textContent = getSessionStageButtonLabel(value);
    }
  }

  syncDetailSessionActionBar(control);
}

function getSessionStatusAlertTone(level = "") {
  const normalizedLevel = String(level || "").trim().toLowerCase();
  if (["critical", "warning", "success"].includes(normalizedLevel)) {
    return normalizedLevel;
  }
  return "info";
}

function getSessionStatusAlertTitle(sessionStatus = "", level = "") {
  const normalizedStatus = normalizeSessionStatus(sessionStatus);
  const isCritical = String(level || "").trim().toLowerCase() === "critical";

  if (normalizedStatus === "soaking") {
    return isCritical ? "Soaking action needed" : "Soaking reminder";
  }

  if (normalizedStatus === "germinating") {
    return isCritical ? "Germination action needed" : "Germination reminder";
  }

  return isCritical ? "Session action needed" : "Session update";
}

function getSessionStatusAlertActionText(sessionStatus = "", level = "") {
  const normalizedStatus = normalizeSessionStatus(sessionStatus);
  const isCritical = String(level || "").trim().toLowerCase() === "critical";

  if (normalizedStatus === "soaking") {
    return isCritical
      ? "Next step: move this session into Germinating when the seeds are ready."
      : "Next step: inspect the seeds and refresh the stage if progress changes.";
  }

  if (normalizedStatus === "germinating") {
    return isCritical
      ? "Next step: plant ready seeds and complete the session when appropriate."
      : "Next step: inspect the tray, lid, heat pad, and seed progress.";
  }

  return "";
}

function areGrowReminderNotificationsEnabled() {
  const notificationPreferences = appState.notificationPreferences || getDefaultNotificationPreferences();
  return notificationPreferences.growRemindersEnabled !== false;
}

function areSpecificGrowReminderNotificationsEnabled(preferenceKey = "") {
  const notificationPreferences = appState.notificationPreferences || getDefaultNotificationPreferences();
  if (notificationPreferences.growRemindersEnabled === false) {
    return false;
  }
  return notificationPreferences?.[preferenceKey] !== false;
}

function areSoakingReminderNotificationsEnabled() {
  return areSpecificGrowReminderNotificationsEnabled("notifySoakingReminders");
}

function areGerminationReminderNotificationsEnabled() {
  return areSpecificGrowReminderNotificationsEnabled("notifyGerminationReminders");
}

function areSnapshotReminderNotificationsEnabled() {
  return areSpecificGrowReminderNotificationsEnabled("notifySnapshotReminders");
}

function areSupplyReminderNotificationsEnabled() {
  return areSpecificGrowReminderNotificationsEnabled("notifySupplyReminders");
}

function areCommunityActivityNotificationsEnabled() {
  const notificationPreferences = appState.notificationPreferences || getDefaultNotificationPreferences();
  return notificationPreferences.notifyCommunityActivity !== false;
}

function renderSessionStatusAlertIcon(level = "") {
  const normalizedLevel = String(level || "").trim().toLowerCase();
  if (normalizedLevel === "critical") {
    return `
      <svg viewBox="0 0 24 24" focusable="false" aria-hidden="true">
        <path d="M12 4.5 20 18.5H4L12 4.5Z"></path>
        <path d="M12 9v4.5"></path>
        <path d="M12 16.5h.01"></path>
      </svg>
    `;
  }

  return `
    <svg viewBox="0 0 24 24" focusable="false" aria-hidden="true">
      <circle cx="12" cy="12" r="8"></circle>
      <path d="M12 10.2v4.2"></path>
      <path d="M12 7.8h.01"></path>
    </svg>
  `;
}

function renderSessionStatusAlertsMarkup(alerts = []) {
  const normalizedAlerts = Array.isArray(alerts)
    ? alerts.filter((alert) => alert && (alert.message || alert.title))
    : [];

  if (!normalizedAlerts.length) {
    return "";
  }

  return normalizedAlerts.map((alert) => {
    const tone = getSessionStatusAlertTone(alert.level);
    return `
      <article class="session-detail-alert session-detail-alert--${escapeHtml(tone)}" role="status">
        <span class="session-detail-alert-icon" aria-hidden="true">${renderSessionStatusAlertIcon(alert.level)}</span>
        <div class="session-detail-alert-copy">
          <strong>${escapeHtml(alert.title || "")}</strong>
          <p>${escapeHtml(alert.message || "")}</p>
          ${alert.actionText ? `<span class="session-detail-alert-action">${escapeHtml(alert.actionText)}</span>` : ""}
        </div>
      </article>
    `;
  }).join("");
}

function getSessionLifecycleRecoveryAlert(session = null) {
  const lifecycleHealth = getGrowSessionLifecycleHealth(session);
  if (!["needs_attention", "stale", "abandoned"].includes(lifecycleHealth.classification)) {
    return null;
  }

  const actionText = lifecycleHealth.classification === "needs_attention"
    ? "Resume session or mark completed when results are ready."
    : "Resume session · Archive session · Mark completed";
  return {
    level: "warning",
    title: lifecycleHealth.label || "Needs attention",
    message: lifecycleHealth.detail || "Review this session before it appears in active workflows.",
    actionText,
  };
}

function updateSessionStatusReminder(element, sessionDate, sessionTime, sessionStatus, germinationStartedAt = "", timerStartAt = "", options = {}) {
  if (!element) {
    return;
  }

  const lifecycleAlert = getSessionLifecycleRecoveryAlert(options.session || null);
  const normalizedStatus = normalizeSessionStatus(sessionStatus);
  if (normalizedStatus === "unselected" || !["soaking", "germinating"].includes(normalizedStatus)) {
    element.innerHTML = lifecycleAlert ? renderSessionStatusAlertsMarkup([lifecycleAlert]) : "";
    element.hidden = !lifecycleAlert;
    return;
  }

  const reminder = getActiveStageReminder(sessionDate, sessionTime, normalizedStatus, germinationStartedAt, timerStartAt, options);
  if (!reminder) {
    element.innerHTML = lifecycleAlert ? renderSessionStatusAlertsMarkup([lifecycleAlert]) : "";
    element.hidden = !lifecycleAlert;
    return;
  }

  element.innerHTML = renderSessionStatusAlertsMarkup([
    ...(lifecycleAlert ? [lifecycleAlert] : []),
    {
    level: reminder.level,
    title: reminder.title || getSessionStatusAlertTitle(normalizedStatus, reminder.level),
    message: reminder.message,
    actionText: reminder.actionText || getSessionStatusAlertActionText(normalizedStatus, reminder.level),
    },
  ]);
  element.hidden = false;
}

  function validateSessionStatus(control, errorElement) {
    const isValid = Boolean(control?.value);
    if (isValid) {
      clearSessionStatusError(control, errorElement);
      return true;
    }

    const trigger = document.querySelector("#session-status-trigger, #detail-session-status-trigger");
    trigger?.classList.add("is-invalid");
    if (errorElement) {
      errorElement.textContent = "Please select a growth stage before saving.";
    }
    return false;
  }

  function clearSessionStatusError(control, errorElement) {
    control?.classList.remove("is-invalid");
    document.querySelector("#session-status-trigger, #detail-session-status-trigger")?.classList.remove("is-invalid");
    if (errorElement) {
      errorElement.textContent = "";
    }
  }

function getActiveStageReminder(sessionDate, sessionTime, sessionStatus, germinationStartedAt = "", timerStartAt = "", options = {}) {
  const schedule = STAGE_REMINDER_SCHEDULES[sessionStatus];
  if (!schedule?.length) {
    return null;
  }

  const stageStart = getStageStartDateTime(sessionDate, sessionTime, sessionStatus, germinationStartedAt, timerStartAt, options);
  if (!stageStart) {
    return null;
  }

  const elapsedHours = Math.max(0, (Date.now() - stageStart.getTime()) / (60 * 60 * 1000));
  return [...schedule]
    .filter((reminder) => {
      const minimumHours = Math.max(0, Number(reminder?.hours) || 0);
      const maximumHours = Number(reminder?.maxHours);
      if (elapsedHours < minimumHours) {
        return false;
      }
      if (Number.isFinite(maximumHours) && elapsedHours > maximumHours) {
        return false;
      }
      return true;
    })
    .sort((left, right) => (Number(right?.hours) || 0) - (Number(left?.hours) || 0))[0] || null;
}

function getStageStartDateTime(sessionDate, sessionTime, sessionStatus, germinationStartedAt = "", timerStartAt = "", options = {}) {
  const normalizedStatus = normalizeSessionStatus(sessionStatus);
  if (normalizedStatus === "germinating") {
    return parseCompletedAtValue(germinationStartedAt);
  }

  return parseCompletedAtValue(options.soakStartedAt || "")
    || parseCompletedAtValue(timerStartAt)
    || parseCompletedAtValue(options.sessionStartedAt || "")
    || parseSessionStartDateTime(sessionDate, sessionTime);
}

function getSessionStageReminderOptions(session = null) {
  return {
    session,
    sessionStartedAt: session?.sessionStartedAt || session?.session_started_at || "",
    soakStartedAt: session?.soakStartedAt || session?.soak_started_at || "",
  };
}

function parseSessionStartDateTime(sessionDate, sessionTime) {
  if (!sessionDate) {
    return null;
  }

  const safeTime = sessionTime || "00:00";
  const parsedDate = new Date(`${sessionDate}T${safeTime}:00`);
  if (Number.isNaN(parsedDate.getTime())) {
    return null;
  }

  return parsedDate;
}

function getTimerStartAtFromCreatedAt(createdAt = "") {
  const createdDate = parseCompletedAtValue(createdAt) || new Date();
  return new Date(createdDate.getTime() + SESSION_SETUP_GRACE_MS).toISOString();
}

function getInitialSoakStartedAt(sessionStartedAt = "", createdAt = "", sessionStatus = "") {
  const sessionStartedDate = parseCompletedAtValue(sessionStartedAt);
  const graceDate = parseCompletedAtValue(getTimerStartAtFromCreatedAt(createdAt));
  const normalizedStatus = normalizeSessionStatus(sessionStatus);
  if (!sessionStartedDate) {
    return graceDate?.toISOString() || new Date().toISOString();
  }
  if (["germinating", "completed"].includes(normalizedStatus)) {
    return sessionStartedDate.toISOString();
  }
  if (!graceDate || graceDate < sessionStartedDate) {
    return sessionStartedDate.toISOString();
  }
  return graceDate.toISOString();
}

function getEffectiveSessionTimerStartAt(session = null) {
  return getSessionDurationStartAt(session);
}

function getSessionDurationStartAt(session = null) {
  if (!session) {
    return null;
  }

  return parseCompletedAtValue(session.soakStartedAt || session.soak_started_at || "")
    || parseCompletedAtValue(session.sessionStartedAt || session.session_started_at || "")
    || parseSessionStartDateTime(session.date, session.time)
    || parseCompletedAtValue(session.timerStartAt || session.timer_start_at || "")
    || parseCompletedAtValue(session.createdAt || session.created_at || "");
}

function getSessionCompletedAtDate(session = null) {
  return parseCompletedAtValue(session?.completedAt || session?.completed_at || "");
}

function getSessionStageDurationStartAt(session = null) {
  if (!session) {
    return null;
  }

  const normalizedStatus = normalizeSessionStatus(session.sessionStatus || session.session_status || "");
  if (normalizedStatus === "completed") {
    return getSessionCompletedAtDate(session);
  }
  const firstPlantedAt = parseCompletedAtValue(session.firstPlantedAt || session.first_planted_at || "");
  if (firstPlantedAt) {
    return firstPlantedAt;
  }
  const germinationStartedAt = parseCompletedAtValue(session.germinationStartedAt || session.germination_started_at || "");
  if (normalizedStatus === "germinating" || germinationStartedAt) {
    return germinationStartedAt;
  }
  if (normalizedStatus === "soaking") {
    return getSessionDurationStartAt(session);
  }
  return null;
}

function getSessionTimingState(session = null, options = {}) {
  const now = options.now instanceof Date && !Number.isNaN(options.now.getTime())
    ? options.now
    : new Date();
  const totalStartedAt = getSessionDurationStartAt(session);
  const completedAt = getSessionCompletedAtDate(session);
  const currentStageStartedAt = getSessionStageDurationStartAt(session);
  const totalEndedAt = completedAt || now;
  const currentStageEndedAt = completedAt || now;

  return {
    totalStartedAt,
    completedAt,
    currentStageStartedAt,
    totalEndedAt,
    currentStageEndedAt,
    setupGraceActive: !completedAt && isSetupGracePeriodActive(totalStartedAt, now),
  };
}

function getSessionStatusStartedAtValue(session = null) {
  return getEffectiveSessionTimerStartAt(session)?.toISOString()
    || String(session?.createdAt || session?.created_at || "").trim();
}

function isSetupGracePeriodActive(timerStartAt, now = new Date()) {
  return timerStartAt instanceof Date
    && !Number.isNaN(timerStartAt.getTime())
    && now instanceof Date
    && !Number.isNaN(now.getTime())
    && now.getTime() < timerStartAt.getTime();
}

function formatSetupGraceStartsIn(timerStartAt, now = new Date()) {
  if (!isSetupGracePeriodActive(timerStartAt, now)) {
    return "";
  }

  const minutes = Math.max(1, Math.ceil((timerStartAt.getTime() - now.getTime()) / 60000));
  return `Starts in ${minutes} min`;
}

function formatPartitionSeedVariety(partition) {
  return String(partition?.seedVariety || "").trim();
}

function formatPartitionSource(partition) {
  const source = String(partition?.source || "").trim();
  if (source) {
    return source;
  }

  return String(partition?.breeder || "").trim();
}

function normalizeUnitIdValue(value, fallback = "A") {
  const normalized = String(value || "").trim();
  return normalized || fallback;
}

function getFirstNamedPartition(partitions = []) {
  return (Array.isArray(partitions) ? partitions : [])
    .find((partition) => formatPartitionSeedVariety(partition).trim());
}

function buildGeneratedSessionNameBase({
  partitions = [],
  firstPartition = null,
  systemType = "",
  unitId = "",
} = {}) {
  const partitionList = Array.isArray(partitions) && partitions.length
    ? partitions
    : (firstPartition ? [firstPartition] : []);
  const namedPartition = getFirstNamedPartition(partitionList);
  const varietyName = formatPartitionSeedVariety(namedPartition || {}).trim();
  if (!varietyName) {
    return "Untitled Grow Session";
  }

  const normalizedSystemType = String(systemType || "").trim().toUpperCase();
  const normalizedUnitId = String(unitId || "").trim();
  const systemLabel = [normalizedSystemType, normalizedUnitId].filter(Boolean).join(" ");
  const varietySessionName = `${varietyName} Session`;
  return systemLabel ? `${systemLabel} - ${varietySessionName}` : varietySessionName;
}

function getNewSessionNameSuggestionFromForm(form) {
  if (!(form instanceof HTMLFormElement)) {
    return "Untitled Grow Session";
  }

  const partitions = [...form.querySelectorAll(".partition-row")].map((row, index) => ({
    id: row.dataset.partitionId || index + 1,
    source: row.querySelector('input[name^="source-"]')?.value.trim() || "",
    seedVariety: row.querySelector('input[name^="seedVariety-"]')?.value.trim() || "",
  }));
  return buildGeneratedSessionNameBase({
    partitions,
    systemType: form.elements.systemType?.value || "",
    unitId: form.elements.unitId?.value || "",
  });
}

function updateNewSessionNameDefaultSuggestion(form) {
  const sessionNameField = getNewSessionNameField(form);
  if (!sessionNameField || String(sessionNameField.value || "").trim()) {
    return;
  }

  sessionNameField.placeholder = getNewSessionNameSuggestionFromForm(form);
}

function primeUnitIdDefault(form) {
  const unitIdField = form?.elements?.unitId;
  if (!(unitIdField instanceof HTMLInputElement || unitIdField instanceof HTMLSelectElement)) {
    return;
  }

  if (!String(unitIdField.value || "").trim()) {
    unitIdField.value = "A";
  }
}

function buildFinalSessionName(inputName, firstPartition, sessionDate, options = {}) {
  const manualName = String(inputName || "").trim();
  const baseName = manualName || buildGeneratedSessionNameBase({
    firstPartition,
    partitions: options.partitions,
    systemType: options.systemType,
    unitId: options.unitId,
  });
  return `${baseName} - ${formatSessionNameDate(sessionDate)}`;
}

function formatSessionNameDate(sessionDate) {
  if (!sessionDate) {
    return "Unknown date";
  }

  const parsedDate = new Date(`${sessionDate}T00:00:00`);
  if (Number.isNaN(parsedDate.getTime())) {
    return sessionDate;
  }

  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  }).format(parsedDate);
}

function buildSystemLayoutPlaceholder(systemType) {
  const label = systemType === "TRA" ? "TRA layout reference coming next" : "Choose a system type";
  return `
    <div class="layout-reference-copy">
      <p>${label}</p>
    </div>
    <div class="layout-placeholder" aria-label="${label}">
      <span>${systemType || "System"}</span>
    </div>
  `;
}

function buildSystemLayoutUnavailableMarkup(systemType) {
  return `
    <div class="layout-reference-copy">
      <p>Layout image unavailable</p>
    </div>
    <div class="layout-placeholder" aria-label="${systemType || "System"} layout image unavailable">
      <span>${systemType || "System"}</span>
    </div>
  `;
}

async function getInlineSvgMarkup(systemType) {
  if (inlineSvgCache[systemType]) {
    return inlineSvgCache[systemType];
  }

  try {
    const response = await fetch(SYSTEM_LAYOUT_ASSETS[systemType]);
    if (!response.ok) {
      return "";
    }

    const svgMarkup = normalizeInlineSvgMarkup(await response.text());
    if (!/^<svg[\s>]/i.test(svgMarkup)) {
      return "";
    }

    inlineSvgCache[systemType] = svgMarkup;
    return svgMarkup;
  } catch {
    return "";
  }
}

function normalizeInlineSvgMarkup(svgMarkup) {
  return svgMarkup
    .replace(/<\?xml[\s\S]*?\?>\s*/i, "")
    .replace(/<!DOCTYPE[\s\S]*?>\s*/i, "")
    .trim();
}

function bindPartitionRowHighlighting(form) {
  if (form.dataset.partitionHighlightBound === "true") {
    return;
  }

  form.addEventListener("focusin", (event) => {
    const row = event.target.closest(".partition-row");
    if (row) {
      setActiveSystemLayoutPartition(form, row.dataset.partitionId);
    }
  });

  form.addEventListener("click", (event) => {
    const row = event.target.closest(".partition-row");
    if (row) {
      if (!event.target.closest("input, select, option")) {
        row.focus({ preventScroll: true });
      }
      setActiveSystemLayoutPartition(form, row.dataset.partitionId);
    }
  });

  form.addEventListener("focusout", () => {
    window.setTimeout(() => {
      const activeRow = document.activeElement?.closest(".partition-row");
      if (activeRow && form.contains(activeRow)) {
        setActiveSystemLayoutPartition(form, activeRow.dataset.partitionId);
        return;
      }

      clearActiveSystemLayout(form);
    }, 0);
  });

  form.dataset.partitionHighlightBound = "true";
}

function setActiveSystemLayoutPartition(scope, partitionId) {
  const nodes = getSystemLayoutNodes(scope);
  if (!nodes.length || !partitionId) {
    return;
  }

  const activeSection = getTraSectionForPartition(partitionId);
  nodes.forEach((node) => {
    const isActive = node.dataset.partition === String(partitionId);
    const isSectionActive = !isActive && node.dataset.section && node.dataset.section === activeSection;
    applySystemLayoutNodeState(node, { isActive, isSectionActive });
  });

  updatePartitionDebugState(scope, {
    activePartition: String(partitionId),
    activeSection,
    nodeCount: nodes.length,
  });
}

function clearActiveSystemLayout(scope) {
  getSystemLayoutNodes(scope).forEach((node) => {
    applySystemLayoutNodeState(node, { isActive: false, isSectionActive: false });
  });
  updatePartitionDebugState(scope, {
    activePartition: "",
    activeSection: "",
    nodeCount: getSystemLayoutNodes(scope).length,
  });
}

function getSystemLayoutNodes(scope) {
  const layout = scope.querySelector("[data-system-layout]");
  if (!layout) {
    return [];
  }

  const inlineNodes = [...layout.querySelectorAll(".partition-node")];
  if (inlineNodes.length) {
    return inlineNodes;
  }

  const objectElement = layout.querySelector(".system-layout-object");
  if (!objectElement?.contentDocument) {
    return [];
  }

  return [...objectElement.contentDocument.querySelectorAll(".partition-node")];
}

function attachSystemLayoutReady(container) {
  const objectElement = container.querySelector(".system-layout-object");
  if (!objectElement) {
    updatePartitionDebugState(container, {
      renderMode: "inline",
      nodeCount: getSystemLayoutNodes(container).length,
    });
    return;
  }

  objectElement.addEventListener("load", () => {
    const form = container.closest("form");
    const activeRow = form?.querySelector(".partition-row:focus-within");
    updatePartitionDebugState(container, {
      renderMode: "object",
      nodeCount: getSystemLayoutNodes(container).length,
    });
    if (activeRow) {
      setActiveSystemLayoutPartition(form, activeRow.dataset.partitionId);
    }
  }, { once: true });
}

function applySystemLayoutNodeState(node, state) {
  node.classList.toggle("is-active", state.isActive);
  node.classList.toggle("section-active", state.isSectionActive);

  if (state.isActive) {
    Object.entries(ACTIVE_PARTITION_STYLE).forEach(([property, value]) => {
      node.style[property] = value;
    });
    return;
  }

  if (state.isSectionActive) {
    node.style.removeProperty("fill");
    node.style.stroke = ACTIVE_SECTION_STYLE.stroke;
    node.style.strokeWidth = ACTIVE_SECTION_STYLE.strokeWidth;
    node.style.removeProperty("filter");
    return;
  }

  node.style.removeProperty("fill");
  node.style.removeProperty("stroke");
  node.style.removeProperty("stroke-width");
  node.style.removeProperty("filter");
}

function updatePartitionDebugState(scope, values) {
  window.__partitionLayoutDebug = {
    ...(window.__partitionLayoutDebug || {}),
    ...values,
  };

  const layout = scope.querySelector?.("[data-system-layout]") || scope.closest?.("[data-system-layout]");
  if (!layout) {
    return;
  }

  if ("activePartition" in values) {
    layout.dataset.activePartition = values.activePartition;
  }
  if ("activeSection" in values) {
    layout.dataset.activeSection = values.activeSection;
  }
  if ("nodeCount" in values) {
    layout.dataset.nodeCount = String(values.nodeCount);
  }
  if ("renderMode" in values) {
    layout.dataset.renderMode = values.renderMode;
  }
}

function getTraSectionForPartition(partitionId) {
  const number = Number(partitionId);
  if (number >= 1 && number <= 4) {
    return "A";
  }
  if (number >= 5 && number <= 8) {
    return "B";
  }
  if (number >= 9 && number <= 12) {
    return "C";
  }
  if (number >= 13 && number <= 16) {
    return "D";
  }
  return "";
}

function validatePartitions(form, options = { showMessage: false }) {
  const rows = [...form.querySelectorAll(".partition-row")];
  let firstInvalidField = null;

  rows.forEach((row) => {
    const result = validatePartitionRow(row);
    if (!result.isValid && !firstInvalidField) {
      firstInvalidField = result.firstInvalidField;
    }
  });

  return {
    isValid: !firstInvalidField,
    firstInvalidField,
  };
}

function validatePartitionRow(row) {
  const sourceInput = row.querySelector('input[name^="source-"]');
  const varietyInput = row.querySelector('input[name^="seedVariety-"]');
  const typeSelect = row.querySelector('select[name^="seedType-"]');
  const sexSelect = row.querySelector('select[name^="feminized-"]');
  const seedInput = row.querySelector('input[name^="seedCount-"]');
  const seedAgeInput = row.querySelector('input[name^="seedAgeYears-"]');
  const plantedInput = row.querySelector('input[name="plantedCount"]');
  syncPartitionSeedAgeFieldState(row);
  const varietyLabel = varietyInput.closest("label");
  const typeLabel = typeSelect.closest("label");
  const sexLabel = sexSelect.closest("label");
  const seedLabel = seedInput.closest("label");
  const seedAgeLabel = seedAgeInput?.closest("label") || null;
  const plantedLabel = plantedInput.closest("label");

  const sourceValue = sourceInput.value.trim();
  const varietyValue = varietyInput.value.trim();
  const typeValue = typeSelect.value;
  const sexValue = sexSelect.value;
  const seedValue = seedInput.value.trim();
  const seedAgeValue = seedAgeInput?.value.trim() || "";
  const plantedValue = plantedInput.value.trim();
  const successOutput = row.querySelector("[data-success-output]");
  const hasSeedCount = seedValue !== "";
  const hasSeedAge = seedAgeValue !== "";
  const hasPlantedCount = plantedValue !== "";
  const seedNumber = Number(seedValue);
  const plantedNumber = Number(plantedValue);
  const seedCountValid = hasSeedCount && seedNumber > 0;
  const seedAgeValid = !seedAgeInput || isValidSeedAgeYearsInput(seedAgeValue, { allowBlank: true });
  const plantedCountValid = !hasPlantedCount || (Number.isFinite(plantedNumber) && plantedNumber >= 0 && seedCountValid && plantedNumber <= seedNumber);

  const rowStarted = Boolean(sourceValue || varietyValue || typeValue || sexValue || hasSeedCount || hasSeedAge || hasPlantedCount);
  const fieldsComplete = Boolean(varietyValue && typeValue && sexValue && seedCountValid && plantedCountValid);
  const rowInvalid = (rowStarted && !fieldsComplete) || !seedAgeValid || !plantedCountValid;
  const sessionStatus = row.closest(".partition-table")?.dataset.sessionStatus || row.closest("form")?.dataset.currentStage || "";
  const normalizedSessionStatus = normalizeSessionStatus(sessionStatus);
  const rowState = getPartitionRowState({
    sourceValue,
    varietyValue,
    typeValue,
    sexValue,
    seedValue,
    seedAgeValue,
    plantedValue,
  }, sessionStatus);

  row.classList.toggle("partition-row--filled", rowStarted);
  row.classList.toggle("partition-row--inactive", normalizedSessionStatus === "germinating" && !rowStarted);
  row.classList.toggle("row--completed", fieldsComplete);
  row.classList.toggle("row-has-warning", rowInvalid);
  row.classList.toggle("row-complete", normalizedSessionStatus === "completed" && rowStarted);
  row.classList.toggle("row-completed-empty", normalizedSessionStatus === "completed" && !rowStarted);
  updatePartitionButtonState(row, rowState);
  applyPartitionRowVisualState(row);

  varietyLabel.classList.toggle("field-has-warning", rowInvalid && !varietyValue);
  typeLabel.classList.toggle("field-has-warning", rowInvalid && !typeValue);
  sexLabel.classList.toggle("field-has-warning", rowInvalid && !sexValue);
  seedLabel.classList.toggle("field-has-warning", rowInvalid && !seedCountValid);
  seedAgeLabel?.classList.toggle("field-has-warning", !seedAgeValid);
  plantedLabel.classList.toggle("field-has-warning", !plantedCountValid);

  typeSelect.classList.toggle("is-missing", rowInvalid && !typeValue);
  sexSelect.classList.toggle("is-missing", rowInvalid && !sexValue);
  varietyInput.classList.toggle("is-missing", rowInvalid && !varietyValue);
  seedInput.classList.toggle("is-missing", rowInvalid && !seedCountValid);
  seedAgeInput?.classList.toggle("is-missing", !seedAgeValid);
  plantedInput.classList.toggle("is-missing", !plantedCountValid);
  syncCustomSelect(typeSelect);
  syncCustomSelect(sexSelect);
  if (successOutput) {
    successOutput.textContent = formatSuccessPercent(
      hasSeedCount ? seedNumber : "",
      hasPlantedCount ? plantedNumber : "",
    );
  }

  let firstInvalidField = null;
  if (rowInvalid) {
    firstInvalidField = varietyValue ? null : varietyInput;
    if (!firstInvalidField && !typeValue) {
      firstInvalidField = getCustomSelectTrigger(typeSelect) || typeSelect;
    }
    if (!firstInvalidField && !sexValue) {
      firstInvalidField = getCustomSelectTrigger(sexSelect) || sexSelect;
    }
    if (!firstInvalidField && !seedCountValid) {
      firstInvalidField = seedInput;
    }
    if (!firstInvalidField && !seedAgeValid) {
      firstInvalidField = seedAgeInput;
    }
    if (!firstInvalidField && !plantedCountValid) {
      firstInvalidField = plantedInput;
    }
  }

  return {
    isValid: !rowInvalid,
    firstInvalidField,
  };
}

function formatSuccessPercent(seedCount, plantedCount) {
  const seeds = Number(seedCount);
  const planted = Number(plantedCount);

  if (!Number.isFinite(seeds) || !Number.isFinite(planted) || seeds <= 0) {
    return "";
  }

  if (planted < 0 || planted > seeds) {
    return "";
  }

  return `${Math.round((planted / seeds) * 100)}%`;
}

function updateSessionSuccessSummary(form, summaryElement) {
  if (!form || !summaryElement) {
    return;
  }

  const summary = getSessionResultSummary({
    partitions: buildPartitionDraftValuesFromContainer(form.querySelector("#partition-fields") || form),
  });
  const totals = summary.overall;

  if (totals.totalSeeds <= 0) {
    summaryElement.textContent = "";
    summaryElement.hidden = true;
    return;
  }

  summaryElement.textContent = `Session Success: ${totals.percentage || 0}% (${totals.totalGerminated} / ${totals.totalSeeds})`;
  summaryElement.hidden = false;
}

function getPartitionProgressDataFromForm(form) {
  return [...form.querySelectorAll(".partition-row")].map((row, index) => ({
    id: Number(row.dataset.partitionId) || index + 1,
    seedCount: Number(row.querySelector('input[name^="seedCount-"]')?.value) || 0,
    plantedCount: Number(row.querySelector('input[name="plantedCount"]')?.value) || 0,
  }));
}

function updatePartitionProgressChart(partitions, chartElement, sectionElement) {
  if (!chartElement || !sectionElement) {
    return;
  }

  const items = getSessionResultSummary({ partitions }).partitions.filter((partition) => partition.hasSeeds || partition.hasResultValue);

  if (!items.length) {
    chartElement.innerHTML = "";
    sectionElement.hidden = true;
    return;
  }

  sectionElement.hidden = false;
  chartElement.innerHTML = items.map((partition) => {
    const seeds = partition.totalCount;
    const planted = partition.germinatedCount;
    const plantedPercentage = partition.percentage === null ? 0 : Math.max(0, Math.min(100, partition.percentage));
    const plantedPercentageLabel = partition.percentageLabel;

    return `
      <div class="progress-chart-row">
        <div class="progress-chart-label">${escapeHtml(partition.label)} <span class="progress-chart-percent">(${escapeHtml(plantedPercentageLabel)})</span></div>
        <div class="progress-bar-track" aria-label="${escapeHtml(partition.displayLabel)} germination progress">
          <div class="progress-bar-total" style="width: 100%"></div>
          <div class="progress-bar-fill" style="width: ${plantedPercentage}%"></div>
        </div>
      <div class="progress-chart-values">${planted} / ${seeds}</div>
      </div>
    `;
  }).join("");
}

function updateSessionTimingSummary(summaryElement, sectionElement, sessionDate, sessionTime, sessionStatus, completedAt = "", timerStartAt = "", options = {}) {
  if (!summaryElement || !sectionElement) {
    return;
  }

  const timingState = options.session ? getSessionTimingState(options.session) : null;
  const startedAt = timingState?.totalStartedAt
    || parseCompletedAtValue(options.sessionDurationStartAt || "")
    || parseCompletedAtValue(timerStartAt)
    || parseSessionStartDateTime(sessionDate, sessionTime);
  if (!startedAt) {
    summaryElement.innerHTML = "";
    sectionElement.hidden = true;
    return;
  }

  const now = new Date();
  const normalizedStatus = normalizeSessionStatus(sessionStatus);
  const completedDate = normalizedStatus === "completed"
    ? timingState?.completedAt || parseCompletedAtValue(completedAt) || new Date()
    : null;
  const durationTarget = completedDate || now;
  const setupGraceActive = timingState
    ? timingState.setupGraceActive
    : !completedDate && isSetupGracePeriodActive(startedAt, now);
  const elapsedLabel = setupGraceActive
    ? formatSetupGraceStartsIn(startedAt, now)
    : formatDurationBetween(startedAt, durationTarget);

  summaryElement.innerHTML = `
    <article class="timing-card timing-card-started${setupGraceActive ? " timing-card-setup" : ""}">
      <strong>${setupGraceActive ? "Timer Starts" : "Started"}</strong>
      <p>${formatTimingDateTime(startedAt)}</p>
    </article>
    ${completedDate ? `
      <article class="timing-card">
        <strong>Completed On</strong>
        <p>${formatTimingDateTime(completedDate)}</p>
      </article>
      <article class="timing-card">
        <strong>Total Duration</strong>
        <p>${formatDurationBetween(startedAt, completedDate)}</p>
      </article>
    ` : `
      <article class="timing-card timing-card-elapsed${setupGraceActive ? " timing-card-setup" : ""}">
        <strong>${setupGraceActive ? "Setup Grace Period" : "Session Duration"}</strong>
        <p>${elapsedLabel || "0m"}</p>
      </article>
    `}
  `;
  sectionElement.hidden = false;
}

function updateRunProgressSummary(summaryElement, sectionElement, sessionStatus, partitions) {
  if (!summaryElement || !sectionElement) {
    return;
  }

  const resultSummary = getSessionResultSummary({ partitions });
  const totals = resultSummary.overall;

  if (totals.totalSeeds <= 0) {
    summaryElement.innerHTML = "";
    sectionElement.hidden = true;
    return;
  }

  const progressPercent = Math.max(0, Math.min(100, totals.percentage || 0));
  const progressGradient = getRunProgressGradient(progressPercent);
  sectionElement.hidden = false;
  summaryElement.innerHTML = `
    <div class="run-progress-meta">
      <strong>${totals.totalPlanted} / ${totals.totalSeeds} germinated</strong>
      <span>${progressPercent}%</span>
    </div>
    <div class="run-progress-track" aria-label="Run progress">
      <div class="run-progress-fill" style="width: ${progressPercent}%; background: ${progressGradient};"></div>
    </div>
  `;
}

function getRunProgressGradient(progressPercent) {
  return "linear-gradient(90deg, #c2410c 0%, #f59e0b 35%, #84cc16 65%, #166534 100%)";
}

function updateSessionLifecycleTimeline(summaryElement, sectionElement, state) {
  if (!summaryElement || !sectionElement) {
    return;
  }

  if (!state.startedAt && !state.showEmptyTimeline) {
    summaryElement.innerHTML = "";
    sectionElement.hidden = true;
    return;
  }

  summaryElement.innerHTML = renderSessionLifecycleTimelineMarkup(state);
  sectionElement.hidden = false;
}

function getSessionLifecycleTimelineEvents(state = {}) {
  const setupGraceActive = Boolean(state.setupGraceActive);
  const events = [
    {
      key: "soaking",
      label: "Soaking",
      timestamp: state.startedAt,
      displayLabel: setupGraceActive
        ? formatSetupGraceStartsIn(state.startedAt)
        : (state.startedDisplayLabel || ""),
      tone: "soaking",
      complete: state.startedComplete !== undefined ? state.startedComplete : Boolean(state.startedAt),
      setupGraceActive,
    },
    {
      key: "germination",
      label: "Germinating",
      timestamp: state.germinationStartedAt,
      displayLabel: state.germinationStartedDisplayLabel || "",
      tone: "germination",
      complete: state.germinationStartedComplete !== undefined ? state.germinationStartedComplete : Boolean(state.germinationStartedAt),
    },
    {
      key: "first-germinated",
      label: "Germination Started",
      timestamp: state.firstPlantedAt,
      displayLabel: state.firstPlantedDisplayLabel || "",
      tone: "green",
      complete: state.firstPlantedComplete !== undefined ? state.firstPlantedComplete : Boolean(state.firstPlantedAt),
    },
    {
      key: "completed",
      label: "Completed",
      timestamp: state.completedAt,
      displayLabel: state.completedDisplayLabel || "",
      tone: "completed",
      complete: state.completedComplete !== undefined ? state.completedComplete : Boolean(state.completedAt),
    },
  ];

  const currentProgressKey = String(state.currentProgressKey || "").trim();
  const resolvedProgressKey = currentProgressKey
    || resolveGrowSessionCurrentProgressKey({
      sessionStatus: state.sessionStatus || "",
      germinationStartedAt: state.germinationStartedAt ? state.germinationStartedAt.toISOString?.() || state.germinationStartedAt : "",
      firstPlantedAt: state.firstPlantedAt ? state.firstPlantedAt.toISOString?.() || state.firstPlantedAt : "",
      completedAt: state.completedAt ? state.completedAt.toISOString?.() || state.completedAt : "",
    });
  const progressKeyIndex = events.findIndex((event) => event.key === resolvedProgressKey);
  const currentIndex = progressKeyIndex >= 0
    ? progressKeyIndex
    : events.reduce((activeIndex, event, index) => (event.complete ? index : activeIndex), -1);
  const resolvedCurrentIndex = currentIndex >= 0 ? currentIndex : (state.showEmptyTimeline ? -1 : 0);
  const iconNameByKey = {
    soaking: "stage-soaking",
    germination: "stage-germination",
    "first-germinated": "stage-first-germinated",
    completed: "stage-completed",
  };

  return events.map((event, index) => ({
    ...event,
    statusText: getSessionLifecycleTimelineStatusText({
      ...event,
      isCurrent: resolvedCurrentIndex === index,
      isFuture: resolvedCurrentIndex < index,
      isComplete: index < resolvedCurrentIndex || (event.complete && resolvedCurrentIndex >= index),
    }),
    timestampText: event.displayLabel || (event.timestamp ? formatTimingDateTime(event.timestamp) : "Not recorded yet"),
    iconName: iconNameByKey[event.key] || "stage-soaking",
    isCurrent: resolvedCurrentIndex === index,
    isFuture: resolvedCurrentIndex < index,
    isComplete: index < resolvedCurrentIndex || (event.complete && resolvedCurrentIndex >= index),
  }));
}

function getSessionLifecycleTimelineResolvedProgressKey(state = {}) {
  const currentProgressKey = String(state.currentProgressKey || "").trim();
  return currentProgressKey
    || resolveGrowSessionCurrentProgressKey({
      sessionStatus: state.sessionStatus || "",
      germinationStartedAt: state.germinationStartedAt ? state.germinationStartedAt.toISOString?.() || state.germinationStartedAt : "",
      firstPlantedAt: state.firstPlantedAt ? state.firstPlantedAt.toISOString?.() || state.firstPlantedAt : "",
      completedAt: state.completedAt ? state.completedAt.toISOString?.() || state.completedAt : "",
    });
}

function getSessionLifecycleTimelineCurrentStageStartAt(state = {}) {
  const resolvedProgressKey = getSessionLifecycleTimelineResolvedProgressKey(state);
  switch (resolvedProgressKey) {
    case "completed":
      return state.completedAt || null;
    case "first-germinated":
      return state.firstPlantedAt || null;
    case "germination":
      return state.germinationStartedAt || null;
    case "soaking":
      return state.startedAt || null;
    default:
      return null;
  }
}

function getSessionLifecycleTimelineStageStarts(state = {}) {
  const resolvedProgressKey = getSessionLifecycleTimelineResolvedProgressKey(state);
  const stageOrder = ["soaking", "germination", "first-germinated", "completed"];
  const currentIndex = stageOrder.indexOf(resolvedProgressKey);
  const currentStageStartAt = getSessionLifecycleTimelineCurrentStageStartAt(state);
  const maybeCurrentStartAt = (stageKey) => {
    const stageIndex = stageOrder.indexOf(stageKey);
    return stageIndex >= 0 && stageIndex === currentIndex ? currentStageStartAt : null;
  };

  return {
    soaking: state.startedAt || null,
    germination: state.germinationStartedAt || maybeCurrentStartAt("germination"),
    "first-germinated": state.firstPlantedAt || maybeCurrentStartAt("first-germinated"),
    completed: state.completedAt || maybeCurrentStartAt("completed"),
  };
}

function getSessionLifecycleTimelineStageBounds(state = {}, eventKey = "") {
  const stageStarts = getSessionLifecycleTimelineStageStarts(state);
  switch (eventKey) {
    case "soaking":
      return {
        startAt: stageStarts.soaking || null,
        finishAt: stageStarts.germination || null,
      };
    case "germination":
      return {
        startAt: stageStarts.germination || null,
        finishAt: stageStarts["first-germinated"] || null,
      };
    case "first-germinated":
      return {
        startAt: stageStarts["first-germinated"] || null,
        finishAt: stageStarts.completed || null,
      };
    case "completed":
      return {
        startAt: stageStarts.soaking || null,
        finishAt: stageStarts.completed || null,
      };
    default:
      return {
        startAt: null,
        finishAt: null,
      };
  }
}

function getSessionLifecycleTimelineCardMeta(state = {}, event = {}) {
  const { startAt, finishAt } = getSessionLifecycleTimelineStageBounds(state, event.key);
  const hasValidStart = startAt instanceof Date && !Number.isNaN(startAt.getTime());
  const hasValidFinish = finishAt instanceof Date && !Number.isNaN(finishAt.getTime());

  let lengthText = "Pending";

  if (event.isFuture) {
    lengthText = "Pending";
  } else if (event.setupGraceActive && hasValidStart) {
    lengthText = formatSetupGraceStartsIn(startAt) || "0m";
  } else if (event.isCurrent && hasValidStart) {
    const durationLabel = formatDurationBetween(startAt, new Date());
    lengthText = durationLabel || "In progress";
  } else if (event.isComplete && hasValidStart && hasValidFinish) {
    const durationLabel = formatDurationBetween(startAt, finishAt);
    lengthText = durationLabel || "Pending";
  } else if (event.isComplete && hasValidStart) {
    const durationLabel = formatDurationBetween(startAt, new Date());
    lengthText = durationLabel || "In progress";
  }

  return {
    lengthText,
  };
}

function getSessionLifecycleTimelineStatusText(event) {
  if (event.isCurrent) {
    switch (event.key) {
      case "soaking":
        return event.setupGraceActive ? "Timer starts soon" : "Currently soaking";
      case "germination":
        return "Germination underway";
      case "first-germinated":
        return "First sprout recorded";
      case "completed":
        return event.complete ? "Session completed" : "Ready to complete";
      default:
        return "In progress";
    }
  }

  if (event.isComplete) {
    switch (event.key) {
      case "soaking":
        return "Soaking completed";
      case "germination":
        return "Germination underway";
      case "first-germinated":
        return "First sprout recorded";
      case "completed":
        return "Session completed";
      default:
        return "Completed";
    }
  }

  switch (event.key) {
    case "soaking":
      return "Waiting to begin";
    case "germination":
      return "Awaiting germination";
    case "first-germinated":
      return "Awaiting first sprout";
    case "completed":
      return "Awaiting completion";
    default:
      return "Up next";
  }
}

function getSessionLifecycleTimelineStatusLines(statusText = "") {
  const normalizedStatusText = String(statusText || "").trim();
  const statusLineMap = {
    "Timer starts soon": ["Timer starts", "soon"],
    "Currently soaking": ["Currently", "soaking"],
    "Germination underway": ["Germination", "underway"],
    "First sprout recorded": ["First sprout", "recorded"],
    "Session completed": ["Session", "completed"],
    "Ready to complete": ["Ready to", "complete"],
    "Soaking completed": ["Soaking", "completed"],
    "Waiting to begin": ["Waiting", "to begin"],
    "Awaiting germination": ["Awaiting", "germination"],
    "Awaiting first sprout": ["Awaiting", "first sprout"],
    "Awaiting completion": ["Awaiting", "completion"],
    "In progress": ["In", "progress"],
    Completed: ["Completed", ""],
    "Up next": ["Up", "next"],
  };

  if (statusLineMap[normalizedStatusText]) {
    return statusLineMap[normalizedStatusText];
  }

  const words = normalizedStatusText.split(/\s+/).filter(Boolean);
  if (words.length <= 1) {
    return [normalizedStatusText, ""];
  }

  const splitIndex = Math.ceil(words.length / 2);
  return [
    words.slice(0, splitIndex).join(" "),
    words.slice(splitIndex).join(" "),
  ];
}

function renderSessionLifecycleTimelineStatusMarkup(statusText = "") {
  const lines = getSessionLifecycleTimelineStatusLines(statusText);
  return lines.map((line, index) => (
    `<span class="session-command-stage-helper-line session-command-stage-helper-line--${index + 1}">${line ? escapeHtml(line) : "&nbsp;"}</span>`
  )).join("");
}

function renderSessionLifecycleTimelineMarkup(state) {
  const events = getSessionLifecycleTimelineEvents(state);

  return `
    <div class="session-command-stage-grid session-lifecycle-progress-grid stage-progress-row" role="list" aria-label="Session timeline progress">
      ${events.map((event, index) => {
        const nextEvent = events[index + 1] || null;
        const connectorIsActive = Boolean(
          nextEvent
          && (event.isComplete || nextEvent.isComplete || nextEvent.isCurrent)
        );
        const iconStageKey = event.key === "germination-started" ? "first-germinated" : event.key;
        const cardMeta = getSessionLifecycleTimelineCardMeta(state, event);

        return `
        <article
          class="session-command-stage stage-item session-lifecycle-stage session-command-stage--${escapeHtml(event.tone)} ${event.isComplete ? "is-complete" : ""} ${event.isCurrent ? "is-current" : ""} ${event.isFuture ? "is-future" : ""}"
          role="listitem"
        >
          ${renderCommandCenterIconMarkup(`stage-${iconStageKey}`, `command-icon--stage command-icon--stage-${iconStageKey}`)}
          <strong>${escapeHtml(event.label)}</strong>
          <p class="session-command-stage-helper">${renderSessionLifecycleTimelineStatusMarkup(event.statusText)}</p>
          <div class="session-lifecycle-stage-card" aria-label="${escapeHtml(`${event.label} timing details`)}">
            <dl class="session-lifecycle-stage-card-grid">
              <dt>Stage Duration</dt>
              <dd>${escapeHtml(cardMeta.lengthText)}</dd>
            </dl>
          </div>
        </article>
        ${nextEvent ? `<div class="stage-connector session-lifecycle-stage-connector${connectorIsActive ? " stage-connector--active" : ""}" aria-hidden="true"></div>` : ""}
      `;
      }).join("")}
    </div>
  `;
}

function getSpotlightLifecycleEvents(session = null) {
  const currentProgressKey = session ? getSessionProgressKeyFromSession(session) : "";

  const stageConfig = [
    { key: "soaking", label: "Soaking", tone: "soaking", currentLabel: "Soaking" },
    { key: "germination", label: "Germinating", tone: "germination", currentLabel: "Germinating" },
    { key: "first-germinated", label: "Germination Started", tone: "green", currentLabel: "Germination Started" },
    { key: "completed", label: "Completed", tone: "completed", currentLabel: "Completed" },
  ];

  const currentIndex = stageConfig.findIndex((event) => event.key === currentProgressKey);

  return stageConfig.map((event, index) => {
    const isCurrent = currentIndex === index;
    const isComplete = currentIndex > index;
    const statusText = isComplete
      ? `${event.label} completed`
      : (isCurrent ? event.currentLabel : "");

    return {
      ...event,
      isCurrent,
      isComplete,
      isActive: isCurrent || isComplete,
      statusText,
    };
  });
}

function renderSpotlightLifecycleMarkup(session = null) {
  const events = getSpotlightLifecycleEvents(session);

  return `
    <div class="spotlight-lifecycle-grid">
      ${events.map((event) => `
        <article class="spotlight-lifecycle-stage spotlight-lifecycle-stage-${event.tone} ${event.isComplete ? "is-complete" : ""} ${event.isCurrent ? "is-current" : ""}">
          <span class="spotlight-lifecycle-line lifecycle-${event.tone} ${event.isActive ? "is-active" : ""}"></span>
          <strong>${escapeHtml(event.label)}</strong>
          <p>${event.statusText ? escapeHtml(event.statusText) : "&nbsp;"}</p>
        </article>
      `).join("")}
    </div>
  `;
}

function getSessionCommandCenterPrimaryStrain(session = null) {
  const directVariety = String(session?.seedVarietyName || "").trim();
  if (directVariety) {
    return directVariety;
  }

  const firstPartitionWithVariety = (session?.partitions || []).find((partition) => String(partition?.seedVariety || "").trim());
  return String(firstPartitionWithVariety?.seedVariety || "").trim();
}

function getSessionCommandCenterStageBadge(session = null) {
  const lifecycleHealth = getGrowSessionLifecycleHealth(session);
  if (lifecycleHealth.classification === "needs_attention") {
    return { label: "Needs attention", className: "is-needs-attention" };
  }
  if (lifecycleHealth.classification === "stale") {
    return { label: "Session inactive", className: "is-stale" };
  }
  if (lifecycleHealth.classification === "abandoned") {
    return { label: "Session inactive", className: "is-abandoned" };
  }
  const stageState = session ? buildSessionLifecycleState(session) : null;
  const normalizedStage = normalizeSessionStatus(session?.sessionStatus || "");

  if (normalizedStage === "completed") {
    return { label: "Completed", className: "is-completed" };
  }
  if (stageState?.firstPlantedAt) {
    return { label: getCanonicalSessionStageDisplayLabel("first-germinated"), className: "is-first-germinated" };
  }
  if (normalizedStage === "germinating" || stageState?.germinationStartedAt) {
    return { label: getCanonicalSessionStageDisplayLabel("germinating"), className: "is-germinating" };
  }
  if (normalizedStage === "soaking") {
    return { label: getCanonicalSessionStageDisplayLabel("soaking"), className: "is-soaking" };
  }
  return { label: "Not Started", className: "is-inactive" };
}

function getSessionCommandCenterProgressEvents(session = null) {
  const displayLabelByKey = {
    soaking: getCanonicalSessionStageDisplayLabel("soaking"),
    germination: getCanonicalSessionStageDisplayLabel("germination"),
    "first-germinated": getCanonicalSessionStageDisplayLabel("first-germinated"),
    completed: getCanonicalSessionStageDisplayLabel("completed"),
  };
  const iconByKey = {
    soaking: "clock",
    germination: "activeSessionWaveform",
    "first-germinated": "mySessionsSprout",
    completed: "check",
  };

  return getSpotlightLifecycleEvents(session).map((event) => {
    const displayLabel = displayLabelByKey[event.key] || event.label;
    let subtext = "Up next";

    if (!session) {
      subtext = "Awaiting session";
    } else if (event.isComplete) {
      subtext = `${displayLabel} completed`;
    } else if (event.isCurrent) {
      switch (event.key) {
        case "soaking":
          subtext = "Currently soaking";
          break;
        case "germination":
          subtext = "Germination active";
          break;
        case "first-germinated":
          subtext = "First sprout recorded";
          break;
        case "completed":
          subtext = "Ready to complete";
          break;
        default:
          subtext = "In progress";
      }
    } else {
      switch (event.key) {
        case "soaking":
          subtext = "Waiting to begin";
          break;
        case "germination":
          subtext = "Awaiting germination";
          break;
        case "first-germinated":
          subtext = "Awaiting first sprout";
          break;
        case "completed":
          subtext = "Session Completed";
          break;
        default:
          subtext = "Up next";
      }
    }

    return {
      ...event,
      displayLabel,
      iconName: iconByKey[event.key] || "info",
      subtext,
    };
  });
}

function renderCommandCenterIconMarkup(iconName, className = "") {
  const classes = [
    "command-icon",
    iconName === "header" ? "" : "command-icon-tile",
    className,
  ].filter(Boolean).join(" ");
  const svgClass = "command-icon-svg";
  const stageIconAssetPath = TIMELINE_STAGE_ICON_ASSETS[iconName];

  if (stageIconAssetPath) {
    return `
      <span class="${classes}" aria-hidden="true">
        <img class="command-icon-image command-icon-image--stage" src="${escapeHtml(stageIconAssetPath)}" alt="" loading="lazy" decoding="async" draggable="false">
      </span>
    `;
  }

  switch (iconName) {
    case "header":
      return `
        <span class="${classes}" aria-hidden="true">
          <svg class="${svgClass}" viewBox="0 0 24 24" focusable="false" aria-hidden="true">
            <circle cx="12" cy="12" r="7.25"></circle>
            <path d="M12 2.75v3.1M12 18.15v3.1M2.75 12h3.1M18.15 12h3.1" stroke-linecap="round"></path>
            <circle cx="12" cy="12" r="1.85" fill="currentColor" stroke="none"></circle>
          </svg>
        </span>
      `;
    case "session-thumb":
      return `
        <span class="${classes}" aria-hidden="true">
          <svg class="${svgClass}" viewBox="0 0 24 24" focusable="false" aria-hidden="true">
            <path d="M12 19.5v-6" stroke-linecap="round"></path>
            <path d="M12 13.7c0-3.1 2.4-5.2 5.8-5.2 0 3.2-2.3 5.2-5.8 5.2Z" stroke-linejoin="round"></path>
            <path d="M12 15.6c0-2.7-2.1-4.5-5.2-4.5 0 2.8 2 4.5 5.2 4.5Z" stroke-linejoin="round"></path>
            <path d="M8.8 19.5h6.4" stroke-linecap="round"></path>
          </svg>
        </span>
      `;
    case "metric-active":
      return `
        <span class="${classes}" aria-hidden="true">
          <svg class="${svgClass}" viewBox="0 0 24 24" focusable="false" aria-hidden="true">
            <path d="M2.5 12h4l2.2-4.5 3.1 9 2.8-6h6.9" stroke-linecap="round" stroke-linejoin="round"></path>
          </svg>
        </span>
      `;
    case "metric-saved":
      return `
        <span class="${classes}" aria-hidden="true">
          <svg class="${svgClass}" viewBox="0 0 24 24" focusable="false" aria-hidden="true">
            <path d="M7 4.5h10a1.5 1.5 0 0 1 1.5 1.5v13.5L12 15.7 5.5 19.5V6A1.5 1.5 0 0 1 7 4.5Z" stroke-linejoin="round"></path>
          </svg>
        </span>
      `;
    case "metric-leading":
      return `
        <span class="${classes}" aria-hidden="true">
          <svg class="${svgClass}" viewBox="0 0 24 24" focusable="false" aria-hidden="true">
            <path d="m5 17 1.5-9 5.5 4 5.5-4L19 17H5Z" stroke-linejoin="round"></path>
            <path d="M8 17v2h8v-2" stroke-linecap="round"></path>
          </svg>
        </span>
      `;
    case "metric-rate":
      return `
        <span class="${classes}" aria-hidden="true">
          <svg class="${svgClass}" viewBox="0 0 24 24" focusable="false" aria-hidden="true">
            <path d="m6.5 12 3.1 3.1 7.9-8.1" stroke-linecap="round" stroke-linejoin="round"></path>
            <path d="M5 5.5h14" stroke-linecap="round" opacity="0.45"></path>
          </svg>
        </span>
      `;
    case "filter-paper":
      return `
        <span class="${classes}" aria-hidden="true">
          <svg class="${svgClass}" viewBox="0 0 24 24" focusable="false" aria-hidden="true">
            <circle class="filter-disc-shadow" cx="12" cy="12.8" r="7.95"></circle>
            <circle class="filter-disc-base" cx="12" cy="12" r="7.95"></circle>
            <circle class="filter-disc-rim" cx="12" cy="12" r="7.95"></circle>
            <path class="filter-disc-detail" d="M12 4.95v14.1M4.95 12h14.1" stroke-linecap="round"></path>
            <path class="filter-disc-detail" d="m7.05 7.05 9.9 9.9M16.95 7.05l-9.9 9.9" stroke-linecap="round"></path>
            <circle class="filter-disc-core" cx="12" cy="12" r="2.15"></circle>
          </svg>
        </span>
      `;
    default:
      return `
        <span class="${classes}" aria-hidden="true">
          <svg class="${svgClass}" viewBox="0 0 24 24" focusable="false" aria-hidden="true">
            <circle cx="12" cy="12" r="2.25"></circle>
          </svg>
        </span>
      `;
  }
}

function renderSessionCommandCenterProgressMarkup(session = null, options = {}) {
  const requiresSignIn = Boolean(options.requiresSignIn);
  const events = getSessionCommandCenterProgressEvents(session);
  const rowMarkup = events.map((event, index) => {
    const nextEvent = events[index + 1] || null;
    const connectorIsActive = Boolean(
      nextEvent
      && (event.isComplete || nextEvent.isComplete || nextEvent.isCurrent)
    );

    return `
      <article class="session-command-stage stage-item session-command-stage--${escapeHtml(event.tone)} ${event.isComplete ? "is-complete" : ""} ${event.isCurrent ? "is-current" : ""} ${!event.isActive ? "is-future" : ""}">
        ${renderCommandCenterIconMarkup(`stage-${event.key === "germination-started" ? "first-germinated" : event.key}`, `command-icon--stage command-icon--stage-${event.key === "germination-started" ? "first-germinated" : event.key}`)}
        <strong>${escapeHtml(event.displayLabel)}</strong>
        <p>${escapeHtml(session ? event.subtext : (requiresSignIn ? "Sign in to begin" : event.subtext))}</p>
      </article>
      ${nextEvent ? `<div class="stage-connector${connectorIsActive ? " stage-connector--active" : ""}" aria-hidden="true"></div>` : ""}
    `;
  }).join("");

  return `
    <div class="session-command-stage-grid stage-progress-row">
      ${rowMarkup}
    </div>
  `;
}

function renderSessionCommandCenterStatsMarkup(session = null, options = {}) {
  const requiresSignIn = Boolean(options.requiresSignIn);
  const normalizedStage = normalizeSessionStatus(session?.sessionStatus || "");
  const totalsForSession = session ? getSessionSeedTotals(session) : { totalSeeds: 0, totalPlanted: 0 };
  const stageStart = session
    ? getStageStartDateTime(
      session.date,
      session.time,
      normalizedStage,
      session.germinationStartedAt || "",
      session.timerStartAt || "",
      getSessionStageReminderOptions(session),
    )
    : null;
  const rateValue = session && totalsForSession.totalSeeds > 0
    ? `${Math.round((totalsForSession.totalPlanted / totalsForSession.totalSeeds) * 100)}%`
    : "--";
  const statCards = [
    {
      label: "Stage Timer",
      value: session ? formatSpotlightElapsed(stageStart) : "--",
      caption: requiresSignIn ? "Sign in to track" : "Elapsed",
      tone: "blue",
    },
    {
      label: "Seeds Progress",
      value: session ? `${totalsForSession.totalPlanted} / ${totalsForSession.totalSeeds} seeds` : "--",
      caption: "Planted",
      tone: "green",
    },
    {
      label: "Germination Rate",
      value: rateValue,
      caption: "Current rate",
      tone: "orange",
    },
  ];

  return statCards.map((card) => `
    <article class="session-command-stat-card session-command-stat-card--${escapeHtml(card.tone)}">
      <span>${escapeHtml(card.label)}</span>
      <strong>${escapeHtml(card.value)}</strong>
      <p>${escapeHtml(card.caption)}</p>
    </article>
  `).join("");
}

function renderSessionCommandCenterFilterPaperSupplyMarkup() {
  const supply = getFilterPaperSupplyDisplayState();
  return `
    <section class="session-command-center-supply-panel session-command-center-supply-panel--${escapeHtml(supply.tone)}" aria-labelledby="session-command-center-supply-title">
      <div class="session-command-center-supply-copy">
        <div class="session-command-center-supply-head">
          ${renderCommandCenterIconMarkup("filter-paper", `command-icon--supply command-icon--supply-${supply.tone}`)}
          <div class="session-command-center-supply-title-group">
            <p class="eyebrow">SUPPLIES</p>
            <h4 id="session-command-center-supply-title">Global Filter Paper Supply</h4>
          </div>
        </div>
        <p class="session-command-center-supply-count">${escapeHtml(supply.countLabel)}</p>
        <p class="session-command-center-supply-helper">${escapeHtml(supply.helperText)}</p>
        ${renderFilterPaperInventoryErrorMarkup("session-command-center-supply-error")}
      </div>
      <div class="session-command-center-supply-actions">
        <span class="filter-paper-status-badge filter-paper-status-badge--${escapeHtml(supply.tone)}">${escapeHtml(supply.statusLabel)}</span>
        <div class="session-command-center-supply-button-row">
          ${renderFilterPaperSupplyActionButtonsMarkup(supply)}
        </div>
      </div>
    </section>
  `;
}

function formatSessionCommandCenterDayLabel(session = null) {
  const startedAt = getEffectiveSessionTimerStartAt(session);
  if (!(startedAt instanceof Date) || Number.isNaN(startedAt.getTime())) {
    return "";
  }

  if (isSetupGracePeriodActive(startedAt)) {
    return "Setup";
  }

  const totalDays = Math.max(1, Math.floor((Date.now() - startedAt.getTime()) / (24 * 60 * 60 * 1000)) + 1);
  return `Day ${totalDays}`;
}

function renderMySessionsCommandCenterListMarkup(activeSessions = [], selectedSessionId = "", options = {}) {
  const requiresSignIn = Boolean(options.requiresSignIn);
  const hasSessionHistory = Boolean(options.hasSessionHistory);

  if (requiresSignIn) {
    return `
      <div class="session-command-empty">
        <p>Sign in to start and continue tracking your grow sessions.</p>
        <a class="button button-primary" href="#new" data-session-entry="true">Sign In to Start Session</a>
      </div>
      <a class="session-command-start-link" href="#new" data-session-entry="true">+ Start New Session</a>
    `;
  }

  if (!activeSessions.length) {
    return `
      <div class="session-command-empty">
        <p>${escapeHtml(hasSessionHistory ? "No active sessions right now. Start a new grow session when you're ready." : "No sessions yet. Start your first grow session to open the command center.")}</p>
        <a class="button button-primary" href="#new" data-session-entry="true">${escapeHtml(hasSessionHistory ? "Start New Session" : "Create Your First Session")}</a>
        ${renderLearnEmptyStateCtaMarkup("creating-your-first-session", "Creating Your First Session")}
      </div>
      <a class="session-command-start-link" href="#new" data-session-entry="true">+ Start New Session</a>
    `;
  }

  const cardsMarkup = activeSessions.map((session) => {
    const isSelected = session.id === selectedSessionId;
    const stageBadge = getSessionCommandCenterStageBadge(session);
    const lifecycleHealth = getGrowSessionLifecycleHealth(session);
    const varietyLabel = getSessionCommandCenterPrimaryStrain(session) || "Variety not set";
    const dateLabel = formatSessionNameDate(session.date);
    const dayLabel = formatSessionCommandCenterDayLabel(session);

    return `
      <article
        class="session-command-session-card${isSelected ? " is-selected" : ""} is-lifecycle-${escapeHtml(lifecycleHealth.classification)}"
        data-session-command-select="${escapeHtml(session.id)}"
        tabindex="0"
        role="button"
        aria-pressed="${isSelected ? "true" : "false"}"
      >
        ${renderCommandCenterIconMarkup("session-thumb", "command-icon--session-thumb")}
        <div class="session-command-session-copy">
          <strong>${escapeHtml(formatSessionLabel(session))}</strong>
          <div class="session-command-session-meta">
            <p class="session-command-session-date">${escapeHtml(dateLabel)}</p>
            ${dayLabel ? `<p class="session-command-session-day">${escapeHtml(dayLabel)}</p>` : ""}
            <p class="session-command-session-strain">${escapeHtml(varietyLabel)}</p>
          </div>
          <div class="session-command-session-footer">
            <span class="session-command-stage-badge session-status-pill ${escapeHtml(stageBadge.className)}">${escapeHtml(stageBadge.label)}</span>
            ${lifecycleHealth.classification === "needs_attention" ? `<span class="session-command-session-recovery">${escapeHtml(lifecycleHealth.detail || "Review session")}</span>` : ""}
          </div>
        </div>
        <div class="session-command-session-actions">
          <a class="button button-primary session-command-session-continue session-continue-button" href="#sessions/${escapeHtml(session.id)}"><span class="session-continue-button-icon" aria-hidden="true">&#9654;</span><span>Continue</span></a>
          <a class="session-command-session-menu" href="#sessions/${escapeHtml(session.id)}" aria-label="Open ${escapeHtml(formatSessionLabel(session))}">
            <span aria-hidden="true">&bull;&bull;&bull;</span>
          </a>
        </div>
      </article>
    `;
  }).join("");

  return `
    ${cardsMarkup}
    <a class="session-command-start-link" href="#new" data-session-entry="true">+ Start New Session</a>
  `;
}

function renderMySessionsCommandCenterMetricsMarkup(sessions = [], activeSessions = [], options = {}) {
  const compactVariant = String(options.metricsVariant || "").trim().toLowerCase() === "compact";
  const compactCardClass = compactVariant ? " home-session-summary-card--compact" : "";
  const compactRateRingClass = compactVariant ? " overall-rate-ring--compact" : "";
  const visibleSessions = getVisibleUserSessions(Array.isArray(sessions) ? sessions : []);
  const visibleActiveSessions = getVisibleUserSessions(Array.isArray(activeSessions) ? activeSessions : []);
  const totalSessions = visibleSessions.length;
  const activeCount = visibleActiveSessions.length;
  const activeSubtext = activeCount ? "in progress" : "No active sessions";
  const aggregateStatsSessions = getAggregateStatsSessions(
    Array.isArray(options.aggregateSessions) ? options.aggregateSessions : sessions,
  );
  const visibleAnalyticsSessions = getAggregateStatsSessions(visibleSessions);

  const bestSession = getBestCompletedSession(visibleAnalyticsSessions);
  const bestSessionName = bestSession ? formatSessionLabel(bestSession) : "No completed sessions yet";
  const bestSessionDate = bestSession ? formatSessionNameDate(bestSession.date) : "";
  const bestSessionTotals = bestSession ? getSessionSeedTotals(bestSession) : { totalSeeds: 0, totalPlanted: 0 };
  const bestSessionPercentage = bestSessionTotals.totalSeeds > 0
    ? Math.round((bestSessionTotals.totalPlanted / bestSessionTotals.totalSeeds) * 100)
    : 0;
  const bestDurationLabel = bestSession ? formatDurationMsShort(getSessionCompletedDurationMs(bestSession)) : "";
  const bestSessionResult = bestSession
    ? (bestDurationLabel ? `${bestSessionPercentage}% · ${bestDurationLabel}` : `${bestSessionPercentage}%`)
    : "";

  const overallTotals = aggregateStatsSessions.reduce((accumulator, session) => {
    const sessionTotals = getSessionSeedTotals(session);
    accumulator.totalSeeds += sessionTotals.totalSeeds;
    accumulator.totalPlanted += sessionTotals.totalPlanted;
    return accumulator;
  }, { totalSeeds: 0, totalPlanted: 0 });
  const overallPercentage = overallTotals.totalSeeds > 0
    ? Math.round((overallTotals.totalPlanted / overallTotals.totalSeeds) * 100)
    : 0;

  return `
    <a id="active-sessions-card" class="card stat-card summary-link-card card-accent card-accent-blue${compactCardClass}" href="#active-sessions">
      <div class="card-content">
        <div class="summary-card-head">
          ${renderCommandCenterIconMarkup("metric-active", "command-icon--metric command-icon--metric-active")}
          <span class="stat-label">Active Sessions</span>
        </div>
        <div class="summary-card-body">
          <strong class="stat-value">${escapeHtml(String(activeCount))}</strong>
          <p class="summary-subtext">${escapeHtml(activeSubtext)}</p>
        </div>
      </div>
      <span class="summary-card-action card-action">View All <span aria-hidden="true">&rarr;</span></span>
    </a>
    <a id="saved-sessions-card" class="card stat-card summary-link-card card-accent card-accent-orange${compactCardClass}" href="#sessions" data-session-scroll-target="session-history">
      <div class="card-content">
        <div class="summary-card-head">
          ${renderCommandCenterIconMarkup("metric-saved", "command-icon--metric command-icon--metric-saved")}
          <span class="stat-label">Saved Sessions</span>
        </div>
        <div class="summary-card-body">
          <strong class="stat-value">${escapeHtml(String(totalSessions))}</strong>
          <p class="summary-subtext">total saved</p>
        </div>
      </div>
      <span class="summary-card-action card-action">View All <span aria-hidden="true">&rarr;</span></span>
    </a>
    <a id="best-session-card" class="card stat-card best-session-card summary-link-card card-accent card-accent-green${compactCardClass}" href="${escapeHtml(bestSession ? `#sessions/${bestSession.id}` : "#sessions")}">
      <div class="card-content">
        <div class="summary-card-head best-session-header">
          <div class="summary-card-head-main">
            ${renderCommandCenterIconMarkup("metric-leading", "command-icon--metric command-icon--metric-leading")}
            <span class="stat-label">Leading Session</span>
          </div>
          ${bestSession ? '<span class="best-session-indicator">Recorded</span>' : ""}
        </div>
        <div class="summary-card-body">
          <strong class="best-session-name">${escapeHtml(bestSessionName)}</strong>
          <p class="summary-subtext">${escapeHtml(bestSessionDate)}</p>
          <p class="best-session-result">${escapeHtml(bestSessionResult)}</p>
        </div>
      </div>
      <span class="summary-card-action card-action">View Details <span aria-hidden="true">&rarr;</span></span>
    </a>
    <a id="overall-rate-card" class="card stat-card overall-rate-card summary-link-card card-accent card-accent-brown${compactCardClass}" href="#sessions" data-session-scroll-target="session-analytics">
      <div class="card-content">
        <div class="summary-card-head">
          ${renderCommandCenterIconMarkup("metric-rate", "command-icon--metric command-icon--metric-rate")}
          <span class="stat-label">All Sessions Germination Rate</span>
        </div>
        <div class="overall-rate-content">
          <div class="overall-rate-ring${compactRateRingClass}" aria-hidden="true" style="--overall-ring-progress:${escapeHtml(`${overallPercentage}%`)};">
            <strong class="overall-rate-value">${escapeHtml(`${overallPercentage}%`)}</strong>
          </div>
          <div class="overall-rate-copy">
            <p class="overall-rate-total">${escapeHtml(`${overallTotals.totalPlanted} / ${overallTotals.totalSeeds} seeds`)}</p>
          </div>
        </div>
        <div class="overall-rate-bar" aria-label="Overall germination rate">
          <div class="overall-rate-fill" style="width:${escapeHtml(`${overallPercentage}%`)};"></div>
        </div>
      </div>
      <span class="summary-card-action card-action">View Analytics <span aria-hidden="true">&rarr;</span></span>
    </a>
  `;
}

function renderMySessionsCommandCenterSectionMarkup(activeSessions = [], selectedSessionId = "", options = {}) {
  const requiresSignIn = Boolean(options.requiresSignIn);
  const sessions = getVisibleUserSessions(Array.isArray(options.sessions) ? options.sessions : []);
  const visibleActiveSessions = getVisibleUserSessions(Array.isArray(activeSessions) ? activeSessions : []);
  const selectedSession = visibleActiveSessions.find((session) => session.id === selectedSessionId) || visibleActiveSessions[0] || null;
  const headerEyebrow = String(options.headerEyebrow || "ACTIVE SESSION").trim() || "ACTIVE SESSION";
  const headerTitle = String(options.headerTitle || "SESSION COMMAND CENTER").trim() || "SESSION COMMAND CENTER";
  const headerDescription = String(options.headerDescription || "").trim();
  const viewAllHref = String(options.viewAllHref || getActiveSessionsRouteHash()).trim() || getActiveSessionsRouteHash();
  const showViewAllLink = options.showViewAllLink !== false;
  const showMetrics = options.showMetrics !== false;
  const metricsPlacement = String(options.metricsPlacement || "bottom").trim().toLowerCase() === "top" ? "top" : "bottom";
  const metricsVariant = String(options.metricsVariant || "").trim().toLowerCase();
  const headerActionHref = String(options.headerActionHref || "").trim();
  const headerActionLabel = String(options.headerActionLabel || "").trim();
  const countBadgeLabel = requiresSignIn
    ? "Sign in"
    : `${visibleActiveSessions.length} ${visibleActiveSessions.length === 1 ? "in progress" : "in progress"}`;
  const metricsMarkup = showMetrics
    ? `
      <div class="summary-grid session-command-center-metrics${metricsVariant === "compact" ? " home-session-summary-grid--compact" : ""}">
        ${renderMySessionsCommandCenterMetricsMarkup(sessions, visibleActiveSessions, {
          aggregateSessions: options.aggregateSessions || sessions,
          metricsVariant,
        })}
      </div>`
    : "";

  return `
    <section id="session-command-center" class="session-command-center-shell session-command-center-shell--sessions${options.compact ? " session-command-center-shell--compact" : ""}${metricsPlacement === "top" ? " session-command-center-shell--metrics-top" : ""} card card-accent card-accent-green">
      <header class="session-command-center-head session-command-center-header">
        ${renderCommandCenterIconMarkup("header", "command-icon--header")}
        <div class="session-command-center-header-text session-command-center-title-copy">
            <p class="eyebrow">${escapeHtml(headerEyebrow)}</p>
            <h3 id="active-sessions-command-title">${escapeHtml(headerTitle)}</h3>
            ${headerDescription ? `<p class="session-command-center-header-description">${escapeHtml(headerDescription)}</p>` : ""}
            <div class="session-command-center-header-divider" aria-hidden="true"></div>
        </div>
        ${headerActionHref && headerActionLabel ? `<a class="session-command-center-header-link" href="${escapeHtml(headerActionHref)}">${escapeHtml(headerActionLabel)}</a>` : ""}
      </header>
      ${metricsPlacement === "top" ? metricsMarkup : ""}
      <div class="session-command-center session-command-center-grid" data-session-command-center="true">
        <section class="session-command-panel session-command-panel--sessions active-sessions-panel" aria-labelledby="active-sessions-command-list-title">
          <div class="session-command-panel-heading">
            <div class="session-command-panel-heading-copy">
              <div class="session-command-panel-heading-row">
                <h4 id="active-sessions-command-list-title">ACTIVE SESSIONS</h4>
                <span class="session-command-count-badge">${escapeHtml(countBadgeLabel)}</span>
              </div>
            </div>
            ${showViewAllLink ? `<a class="session-command-panel-link" href="${escapeHtml(viewAllHref)}" aria-label="View all active sessions">View All Active <span aria-hidden="true">&rarr;</span></a>` : ""}
          </div>
          <div class="session-command-list">${renderMySessionsCommandCenterListMarkup(visibleActiveSessions, selectedSession?.id || "", options)}</div>
        </section>
        <section class="session-command-panel session-command-panel--progress stage-progress-panel" aria-labelledby="active-sessions-command-progress-title">
          <div class="session-command-panel-heading">
            <div class="session-command-panel-heading-row">
              <h4 id="active-sessions-command-progress-title">STAGE PROGRESS</h4>
            </div>
          </div>
          <div class="session-command-progress" aria-label="Selected session progress">
            ${renderSessionCommandCenterProgressMarkup(selectedSession, { requiresSignIn })}
          </div>
          <div class="session-command-stats">
            ${renderSessionCommandCenterStatsMarkup(selectedSession, { requiresSignIn })}
          </div>
        </section>
      </div>
      ${metricsPlacement === "bottom" ? metricsMarkup : ""}
      ${renderSessionCommandCenterFilterPaperSupplyMarkup()}
    </section>
  `;
}

function mountSharedSessionCommandCenter(host, options = {}) {
  if (!(host instanceof Element)) {
    return null;
  }

  const activeSessions = getVisibleUserSessions(Array.isArray(options.activeSessions) ? options.activeSessions : []);
  const sessions = getVisibleUserSessions(Array.isArray(options.sessions) ? options.sessions : []);
  const aggregateSessions = Array.isArray(options.aggregateSessions) ? options.aggregateSessions : sessions;
  const hasSessionHistory = Boolean(options.hasSessionHistory);
  const requiresSignIn = Boolean(options.requiresSignIn);
  let selectedCommandCenterSessionId = options.selectedSessionId || activeSessions[0]?.id || "";

  const renderSessionCommandCenter = () => {
    const selectedSession = activeSessions.find((session) => session.id === selectedCommandCenterSessionId) || activeSessions[0] || null;
    host.innerHTML = renderMySessionsCommandCenterSectionMarkup(activeSessions, selectedSession?.id || "", {
      hasSessionHistory,
      requiresSignIn,
      sessions,
      aggregateSessions,
      compact: options.compact,
      showMetrics: options.showMetrics,
      showViewAllLink: options.showViewAllLink,
      viewAllHref: options.viewAllHref,
      headerEyebrow: options.headerEyebrow,
      headerTitle: options.headerTitle,
      metricsPlacement: options.metricsPlacement,
      metricsVariant: options.metricsVariant,
    });
    hydrateAppIconSlots(host);
    applySupplyStatusToSessionEntryButtons(host);
    bindFilterPaperCardActions(host, { onSave: renderSessionCommandCenter });
  };

  if (host.dataset.sessionCommandCenterBound !== "true") {
    host.dataset.sessionCommandCenterBound = "true";

    host.addEventListener("click", (event) => {
      const target = event.target;
      if (!(target instanceof Element)) {
        return;
      }
      const dashboardLink = target.closest("[data-session-scroll-target]");
      if (dashboardLink instanceof HTMLAnchorElement) {
        const scrollTarget = String(dashboardLink.getAttribute("data-session-scroll-target") || "").trim();
        const href = String(dashboardLink.getAttribute("href") || "#sessions").trim() || "#sessions";
        if (scrollTarget) {
          event.preventDefault();
          if (normalizeNavigationHash(window.location.hash || "#home") === normalizeNavigationHash(href)) {
            if (!scrollToSessionDashboardSection(scrollTarget)) {
              appState.sessionDashboardScrollTarget = scrollTarget;
            }
            return;
          }
          appState.sessionDashboardScrollTarget = scrollTarget;
          navigateToHashRoute(href);
          return;
        }
      }
      if (target.closest("a, button")) {
        return;
      }
      const card = target.closest("[data-session-command-select]");
      if (!card) {
        return;
      }
      selectedCommandCenterSessionId = String(card.getAttribute("data-session-command-select") || "");
      renderSessionCommandCenter();
    });

    host.addEventListener("keydown", (event) => {
      const target = event.target;
      if (!(target instanceof Element)) {
        return;
      }
      const card = target.closest("[data-session-command-select]");
      if (!card || (event.key !== "Enter" && event.key !== " ")) {
        return;
      }
      event.preventDefault();
      selectedCommandCenterSessionId = String(card.getAttribute("data-session-command-select") || "");
      renderSessionCommandCenter();
    });
  }

  renderSessionCommandCenter();
  startSessionTimer(renderSessionCommandCenter);
  return renderSessionCommandCenter;
}

function formatPublicTimelineElapsedDuration(startedAt, endedAt) {
  if (!(startedAt instanceof Date) || Number.isNaN(startedAt.getTime())) {
    return "";
  }

  if (!(endedAt instanceof Date) || Number.isNaN(endedAt.getTime())) {
    return "";
  }

  const totalMinutes = Math.max(0, Math.floor((endedAt.getTime() - startedAt.getTime()) / 60000));
  return formatElapsedMinutesShorthand(totalMinutes);
}

function renderPublicSessionLifecycleTimelineMarkup(state) {
  const soakingDuration = formatPublicTimelineElapsedDuration(state.startedAt, state.germinationStartedAt);
  const germinationDuration = formatPublicTimelineElapsedDuration(state.germinationStartedAt, state.firstPlantedAt);
  const completedDuration = formatPublicTimelineElapsedDuration(state.startedAt, state.completedAt);

  const events = [
    {
      label: "SOAKING",
      displayLabel: soakingDuration || "Duration unavailable",
      tone: "soaking",
      complete: Boolean(state.startedAt && state.germinationStartedAt),
    },
    {
      label: "GERMINATION",
      displayLabel: state.germinationStartedAt
        ? (germinationDuration || "Duration unavailable")
        : "Not started",
      tone: "germination",
      complete: Boolean(state.germinationStartedAt),
    },
    {
      label: "FIRST GERMINATED",
      displayLabel: soakingDuration && germinationDuration
        ? `${soakingDuration} + ${germinationDuration}`
        : "Duration unavailable",
      tone: "green",
      complete: Boolean(state.firstPlantedAt),
    },
    {
      label: "COMPLETED",
      displayLabel: completedDuration || "Duration unavailable",
      tone: "completed",
      complete: Boolean(state.completedAt),
    },
  ];

  return `
    <div class="lifecycle-bar">
      ${events.map((event) => `
        <span class="lifecycle-segment lifecycle-${event.tone} ${event.complete ? "is-complete" : ""}"></span>
      `).join("")}
    </div>
    <div class="lifecycle-events">
      ${events.map((event) => `
        <article class="lifecycle-event lifecycle-event-${event.tone} ${event.complete ? "is-complete" : ""}">
          <strong>${event.label}</strong>
          <p>${escapeHtml(event.displayLabel)}</p>
        </article>
      `).join("")}
    </div>
  `;
}

function buildFormLifecycleState(form) {
  const normalizedStatus = normalizeSessionStatus(form.dataset.currentStage || form.elements.sessionStatus?.value || "");
  if (normalizedStatus === "unselected") {
    return {
      showEmptyTimeline: true,
      startedAt: null,
      germinationStartedAt: null,
      firstPlantedAt: null,
      completedAt: null,
    };
  }

  return {
    showEmptyTimeline: false,
    sessionStatus: normalizedStatus,
    currentProgressKey: resolveGrowSessionCurrentProgressKey({
      sessionStatus: normalizedStatus,
      germinationStartedAt: form.dataset.germinationStartedAt || "",
      firstPlantedAt: form.dataset.firstPlantedAt || "",
      completedAt: form.dataset.completedAt || "",
    }),
    startedAt: parseSessionStartDateTime(form.elements.date.value, form.elements.time.value),
    germinationStartedAt: parseCompletedAtValue(form.dataset.germinationStartedAt || ""),
    firstPlantedAt: parseCompletedAtValue(form.dataset.firstPlantedAt || ""),
    completedAt: parseCompletedAtValue(form.dataset.completedAt || ""),
    lastUpdatedAt: null,
    setupGraceActive: false,
  };
}

function buildSessionLifecycleState(session) {
  const timingState = getSessionTimingState(session);
  const startedAt = timingState.totalStartedAt;
  const completedAt = timingState.completedAt;
  return {
    showEmptyTimeline: false,
    sessionStatus: normalizeSessionStatus(session?.sessionStatus || ""),
    currentProgressKey: getSessionProgressKeyFromSession(session),
    startedAt,
    germinationStartedAt: parseCompletedAtValue(session.germinationStartedAt || session.germination_started_at || ""),
    firstPlantedAt: parseCompletedAtValue(session.firstPlantedAt || session.first_planted_at || ""),
    completedAt,
    setupGraceActive: timingState.setupGraceActive,
  };
}

function buildMockPublicSessionLifecycleState(scenario = null) {
  const activeScenario = scenario || MOCK_PUBLIC_SESSION_SCENARIOS[0];
  return {
    showEmptyTimeline: false,
    startedAt: parseCompletedAtValue(activeScenario.timeline.startedAt),
    germinationStartedAt: parseCompletedAtValue(activeScenario.timeline.germinationStartedAt),
    firstPlantedAt: parseCompletedAtValue(activeScenario.timeline.firstPlantedAt),
    completedAt: parseCompletedAtValue(activeScenario.timeline.completedAt),
  };
}

function buildPublicSessionLifecycleState(snapshot) {
  const activeMockScenario = getActiveMockPublicSessionScenario(snapshot);
  if (activeMockScenario) {
    return buildMockPublicSessionLifecycleState(activeMockScenario);
  }

  const linkedSession = getGallerySnapshotSession(snapshot);
  if (linkedSession) {
    return buildSessionLifecycleState(linkedSession);
  }

  const sessionDate = String(snapshot?.sessionDate || "").trim();
  const sessionTime = String(snapshot?.sessionTime || snapshot?.session_time || "").trim();
  const startedAt = sessionDate && sessionTime ? parseSessionStartDateTime(sessionDate, sessionTime) : null;
  const germinationStartedAt = parseCompletedAtValue(snapshot?.germinationStartedAt || snapshot?.germination_started_at || "");
  const firstPlantedAt = parseCompletedAtValue(snapshot?.firstPlantedAt || snapshot?.first_planted_at || "");
  const completedAt = parseCompletedAtValue(snapshot?.completedAt || snapshot?.completed_at || "");
  const startedDisplayLabel = !startedAt && sessionDate ? getGallerySnapshotSubmittedDateLabel(snapshot) : "";
  const hasTimelineData = Boolean(
    startedAt
    || startedDisplayLabel
    || germinationStartedAt
    || firstPlantedAt
    || completedAt
  );

  if (!hasTimelineData) {
    return null;
  }

  return {
    showEmptyTimeline: false,
    startedAt,
    startedDisplayLabel,
    startedComplete: Boolean(startedAt || startedDisplayLabel),
    germinationStartedAt,
    firstPlantedAt,
    completedAt,
  };
}

function renderPublicSessionTimelineSection(snapshot) {
  const lifecycleState = buildPublicSessionLifecycleState(snapshot);
  const timelineMarkup = lifecycleState
    ? renderPublicSessionLifecycleTimelineMarkup(lifecycleState)
    : '<p class="public-session-timeline-empty">Timeline not shared.</p>';

  return `
    <section class="session-lifecycle-section public-session-timeline-section" aria-labelledby="public-session-progress-title">
      <div class="progress-chart-heading">
        <p class="eyebrow">Timeline</p>
        <h4 id="public-session-progress-title" class="section-title-with-icon">
          <svg class="section-title-icon" viewBox="0 0 24 24" focusable="false" aria-hidden="true">
            <path d="M5 12h3l2.2-4 3.6 8 2.2-4H19"></path>
            <path d="M5 6v12"></path>
          </svg>
          <span>Session Progress</span>
        </h4>
      </div>
      <div class="session-lifecycle-summary">
        ${timelineMarkup}
      </div>
    </section>
  `;
}

function captureFirstPlantedEventForForm(form) {
  if (form.dataset.firstPlantedAt) {
    return;
  }

  const hasPlantedValue = getPartitionProgressDataFromForm(form)
    .some((partition) => Number(partition.plantedCount) > 0);
  if (hasPlantedValue) {
    form.dataset.firstPlantedAt = new Date().toISOString();
  }
}

function captureFirstPlantedEventForSession(session) {
  if (session.firstPlantedAt) {
    return;
  }

  const hasPlantedValue = (session.partitions || [])
    .some((partition) => Number(partition.plantedCount) > 0);
  if (hasPlantedValue) {
    session.firstPlantedAt = new Date().toISOString();
  }
}

function syncSessionPartitionsFromContainer(session, container, options = {}) {
  if (!session || !container) {
    return;
  }

  if (container.dataset.partitionRenderMode === "completed-report") {
    session.partitions = normalizeSessionPartitions(container.__partitionDraftValues || session.partitions || []);
    return;
  }

  const seedAgeForm = options.form instanceof HTMLFormElement
    ? options.form
    : container.closest("form");
  const seedAgeState = seedAgeForm
    ? getSeedAgeSettingsFromForm(seedAgeForm)
    : getSessionSeedAgeMetadata(session);
  session.partitions = [...container.querySelectorAll(".partition-row")].map((row, index) => {
    const existingPartition = session.partitions?.[index] || {};
    return {
      id: Number(row.dataset.partitionId) || existingPartition.id || index + 1,
      source: getPartitionRowFieldValue(row, "source").trim(),
      seedVariety: getPartitionRowFieldValue(row, "seedVariety").trim(),
      breeder: existingPartition.breeder || "",
      seedType: normalizeSeedTypeId(getPartitionRowFieldValue(row, "seedType")),
      feminized: getPartitionRowFieldValue(row, "feminized").trim(),
      seedCount: Number(getPartitionRowFieldValue(row, "seedCount")) || 0,
      seedAgeYears: getEffectivePartitionSeedAgeFromRow(row, seedAgeState),
      plantedCount: getPartitionRowFieldValue(row, "plantedCount").trim(),
    };
  });
}

function bindFormTimelineDebugTools(form, onUpdate) {
  const debugPanel = form.querySelector(".timeline-debug-panel");
  if (!debugPanel || debugPanel.dataset.bound === "true") {
    return;
  }

  debugPanel.addEventListener("click", (event) => {
    const action = event.target.closest("[data-debug-event]")?.dataset.debugEvent;
    if (!action) {
      return;
    }

    applyDebugEventToForm(form, action);
    onUpdate?.(action);
  });

  debugPanel.dataset.bound = "true";
}

function bindSessionTimelineDebugTools(scope, onUpdate) {
  const debugPanel = scope.querySelector(".timeline-debug-panel");
  if (!debugPanel || debugPanel.dataset.bound === "true") {
    return;
  }

  debugPanel.addEventListener("click", (event) => {
    const action = event.target.closest("[data-debug-event]")?.dataset.debugEvent;
    if (!action) {
      return;
    }

    onUpdate?.(action);
  });

  debugPanel.dataset.bound = "true";
}

function applyDebugEventToForm(form, action) {
  const stageField = form.elements.sessionStatus;
  const firstSeedInput = form.querySelector('input[name^="seedCount-"]');
  const firstPlantedInput = form.querySelector('input[name="plantedCount"]');

  if (action === "reset") {
    delete form.dataset.germinationStartedAt;
    delete form.dataset.firstPlantedAt;
    delete form.dataset.completedAt;
    stageField.value = "";
    if (firstPlantedInput) {
      firstPlantedInput.value = "";
    }
    return;
  }

  if (action === "germination") {
    if (!form.dataset.germinationStartedAt) {
      form.dataset.germinationStartedAt = new Date().toISOString();
    }
    stageField.value = "germinating";
    form.dataset.currentStage = "germinating";
    return;
  }

  if (action === "first-planted") {
    if (!form.dataset.germinationStartedAt) {
      form.dataset.germinationStartedAt = new Date().toISOString();
    }
    if (!form.dataset.firstPlantedAt) {
      form.dataset.firstPlantedAt = new Date().toISOString();
    }
    stageField.value = "germinating";
    form.dataset.currentStage = "germinating";
    if (firstSeedInput && !firstSeedInput.value) {
      firstSeedInput.value = "4";
    }
    if (firstPlantedInput && !firstPlantedInput.value) {
      firstPlantedInput.value = "1";
    }
    return;
  }

  if (action === "completed") {
    if (!form.dataset.germinationStartedAt) {
      form.dataset.germinationStartedAt = new Date().toISOString();
    }
    if (!form.dataset.firstPlantedAt) {
      form.dataset.firstPlantedAt = new Date().toISOString();
    }
    if (!form.dataset.completedAt) {
      form.dataset.completedAt = new Date().toISOString();
    }
    stageField.value = "completed";
    form.dataset.currentStage = "completed";
  }
}

function applyDebugEventToSession(session, stageField, action) {
  if (action === "reset") {
    session.germinationStartedAt = "";
    session.firstPlantedAt = "";
    session.completedAt = "";
    session.sessionStatus = "soaking";
    stageField.value = "soaking";
    return;
  }

  if (action === "germination") {
    if (!session.germinationStartedAt) {
      session.germinationStartedAt = new Date().toISOString();
    }
    session.sessionStatus = "germinating";
    stageField.value = "germinating";
    return;
  }

  if (action === "first-planted") {
    if (!session.germinationStartedAt) {
      session.germinationStartedAt = new Date().toISOString();
    }
    if (!session.firstPlantedAt) {
      session.firstPlantedAt = new Date().toISOString();
    }
    session.sessionStatus = "germinating";
    stageField.value = "germinating";
    return;
  }

  if (action === "completed") {
    if (!session.germinationStartedAt) {
      session.germinationStartedAt = new Date().toISOString();
    }
    if (!session.firstPlantedAt) {
      session.firstPlantedAt = new Date().toISOString();
    }
    if (!session.completedAt) {
      session.completedAt = new Date().toISOString();
    }
    session.sessionStatus = "completed";
    stageField.value = "completed";
  }
}

async function saveSessionUpdate(session) {
  try {
    const previousSession = getSessions().find((entry) => String(entry?.id || "").trim() === String(session?.id || "").trim()) || null;
    const previousStatus = previousSession?.sessionStatus || "";
    const isNewCompletion = normalizeSessionStatus(session?.sessionStatus || "") === "completed"
      && normalizeSessionStatus(previousStatus) !== "completed";
    if (isNewCompletion && !areSessionSeedResultsFullyAccountedFor(session)) {
      throw new Error(SESSION_RESULTS_INCOMPLETE_COMPLETION_MESSAGE);
    }
    autoCompleteSessionWhenResultsAccounted(session);
    session.unitId = normalizeUnitIdValue(session.unitId);
    const savedSession = await updateCloudSession(session);
    processSessionNotificationTriggers(savedSession, {
      previousSession,
      existingSessions: getSessions(),
      isNewSession: false,
    });
    Object.assign(session, savedSession);
    return savedSession;
  } catch (error) {
    console.error("Failed to save session update", error);
    setUnsavedChangesLastSaveError(error, "Could not save session.");
    return null;
  }
}

function parseCompletedAtValue(completedAt) {
  if (!completedAt) {
    return null;
  }

  const parsedDate = new Date(completedAt);
  if (Number.isNaN(parsedDate.getTime())) {
    return null;
  }

  return parsedDate;
}

function formatTimingDateTime(value) {
  const datePart = new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  }).format(value);
  const hours = String(value.getHours()).padStart(2, "0");
  const minutes = String(value.getMinutes()).padStart(2, "0");
  const timePart = formatStoredTime(`${hours}:${minutes}`);
  return `${datePart} - ${timePart}`;
}

function formatSpotlightElapsed(startedAt) {
  if (!(startedAt instanceof Date) || Number.isNaN(startedAt.getTime())) {
    return "--";
  }

  const now = new Date();
  if (isSetupGracePeriodActive(startedAt, now)) {
    return formatSetupGraceStartsIn(startedAt, now);
  }

  const totalMinutes = Math.max(0, Math.floor((now.getTime() - startedAt.getTime()) / 60000));
  return formatElapsedMinutesShorthand(totalMinutes);
}

function formatDurationBetween(startedAt, endedAt) {
  if (!(startedAt instanceof Date) || Number.isNaN(startedAt.getTime())) {
    return "";
  }

  if (!(endedAt instanceof Date) || Number.isNaN(endedAt.getTime())) {
    return "";
  }

  const totalMinutes = Math.max(0, Math.floor((endedAt.getTime() - startedAt.getTime()) / 60000));
  return formatElapsedMinutesShorthand(totalMinutes);
}

function startSessionTimer(callback) {
  clearSessionTimerInterval();
  callback();
  sessionTimerInterval = window.setInterval(callback, 60 * 1000);
}

function clearSessionTimerInterval() {
  if (sessionTimerInterval) {
    window.clearInterval(sessionTimerInterval);
    sessionTimerInterval = null;
  }
}

function initializeTimeFormatField(form, initialTime = "") {
  const storedTimeField = form.elements.time;
  const displayTimeField = form.elements.timeDisplay;
  if (!storedTimeField || !displayTimeField) {
    return;
  }

  const preferredFormat = getPreferredTimeFormat();
  setTimeFormatButtons(form, preferredFormat);
  storedTimeField.value = initialTime || storedTimeField.value || "";
  displayTimeField.placeholder = preferredFormat === "12h" ? "7:04 PM" : "19:04";
  displayTimeField.value = formatStoredTime(storedTimeField.value, preferredFormat);

  if (form.dataset.timeFormatInitialized === "true") {
    return;
  }

  form.dataset.timeFormatInitialized = "true";

  form.querySelectorAll("[data-time-format]").forEach((button) => {
    button.addEventListener("click", () => {
      const nextFormat = button.dataset.timeFormat;
      setPreferredTimeFormat(nextFormat);
      setTimeFormatButtons(form, nextFormat);
      displayTimeField.placeholder = nextFormat === "12h" ? "7:04 PM" : "19:04";
      if (storedTimeField.value) {
        displayTimeField.value = formatStoredTime(storedTimeField.value, nextFormat);
      }
    });
  });

  displayTimeField.addEventListener("input", () => {
    syncStoredTimeFromDisplay(form, { normalize: false, forceError: false });
  });

  displayTimeField.addEventListener("blur", () => {
    syncStoredTimeFromDisplay(form, { normalize: true, forceError: true });
  });
}

function syncStoredTimeFromDisplay(form, options = { normalize: false, forceError: false }) {
  const storedTimeField = form.elements.time;
  const displayTimeField = form.elements.timeDisplay;
  if (!storedTimeField || !displayTimeField) {
    return false;
  }

  const rawValue = displayTimeField.value.trim();
  if (!rawValue) {
    storedTimeField.value = "";
    if (options.forceError) {
      displayTimeField.setCustomValidity("Please enter a time.");
      displayTimeField.reportValidity();
    } else {
      displayTimeField.setCustomValidity("");
    }
    return false;
  }

  const parsedTime = parseDisplayTime(rawValue, getPreferredTimeFormat());
  if (!parsedTime) {
    storedTimeField.value = "";
    if (options.forceError) {
      displayTimeField.setCustomValidity(getPreferredTimeFormat() === "12h" ? "Enter time like 7:04 PM." : "Enter time like 19:04.");
      displayTimeField.reportValidity();
    } else {
      displayTimeField.setCustomValidity("");
    }
    return false;
  }

  storedTimeField.value = parsedTime;
  displayTimeField.setCustomValidity("");
  if (options.normalize) {
    displayTimeField.value = formatStoredTime(parsedTime, getPreferredTimeFormat());
  }
  return true;
}

function parseDisplayTime(value, format = getPreferredTimeFormat()) {
  const rawValue = String(value || "").trim();
  if (!rawValue) {
    return "";
  }

  if (format === "24h") {
    const match = rawValue.match(/^([01]?\d|2[0-3]):([0-5]\d)$/);
    if (!match) {
      return "";
    }

    const hours = String(match[1]).padStart(2, "0");
    return `${hours}:${match[2]}`;
  }

  const match = rawValue.match(/^(1[0-2]|0?[1-9]):([0-5]\d)\s*([AP]M)$/i);
  if (!match) {
    return "";
  }

  let hours = Number(match[1]);
  const minutes = match[2];
  const meridiem = match[3].toUpperCase();
  if (meridiem === "AM" && hours === 12) {
    hours = 0;
  } else if (meridiem === "PM" && hours !== 12) {
    hours += 12;
  }

  return `${String(hours).padStart(2, "0")}:${minutes}`;
}

function formatStoredTime(value, format = getPreferredTimeFormat()) {
  const rawValue = String(value || "").trim();
  const match = rawValue.match(/^([01]\d|2[0-3]):([0-5]\d)$/);
  if (!match) {
    return rawValue;
  }

  const hours = Number(match[1]);
  const minutes = match[2];
  if (format === "24h") {
    return `${match[1]}:${minutes}`;
  }

  const suffix = hours >= 12 ? "PM" : "AM";
  const displayHours = hours % 12 || 12;
  return `${displayHours}:${minutes} ${suffix}`;
}

function setTimeFormatButtons(form, format) {
  form.querySelectorAll("[data-time-format]").forEach((button) => {
    button.classList.toggle("is-active", button.dataset.timeFormat === format);
    button.setAttribute("aria-pressed", button.dataset.timeFormat === format ? "true" : "false");
  });
}

function getPreferredTimeFormat() {
  return localStorage.getItem(TIME_FORMAT_KEY) || detectDefaultTimeFormat();
}

function setPreferredTimeFormat(format) {
  localStorage.setItem(TIME_FORMAT_KEY, format);
}

function detectDefaultTimeFormat() {
  const hasDayPeriod = new Intl.DateTimeFormat(undefined, { hour: "numeric" })
    .formatToParts(new Date("2026-04-22T13:00:00"))
    .some((part) => part.type === "dayPeriod");
  return hasDayPeriod ? "12h" : "24h";
}

function escapeHtml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

function normalizeNavigationHash(hash) {
  const raw = String(hash || "").trim();
  if (!raw || raw === "#") {
    return "#home";
  }

  if (isSupabaseAuthFragmentHash(raw)) {
    return "#home";
  }

  return raw.startsWith("#") ? raw : `#${raw.replace(/^#+/, "")}`;
}

function buildPartitionDraftValuesFromContainer(container) {
  if (!container) {
    return [];
  }

  if (container.dataset.partitionRenderMode === "completed-report") {
    return normalizeSessionPartitions(container.__partitionDraftValues || []).map((partition) => ({
      id: Number(partition.id) || 0,
      source: String(partition.source || "").trim(),
      seedVariety: String(partition.seedVariety || "").trim(),
      seedType: normalizeSeedTypeId(partition.seedType || ""),
      feminized: String(partition.feminized || "").trim(),
      seedCount: String(partition.seedCount ?? "").trim(),
      seedAgeYears: String(partition.seedAgeYears ?? "").trim(),
      plantedCount: String(partition.plantedCount ?? "").trim(),
      seedVaultEntryId: String(partition.seedVaultEntryId || "").trim(),
      seedVaultEntrySnapshot: partition.seedVaultEntrySnapshot || null,
    }));
  }

  return [...container.querySelectorAll(".partition-row")].map((row, index) => ({
    id: Number(row.dataset.partitionId) || index + 1,
    source: getPartitionRowFieldValue(row, "source").trim(),
    seedVariety: getPartitionRowFieldValue(row, "seedVariety").trim(),
    seedType: normalizeSeedTypeId(getPartitionRowFieldValue(row, "seedType")),
    feminized: getPartitionRowFieldValue(row, "feminized").trim(),
    seedCount: getPartitionRowFieldValue(row, "seedCount").trim(),
    seedAgeYears: getPartitionRowFieldValue(row, "seedAgeYears").trim(),
    plantedCount: getPartitionRowFieldValue(row, "plantedCount").trim(),
    seedVaultEntryId: String(row.dataset.seedVaultEntryId || "").trim(),
    seedVaultEntrySnapshot: readPartitionSeedVaultSnapshotFromRow(row),
  }));
}

function buildNewSessionDraftSignature(form) {
  if (!form) {
    return "";
  }

  return JSON.stringify({
    sessionName: String(form.elements.sessionName?.value || "").trim(),
    date: String(form.elements.date?.value || "").trim(),
    time: String(form.elements.time?.value || "").trim(),
    timeDisplay: String(form.elements.timeDisplay?.value || "").trim(),
    systemType: String(form.elements.systemType?.value || "").trim(),
    unitId: String(form.elements.unitId?.value || "").trim(),
    sessionStatus: String(form.elements.sessionStatus?.value || "").trim(),
    seedAgeTrackingEnabled: Boolean(form.elements.seedAgeTrackingEnabled?.checked),
    seedAgeMode: String(form.querySelector('input[name="seedAgeMode"]:checked')?.value || "").trim(),
    sessionSeedAgeYears: String(form.elements.sessionSeedAgeYears?.value || "").trim(),
    sessionNotes: String(form.elements.sessionNotes?.value || "").trim(),
    publicGrowNote: getEffectivePublicGrowNoteValue(form.querySelector("#share-snapshot-section")?.__snapshotState),
    includePublicGrowNote: shouldIncludePublicGrowNote(form.querySelector("#share-snapshot-section")?.__snapshotState),
    germinationStartedAt: String(form.dataset.germinationStartedAt || "").trim(),
    firstPlantedAt: String(form.dataset.firstPlantedAt || "").trim(),
    completedAt: String(form.dataset.completedAt || "").trim(),
    partitions: buildPartitionDraftValuesFromContainer(form.querySelector("#partition-fields")),
  });
}

function buildSessionDetailDraftSignature(session, partitions, statusField, notesField, detailsForm = null, seedAgeForm = null) {
  const detailSnapshotState = document.querySelector("#detail-share-snapshot-section")?.__snapshotState;
  const detailPublicGrowNoteValue = detailSnapshotState
    ? getEffectivePublicGrowNoteValue(detailSnapshotState)
    : (session?.snapshotState?.publicGrowNote || "");
  const detailIncludePublicGrowNote = detailSnapshotState
    ? shouldIncludePublicGrowNote(detailSnapshotState)
    : Boolean(session?.snapshotState?.includePublicGrowNote);
  const detailSeedAgeState = seedAgeForm instanceof HTMLFormElement
    ? getSeedAgeSettingsFromForm(seedAgeForm)
    : getSessionSeedAgeMetadata(session);
  return JSON.stringify({
    sessionId: String(session?.id || "").trim(),
    sessionName: String(detailsForm?.elements?.sessionName?.value || getSessionDetailEditableName(session)).trim(),
    date: String(session?.date || "").trim(),
    time: String(session?.time || "").trim(),
    timeDisplay: String(formatStoredTime(session?.time || "", getPreferredTimeFormat())).trim(),
    sessionStartedAt: String(session?.sessionStartedAt || "").trim(),
    soakStartedAt: String(session?.soakStartedAt || session?.timerStartAt || "").trim(),
    systemType: String(session?.systemType || "").trim(),
    unitId: String(detailsForm?.elements?.unitId?.value || session?.unitId || "").trim(),
    seedAgeTrackingEnabled: Boolean(detailSeedAgeState?.trackingEnabled),
    seedAgeMode: String(detailSeedAgeState?.mode || "").trim(),
    sessionSeedAgeYears: detailSeedAgeState?.sessionSeedAgeYears === null || detailSeedAgeState?.sessionSeedAgeYears === undefined
      ? ""
      : String(detailSeedAgeState.sessionSeedAgeYears).trim(),
    sessionStatus: String(statusField?.value || session?.sessionStatus || "").trim(),
    sessionNotes: String(notesField?.value || session?.sessionNotes || "").trim(),
    publicGrowNote: normalizePublicGrowNote(detailPublicGrowNoteValue),
    includePublicGrowNote: detailIncludePublicGrowNote,
    germinationStartedAt: String(session?.germinationStartedAt || "").trim(),
    firstPlantedAt: String(session?.firstPlantedAt || "").trim(),
    completedAt: String(session?.completedAt || "").trim(),
    partitions: buildPartitionDraftValuesFromContainer(partitions),
  });
}

function normalizeUnsavedChangesContextType(contextType) {
  const normalizedType = String(contextType || "").trim().toLowerCase();
  if (normalizedType === "profile") {
    return "profile";
  }
  if (normalizedType === "session") {
    return "session";
  }
  return "generic";
}

function syncUnsavedChangesDirtyFlags() {
  const activeContextType = normalizeUnsavedChangesContextType(appState.unsavedChanges.contextType);
  const hasUnsavedChanges = Boolean(appState.unsavedChanges.active && appState.unsavedChanges.hasUnsavedChanges);
  appState.unsavedChanges.sessionDirty = activeContextType === "session" && hasUnsavedChanges;
  appState.unsavedChanges.profileDirty = activeContextType === "profile" && hasUnsavedChanges;
}

function getUnsavedChangesPromptCopy() {
  const contextType = normalizeUnsavedChangesContextType(appState.unsavedChanges.contextType);
  if (contextType === "profile") {
    return {
      title: "You have unsaved profile changes. Save before leaving?",
      body: "You have unsaved profile changes. Are you sure you want to leave?",
      saveError: "Could not save your profile changes before leaving.",
      beforeUnload: "You have unsaved profile changes. Are you sure you want to leave?",
    };
  }

  if (contextType === "session") {
    return {
      title: "You have unsaved grow session changes. Save before leaving?",
      body: "You have unsaved grow session changes. Are you sure you want to leave?",
      saveError: "Could not save this session before leaving.",
      beforeUnload: "You have unsaved grow session changes. Are you sure you want to leave?",
    };
  }

  return {
    title: "You have unsaved changes. Save before leaving?",
    body: "You have unsaved changes. Are you sure you want to leave?",
    saveError: "Could not save your changes before leaving.",
    beforeUnload: "You have unsaved changes. Are you sure you want to leave?",
  };
}

function isDevelopmentErrorDetailsEnabled() {
  return isLocalDevelopmentHost() || isLocalDevQaBypassActive();
}

function getReadableErrorDetails(error) {
  if (!error) {
    return "";
  }

  return [...new Set([
    error.message,
    error.details,
    error.hint,
    error.code,
  ]
    .map((value) => String(value || "").trim())
    .filter(Boolean))].join(" | ");
}

function formatSaveErrorForDisplay(error, fallback = "Could not save your changes.") {
  const details = getReadableErrorDetails(error);
  if (details && isDevelopmentErrorDetailsEnabled()) {
    return details;
  }
  return String(error?.message || fallback || "Could not save your changes.").trim();
}

function setUnsavedChangesLastSaveError(error, fallback = "") {
  const message = formatSaveErrorForDisplay(error, fallback);
  appState.unsavedChanges.lastSaveError = {
    message,
    raw: error || null,
  };
  return message;
}

function clearUnsavedChangesLastSaveError() {
  appState.unsavedChanges.lastSaveError = null;
}

function clearUnsavedChangesContext() {
  appState.unsavedChanges.active = false;
  appState.unsavedChanges.hasUnsavedChanges = false;
  appState.unsavedChanges.contextType = "";
  appState.unsavedChanges.pageHash = "";
  appState.unsavedChanges.baselineSignature = "";
  appState.unsavedChanges.getSignature = null;
  appState.unsavedChanges.saveFn = null;
  appState.unsavedChanges.promptOpen = false;
  appState.unsavedChanges.lastSaveError = null;
  syncUnsavedChangesDirtyFlags();
}

function registerUnsavedChangesContext({ pageHash, getSignature, saveFn, contextType = "generic" }) {
  if (typeof getSignature !== "function" || typeof saveFn !== "function") {
    clearUnsavedChangesContext();
    return;
  }

  appState.unsavedChanges.active = true;
  appState.unsavedChanges.contextType = normalizeUnsavedChangesContextType(contextType);
  appState.unsavedChanges.pageHash = normalizeNavigationHash(pageHash || window.location.hash || "#home");
  appState.unsavedChanges.getSignature = getSignature;
  appState.unsavedChanges.saveFn = saveFn;
  appState.unsavedChanges.baselineSignature = getSignature();
  appState.unsavedChanges.hasUnsavedChanges = false;
  appState.unsavedChanges.lastSaveError = null;
  syncUnsavedChangesDirtyFlags();
}

function refreshUnsavedChangesState() {
  if (!appState.unsavedChanges.active || typeof appState.unsavedChanges.getSignature !== "function") {
    appState.unsavedChanges.hasUnsavedChanges = false;
    syncUnsavedChangesDirtyFlags();
    return false;
  }

  const currentSignature = appState.unsavedChanges.getSignature();
  appState.unsavedChanges.hasUnsavedChanges = currentSignature !== appState.unsavedChanges.baselineSignature;
  syncUnsavedChangesDirtyFlags();
  return appState.unsavedChanges.hasUnsavedChanges;
}

function markUnsavedChangesSaved() {
  if (!appState.unsavedChanges.active || typeof appState.unsavedChanges.getSignature !== "function") {
    appState.unsavedChanges.hasUnsavedChanges = false;
    syncUnsavedChangesDirtyFlags();
    return;
  }

  appState.unsavedChanges.baselineSignature = appState.unsavedChanges.getSignature();
  appState.unsavedChanges.hasUnsavedChanges = false;
  appState.unsavedChanges.lastSaveError = null;
  syncUnsavedChangesDirtyFlags();
}

function patchUnsavedChangesBaseline(mutator) {
  if (!appState.unsavedChanges.active || typeof appState.unsavedChanges.getSignature !== "function") {
    return;
  }

  try {
    const baseline = JSON.parse(appState.unsavedChanges.baselineSignature || "{}");
    const current = JSON.parse(appState.unsavedChanges.getSignature() || "{}");
    const nextBaseline = mutator({ ...baseline }, current) || baseline;
    appState.unsavedChanges.baselineSignature = JSON.stringify(nextBaseline);
    refreshUnsavedChangesState();
  } catch {
    markUnsavedChangesSaved();
  }
}

function hasPendingUnsavedChanges() {
  return refreshUnsavedChangesState();
}

function hasPendingUnsavedSessionChanges() {
  return hasPendingUnsavedChanges();
}

function shouldBlockNavigationForUnsavedChanges(nextHash = window.location.hash || "#home") {
  if (!appState.unsavedChanges.active || appState.unsavedChanges.promptOpen) {
    return false;
  }

  const currentHash = normalizeNavigationHash(appState.unsavedChanges.pageHash || appState.currentRouteHash || "#home");
  const targetHash = normalizeNavigationHash(nextHash);
  if (currentHash === targetHash) {
    return false;
  }

  return hasPendingUnsavedChanges();
}

function navigateWithUnsavedChangesBypass(nextHash) {
  const targetHash = normalizeNavigationHash(nextHash);
  appState.unsavedChanges.ignoreNextHashChange = true;
  clearUnsavedChangesContext();
  if ((window.location.hash || "#home") === targetHash) {
    safeRender();
    return;
  }
  window.location.hash = targetHash;
}

function ensureUnsavedChangesDialog() {
  let modal = document.querySelector("#unsaved-changes-dialog");
  if (modal instanceof HTMLDialogElement) {
    return modal;
  }

  modal = document.createElement("dialog");
  modal.id = "unsaved-changes-dialog";
  modal.className = "snapshot-modal unsaved-changes-dialog";
  modal.innerHTML = `
    <form method="dialog" class="snapshot-modal-card profile-modal-card unsaved-changes-dialog-card">
      <div class="snapshot-modal-copy">
        <p class="eyebrow">Unsaved Changes</p>
        <h3 id="unsaved-changes-dialog-title">You have unsaved changes. Save before leaving?</h3>
        <p id="unsaved-changes-dialog-body" class="muted">You have unsaved changes. Are you sure you want to leave?</p>
      </div>
      <p id="unsaved-changes-dialog-message" class="form-message" role="alert" aria-live="polite"></p>
      <div class="snapshot-modal-actions">
        <button type="button" class="button button-primary" data-unsaved-action="save">Save and continue</button>
        <button type="button" class="button button-danger" data-unsaved-action="leave">Leave without saving</button>
        <button type="button" class="button button-secondary" data-unsaved-action="cancel">Cancel</button>
      </div>
    </form>
  `;
  document.body.appendChild(modal);
  return modal;
}

function promptForUnsavedChangesNavigation(nextHash) {
  const targetHash = normalizeNavigationHash(nextHash);
  if (appState.unsavedChanges.promptOpen || !appState.unsavedChanges.active) {
    return;
  }

  const modal = ensureUnsavedChangesDialog();
  const title = modal.querySelector("#unsaved-changes-dialog-title");
  const body = modal.querySelector("#unsaved-changes-dialog-body");
  const message = modal.querySelector("#unsaved-changes-dialog-message");
  const saveButton = modal.querySelector('[data-unsaved-action="save"]');
  const leaveButton = modal.querySelector('[data-unsaved-action="leave"]');
  const cancelButton = modal.querySelector('[data-unsaved-action="cancel"]');
  if (!(saveButton instanceof HTMLButtonElement) || !(leaveButton instanceof HTMLButtonElement) || !(cancelButton instanceof HTMLButtonElement)) {
    return;
  }
  const promptCopy = getUnsavedChangesPromptCopy();

  appState.unsavedChanges.promptOpen = true;
  if (title) {
    title.textContent = promptCopy.title;
  }
  if (body) {
    body.textContent = promptCopy.body;
  }
  if (message) {
    setFeedbackMessage(message, "");
  }

  const cleanup = () => {
    saveButton.disabled = false;
    leaveButton.disabled = false;
    cancelButton.disabled = false;
    appState.unsavedChanges.promptOpen = false;
    saveButton.onclick = null;
    leaveButton.onclick = null;
    cancelButton.onclick = null;
  };

  cancelButton.onclick = () => {
    cleanup();
    if (modal.open) {
      modal.close();
    }
  };

  leaveButton.onclick = () => {
    cleanup();
    if (modal.open) {
      modal.close();
    }
    navigateWithUnsavedChangesBypass(targetHash);
  };

  saveButton.onclick = async () => {
    saveButton.disabled = true;
    leaveButton.disabled = true;
    cancelButton.disabled = true;
    if (message) {
      setFeedbackMessage(message, "");
    }

    try {
      clearUnsavedChangesLastSaveError();
      const didSave = await appState.unsavedChanges.saveFn({ navigateOnSuccess: false, destinationHash: targetHash });
      if (!didSave) {
        throw new Error(appState.unsavedChanges.lastSaveError?.message || promptCopy.saveError);
      }

      markUnsavedChangesSaved();
      cleanup();
      if (modal.open) {
        modal.close();
      }
      navigateWithUnsavedChangesBypass(targetHash);
    } catch (error) {
      setFeedbackMessage(message, formatSaveErrorForDisplay(error, promptCopy.saveError), "error");
      saveButton.disabled = false;
      leaveButton.disabled = false;
      cancelButton.disabled = false;
    }
  };

  modal.addEventListener("close", cleanup, { once: true });
  modal.showModal();
  saveButton.focus();
}

function capitalize(value) {
  return value.charAt(0).toUpperCase() + value.slice(1);
}

if (document.body) {
  applyTheme(getPreferredTheme(), { persist: false });
}

registerServiceWorker();
bindInstallPromptEvents();

window.addEventListener("error", (event) => {
  reportAppError(event.error || new Error(event.message || "Unknown script error"), "JavaScript Error");
});

window.addEventListener("unhandledrejection", (event) => {
  reportAppError(event.reason instanceof Error ? event.reason : new Error(String(event.reason || "Unhandled promise rejection")), "Unhandled Promise Rejection");
});

document.addEventListener("click", (event) => {
  const learnEmptyTutorialButton = event.target instanceof Element
    ? event.target.closest("[data-learn-empty-tutorial]")
    : null;
  if (learnEmptyTutorialButton instanceof HTMLElement) {
    event.preventDefault();
    event.stopPropagation();
    openLearnTutorialFromHelper(learnEmptyTutorialButton.dataset.learnEmptyTutorial || "", "Empty state");
    return;
  }

  const learnTutorialPathLink = event.target instanceof Element
    ? event.target.closest('a[href^="/learn/tutorial/"]')
    : null;
  if (learnTutorialPathLink instanceof HTMLAnchorElement) {
    const tutorialId = decodeURIComponent(String(learnTutorialPathLink.getAttribute("href") || "").replace(/^\/learn\/tutorial\/?/, ""));
    if (tutorialId) {
      event.preventDefault();
      event.stopPropagation();
      navigateToLearnTutorialDetailRoute(tutorialId);
      return;
    }
  }

  const learnPathLink = event.target instanceof Element
    ? event.target.closest('a[href^="/learn/path/"]')
    : null;
  if (learnPathLink instanceof HTMLAnchorElement) {
    const collectionId = decodeURIComponent(String(learnPathLink.getAttribute("href") || "").replace(/^\/learn\/path\/?/, ""));
    if (collectionId) {
      event.preventDefault();
      event.stopPropagation();
      navigateToLearnCollectionDetailRoute(collectionId);
      return;
    }
  }

  const internalLink = event.target instanceof Element
    ? event.target.closest('a[href^="#"]')
    : null;
  if (internalLink instanceof HTMLAnchorElement) {
    const targetHash = normalizeNavigationHash(internalLink.getAttribute("href") || "#home");
    if (internalLink.dataset.publicLearnLink === "true" && targetHash === "#learn") {
      closeAuthModal();
    }

    const navLockState = getNavigationLockStateForHash(internalLink.getAttribute("href") || "#home");
    if (navLockState.locked) {
      event.preventDefault();
      event.stopPropagation();
      if (internalLink.closest(".mobile-nav-content")) {
        closeMobileNavigation();
      }
      showNavigationLockToast({
        title: navLockState.mode === "community-grow" ? "Community Grow" : "Grow Network",
        message: navLockState.message,
        ctaLabel: navLockState.ctaLabel,
        ctaHref: navLockState.ctaHref,
      });
      return;
    }

    if (shouldBlockNavigationForUnsavedChanges(targetHash)) {
      event.preventDefault();
      event.stopPropagation();
      promptForUnsavedChangesNavigation(targetHash);
      return;
    }
    if (getCurrentAppPathRoute()) {
      event.preventDefault();
      event.stopPropagation();
      navigateToHashRoute(targetHash);
      return;
    }
  }

  const communityInsightsLink = event.target instanceof Element
    ? event.target.closest('a[href="/community-grow#community-insights"]')
    : null;
  if (communityInsightsLink instanceof HTMLAnchorElement) {
    const targetHash = "#gallery/community-insights";
    if (shouldBlockNavigationForUnsavedChanges(targetHash)) {
      event.preventDefault();
      event.stopPropagation();
      promptForUnsavedChangesNavigation(targetHash);
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    navigateToHashRoute(targetHash);
    return;
  }

  const communitySeedAgeInsightsLink = event.target instanceof Element
    ? event.target.closest('a[href="/community-grow#community-insights-seed-age"]')
    : null;
  if (communitySeedAgeInsightsLink instanceof HTMLAnchorElement) {
    const targetHash = "#gallery/community-insights-seed-age";
    if (shouldBlockNavigationForUnsavedChanges(targetHash)) {
      event.preventDefault();
      event.stopPropagation();
      promptForUnsavedChangesNavigation(targetHash);
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    navigateToHashRoute(targetHash);
    return;
  }

  const seedAgeAnalyticsLink = event.target instanceof Element
    ? event.target.closest('a[href="/seed-age-analytics"]')
    : null;
  if (seedAgeAnalyticsLink instanceof HTMLAnchorElement) {
    const targetHash = "#seed-age-analytics";
    if (shouldBlockNavigationForUnsavedChanges(targetHash)) {
      event.preventDefault();
      event.stopPropagation();
      promptForUnsavedChangesNavigation(targetHash);
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    navigateToSeedAgeAnalyticsRoute();
    return;
  }

  const newSessionTrigger = event.target instanceof Element
    ? event.target.closest('a[href="#new"]')
    : null;

  if (newSessionTrigger instanceof HTMLAnchorElement) {
    event.preventDefault();
    appState.newSessionReturnHash = window.location.hash || "#home";
    void promptFilterPaperSetupBeforeNewSession().then((canProceed) => {
      if (!canProceed) {
        return;
      }
      openNewSessionSystemModal();
    });
    return;
  }

  if (!(event.target instanceof Node) || !event.target.closest(".custom-select")) {
    closeAllCustomSelects();
  }

  if (appState.notificationCenterOpen) {
    const clickedInsideNotificationCenter = event.target instanceof Node && (
      appNotificationCenter?.contains(event.target)
      || appNotificationPanel?.contains(event.target)
    );
    if (!clickedInsideNotificationCenter) {
      appState.notificationSnoozeMenuOpenId = "";
      closeAppNotificationCenter();
    }
  }

  if (!appState.accountMenuOpen) {
    return;
  }

  const menuRoot = document.querySelector("[data-account-menu-root]");
  if (menuRoot && event.target instanceof Node && menuRoot.contains(event.target)) {
    return;
  }

  closeAccountMenu();
});

document.addEventListener("keydown", (event) => {
  if (event.key === "Escape") {
    closeAllCustomSelects();
  }

  if (event.key === "Escape" && appState.notificationCenterOpen) {
    appState.notificationSnoozeMenuOpenId = "";
    closeAppNotificationCenter();
  }

  if (event.key === "Escape" && appState.accountMenuOpen) {
    closeAccountMenu();
  }

  if (event.key === "Escape" && appState.mobileNavOpen) {
    closeMobileNavigation();
  }

  const target = event.target;
  const isTypingTarget = target instanceof HTMLElement && (
    target.matches("input, textarea, select")
    || target.isContentEditable
  );
  if (
    !isTypingTarget
    && event.shiftKey
    && String(event.key || "").toLowerCase() === "d"
    && canAccessMockDataControls()
  ) {
    event.preventDefault();
    setMockDataEnabledAndRefresh(!isMockDataEnabled());
  }
});

window.addEventListener("beforeunload", (event) => {
  if (!hasPendingUnsavedChanges()) {
    return;
  }

  event.preventDefault();
  event.returnValue = getUnsavedChangesPromptCopy().beforeUnload;
});

window.addEventListener("resize", requestOpenCustomSelectMenuPositionSync, { passive: true });
document.addEventListener("scroll", requestOpenCustomSelectMenuPositionSync, true);
window.addEventListener("popstate", safeRender);
window.addEventListener("hashchange", handleHashChange);
window.addEventListener("DOMContentLoaded", safeBootstrapApp);
window.removeCannakanSampleSessions = removeSampleSessions;
